function printOutputITEXT(text)
{
	if (!bPDFDesenvolupament)		return;
	if (!scoGSITVal.isFormulariAcusament())	return;
	if (scoGSITVal.isEmpty(text))	return;
	requeridor.TXT_OUTPUT_ITEXT.rawValue = text + "\n";
}

