};

/////////////////////////////////////////////////////////////////////////////
// MÈTODES
/////////////////////////////////////////////////////////////////////////////

///////////////////////////////////////////////////////////////////////
// Nom : mostraAccionsAplicables
// Descripció: Mètode que mostra/oculta les accions aplicables
//////////////////////////////////////////////////////////////////////
function mostraAccionsAplicables(oItem) 
{
	// - Tipus resposta
	var sTipusResposta = scoINSPQuestioItem.obtenirTipusResposta(oItem);

	// - Nodes tipus resposta accions (respostes que activen les accions aplicables)
	var oNodesRespostesAccions = scoINSPQuestioItem.getNodesOpcionRespostaAccions(oItem);

	if (!hiHaAccionsAplicables(oNodesRespostesAccions))
	{
		defVisibilitatPanell(oItem, false);
		return;
	}	
	var bMostrar;
	var oObj = scoINSPQuestioItem.getObjectTipusResposta(oItem, sTipusResposta);
	if (scoINSPQuestions.isSeleccio(sTipusResposta) || scoINSPQuestions.isMultiseleccio(sTipusResposta) ) {
		bMostrar = esRespostaAccioAplicableCheck(oObj, oNodesRespostesAccions);
	}
	else if (scoINSPQuestions.isLlista(sTipusResposta)) {
		bMostrar = esRespostaAccioAplicableLlista(oObj, oNodesRespostesAccions);
	}
	else bMostrar = false;
	defVisibilitatPanell(oItem, bMostrar);
}


///////////////////////////////////////////////////////////////////////
// Nom : defVisibilitatPanell
// Descripció: Mètode que mostra/oculta el panell
//////////////////////////////////////////////////////////////////////
function defVisibilitatPanell(oItem, bMostrar) 
{
	scoSBSMostra.mostrarOcultarPanell(scoGSITPanells.obtenirObjecteFill(oItem, "S_ACCIONS_APLICABLES"), bMostrar, false);
}

///////////////////////////////////////////////////////////////////////
// Nom : esRespostaAccioAplicableCheck
// Descripció: Mètode que comprova si alguna de les opcions de resposta existeix a 'oNodesIds'
//////////////////////////////////////////////////////////////////////
function esRespostaAccioAplicableCheck(oSeleccio, oNodesIds) 
{
	if (oSeleccio == null || oSeleccio == undefined)			return false;
	var oCamps = scoINSPItemSeleccio.getCampsSeleccio(oSeleccio);
	if (oCamps == null || oCamps == undefined)			return false;

	var bTrobat = false;
	var i = 0;
	while (!bTrobat && i < oCamps.length) {
		var oCamp = oCamps.item(i);
		if (scoGSITVal.existeixObjecte(oCamp)) {
			if (scoINSPItemSeleccio.isCheckMarcat(oCamp)) {
				var oTxtId = oCamp.parent.TXT_ID;
				if (scoGSITVal.existeixObjecte(oTxtId)) {
					bTrobat = cercaId(oCamp.parent.TXT_ID.rawValue, oNodesIds);
				}
			}
		}
		i++;
	}
	return bTrobat;
}


///////////////////////////////////////////////////////////////////////
// Nom : esRespostaAccioAplicableLlista
// Descripció: Mètode que comprova si l'element seleccionat a la llista existeix a 'oNodesIds'
//////////////////////////////////////////////////////////////////////
function esRespostaAccioAplicableLlista(oLlista, oNodesIds) 
{
	var oTxtCamp  = scoGSITPanells.obtenirObjecteFill(oLlista, "TXT_CAMP");
	if (!scoGSITVal.existeixObjecte(oTxtCamp))			return false;

	return cercaId(oTxtCamp.rawValue, oNodesIds);
}

///////////////////////////////////////////////////////////////////////
// Nom : cercaId			
// Descripció: Mètode que cerca l'identificador en els nodes 'oNodesIds'
//////////////////////////////////////////////////////////////////////
function cercaId(id, oNodesIds) 
{
	var bTrobat = false;
	var i = 0;
	while (!bTrobat && i < oNodesIds.length) {
		var oId = oNodesIds.item(i);
		if (scoGSITVal.existeixObjecte(oId)) {
			bTrobat = (oId.value == id);
		}
		i++;
	}	
	return bTrobat;
}


///////////////////////////////////////////////////////////////////////
// Nom : hiHaAccionsAplicables
// Descripció: Mètode que comprova si al xml hi ha definides accions aplicables
//////////////////////////////////////////////////////////////////////
function hiHaAccionsAplicables(oNodesIds) 
{
	if (oNodesIds == null || oNodesIds == undefined)			return false;
	return (oNodesIds.length > 0);
}

