/////////////////////////////////////////////////////////////////////////////
// VARIABLES
/////////////////////////////////////////////////////////////////////////////

var CT_SIZE_TITOL_TBLT = "12pt";
var CT_SIZE_TITOL_STD = "8pt";

var CT_MINH_LBL_TBLT = "34pt";
var CT_MINH_LBL_STD = "17pt";

/////////////////////////////////////////////////////////////////////////////
// MÈTODES
/////////////////////////////////////////////////////////////////////////////

///////////////////////////////////////////////////////////////////////
// Nom : setXmlFileAttachments
// Descripció: 
//////////////////////////////////////////////////////////////////////
function setXmlFileAttachments()
{
	try{
		var xml_attachments = "<attachments>"; 
        var d = event.target.dataObjects;
        if (d == null || d == undefined)	return;

		for (var i = 0; i < d.length; i++){
			var name = d[i].name;
        		var fullName = d[i].path;
			var oFile = event.target.getDataObjectContents(name);
        		var vEncodedStream = Net.streamEncode(oFile, "base64");
        		var sBase64 = util.stringFromStream(vEncodedStream);
        		xml_attachments += "<attachment><name>" + fullName + "</name><base64>" + sBase64 + "</base64></attachment>";
        		event.target.removeDataObject(name);
        }
        xml_attachments += "</attachments>";                     
        event.target.createDataObject("attachments.xml", xml_attachments);
	}
    	catch(exc) 
	{
		return scoGSITGen.retornarExcepcio("scoINSPAdjunts.setXmlFileAttachments",exc);
	}
}


///////////////////////////////////////////////////////////////////////
// Nom : getXmlFileAttachments
// Descripció: 
//////////////////////////////////////////////////////////////////////
function getXmlFileAttachments()
{
	try{
    	   var oFile = event.target.getDataObjectContents("attachments.xml");
       var cXMLDoc = util.stringFromStream(oFile);
       var oXml = XMLData.parse(cXMLDoc, true);
       var oNodes = oXml.nodes;
       for(var i=0;i<oNodes.length;i++){
			var oNode = oNodes.item(i);

            var name = "";
            var b64Data = "";
            if (oNode.nodes.item(0).name == "name"){
            		name = oNode.nodes.item(0).value;
			}

            if (oNode.nodes.item(1).name == "base64"){
            		b64Data = oNode.nodes.item(1).value;                                     
			}

            var ReadStream = Net.streamFromString(b64Data);
            var DecodedStream = Net.streamDecode(ReadStream, "base64");
            event.target.createDataObject(name, "");//, "image/png");
            event.target.setDataObjectContents(name, DecodedStream);
		}

        event.target.removeDataObject("attachments.xml");

	}catch(ex){
    		return scoGSITGen.retornarExcepcio("scoINSPAdjunts.getXmlFileAttachments",exc);
    }
}

///////////////////////////////////////////////////////////////////////
// Nom : defineixAdjuntsVisualitzacio
// Descripció: 
//////////////////////////////////////////////////////////////////////
function defineixAdjuntsVisualitzacio()
{
	if (!scoGSITPar.bFormulariTeAdjunts || !scoGSITVal.existeixObjecte(scoGSITPar.oPanellAdjunts))	return;

	var bModeTableta = scoINSPVisualitzacio.esModeTableta();

		// títol
	if (!scoGSITVal.isFormulariAcusament())
	{
		mostraOcultaTitolAdjunts(bModeTableta);
	}	

		// Missatge
	var oMsg = scoGSITPar.oPanellAdjunts.cMissatge;
	oMsg.font.size = (bModeTableta)?CT_SIZE_TITOL_TBLT:CT_SIZE_TITOL_STD;

		// Dades adjunts
	var oAdjunts = scoGSITPar.oPanellAdjunts.resolveNodes("ADJUNT[*]");
	if (oAdjunts != null && oAdjunts != undefined)
	{
		for (var i = 0; i < oAdjunts.length; i++)
		{
			var oAdjunt = oAdjunts.item(i);
			if (oAdjunt != null && oAdjunt != undefined)
			{
				defineixAdjuntVisualitzacio(oAdjunt, bModeTableta);
			}
		}
	}
}


///////////////////////////////////////////////////////////////////////
// Nom : defineixAdjuntVisualitzacio
// Descripció: 
//////////////////////////////////////////////////////////////////////
function defineixAdjuntVisualitzacio(oAdjunt, bModeTableta)
{
	if (!scoGSITVal.existeixObjecte(oAdjunt))	return;

	if (arguments.length < 2)		bModeTableta = scoINSPVisualitzacio.esModeTableta();

	var lblNom = oAdjunt.lblNomFitxer;

	lblNom.font.size = (bModeTableta)?CT_SIZE_TITOL_TBLT:CT_SIZE_TITOL_STD;
	lblNom.minH = (bModeTableta)?CT_MINH_LBL_TBLT:CT_MINH_LBL_STD;

	if (!scoGSITVal.isFormulariAcusament())
	{
		mostraOcultaSubBtns(oAdjunt, bModeTableta);
	}
}

