{
	var oSubTitolTblt = scoGSITPar.oPanellAdjunts.resolveNode("SUB_CAPCALERA[" + scoINSPVisualitzacio.CT_INDEX_TBLT + "]");		
	oSubTitolTblt.presence = (bModeTableta)?"visible":"hidden";

