function accioNormalitzarAdreca(oNormalitzador, subInstancia, index, indexDesti)
{
	if (scoGSITPar.bPDFDesenvolupament)
	{
	 	oNormalitzador.TXT_VERIFICAT.rawValue = "1";		// Per si NO funciona el normalitzador
	}
	else {
		// 02/2020		Encara que NO funcioni el normalitzados marquem que ja s'ha fet l'intent de verificar
		//if (scoGSITNormalitzador.accioVerificaAdreca(this.parent)) {
			scoGSITNormalitzador.accioVerificaAdreca(oNormalitzador);
			oNormalitzador.TXT_VERIFICAT.rawValue = "1";
			scoGSITVal.amagarRequadre(oNormalitzador.BTN_BUSCAR);
		//}
	}


	// Cal copiar a l'altra instància: TXT_NORMALITZADA / TXT_RESULTAT / TXT_MSG_VERIFICAT / TXT_VERIFICAT
	scoINSPVisualitzacio.copiaCampsValor([oNormalitzador.TXT_NORMALITZADA, oNormalitzador.TXT_RESULTAT, oNormalitzador.TXT_VERIFICAT], subInstancia, index, indexDesti);
	scoINSPVisualitzacio.copiaCampsPropietats([oNormalitzador.TXT_NORMALITZADA, oNormalitzador.TXT_MSG_VERIFICAT, oNormalitzador.BTN_BUSCAR, oNormalitzador.BTN_ACCEPTAR], 
											subInstancia, index, indexDesti);
}


