**************************************************************************/

/////////////////////////////////////////////////////////////////////////////
// VARIABLES
/////////////////////////////////////////////////////////////////////////////
var aCampsIdentificacio = ["TXT_NOM", "TXT_COGNOM1", "TXT_COGNOM2", "TXT_TIPUS_IDENTIFICADOR", "TXT_NUM_IDENTIFICADOR", "TXT_PAIS_DOCUMENT", "TXT_PAIS_DOCUMENT_NOM"];


/////////////////////////////////////////////////////////////////////////////
// MÈTODES
/////////////////////////////////////////////////////////////////////////////

////////////////////////////////////////////////////////////
// Nom: getPanellCompareixent
// Descripció:  
////////////////////////////////////////////////////////////
function getPanellCompareixent(nIndex)
{
	return (xfa.resolveNode("contacteAvisos[0].BLOC[0].dadesParticulars[0].S_COMPAREIXENT[" + nIndex + "]"));
}

////////////////////////////////////////////////////////////
// Nom: copiaDadesRequeridorCompareixent
// Descripció: Mètode que copia els camps de requeridor a Compareixent
// Paràmetres d'entrada:
//		bPregunta - Indica si s'ha de preguntar si es vol realitzar la copia
////////////////////////////////////////////////////////////
function copiaDadesRequeridorCompareixent(oPanellCompareixent, subInstancia, index, indexDesti, bPregunta)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (!scoGSITCamps.esVisible(oPanellCompareixent)) return;

		var bPregunta = (scoGSITPanells.teAlgunCampPlePanell(oPanellCompareixent) && bPregunta) ? true : false;

		bCopia = (bPregunta) ? (scoGSITMissatges.MissatgePregunta(msgPreguntaCopiarDadesACompareixent.value,"")) : true;
		if (bCopia) 
		{
			var oPanellRequeridor = scoINSPInspeccionat.getPanellDadesRequeridor(index);
			var sTipusUsuari = scoGSITVal.tipusUsuariPanell(oPanellRequeridor);
			var oContacteRequeridor = scoGSITPanells.obtenirPanellFisicaJuridicaDades(oPanellRequeridor);
			if (scoGSITVal.esPanellAmbRepresentant(sTipusUsuari))   oContacteRequeridor = scoGSITPanells.obtenirObjecteFill(oContacteRequeridor, "REPRESENTANT");

			var oContacteCompareixent = scoGSITPanells.obtenirObjecteFill(oPanellCompareixent, "CONTACTE");

			scoGSITGen.amagarRequadresForm(oContacteCompareixent);
			scoGSITPanells.clonaCampsPanells(oContacteRequeridor, oContacteCompareixent, aCampsIdentificacio, true, false); 

			// 122020	Cal mostrar país document si aquest té valor [no s'està mostrant al fer la còpia]
			var oPaisDocument = oContacteCompareixent.TXT_PAIS_DOCUMENT;
			var oIdDocument = oContacteCompareixent.TXT_NUM_IDENTIFICADOR;
			if (scoGSITVal.existeixObjecte(oPaisDocument) && scoGSITVal.existeixObjecte(oIdDocument))
			{
				oPaisDocument.presence = (scoGSITVal.isEmpty(oPaisDocument))?"invisible":"visible";
				oPaisDocument.access = oIdDocument.access;

				scoINSPVisualitzacio.copiaPropietats(oPaisDocument, subInstancia, index, indexDesti);
			}
		}
	}
	catch(exc) 
	{
		return scoGSITGen.retornarExcepcio("scoINSPCompareixent.copiaDadesRequeridorCompareixent",exc);
	}
}


