///////////////////////////////////////////////////////////////////////
// Nom : initPanellConformitats
// Descripció: Mètode que inicialitza el panell
//////////////////////////////////////////////////////////////////////
function initPanellConformitats()
{
	scoGSITCamps.defVisibilitat(scoGSITPar.oPanellConformitats, (scoINSPVal.hiHaItemsATaula(scoGSITPar.oPanellConformitats, "S_TAULA_CONFORMITATS", "S_CONFORMITAT"))?"visible":"hidden");

	if (scoGSITPar.oPanellConformitats.presence == "visible")
	{
		var oTaulaMotius = scoGSITPar.oPanellConformitats.S_TAULA_CONFORMITATS;
		var defCheck = getDefinicioCheck();

		var oChecks = oTaulaMotius.resolveNodes("S_CONFORMITAT[*].CHECK[0]");
		for (var i = 0; i < oChecks.length; i++)
		{
			defineixCheckConformitat(oChecks.item(i), defCheck);
		}
	}
}               


