///////////////////////////////////////////////////////////////////////
// Nom : defineixCheckConformitat
// Descripció: 
//////////////////////////////////////////////////////////////////////
function defineixCheckConformitat(oCheck, defCheck)
{

	oCheck.minH = defCheck.CT_MIN_HEIGHT;	//"3mm";
	oCheck.ui.checkButton.size = defCheck.CT_CHECK_SIZE;	//"1.8mm";
	oCheck.caption.font.size = defCheck.CT_CAPTION_FONTSIZE;	//"6pt";
	oCheck.margin.topInset = defCheck.CT_MARGIN_TOPINSET;	//"1mm";
	oCheck.margin.bottomInset = defCheck.CT_MARGIN_BOTTOMINSET;	//"0mm";
}

