/////////////////////////////////////////////////////////////////////////////
// Nom: setCoordsFields
// Descripció: Mètode que s'encarrega d'actualitzar els camps amb les mesures de posició d'un camp de signatura
// Paràmetres d'entrada:
//		oPanell - Panell que conté l'objecte signatura i els camps de posició de la signatura (x, y, Height, Width, Pagina)
///////////////////////////////////////////////////////////////////////////// 
function setCoordsFields(oPanell)
{
	// 202012		 posem la condició a la crida quan es necessiti		if (scoGSITVal.isFormulariAcusament())			return;

	var vExtents = getExtents(oPanell);
	if(vExtents == null || vExtents == undefined) 		return;

	var oPosicioX = scoGSITPanells.obtenirObjecteFill(oPanell, "x");
	var oPosicioY = scoGSITPanells.obtenirObjecteFill(oPanell, "y");
	var oPosicioH = scoGSITPanells.obtenirObjecteFill(oPanell, "Height");
	var oPosicioW = scoGSITPanells.obtenirObjecteFill(oPanell, "Width");
	var oPosicioPagina = scoGSITPanells.obtenirObjecteFill(oPanell, "Pagina");

	if (!scoGSITVal.existeixObjecte(oPosicioX) || !scoGSITVal.existeixObjecte(oPosicioY) || 
		!scoGSITVal.existeixObjecte(oPosicioH) || !scoGSITVal.existeixObjecte(oPosicioW) ||
		!scoGSITVal.existeixObjecte(oPosicioPagina) ) return;

	if (vExtents[0] != null && vExtents[0] != undefined) {
		oPosicioX.rawValue =  vExtents[0].x.toFixed(3);
		oPosicioY.rawValue =  vExtents[0].y.toFixed(3);
		oPosicioH.rawValue = vExtents[0].h.toFixed(3);
		oPosicioW.rawValue = vExtents[0].w.toFixed(3);
		oPosicioPagina.rawValue = vExtents[0].page + 1;
	}
}


// This function returns an array of extents for a given object
// There will be one entry in the array for each content area
// an object appears in.
// Each entry is an object with these properties:
//   Extent.page
//   Extent.contentArea  (SOM expression)
//   Extent.x            (absolute page position)
//   Extent.y
//   Extent.w
//   Extent.h   
// All measurements are mm.
function getExtents(vObject)
{
try{
	// The array of extents to return
	var vExtents = new Array();

	// A list of the content areas that vObject and its
	// ancestors occur inside
	var vContentAreas = new Array();

	// A list of our ancestors.
	var vTree = new Array();

	// Gather the list of ancestors
	// Don't include the root subform, since it's origin is always (0,0)
	// so doesn't affect position.

//console.println("- getExtents - " + vObject);
	if (vObject === null || vObject === "undefined" || vObject === undefined) return;

	var vNode = vObject;
	vTree.push(vNode);

//var j = 0;
//console.println("- " + j + " - getExtents - " + vNode.parent.className);
	while (vNode.parent.className != "form")
	{
j++;
//console.println("- " + j + " - getExtents - " + vNode.parent.className);
		// Hey! This object is on a master page.
		// Much different algorithm...
		if (vNode.parent.className == "pageArea")
			return handleMasterPageObject(vObject);

		vNode = vNode.parent;
		vTree.push(vNode);
	} 

	// The first page the object ancestors appear on
	var nFirstPage = xfa.layout.page(vTree[vTree.length-1])-1;

	// The number of pages the object and ancestors appear on
	var nLastPage  = xfa.layout.page(vObject)-1 + xfa.layout.pageSpan(vObject);
	var nPageSpan = nLastPage - nFirstPage;

	var nOffset = 0;
	for (var nPage=0; nPage<nPageSpan; nPage++)
	{
		// get a list of all the objects on the page
		// If an object appears on the page in more than one content area,
		// it will appear multiple times in the list.
		// In each case, you can infer that the corresponding content area
		// will be the most recent content area seen in the object list.
		var vPageList = xfa.layout.pageContent(nPage, "", false);
		var vContentArea = null;
		for (var i=0; i<vPageList.length; i++)
		{
			var vItem = vPageList.item(i);

			// If the object we find is a content area, create an entry in
			// The list of content areas.
			// Each entry in the list has these properties:
			// ca.page	-- the zero-based page number
			// ca.contentArea -- the content area object
			// ca.members -- an array of the ancestors that appear on this page
			if (vItem.className == "contentArea")
			{
				vContentArea = new Object();
				vContentArea.contentArea = vItem;
				vContentArea.members = new Array;
				vContentArea.page = nPage;
				vContentAreas.push(vContentArea);
			}
			// When we encounter one of the objects in our ancestry, 
			// add them to the list for the current content area.
			for (var j=0; j<vTree.length; j++)
			{
				if (vItem == vTree[j])
					vContentArea.members.push(vItem);
			}
		}
	}

	// Now that we have a list of all the ancestors on all the content areas
	// We execute a second pass where we can translate relative offsets to absolute coordinates

	// vContentAreas represents an array of content areas containing ancestors of the requested object
	var nOffset = 0;
	for (var nCA=0; nCA<vContentAreas.length; nCA++)
	{
		var vCA = vContentAreas[nCA];
		for (var i=0; i<vCA.members.length; i++)
		{
			// The object of interest is in this content area
			if (vCA.members[i] == vObject)
			{
				// Create an extent object
				var vExtent = new Object();
				vExtents.push(vExtent);
				vExtent.page = vCA.page;
				vExtent.contentArea = vCA.contentArea.somExpression;
				vExtent.h = xfa.layout.h(vObject, "mm", nOffset);
				vExtent.w = xfa.layout.w(vObject, "mm", nOffset);

				// (x, y) are the sum of all the (x,y) values of the content area plus
				// the relative (x,y) values of all ancestor objects
				vExtent.x = getMillimeters(vCA.contentArea.x);
				vExtent.y = getMillimeters(vCA.contentArea.y);

				// Add up all the relative (x,y) offsets
				for (var k=0; k<vCA.members.length; k++)
				{
					var vAncestor = vCA.members[k];
					// The ancestor object does not necessarily have the same offset
					// If it first appeared on a previous content area, then it
					// has a different offset.
					var nParentOffset = getAncestorOffset(vAncestor, nCA, vContentAreas);
					vExtent.x += xfa.layout.x(vAncestor, "mm", nParentOffset);
					vExtent.y += xfa.layout.y(vAncestor, "mm", nParentOffset);
				}
				nOffset++;
			}
		}
	}
	return vExtents;
}catch(e){console.println("error:getExtents:" + e);}
}

// Loop through the array of content area objects to find the offset
// of the ancestor object in our current content area
function getAncestorOffset(vObject, nTargetCA, vCAList)
{
	var nParentOffset = -1;
	for (var j=0; j<=nTargetCA; j++)
	{
		var vList = vCAList[j].members;
		for (var i=0; i<vList.length; i++)
		{
			if (vList[i] == vObject)
				nParentOffset++;
		}
	}
	return nParentOffset;
}

// Master page objects are simpler.
// They never split.  Their offsets will be relative
// to the pageArea
function handleMasterPageObject(vObject)
{
	var vExtents = new Array();
	var vExtent = new Object();
	vExtents.push(vExtent);
	vExtent.page = xfa.layout.page(vObject)-1;
	vExtent.contentArea = "";
	vExtent.h = xfa.layout.h(vObject, "mm", 0);
	vExtent.w = xfa.layout.w(vObject, "mm", 0);
	vExtent.x = 0;
	vExtent.y = 0;
	while (vObject.className != "pageArea")
	{
		vExtent.x += xfa.layout.x(vObject, "mm", 0);
		vExtent.y += xfa.layout.y(vObject, "mm", 0);	
		vObject = vObject.parent;
	}
	return vExtents;
}

// Convert a measurement to inches
function getInches(measurement)
{
	var vUnits = measurement.substr(-2);
	var vValue = parseFloat(measurement.substr(0, measurement.length-2));
	switch(vUnits)
	{
		case "mm":
			vValue = vValue * 0.0393700787;
			break;
		case "cm":
			vValue = vValue * 0.393700787;
			break;
		case "pt":
			vValue = vValue/72;
	}
	return vValue;
}


// Convert a measurement to milimeters
function getMillimeters(measurement)
{
	var vUnits = measurement.substr(-2);
	var vValue = parseFloat(measurement.substr(0, measurement.length-2));
	switch(vUnits)
	{
		case "in":
			vValue = vValue / 0.0393700787;
			break;
		case "cm":
			vValue = vValue * 10;
			break;
		case "pt":
			vValue = vValue / 2.834645669291;
	}

	return vValue;
}

