{
	var oEstabTblt = getPanellEstabliment(scoINSPVisualitzacio.CT_INDEX_TBLT);
	var oEstabStd = getPanellEstabliment(scoINSPVisualitzacio.CT_INDEX_STD);

	if (!calMostrarEstabliment(oEstabTblt))
	{
		if (!scoGSITVal.isFormulariValidat() || !scoGSITVal.esFormulariGuardat())		esborraDadesEstabliment();
