	{
		var nModeActual = scoINSPVisualitzacio.getModeVisualitzacio();
		oEstabTblt.presence = (nModeActual == scoINSPVisualitzacio.CT_INDEX_TBLT)?"visible":"hidden";
		oEstabStd.presence = (nModeActual == scoINSPVisualitzacio.CT_INDEX_STD)?"visible":"hidden";
	}
}

