///////////////////////////////////////////////////////////////////////
// Nom : defPanellDadesInspector
// Descripció: Mètode que defineix el panell de dades de l'inspector
//////////////////////////////////////////////////////////////////////
function defPanellDadesInspector() 
{
	if (scoGSITVal.isFormulariValidat()) 			return;
	if (scoGSITVal.esFormulariGuardat() && !scoGSITVal.isFormulariAcusament())				return;

	var oPanellsDadesInspector = xfa.resolveNodes(scoGSITPar.sRutaPanellInspector);
	if (oPanellsDadesInspector == null || oPanellsDadesInspector == undefined)		return;

	for (var i = 0; i < oPanellsDadesInspector.length; i++)
	{
		var oPanellDades = oPanellsDadesInspector.item(i);
		var oTxtInspector = scoGSITPanells.obtenirObjecteFill(oPanellDades, "TXT_DADES_INSPECTOR");
		var oTxtOrganisme = scoGSITPanells.obtenirObjecteFill(oPanellDades, "TXT_DADES_ORGANISME");

		if (!scoGSITVal.existeixObjecte(oTxtInspector) || !scoGSITVal.existeixObjecte(oTxtOrganisme))			return;

		var bMostrar = setDadesInspector(oPanellDades, oTxtInspector, oTxtOrganisme);

		// Mostrar el panell només si té dades
		// ITEXT FLAT : NO funciona correctament la comprovació		var bMostrar = (!scoGSITVal.isEmpty(oTxtInspector) || !scoGSITVal.isEmpty(oTxtOrganisme));
		scoSBSMostra.mostrarOcultarPanell(oPanellDades.S_INSPECTOR, bMostrar, false);			// Afegim un nivell per mostrar/ocultar [oPanell és el panell associat al mode de visualització]
	}
}

function defFirmaInspector()
{
	//var oDadesInspector = xfa.record.resolveNode("DadesInspector");
	var oDadesInspector = xfa.record.Cos.Inspector.DadesInspector;
	var oNomInspectorSignatura = xfa.resolveNode("ACTAINSPECCIO.contacteAvisos.BLOC.S_INSPECTORSCOMP.INSPECTOR_1.TXT_NOM");
	var oCognomsInspectorSignatura = xfa.resolveNode("ACTAINSPECCIO.contacteAvisos.BLOC.S_INSPECTORSCOMP.INSPECTOR_1.TXT_COGNOM1");
	var oTipusIdentificacioInspectorSignatura = xfa.resolveNode("ACTAINSPECCIO.contacteAvisos.BLOC.S_INSPECTORSCOMP.INSPECTOR_1.TXT_TIPUS_IDENTIFICADOR");
	var oNumIdentificacioInspectorSignatura = xfa.resolveNode("ACTAINSPECCIO.contacteAvisos.BLOC.S_INSPECTORSCOMP.INSPECTOR_1.TXT_NUM_IDENTIFICADOR");

	oNomInspectorSignatura.rawValue = oDadesInspector.Nom.value;
	var cognom1 = '';
	if (oDadesInspector.Cognom1 != undefined)
	{
		cognom1 = ((!scoGSITVal.isEmpty(oDadesInspector.Cognom1.value))?oDadesInspector.Cognom1.value:'');
	}
	var cognom2 = '';
	if (oDadesInspector.Cognom2 != undefined)
	{
		cognom2 = ((!scoGSITVal.isEmpty(oDadesInspector.Cognom2.value))?oDadesInspector.Cognom2.value:'');
	}

	oCognomsInspectorSignatura.rawValue = cognom1 + " " + cognom2;
