///////////////////////////////////////////////////////////////////////
// Nom : setDadesInspector
// Descripció: Mètode que actualitza el camp amb les dades de l'inspector
// Paràmetres d'entrada:
//		oTxtInspector - Objecte RichText que conté la informació de l'inspector
//		oTxtOrganisme - Objecte RichText que conté la informació de l'organisme
// Paràmetres de sortida:
//		booleà - true si algun dels camps té contingut i false en cas contrari
//////////////////////////////////////////////////////////////////////
function setDadesInspector(oPanellInspector, oTxtInspector, oTxtOrganisme) 
{
	var strInspector = getStrDadesPersonals(oPanellInspector.dataNode.resolveNode("DadesInspector"));
	var strOrganisme = getStrDadesPersonals(oPanellInspector.dataNode.resolveNode("OrganismeCompetent"));

	var bAlgunCampPle = (!scoGSITVal.isEmpty(strInspector) || !scoGSITVal.isEmpty(strOrganisme));
	maquetaTextBloc(oTxtInspector, msgTitolInspector.value, strInspector);
	maquetaTextBloc(oTxtOrganisme, msgTitolOrganisme.value, strOrganisme);

	return bAlgunCampPle;	
}


///////////////////////////////////////////////////////////////////////
// Nom : maquetaTextBloc
// Descripció: Mètode que maqueta un bloc de dades del panell d'inspector
//				(títol en negreta)
// Parametres d'entrada:

//////////////////////////////////////////////////////////////////////
function maquetaTextBloc(oTxt, sTitol, sTextDades)
{
	if (!scoGSITVal.isEmpty(sTextDades)) {
		var sTitol = scoGSITExData.maquetaText(sTitol, "font-weight:bold");
		var sText = scoGSITExData.maquetaParagraf(sTitol + sTextDades);
		scoGSITExData.defValueCampRichText(oTxt, scoGSITExData.maquetaRichTextCamp(sText, "", false));
	}	
}

///////////////////////////////////////////////////////////////////////
// Nom : getStrDadesPersonals
// Descripció: Mètode que composa les dades personal carregades al xml
// Parametres d'entrada:
//				oNodeDades - node xml amb les dades personals
//////////////////////////////////////////////////////////////////////
function getStrDadesPersonals(oNodeDades) 
{
	if (oNodeDades == null || oNodeDades == undefined)			return "";

	var sNomCognoms = getStrNomCognoms(oNodeDades);

	//var sIdentificador = getStrDocumentId(oNodeDades);
	var sAdreca = getStrDadesAdreca(oNodeDades);
	var sDadesContacte = getStrDadesContacte(oNodeDades);

	//return concatStr(concatStr(concatStr(concatStr("",sNomCognoms), sIdentificador),sAdreca), sDadesContacte);
	return concatStr(concatStr(concatStr("",sNomCognoms),sAdreca), sDadesContacte);
}


///////////////////////////////////////////////////////////////////////
// Nom : getStrNomCognoms
// Descripció: Mètode que composa les dades personals
//////////////////////////////////////////////////////////////////////
function getStrNomCognoms(oNodeDades)
{
	if (oNodeDades == null || oNodeDades == undefined)			return "";

	var str = "";
	var arCamps = ["Nom", "Cognom1", "Cognom2"];
	for (var i = 0; i < arCamps.length; i++) {
		str = concatStr(str, scoGSITVal.getValueTagXML(oNodeDades.resolveNode(arCamps[i])));
	}
	return str;
}


///////////////////////////////////////////////////////////////////////
// Nom : getStrDocumentId
// Descripció: Mètode que composa les dades d'identificació
//////////////////////////////////////////////////////////////////////
function getStrDocumentId(oNodeDades)
{
	if (oNodeDades == null || oNodeDades == undefined)			return "";

	var sTipusIdentificador = scoGSITVal.getValueTagXMLMajuscules(oNodeDades.resolveNode("Document.tipusDocument"));
	var sIdentificador = scoGSITVal.getValueTagXML(oNodeDades.resolveNode("Document.Identificador"));
	var sPaisDocument = scoGSITVal.getValueTagXML(oNodeDades.resolveNode("Document.PaisDocument.Nom"));

	var str = (sTipusIdentificador != "")?"(" + sTipusIdentificador + " ":"";
	str += sIdentificador;
	str += (sPaisDocument != "")?" " + sPaisDocument:"";
	str += (sTipusIdentificador != "")?")":"";

	return str;
}

///////////////////////////////////////////////////////////////////////
// Nom : getStrDadesContacte
// Descripció: Mètode que composa les dades de contacte
//////////////////////////////////////////////////////////////////////
function getStrDadesContacte(oNodeDades)
{
	if (oNodeDades == null || oNodeDades == undefined)			return "";

	var sTelefonFix = scoGSITVal.getValueTagXML(oNodeDades.resolveNode("TelefonFix"));
	var sTelefonMobil = scoGSITVal.getValueTagXML(oNodeDades.resolveNode("TelefonMobil"));

	var sTelefon = "";
	var bTelfFix = (sTelefonFix != "");
	var bTelfMobil = (sTelefonMobil != "");
	if (bTelfFix || bTelfMobil) 
	{
		sTelefon = msgTitolTelf.value;
		if (bTelfFix) 			sTelefon += sTelefonFix;
		if (bTelfFix && bTelfMobil)		sTelefon += "/";
		if (bTelfMobil)			sTelefon += sTelefonMobil;
	}

	var sFax = scoGSITVal.getValueTagXML(oNodeDades.resolveNode("TelefonMobil"));
	sFax = (sFax != "")? msgTitolFax.value + sFax:"";

	var sECorreu = scoGSITVal.getValueTagXML(oNodeDades.resolveNode("AdrecaElectronica"));

	var str = sTelefon;
	str = concatStr(str, sFax);
	str = concatStr(str, sECorreu);

	return str;
}


///////////////////////////////////////////////////////////////////////
// Nom : getStrDadesAdreca
// Descripció: Mètode que composa les dades d'un node adreca
//////////////////////////////////////////////////////////////////////
function getStrDadesAdreca(oNodeDades)
{
	if (oNodeDades == null || oNodeDades == undefined)			return "";

	var oNodeAdreca = oNodeDades.resolveNode("Adreca");
	if (oNodeAdreca == null || oNodeAdreca == undefined)			return "";
	var sTipusVia = scoGSITVal.getValueTagXML(oNodeAdreca.resolveNode("TipusVia.Descripcio"));
	var sNomVia = scoGSITVal.getValueTagXML(oNodeAdreca.resolveNode("NomVia"));
	var sNumero = scoGSITVal.getValueTagXML(oNodeAdreca.resolveNode("Numero"));
	var sBloc = scoGSITVal.getValueTagXML(oNodeAdreca.resolveNode("Bloc"));
	var sEscala = scoGSITVal.getValueTagXML(oNodeAdreca.resolveNode("Escala"));
	var sPis = scoGSITVal.getValueTagXML(oNodeAdreca.resolveNode("Pis"));
	var sPorta = scoGSITVal.getValueTagXML(oNodeAdreca.resolveNode("Porta"));
	var sCP = scoGSITVal.getValueTagXML(oNodeAdreca.resolveNode("CodiPostal"));
	var sMunicipi = scoGSITVal.getValueTagXML(oNodeAdreca.resolveNode("Municipi.Nom"));
	var sCodiINEPais = scoGSITVal.getValueTagXML(oNodeAdreca.resolveNode("Pais.CodiINE"));
	var sPais = scoGSITVal.getValueTagXML(oNodeAdreca.resolveNode("Pais.Nom"));

	var str = sTipusVia;
	str = concatStr(str, sNomVia);
	str = concatStr(str, sNumero);
	str = concatStr(str, sBloc);
	str = concatStr(str, sEscala);
	str = concatStr(str, sPis);
	str = concatStr(str, sPorta);
	str = concatStr(str, sCP);
	str = concatStr(str, sMunicipi);
	str = (sCodiINEPais!="108")?concatStr(str, sPais):str;
	return str;
}

///////////////////////////////////////////////////////////////////////
// Nom : concatStr
// Descripció: Mètode que retorna la concatenació 'str' a strOrigen
//				Si cal afegeix un espai entre les dues cadenes
//////////////////////////////////////////////////////////////////////
function concatStr(strOrigen, str)
{
	var concatStr = strOrigen;
	concatStr += (concatStr != "" && str != "")?" " + str:str;
	return concatStr;
}

