 Nom: scoINSPImatges
 Descripció: Mètodes relacionats amb el panell d'imatges
**************************************************************************/

/////////////////////////////////////////////////////////////////////////////
// VARIABLES
/////////////////////////////////////////////////////////////////////////////

var CT_SIZE_TITOL_TBLT = "12pt";
var CT_SIZE_TITOL_STD = "8pt";

/////////////////////////////////////////////////////////////////////////////
// MÈTODES
/////////////////////////////////////////////////////////////////////////////


////////////////////////////////////////////////////////////
// Nom: afegirNovaImatge
// Descripció:  
////////////////////////////////////////////////////////////
function afegirNovaImatge(oSubImatges)
{
	if (!scoGSITVal.existeixObjecte(oSubImatges))		return;

	var oTaulaImatges = oSubImatges.S_TAULA_IMATGES;
	if (!scoGSITVal.existeixObjecte(oSubImatges))		return;

	var oNewImatge = addBlocImatge(oTaulaImatges);

	// Mostrar els botons segons el mode de visualització
	if (scoGSITVal.existeixObjecte(oNewImatge))
	{
		var oAccionsTblt = oNewImatge.resolveNode("SUB_ACCIONS[" + scoINSPVisualitzacio.CT_INDEX_TBLT + "]");
		oAccionsTblt.presence = (scoINSPVisualitzacio.esModeTableta())?"visible":"invisible";

		var oAccionsStd = oNewImatge.resolveNode("SUB_ACCIONS[" + scoINSPVisualitzacio.CT_INDEX_STD + "]");
		oAccionsStd.presence = (scoINSPVisualitzacio.esModeStandard())?"visible":"invisible";
	}
}


///////////////////////////////////////////////////////////////////////
// Nom : addBlocImatge
// Descripció: Funció que afegeix un nou panell d'imatge
//////////////////////////////////////////////////////////////////////
function addBlocImatge(oTaula)
{
	try
	{
		return oPanellImatge = oTaula._S_FILA_IMATGE.addInstance(1);
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoINSPImatges.addBlocImatge", exc);
	}
}	


////////////////////////////////////////////////////////////
// Nom: deleteBlocImatge
// Descripció: Mètode que esborra la instància indicada
// Paràmetres d'entrada: 
////////////////////////////////////////////////////////////
function deleteBlocImatge(oSubImatge, oTaula)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		if (!scoGSITVal.existeixObjecte(oTaula))		return;
		if (!scoGSITVal.existeixObjecte(oSubImatge))	return;

		oTaula._S_FILA_IMATGE.removeInstance(oSubImatge.index);

		tancaImatgeZoom();
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoINSPImatges.deleteBlocImatge", exc);
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : ampliaImatge
// Descripció: Funció que mostra la imatge ampliada
//////////////////////////////////////////////////////////////////////
function ampliaImatge(oImatge, oTaula)
{
	if (!scoGSITVal.existeixObjecte(oImatge) || !scoGSITVal.existeixObjecte(oTaula))	return;

	var oSubImatgeZoom = oTaula.parent.S_IMATGE_ZOOM;
	oSubImatgeZoom.presence = (scoGSITVal.isEmpty(oImatge))?"hidden":"visible";

	oSubImatgeZoom.IMG_ZOOM.rawValue = oImatge.rawValue;
	xfa.host.setFocus(oSubImatgeZoom.IMG_ZOOM.somExpression);
}


///////////////////////////////////////////////////////////////////////
// Nom : tancaImatgeZoom
// Descripció: Funció que mostra la imatge ampliada
//////////////////////////////////////////////////////////////////////
function tancaImatgeZoom()
{
	var oSubImatgeZoom = scoINSPPar.oPanellImatges.S_IMATGE_ZOOM;
	if (!scoGSITVal.existeixObjecte(oSubImatgeZoom))	return;

	oSubImatgeZoom.presence = "hidden";
}


///////////////////////////////////////////////////////////////////////
// Nom : defineixImatgesVisualitzacio
// Descripció: 
//////////////////////////////////////////////////////////////////////
function defineixImatgesVisualitzacio()
{
	var bEsModeTableta = scoINSPVisualitzacio.esModeTableta();

		// Missatge
	var oMsg = scoINSPPar.oPanellImatges.cMissatge;
	oMsg.font.size = (bEsModeTableta)?CT_SIZE_TITOL_TBLT:CT_SIZE_TITOL_STD;
}



////////////////////////////////////////////////////////////
// Nom: compExtensioImatge
// Descripció: Mètode que verifica l'extensió del fitxer IMATGE que es vol adjuntar
////////////////////////////////////////////////////////////
function compExtensioAdjunt(nouAdjunt)
{
	if (nouAdjunt == null)		return;
	var aExtensionsImg = ["BMP", "JPG", "GIF", "PNG", "TIF"];

	var arrNom = nouAdjunt.path.split(".");
	var format = arrNom[arrNom.length - 1];

	var nExtensions = aExtensionsImg.length;
	var bCorrecta = false;
	var n = 0;
	do
	{
		bCorrecta = (aExtensionsImg[n].toLowerCase() == format.toLowerCase());
	} while (++n<nExtensions && !bCorrecta)

	return bCorrecta;
}


////////////////////////////////////////////////////////////
// Nom: seleccionarImatge
// Descripció: 
////////////////////////////////////////////////////////////
function seleccionarImatge(oPanellImatge)
{
	scoGSITVal.amagarRequadre(oPanellImatge.IMG);

	// Cal afegir-ho com a annex, i després extreure'l
	var oDocument = event.target;
	var errCode = oDocument.importDataObject("IMG"); //obre diàleg a l'usuari per escollir fitxer
	if(errCode != true)  return ; 			//si s'ha cancelat el diàleg d'adjuntar

	var nouAdjunt = oDocument.getDataObject("IMG");

	// Comprovem l'extensió del fitxer seleccionat...
	if (!compExtensioAdjunt(nouAdjunt))	
	{
		oDocument.removeDataObject("IMG");		// traiem adjunt!
		scoGSITMissatges.MissatgeInformatiu(msgExtensioImatge.value);
		return;
	}


	// Contingut de la imatge... 
	var oAnexoStream = oDocument.getDataObjectContents("IMG");
	var oAnexoBase64Stream = SOAP.streamEncode(oAnexoStream, "base64");
	var sAnexoBase64 = SOAP.stringFromStream(oAnexoBase64Stream);

	// Assignem la informació al control...
	oPanellImatge.IMG.rawValue = sAnexoBase64;
	oPanellImatge.IMG.caption.value.text.value = nouAdjunt.path;
	setNodeNameXML(oPanellImatge, nouAdjunt.path);

	// Traiem l'adjunt del PDF...
	oDocument.removeDataObject("IMG");

	// Revisem si cal avisar per la mida del PDF...
	if (!scoGSITVal.validarMidaPDF())  app.alert(scoGSITVal.getMsgErrorMidaMaxAdjuntsPDF());

	// Ocultem el botó
// TODO			oPanellImatge.BTN_ADD_IMG.presence = "invisible";
}


////////////////////////////////////////////////////////////
// Nom: setNodeNameXML
// Descripció: 
////////////////////////////////////////////////////////////
function setNodeNameXML(oPanellImatge, nom)
{
	var oNomXML = oPanellImatge.dataNode.resolveNode("NomImatge");
	if (!scoGSITVal.existeixObjecte(oNomXML))	return;
	oNomXML.value = nom;
}


////////////////////////////////////////////////////////////
// Nom: setCaptionImgDeXML
// Descripció: 
////////////////////////////////////////////////////////////
function setCaptionImgDeXML(oPanellImatge)
{
	var oNomXML = oPanellImatge.dataNode.resolveNode("NomImatge");
	if (!scoGSITVal.existeixObjecte(oNomXML))	return;

	oPanellImatge.IMG.caption.value.text.value = oNomXML.value;
}

////////////////////////////////////////////////////////////
// Nom: treureTotesImatges
// Descripció: Mètode que esborra totes les imatges
////////////////////////////////////////////////////////////
function treureTotesImatges(oPanellImatge)
{
	try
	{
		if(scoGSITVal.isFormulariValidat()) return;

		if (!scoGSITVal.existeixObjecte(oPanellImatge)) return;

		var oImatges = oPanellImatge.resolveNodes("S_TAULA_IMATGES[0].S_FILA_IMATGE[*]");

		var iNumImatges = (scoGSITVal.existeixObjecte(oImatges)) ? oImatges.length : 0;	
		for (var n=iNumImatges; n>0; n--)
		{
			var oImatge = oImatges.item(n-1);
			deleteBlocImatge(oImatge, oPanellImatge.S_TAULA_IMATGES)
		}

		tancaImatgeZoom();
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoINSPImatges.treureTotesImatges", exc);
	}	
}



/////////////////////////////////////////////////////
// Nom: validarImatges
// Descripció: 
////////////////////////////////////////////////////////////
function validarImatges(msgError)
{
	var result = scoGSITVal.inicialitzarVariableValidacioEspecificaCorrecte();

	var oImatges = scoINSPPar.oPanellImatges.S_TAULA_IMATGES.resolveNodes("S_FILA_IMATGE[*]");
	if (!scoGSITVal.existeixObjecte(oImatges))	return result;

	var bAlgunaBuida = false;
	var i = 0; 
	while (!bAlgunaBuida && i < oImatges.length)
	{
		var oImatge = oImatges.item(i);

		bAlgunaBuida = scoGSITVal.isEmpty(oImatge.IMG.rawValue);
		if (!bAlgunaBuida)	i++;
	}

	if (bAlgunaBuida)
	{
		result.validacioCorrecte = false;
		result.missatgeError = msgError;
		result.campsIncorrectes = [oImatges.item(i).IMG];
	}
	return result;
}

