		// Copiar visibilitat pais document
	var oContacteOrigen= scoGSITPanells.obtenirContactePanellMultiple(oPanellPrincipal);
	var oContacteDesti = scoGSITPanells.obtenirContactePanellMultiple(oPanell);

	var oPaisDocumentOrigen = oContacteOrigen.TXT_PAIS_DOCUMENT;
	var oPaisDocumentDesti = oContacteDesti.TXT_PAIS_DOCUMENT;

	oPaisDocumentDesti.presence = oPaisDocumentOrigen.presence;
}



