 Nom: scoINSPLlista
 Descripció: Mètodes especifics tipus 'Llista' d'una qüestió
**************************************************************************/

/////////////////////////////////////////////////////////////////////////////
// VARIABLES
/////////////////////////////////////////////////////////////////////////////


/////////////////////////////////////////////////////////////////////////////
// VARIABLES
/////////////////////////////////////////////////////////////////////////////

var defLlistaTamanyTablet = {
	definicio : {
		CT_FONTSIZE : '12pt',
		CT_CAPTION_FONTSIZE : '12pt',
		CT_HEIGHT : '10mm'
	},
	defCalculs : {
		CT_POINTS_PER_CARACTER_CAPTION : 5, //3.8,
		CT_MARGE_SEGURETAT_CAPTION : 12, //10,
		CT_POINTS_PER_CARACTER_VALUE : 8, // 5,
		CT_MARGE_SEGURETAT_VALUE : 20 //18
	}
};

var defLlistaTamanyNormal = {
	definicio : {
		CT_FONTSIZE : '8pt',
		CT_CAPTION_FONTSIZE : '8pt',
		CT_HEIGHT : '7mm'
	},
	defCalculs : {
		CT_POINTS_PER_CARACTER_CAPTION : 4,
		CT_MARGE_SEGURETAT_CAPTION : 10,
		CT_POINTS_PER_CARACTER_VALUE : 6.2,
		CT_MARGE_SEGURETAT_VALUE : 18
	}
	};	

/////////////////////////////////////////////////////////////////////////////
// MÈTODES
/////////////////////////////////////////////////////////////////////////////

///////////////////////////////////////////////////////////////////////
// Nom : initLlista
// Descripció: 
//////////////////////////////////////////////////////////////////////
function initLlista(oItem)
{

	if(scoGSITVal.isFormulariValidat()) return;

	defLlista(oItem);	

	var aValors = scoINSPQuestioItem.getArrayOpcionsResposta(oItem);
	carregaLlista(oItem, aValors);

	var oCamp = getCampLlista(oItem);
	longitudLlista(oItem, oCamp, aValors);
	defineixLlistaVisualitzacio(oItem);

	// 202203 Sol·licitud: precarreguem valor resposta, si cal
	// Acusament: precarreguem valor guardat.
	if ( !scoGSITVal.esFormulariGuardat() || scoGSITVal.isFormulariAcusament())		setValueCamp(oItem, !scoGSITVal.isFormulariAcusament());
}

///////////////////////////////////////////////////////////////////////
// Nom : getObjecteLlista
// Descripció: Mètode que retorna el camp d'un tipus resposta 'Llista'
//////////////////////////////////////////////////////////////////////
function getObjecteLlista(oItem) 
{
	return scoINSPQuestioItem.getObjectTipusResposta(oItem, "Llista");
}

///////////////////////////////////////////////////////////////////////
// Nom : getCampLlista
// Descripció: Mètode que retorna el camp d'un tipus resposta 'Llista'
//////////////////////////////////////////////////////////////////////
function getCampLlista(oItem) 
{
	return (scoGSITPanells.obtenirObjecteFill(getObjecteLlista(oItem), "TXT_CAMP"));
}

///////////////////////////////////////////////////////////////////////
// Nom : getValorCampLlista
// Descripció: Mètode que retorna el valor d'un camp de tipus resposta 'Llista'
//////////////////////////////////////////////////////////////////////
function getValorCampLlista(oItem) 
{
	var oCamp = getCampLlista(oItem);
	return (scoGSITVal.isEmpty(oCamp)?"":oCamp.rawValue);
}

///////////////////////////////////////////////////////////////////////
// Nom : defLlista
// Descripció: Mètode que defineix una llista
//////////////////////////////////////////////////////////////////////
function defLlista(oItem)
{
	var oLlista = getCampLlista(oItem);
	if (!scoGSITVal.existeixObjecte(oLlista))		return;

	oLlista.assist.toolTip = scoINSPQuestioItem.getValuePregunta(oItem);
}



///////////////////////////////////////////////////////////////////////
// Nom : carregaLlista
// Descripció: Mètode que carrega al tipusresposta 'Llista' de l'element els ítems
//////////////////////////////////////////////////////////////////////
function carregaLlista(oItem, aValors)
{
	scoGSITCombo.inicialitzaLlistaSiBuida(getCampLlista(oItem), aValors);
}


///////////////////////////////////////////////////////////////////////
// Nom : setResposta
// Descripció: Actualitza el node Resposta de l'item passat com a paràmetre (valor de la resposta + text vinculat a la resposta)
//////////////////////////////////////////////////////////////////////
function setResposta(oItem)
{
	var valorResposta = getValorCampLlista(oItem);
	scoINSPQuestioItem.setValueResposta(oItem, valorResposta);

	scoINSPQuestioItem.concatValueTextVinculatResposta(oItem, new Array(valorResposta));
}

///////////////////////////////////////////////////////////////////////
// Nom : setValueCamp
// Descripció: Actualitza el camp 'llista' amb el valor guardat a la resposta de l'ítem
//////////////////////////////////////////////////////////////////////
function setValueCamp(oItem, bExecutaAccionsCamps)
{
	var oCamp = getCampLlista(oItem);
	if (!scoGSITVal.existeixObjecte(oCamp))			return;

	oCamp.rawValue = scoINSPQuestioItem.getValueResposta(oItem);

	// Si cal, executem les accions associades al canvi de valor del camp
	if (bExecutaAccionsCamps)
	{
		scoINSPAccions.mostraAccionsAplicables(oItem);
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : netejaCamp
// Descripció: Neteja el valor del camp
//////////////////////////////////////////////////////////////////////
function netejaCamp(oItem)
{
	getCampLlista(oItem).rawValue = "";	
}


///////////////////////////////////////////////////////////////////////
// Nom : longitudLlista
// Descripció: 
//////////////////////////////////////////////////////////////////////
function longitudLlista(oItem, oCamp, aValors)
{
	var defLlista = getDefinicioLlista().defCalculs;

	//Longitud del caption	
	var sTitol = scoINSPQuestioItem.getValuePregunta(oItem);
	var nLongCaractCaption = String(sTitol).length;
	var nLongCaption = (nLongCaractCaption * defLlista.CT_POINTS_PER_CARACTER_CAPTION) + defLlista.CT_MARGE_SEGURETAT_CAPTION;

	//Calculem la longitud dels valors a mostrar en la llista

	var nLongCaractValors = maxValue(aValors);
	var nLongValors = (nLongCaractValors * defLlista.CT_POINTS_PER_CARACTER_VALUE) + defLlista.CT_MARGE_SEGURETAT_VALUE;
	//El màxim entre el caption o el valor
	var nLong = Math.max(nLongCaption, nLongValors);

	//Com a màxim una línia
	var nLong = Math.min(nLong, scoINSPPar.CT_POINTS_PER_LINEA - 2) ;

	var nLong = Math.floor(nLong);
	oCamp.w =  nLong + "pt";
}

///////////////////////////////////////////////////////////////////////
// Nom : maxValue
// Descripció: 
//////////////////////////////////////////////////////////////////////
function maxValue(aValors)
{
	var nMax = 0;
	for(var x=0; x<aValors.length; x++)
		if(aValors[x][0].length > nMax) nMax = aValors[x][0].length;

	return nMax;
}


///////////////////////////////////////////////////////////////////////
// Nom : defineixLlistaVisualitzacio
// Descripció: 
//////////////////////////////////////////////////////////////////////
function defineixLlistaVisualitzacio(oItem)
{
	if (oItem == null || oItem == undefined)		return;

	var oCamp = getCampLlista(oItem);
	if (oCamp == null || oCamp == undefined)		return;

	var defLlista = getDefinicioLlista().definicio;
	if (oCamp.caption)	oCamp.caption.font.size = defLlista.CT_CAPTION_FONTSIZE;
	oCamp.font.size = defLlista.CT_FONTSIZE;
	oCamp.h = defLlista.CT_HEIGHT;
}


///////////////////////////////////////////////////////////////////////
// Nom : getDefinicioLlista
// Descripció: 
//////////////////////////////////////////////////////////////////////
function getDefinicioLlista()
{
	return ((scoINSPVisualitzacio.esModeTableta())?defLlistaTamanyTablet:defLlistaTamanyNormal);
}

/***************************************************************
 Nom: scoINSPLliure
 Descripció: Mètodes especifics tipus 'Lliure' d'una qüestió
**************************************************************************/

/////////////////////////////////////////////////////////////////////////////
// VARIABLES
/////////////////////////////////////////////////////////////////////////////

var defLliureTamanyTablet = {
		CT_FONTSIZE : '12pt',
		CT_CAPTION_FONTSIZE : '12pt',
		CT_MIN_HEIGHT : '10mm'
	};

var defLliureTamanyNormal = {
		CT_FONTSIZE : '8pt',
		CT_CAPTION_FONTSIZE : '8pt',
		CT_MIN_HEIGHT : '7mm'
	};	

