///////////////////////////////////////////////////////////////////////
// Nom : initLliure
// Descripció: 
//////////////////////////////////////////////////////////////////////
function initLliure(oItem)
{

	if(scoGSITVal.isFormulariValidat()) return;
	defLliure(oItem);	

	// 202203 Sol·licitud: precarreguem valor resposta, si cal
	// Acusament: precarreguem valor guardat.
	if ( !scoGSITVal.esFormulariGuardat() || scoGSITVal.isFormulariAcusament())		setValueCamp(oItem, !scoGSITVal.isFormulariAcusament());
}

///////////////////////////////////////////////////////////////////////
// Nom : getObjecteLliure
// Descripció: Mètode que retorna el camp d'un tipus resposta 'Lliure'
//////////////////////////////////////////////////////////////////////
function getObjecteLliure(oItem) 
{
	return scoINSPQuestioItem.getObjectTipusResposta(oItem, "Lliure");
}

///////////////////////////////////////////////////////////////////////
// Nom : getCampLliure
// Descripció: Mètode que retorna el camp d'un tipus resposta 'Lliure'
//////////////////////////////////////////////////////////////////////
function getCampLliure(oItem) 
{
	return (scoGSITPanells.obtenirObjecteFill(getObjecteLliure(oItem), "TXT_CAMP"));
}


///////////////////////////////////////////////////////////////////////
// Nom : getValorCampLliure
// Descripció: Mètode que retorna el valor d'un camp de tipus resposta 'Lliure'
//////////////////////////////////////////////////////////////////////
function getValorCampLliure(oItem) 
{
	var oCamp = getCampLliure(oItem);
	return (scoGSITVal.isEmpty(oCamp))?"":oCamp.rawValue;
}

///////////////////////////////////////////////////////////////////////
// Nom : defLliure
// Descripció: Mètode que defineix un camp lliure
//////////////////////////////////////////////////////////////////////
function defLliure(oItem)
{
	var oCamp = getCampLliure(oItem);
	if (!scoGSITVal.existeixObjecte(oCamp))		return;

	oCamp.assist.toolTip = scoINSPQuestioItem.getValuePregunta(oItem);

	defineixLliureVisualitzacio(oItem);
}


///////////////////////////////////////////////////////////////////////
// Nom : setResposta
// Descripció: Actualitza el node Resposta de l'item passat com a paràmetre
//////////////////////////////////////////////////////////////////////
function setResposta(oItem)
{
	scoINSPQuestioItem.setValueResposta(oItem, getValorCampLliure(oItem));
}


///////////////////////////////////////////////////////////////////////
// Nom : setValueCamp
// Descripció: Actualitza el camp 'lliure' amb el valor guardat a la resposta de l'ítem
//////////////////////////////////////////////////////////////////////
function setValueCamp(oItem, bExecutaAccionsCamp)
{
	var oCamp = getCampLliure(oItem);
	if (!scoGSITVal.existeixObjecte(oCamp))			return;

	oCamp.rawValue = scoINSPQuestioItem.getValueResposta(oItem);
}

///////////////////////////////////////////////////////////////////////
// Nom : netejaCamp
// Descripció: Neteja el valor del camp
//////////////////////////////////////////////////////////////////////
function netejaCamp(oItem)
{
	getCampLliure(oItem).rawValue = "";
}


///////////////////////////////////////////////////////////////////////
// Nom : defineixLliureVisualitzacio
// Descripció: 
//////////////////////////////////////////////////////////////////////
function defineixLliureVisualitzacio(oItem)
{
	if (oItem == null || oItem == undefined)		return;

	var oCamp = getCampLliure(oItem);
	if (oCamp == null || oCamp == undefined)		return;

	var defLliure = getDefinicioLliure();

	if (oCamp.caption)	oCamp.caption.font.size = defLliure.CT_CAPTION_FONTSIZE;
	oCamp.font.size = defLliure.CT_FONTSIZE;
	oCamp.minH = defLliure.CT_MIN_HEIGHT;
}


///////////////////////////////////////////////////////////////////////
// Nom : getDefinicioLliure
// Descripció: 
//////////////////////////////////////////////////////////////////////
function getDefinicioLliure()
{
	return ((scoINSPVisualitzacio.esModeTableta())?defLliureTamanyTablet:defLliureTamanyNormal);
}

