var CT_CHECK_ACTIVAT = 1;
var CT_CHECK_DESACTIVAT = 0;

var CT_SEPARADOR_RESPOSTA = "|";


/////////////////////////////////////////////////////////////////////////////
// MÈTODES
/////////////////////////////////////////////////////////////////////////////

///////////////////////////////////////////////////////////////////////
// Nom : iniCheckSeleccio
// Descripció: 
//////////////////////////////////////////////////////////////////////
function iniCheckSeleccio(oItem, sTipusResposta)
{

	if(scoGSITVal.isFormulariValidat()) return;

	carregaChecks(oItem, sTipusResposta);
	defineixChecksVisualitzacio(oItem, sTipusResposta);

	// 202203 Sol·licitud: precarreguem valor resposta, si cal
	// Acusament: precarreguem valor guardat.
	if ( !scoGSITVal.esFormulariGuardat() || scoGSITVal.isFormulariAcusament())			setValueCamp(oItem, sTipusResposta, !scoGSITVal.isFormulariAcusament());
}

///////////////////////////////////////////////////////////////////////
// Nom : carregaChecks
// Descripció: Mètode que carrega al tipusresposta 'Seleccio' o 'Multiseleccio' de l'element els ítems
//////////////////////////////////////////////////////////////////////
function carregaChecks(oItem, sTipusResposta)
{
	if (scoGSITVal.esFormulariGuardat() && !scoGSITVal.isFormulariAcusament())			return;	

	var oOpcionsResposta = scoINSPQuestioItem.getNodesOpcionResposta(oItem, sTipusResposta);
	if (oOpcionsResposta == null || oOpcionsResposta == undefined)			return;

	var oObj = scoINSPQuestioItem.getObjectTipusResposta(oItem, sTipusResposta);
	var oChecks = oObj.resolveNodes("CHECK[*]");
	for (var i = 0; i < oOpcionsResposta.length; i++) {
		var oCheck;
		if (scoGSITVal.isFormulariAcusament())		oCheck = oChecks.item(i);
		else											oCheck = oObj._CHECK.addInstance(1);

		defCheck(oCheck, oOpcionsResposta.item(i));
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : getFirstCheck
// Descripció: Mètode que retorna el primer objecte CHECK de la selecció
//////////////////////////////////////////////////////////////////////
function getFirstCheck(oItem, sTipusResposta)
{
	var oChecks = getCampsSeleccio(scoINSPQuestioItem.getObjectTipusResposta(oItem, sTipusResposta));
	if (!scoGSITVal.existeixObjecte(oChecks))			return null;

	if (oChecks.length <= 0)			return null;
	return oChecks.item(0);
}

///////////////////////////////////////////////////////////////////////
// Nom : defCheck
// Descripció: Mètode que defineix un Check amb la informació del node 'OpcioResposta'
//////////////////////////////////////////////////////////////////////
function defCheck(oCheck, oOpcioResposta)
{
	if (oOpcioResposta == null || oOpcioResposta == undefined)			return;

	var oNodeId = oOpcioResposta.resolveNode("Id");
	var oNodeDesc = oOpcioResposta.resolveNode("Descripcio");

	oCheck.TXT_ID.rawValue = oNodeId.value;	
	oCheck.TXT_CAMP.caption.value.text.value = oNodeDesc.value;
}

//////////////////////////////////////////////////////////////////////
// Nom : canviCheckMarcat
// Descripció: 
//////////////////////////////////////////////////////////////////////
function canviCheckMarcat(oParentCamp, oCheck)
{
	if(scoGSITVal.isFormulariValidat()) return;

    if(!isCheckMarcat(oCheck)) return;

	// 090962020			scoGSITCamps.remarcarCampValid(oParentCamp.parent);

	var oChecks = getCampsSeleccio(oParentCamp);
	for(var x=0; x<oChecks.length; x++)
		if(!execucioProvocadaPerCheckOriginal(oChecks.item(x))) oChecks.item(x).rawValue = CT_CHECK_DESACTIVAT;
}

///////////////////////////////////////////////////////////////////////
// Nom : getCampsSeleccio
// Descripció: Retorna tots els camps TXT_CAMP que composen la selecció
//////////////////////////////////////////////////////////////////////
function getCampsSeleccio(oParentCamp) 
{
	return oParentCamp.resolveNodes("CHECK[*].TXT_CAMP");
}

///////////////////////////////////////////////////////////////////////
// Nom : getIdCheck
// Descripció: Retorna l'identificador corresponent al check passat com a paràmetre
//////////////////////////////////////////////////////////////////////
function getIdCheck(oCheck) 
{
	if (!scoGSITVal.existeixObjecte(oCheck))			return;

	var oIdCheck = oCheck.parent.resolveNode("TXT_ID");
	return (scoGSITVal.isEmpty(oIdCheck)?"":oIdCheck.rawValue);

}

///////////////////////////////////////////////////////////////////////
// Nom : getIndexCheck
// Descripció: Retorna líndex 
//////////////////////////////////////////////////////////////////////
function getIndexCheck(oChecks, id) 
{
	if (!scoGSITVal.existeixObjecte(oChecks))			return;

	var bTrobat = false;
	var i = 0;
	while (!bTrobat && i < oChecks.length) {
		bTrobat = (getIdCheck(oChecks.item(i)) == id);
		if (!bTrobat)		i++;
	}
	if (bTrobat)		return i;
	return -1;
}

///////////////////////////////////////////////////////////////////////
// Nom : isCheckMarcat
// Descripció: 
//////////////////////////////////////////////////////////////////////
function isCheckMarcat(oCheck)
{
	return(oCheck.rawValue == CT_CHECK_ACTIVAT);
}

///////////////////////////////////////////////////////////////////////
// Nom : execucioProvocadaPerCheckOriginal
// Descripció: 
//////////////////////////////////////////////////////////////////////
function execucioProvocadaPerCheckOriginal(oCheck)
{
	if (xfa.event.target.somExpression == oCheck.somExpression) return true;
	return false;

} 


///////////////////////////////////////////////////////////////////////
// Nom : defineixChecksVisualitzacio
// Descripció: 
//////////////////////////////////////////////////////////////////////
function defineixChecksVisualitzacio(oItem, sTipusResposta)
{
	var oParentCamp = scoINSPQuestioItem.getObjectTipusResposta(oItem, sTipusResposta);
	var oChecks = oParentCamp.resolveNodes("CHECK[*].TXT_CAMP");
	var bCheckReduit = (oChecks.length > CT_NUM_CHECKS_LIMIT_MODIF_TAMANY);		
	//  if(bCheckReduit) checksReduits(oParentCamp);
	defineixChecks(oParentCamp, bCheckReduit);

	//Comprovem si cap tot en una mateixa línia	
	var aCaractersChecks = arrayCaractersChecks(oItem, sTipusResposta, bCheckReduit);
	var aPointsChecks = arrayPointsChecks(aCaractersChecks,  bCheckReduit);	
	var nPointsChecks = sumatori(aPointsChecks);

	var nPointsTotal = nPointsChecks; 

	var bnomesUnaLinia = (nPointsTotal <= scoINSPPar.CT_POINTS_PER_LINEA);
	if(bnomesUnaLinia)
	{
		//SubformPare
		oParentCamp.w = nPointsTotal + "pt";

		//Check i subform que conté el check		
		for(var x=0; x<oChecks.length; x++)
		{
			oChecks.item(x).w = aPointsChecks[x] + "pt";
			oChecks.item(x).parent.w = aPointsChecks[x] + "pt";
		}

	}else{

		//SubformPare: ocupa tota la linia
		oParentCamp.w = scoINSPPar.CT_POINTS_PER_LINEA+ "pt";

		//Checks

		//Fem desviació estandar i la mitja 
		var stdDev = standardDeviation(aCaractersChecks);
		var avg = average(aCaractersChecks);

		//El núm de caràcters que assignarem serà de numCar (desviació estàndard + mitja)
		var numCar = stdDev + avg;	

		//Cada check ocupa numCar * mida de cada caràcter + el que ocupa el propi check (solid square)
		var nPointsCheck = calculaPoints(numCar, true, bCheckReduit);

		//Calculem quantes columnes hi caben per fila
		var nColumnes = Math.floor(scoINSPPar.CT_POINTS_PER_LINEA / nPointsCheck);
		if(nColumnes < 1) nColumnes = 1; 

		//Calculem quants points queden lliures per finalitzar una línia
		var nPointsLliures = scoINSPPar.CT_POINTS_PER_LINEA - (nColumnes * nPointsCheck);
		if(nPointsLliures < 0) nPointsLliures = 0;

		//Distribuim els points lliures entre les columnes
		var nPointsAfegirColumna = Math.floor(nPointsLliures / nColumnes);
		var nPointsFinal = Math.min(nPointsCheck + nPointsAfegirColumna, scoINSPPar.CT_POINTS_PER_LINEA) ;

		//Asignem la longitud
		var oChecks = oParentCamp.resolveNodes("CHECK[*].TXT_CAMP");
		for(var x=0; x<oChecks.length; x++)
		{
			oChecks.item(x).w = nPointsFinal + "pt";
			oChecks.item(x).parent.w = nPointsFinal + "pt";
		}
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : arrayPointsChecks
// Descripció: 
//////////////////////////////////////////////////////////////////////
function arrayPointsChecks(aCaractersChecks, bCheckReduit)
{
	var aValors = new Array();

	for(var x=0; x<aCaractersChecks.length; x++)
		aValors[aValors.length] = calculaPoints(aCaractersChecks[x], true, bCheckReduit);

	return aValors;
}

///////////////////////////////////////////////////////////////////////
// Nom : arrayCaractersChecks
// Descripció: 
//////////////////////////////////////////////////////////////////////
function arrayCaractersChecks(oItem, sTipusResposta, bCheckReduit)
{
	var aValors = new Array();
	var oItems = scoINSPQuestioItem.getNodesOpcionResposta(oItem, sTipusResposta);
	for(var x=0; x<oItems.length; x++)
	{
		var sDescripcio = oItems.item(x).Descripcio.value;
		aValors[aValors.length] = sDescripcio.length;
	}

	return aValors;
}

///////////////////////////////////////////////////////////////////////
// Nom : calculaPoints
// Descripció: 
//////////////////////////////////////////////////////////////////////
function calculaPoints(nCaracters, bEsCheck, bCheckReduit)
{
	var stDefC = getDefinicioChecks(bCheckReduit);

	var mapDefCalcul = stDefC.calculPoints;

	//var defCheck = (bCheckReduit) ? defCheckTamanyReduit : defCheckTamanyNormal ;	
	var nPoints = nCaracters * mapDefCalcul.CT_POINTS_PER_CARACTER + mapDefCalcul.CT_MARGE_SEGURETAT;
	if(bEsCheck) nPoints += mapDefCalcul.CT_POINT_SQUARE + mapDefCalcul.CT_SEPARACIO_ENTRE_CHECKS;

	var nPointsTotal = Math.min(Math.round(nPoints), scoINSPPar.CT_POINTS_PER_LINEA);
	return nPointsTotal;
}


///////////////////////////////////////////////////////////////////////
// Nom : defineixChecks
// Descripció: 
//////////////////////////////////////////////////////////////////////
function defineixChecks(oParentCamp, bChecksReduits)
{
	// bChecksReduits --->  Si hi ha més de CT_NUM_CHECKS_LIMIT_MODIF_TAMANY d'opcions
	//llavors modifiquem el radiobutton per un altre més petit
	var defC = getDefinicioChecks(bChecksReduits).definicio;

	var oChecks = oParentCamp.resolveNodes("CHECK[*].TXT_CAMP");
	for(var x=0; x<oChecks.length; x++)
	{

		oChecks.item(x).minH = defC.CT_MIN_HEIGHT;	//"3mm";
		oChecks.item(x).ui.checkButton.size = defC.CT_CHECK_SIZE;	//"1.8mm";
		oChecks.item(x).caption.font.size = defC.CT_CAPTION_FONTSIZE;	//"6pt";
		oChecks.item(x).margin.topInset = defC.CT_MARGIN_TOPINSET;	//"1mm";
		oChecks.item(x).margin.bottomInset = defC.CT_MARGIN_BOTTOMINSET;	//"0mm";
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : checksReduits	 TODO DEPRECATED
// Descripció: 
//////////////////////////////////////////////////////////////////////
function checksReduits(oParentCamp)
{
	//Si hi ha més de CT_NUM_CHECKS_LIMIT_MODIF_TAMANY d'opcions
	//llavors modifiquem el radiobutton per un altre més petit

	//Definim el check de tamany petit si pertoca
	var oChecks = oParentCamp.resolveNodes("CHECK[*].TXT_CAMP");
	for(var x=0; x<oChecks.length; x++)
	{
		oChecks.item(x).minH = "3mm";
		oChecks.item(x).ui.checkButton.size = "1.8mm";
		oChecks.item(x).caption.font.size = "6pt";
		oChecks.item(x).margin.topInset = "1mm";
		oChecks.item(x).margin.bottomInset = "0mm";
	}

}

///////////////////////////////////////////////////////////////////////
// Nom : standardDeviation
// Descripció: 
//////////////////////////////////////////////////////////////////////
function standardDeviation(values){
  var avg = average(values);

  var squareDiffs = new Array();
  for(var x=0; x<values.length; x++)
  {
  	var diff = values[x] - avg;
    var sqrDiff = diff * diff;
    squareDiffs[x] = sqrDiff;
  }

  var avgSquareDiff = average(squareDiffs);

  var stdDev = Math.sqrt(avgSquareDiff);
  return stdDev;
}

///////////////////////////////////////////////////////////////////////
// Nom : average
// Descripció: 
//////////////////////////////////////////////////////////////////////
function average(data){

  var sum = sumatori(data);

  var avg = sum / data.length;

  return avg;
}

///////////////////////////////////////////////////////////////////////
// Nom : sumatori
// Descripció: 
//////////////////////////////////////////////////////////////////////
function sumatori(data)
{
	var sum = 0;

	for(var x=0; x<data.length; x++)
	sum = sum + data[x];

  return sum;
}

///////////////////////////////////////////////////////////////////////
// Nom : getObjecteSeleccio
// Descripció: Mètode que retorna el camp d'un tipus resposta 'Llista'
//////////////////////////////////////////////////////////////////////
function getObjecteSeleccio(oItem, sTipusResposta) 
{
	return scoINSPQuestioItem.getObjectTipusResposta(oItem, sTipusResposta);
}

///////////////////////////////////////////////////////////////////////
// Nom : setResposta
// Descripció: Actualitza el node Resposta de l'item passat com a paràmetre
//////////////////////////////////////////////////////////////////////
function setResposta(oItem, sTipusResposta)
{
	var sResposta = "";
	var oChecks = getCampsSeleccio(getObjecteSeleccio(oItem, sTipusResposta));

	for (var i = 0; i < oChecks.length; i++) {
		var oCheck = oChecks.item(i);
		if (scoGSITVal.existeixObjecte(oCheck)) {
			if (isCheckMarcat(oCheck)) {
				sResposta = concatId(sResposta, getIdCheck(oCheck));
			}
		}
	}
	scoINSPQuestioItem.setValueResposta(oItem, sResposta, false);
	scoINSPQuestioItem.concatValueTextVinculatResposta(oItem, sResposta.split(CT_SEPARADOR_RESPOSTA));
}

///////////////////////////////////////////////////////////////////////
// Nom : concatId
// Descripció: Mètode que retorna la concatenació 'strId' a strIdsOrigen
//				Si cal afegeix un separador entre les dues cadenes
//////////////////////////////////////////////////////////////////////
function concatId(strIdsOrigen, strId)
{
	var concatStr = strIdsOrigen;
	concatStr += (concatStr != "" && strId != "")?CT_SEPARADOR_RESPOSTA + strId:strId;
	return concatStr;
}

///////////////////////////////////////////////////////////////////////
// Nom : algunCheckMarcat
// Descripció: Comprova si hi ha algun check marcat
//////////////////////////////////////////////////////////////////////
function algunCheckMarcat(oItem, sTipusResposta) 
{
	var oChecks = getCampsSeleccio(getObjecteSeleccio(oItem, sTipusResposta));
	if (!scoGSITVal.existeixObjecte(oChecks))			return;

	var bOk = false;
	var i = 0;
	while (!bOk && i < oChecks.length) {
		var oCheck = oChecks.item(i);
		if (scoGSITVal.existeixObjecte(oCheck)) {
			bOk = isCheckMarcat(oCheck);
			i++;
		}
	}
	return bOk;
}

///////////////////////////////////////////////////////////////////////
// Nom : setValueCamp
// Descripció: Actualitza el camp 'lliure' amb el valor guardat a la resposta de l'ítem
//////////////////////////////////////////////////////////////////////
function setValueCamp(oItem, sTipusResposta, bExecutaAccionsCamps)
{
	var oChecks = getCampsSeleccio(scoINSPQuestioItem.getObjectTipusResposta(oItem, sTipusResposta));
	if (!scoGSITVal.existeixObjecte(oChecks))			return;

	var sIdsSel = scoINSPQuestioItem.getValueResposta(oItem);

	var arIdsSel = sIdsSel.split(CT_SEPARADOR_RESPOSTA);
	if (arIdsSel == null || arIdsSel == undefined)			return;

	for (var i = 0; i < arIdsSel.length; i++) {
		var nIndex = getIndexCheck(oChecks, arIdsSel[i]);
		if (nIndex >= 0)			oChecks.item(nIndex).rawValue = CT_CHECK_ACTIVAT;	
	}

	// Si cal, executem les accions associades al canvi de valor del camp
	if (bExecutaAccionsCamps)
	{
		scoINSPAccions.mostraAccionsAplicables(oItem);
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : netejaCamp
// Descripció: Neteja el valor del camp
//////////////////////////////////////////////////////////////////////
function netejaCamp(oItem, sTipusResposta)
{
	var oChecks = getCampsSeleccio(getObjecteSeleccio(oItem, sTipusResposta));

	for (var i = 0; i < oChecks.length; i++) {
		oChecks.item(i).rawValue = CT_CHECK_DESACTIVAT;
	}
}



///////////////////////////////////////////////////////////////////////
// Nom : initObligatorietat
// Descripció: Inicialitza l'obligatorietat del selector 
//////////////////////////////////////////////////////////////////////
function initObligatorietat(oItem, sTipusResposta, bObligatori)
{
	var oObj = scoINSPQuestioItem.getObjectTipusResposta(oItem, sTipusResposta);
	if (!scoGSITVal.existeixObjecte(oObj))			return;

	// console.println("SET OBLIGATORI " + oObj.somExpression + " " + bObligatori);
	scoGSITCamps.assignarCampObligatori(oObj, bObligatori);
	//this.validate.nullTest = "error";
}


