// Nom : getDefinicioChecks
// Descripció: 
//////////////////////////////////////////////////////////////////////
function getDefinicioChecks(bCheckReduit)
{
	if (scoINSPVisualitzacio.esModeTableta())	return defCheckTamanyTablet;		// no opció a checks reduits

	return ((bCheckReduit)?defCheckTamanyReduit:defCheckTamanyNormal);
}

/***************************************************************************
