 Descripció: Conté els mètodes necessaris per gestionar el panell de Motius
**************************************************************************/

/////////////////////////////////////////////////////////////////////////////
// VARIABLES
/////////////////////////////////////////////////////////////////////////////

var defCheckTamanyTablet = {
		CT_FONTSIZE_CAPTION : '12pt',
		CT_MIN_HEIGHT : '3mm',			// minH
		CT_CHECK_SIZE : '6mm',
		CT_CAPTION_FONTSIZE : '12pt',
		CT_MARGIN_TOPINSET : '1mm',
		CT_MARGIN_BOTTOMINSET : '0mm',
		CT_CAPTION_TEXTINDENT : '24pt'
};


var defCheckTamanyNormal = {
		CT_FONTSIZE_CAPTION : '8pt',
		CT_MIN_HEIGHT : '3mm',			// minH
		CT_CHECK_SIZE : '3mm',
		CT_CAPTION_FONTSIZE : '8pt',
		CT_MARGIN_TOPINSET : '0mm',//'1mm',
		CT_MARGIN_BOTTOMINSET : '2mm', //'0mm'
		CT_CAPTION_TEXTINDENT : '12pt'
};	


var defSizeTitol = {
		CT_FONTSIZE_TBLT : '15pt',
		CT_FONTSIZE_STD : '11pt'
}

/////////////////////////////////////////////////////////////////////////////
// MÈTODES
/////////////////////////////////////////////////////////////////////////////

///////////////////////////////////////////////////////////////////////
// Nom : initPanellMotius
// Descripció: Mètode que inicialitza el panell
//////////////////////////////////////////////////////////////////////
function initPanellMotius()
{
	if (scoGSITVal.isFormulariValidat()) return;
	if (scoGSITPar.oPanellMotius == null || scoGSITPar.oPanellMotius == undefined)	return;

	scoGSITCamps.defVisibilitat(scoGSITPar.oPanellMotius, (scoINSPVal.hiHaItemsATaula(scoGSITPar.oPanellMotius, "S_TAULA_MOTIUS", "S_MOTIU"))?"visible":"hidden");

	if (scoGSITPar.oPanellMotius.presence == "visible")
	{
		defineixMotiusVisualitzacio();
	}
}               


////////////////////////////////////////////////////////////
// Nom: defineixMotiusVisualitzacio
// Descripció:  
////////////////////////////////////////////////////////////
function defineixMotiusVisualitzacio()
{
	if (scoGSITPar.oPanellMotius == null || scoGSITPar.oPanellMotius == undefined)		return;

	// definim el tamany del títol
	initFontSizeTitol(scoGSITPar.oPanellMotius.S_TITOL.Titol);

	// definim el tamany dels checks
	var oTaulaMotius = scoGSITPar.oPanellMotius.S_TAULA_MOTIUS;
	var defCheck = getDefinicioCheck();

	var oChecks = oTaulaMotius.resolveNodes("S_MOTIU[*].CHECK[0]");
	for (var i = 0; i < oChecks.length; i++)
	{
		defineixCheckMotiu(oChecks.item(i), defCheck);
	}
}

////////////////////////////////////////////////////////////
// Nom: initFontSizeTitol
// Descripció:  
////////////////////////////////////////////////////////////
function initFontSizeTitol(oLblTitol)
{
	if (!scoGSITVal.existeixObjecte(oLblTitol))		return;

	var size = (scoINSPVisualitzacio.esModeTableta()?defSizeTitol.CT_FONTSIZE_TBLT:defSizeTitol.CT_FONTSIZE_STD);
	oLblTitol.font.size = size;
}

///////////////////////////////////////////////////////////////////////
// Nom : defineixCheckMotiu
// Descripció: 
//////////////////////////////////////////////////////////////////////
function defineixCheckMotiu(oCheck, defCheck)
{

	oCheck.minH = defCheck.CT_MIN_HEIGHT;	//"3mm";
	oCheck.ui.checkButton.size = defCheck.CT_CHECK_SIZE;	//"1.8mm";
	oCheck.caption.font.size = defCheck.CT_CAPTION_FONTSIZE;	//"6pt";
	oCheck.margin.topInset = defCheck.CT_MARGIN_TOPINSET;	//"1mm";
	oCheck.margin.bottomInset = defCheck.CT_MARGIN_BOTTOMINSET;	//"0mm";
	oCheck.caption.para.textIndent = defCheck.CT_CAPTION_TEXTINDENT;
}

///////////////////////////////////////////////////////////////////////
// Nom : getDefinicioCheck
// Descripció: 
//////////////////////////////////////////////////////////////////////
function getDefinicioCheck()
{
	return ((scoINSPVisualitzacio.esModeTableta())?defCheckTamanyTablet:defCheckTamanyNormal);
}

///////////////////////////////////////////////////////////////////////
// Nom : defCaptionAccio
// Descripció: Actualitza el caption del check passat com a paràmetre amb dades de l'esquema
//////////////////////////////////////////////////////////////////////
function defCaptionAccio(oCheck)
{
	var indexBloc = oCheck.parent.parent.parent.parent.parent.index;
	var indexItem = oCheck.parent.parent.parent.parent.index;
	var indexAccio = oCheck.parent.index;

	// ITEXT: Fent servir 
	// xfa.resolveNode(scoINSPPar.sRutaNodeXMLCheckList);
	// No funciona el aplanat amb iText!!		
	var oDesc = xfa.record.Cos.Contingut.ContingutActa.ManifestInspector.Checklist.resolveNode("Bloc[" + indexBloc + "].Item[" + indexItem + "].Pregunta.AccionsAplicables.Accio[" + indexAccio + "].Descripcio");
	if (scoGSITVal.existeixObjecte(oDesc))			oCheck.caption.value.text.value = oDesc.value;

}

///////////////////////////////////////////////////////////////////////
// Nom : defCaptionMotiu
// Descripció: Actualitza el caption del check passat com a paràmetre amb dades de l'esquema
//////////////////////////////////////////////////////////////////////
function defCaptionMotiu(oCheck)
{
	var indexMotiu = oCheck.parent.index;

	// ITEXT: Fent servir 
	// xfa.resolveNode(scoINSPPar.sRutaNodeXMLMotiu);
	// No funciona el aplanat amb iText!!			
	var oDesc = xfa.record.Cos.MotiusInspeccio.resolveNode("MotiuInspeccio[" + indexMotiu + "].Descripcio");
	oCheck.caption.value.text.value = oDesc.value;
}

/***************************************************************
 Nom: scoINSPNeteja
 Descripció: Conté els mètodes necessaris per tractar la neteja de les dades
**************************************************************************/


///////////////////////////////////////////////////////////////////////
// Nom : netejaPlanaRequeridor
// Descripció: Neteja la plana requeridor
//////////////////////////////////////////////////////////////////////
function netejaPlanaRequeridor()
{
	try
	{
		if(scoGSITVal.isFormulariValidat()) return;

		if (scoGSITVal.esborrarPagina())
		{		
			scoINSPInspeccionat.esborraDadesRequeridor();
			scoINSPEstabliment.esborraDadesEstabliment();
		}
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoINSPNeteja.netejaPlanaRequeridor",exc);
	}
}


///////////////////////////////////////////////////////////////////////
// Nom : netejaDPiCA
// Descripció: Neteja la plana de dades particulars i de contacte/avisos
//////////////////////////////////////////////////////////////////////
function netejaDPiCA()
{
	try
	{
		if(scoGSITVal.isFormulariValidat()) return;

		if (scoGSITVal.esborrarPagina())
		{		
			scoINSPCompareixent.esborraDadesCompareixent();
			scoGSITGen.netejarForm(scoGSITPar.oPanellMotius);	
			scoGSITGen.netejarForm(scoGSITPar.oPanellDescripcioFets);	
			scoINSPQuestions.netejaPanellQuestions();
			scoGSITAdj.treureTotsAdjunts(scoGSITPar.oPanellAdjunts);
			scoINSPImatges.treureTotesImatges(scoINSPPar.oPanellImatges);
			scoINSPDC.esborraDadesDC();
			scoINSPNotificacions.esborraDadesNotificacions();

			scoGSITGen.netejarForm(scoGSITPar.oPanellConformitats);
			scoGSITGen.netejarForm(scoGSITPar.oPanellConsentiment.S_CHCK_CONFIRMACIO_BIO);
			scoINSPVal.netejaPanellValidacio();
		}
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoINSPNeteja.netejaDPiCA",exc);
	}
}

