////////////////////////////////////////////////////////////
function acceptaNotificacionsMultiples(oCheck, oNotif, sSubPrincipal, indexOrigen, indexDesti)
{
	scoOGENotificacions.acceptaNotificacionsMultiples(oNotif);

	scoINSPVisualitzacio.copiaValor(oCheck, sSubPrincipal, indexOrigen, indexDesti);	
	var oNotifDesti = scoINSPVisualitzacio.getObjDesti(oNotif, sSubPrincipal, indexOrigen, indexDesti);
