{
	scoOGENotificacions.addBlocPersona(oNotif);

	var oNotifDesti = scoINSPVisualitzacio.getObjDesti(oNotif, sSubPrincipal, indexOrigen, indexDesti);
	scoOGENotificacions.addBlocPersona(oNotifDesti);
}

////////////////////////////////////////////////////////////
// Nom: deletePersonaNotif
// Descripció: 
////////////////////////////////////////////////////////////
function deletePersonaNotif(oBtn, sSubPrincipal, indexOrigen, indexDesti)
{
	var oBtnDesti = scoINSPVisualitzacio.getObjDesti(oBtn, sSubPrincipal, indexOrigen, indexDesti);

	scoOGENotificacions.deletePersonaNotif(oBtn);
	scoOGENotificacions.deletePersonaNotif(oBtnDesti);
}


////////////////////////////////////////////////////////////
// Nom: copiaDadesANotifMultiple
// Descripció: 
////////////////////////////////////////////////////////////
function copiaDadesANotifMultiple(oPanellNotif, bPregunta, subInstancia, indexOrigen, indexDesti)
{
	if (scoOGENotificacions.copiaDadesANotifMultiple(oPanellNotif, bPregunta))
	{
		var oPanellNotifDesti = scoINSPVisualitzacio.getObjDesti(oPanellNotif, subInstancia, indexOrigen, indexDesti);
		scoOGENotificacions.copiaDadesANotifMultiple(oPanellNotifDesti, false);

		// 122020	Cal mostrar país document si aquest té valor [no s'està mostrant al fer la còpia]
		var oPaisDocument = scoGSITPanells.obtenirObjecteFill(oPanellNotif, "TXT_PAIS_DOCUMENT");
		if (scoGSITVal.existeixObjecte(oPaisDocument))
		{
			scoINSPVisualitzacio.copiaPropietats(oPaisDocument, subInstancia, indexOrigen, indexDesti);
		}
	}
}

