	scoOGENotificacions.netejaPanellNotificacions(getPanellNotif(scoINSPVisualitzacio.CT_INDEX_TBLT));
	scoOGENotificacions.netejaPanellNotificacions(getPanellNotif(scoINSPVisualitzacio.CT_INDEX_STD));
