 Nom: scoINSPQuestioItem
 Descripció: Mètodes associats al nivell ITEM d'una qüestió
**************************************************************************/

/////////////////////////////////////////////////////////////////////////////
// VARIABLES
/////////////////////////////////////////////////////////////////////////////

var defPreguntaTamanyTablet = {
		CT_FONTSIZE : '12pt',
		CT_CAPTION_FONTSIZE : '12pt',
		CT_MIN_HEIGHT : '5.644mm',	//'10mm',			// minH
		CT_MARGIN_TOPINSET : '0.5mm'
	};

var defPreguntaTamanyNormal = {
		CT_FONTSIZE : '8pt',
		CT_CAPTION_FONTSIZE : '8pt',
		CT_MIN_HEIGHT : '5.644mm',			// minH
		CT_MARGIN_TOPINSET : '0.5mm'
	};	



var defNormativaTamanyTablet = {
		CT_FONTSIZE : '11pt',
		CT_CAPTION_FONTSIZE : '11pt'
};

var defNormativaTamanyNormal = {
		CT_FONTSIZE : '7pt',
		CT_CAPTION_FONTSIZE : '7pt'
};	



/////////////////////////////////////////////////////////////////////////////
// MÈTODES
/////////////////////////////////////////////////////////////////////////////


///////////////////////////////////////////////////////////////////////
// Nom : initItemQuestions
// Descripció: Inicialitza un ítem concret de qüestions
//////////////////////////////////////////////////////////////////////
function initItemQuestions(oItem) 
{
	if (oItem == null || oItem == undefined)		return;

	// - Tipus resposta
	var sTipusResposta = obtenirTipusResposta(oItem);
	if (scoGSITVal.isEmpty(sTipusResposta))			return;

	initPregunta(oItem);
	defineixPreguntaVisualitzacio(oItem);
	initVisibilitatTipusResposta(oItem, sTipusResposta);	
	iniObligatorietat(oItem, sTipusResposta, obtenirObligatorietat(oItem));
	iniHint(oItem);

	if (scoINSPQuestions.isSeleccio(sTipusResposta))					initSeleccio(oItem);
	else if (scoINSPQuestions.isMultiseleccio(sTipusResposta))			initMultiseleccio(oItem);
	else if (scoINSPQuestions.isLlista(sTipusResposta))					initLlista(oItem);
	else if (scoINSPQuestions.isLliure(sTipusResposta))					initLliure(oItem);

	// IMPORTANT fer-ho després d'inicialitzar els camps, ja que depen dels seus valors	
	iniAccionsAplicables(oItem, sTipusResposta);
}

///////////////////////////////////////////////////////////////////////
// Nom : initPregunta
// Descripció: Inicialitza el títol de la qüestió
//////////////////////////////////////////////////////////////////////
function initPregunta(oItem) 
{
	// Hem eliminat el binding del camp, per després poder eliminar el node d'informació d'un ítem!!!
	var oTitol = getTitol(oItem);
	if (!scoGSITVal.existeixObjecte(oTitol))			return;

	oTitol.rawValue = getValuePregunta(oItem);

	initNormativaVisualitzacio(oItem);
	scoINSPAccions.defineixAccionsVisualitzacio(getPregunta(oItem));
}

///////////////////////////////////////////////////////////////////////
// Nom : getPregunta
// Descripció: 
//////////////////////////////////////////////////////////////////////
function getPregunta(oItem)
{
	return scoGSITPanells.obtenirObjecteFill(oItem, "S_PREGUNTA");	
}

///////////////////////////////////////////////////////////////////////
// Nom : getSubTitol
// Descripció: 
//////////////////////////////////////////////////////////////////////
function getSubTitol(oItem)
{
	return scoGSITPanells.obtenirObjecteFill(oItem, "S_TITOL");
}


///////////////////////////////////////////////////////////////////////
// Nom : getTitol
// Descripció: 
//////////////////////////////////////////////////////////////////////
function getTitol(oItem)
{
	return scoGSITPanells.obtenirObjecteFill(oItem, "TXT_TITOL");
}

///////////////////////////////////////////////////////////////////////
// Nom : initSeleccio
// Descripció: Inicialitza una qüestió de tipus selecció
//////////////////////////////////////////////////////////////////////
function initSeleccio(oItem) 
{
	scoINSPItemSeleccio.iniCheckSeleccio(oItem, "Seleccio");
}

///////////////////////////////////////////////////////////////////////
// Nom : initMultiseleccio
// Descripció: Inicialitza una qüestió de tipus multiseleccio
//////////////////////////////////////////////////////////////////////
function initMultiseleccio(oItem) 
{
	scoINSPItemSeleccio.iniCheckSeleccio(oItem, "Multiseleccio");
}

///////////////////////////////////////////////////////////////////////
// Nom : initLlista
// Descripció: Inicialitza una qüestió de tipus llista
//////////////////////////////////////////////////////////////////////
function initLlista(oItem) 
{
	scoINSPItemLlista.initLlista(oItem);
}

///////////////////////////////////////////////////////////////////////
// Nom : initLliure
// Descripció: Inicialitza una qüestió de tipus lliure
//////////////////////////////////////////////////////////////////////
function initLliure(oItem) 
{
	scoINSPItemLliure.initLliure(oItem);
}

///////////////////////////////////////////////////////////////////////
// Nom : initVisibilitatTipusResposta
// Descripció: Inicialitza la visibilitat de la resposta d'un ítem concret de qüestions
// Precondició: sTipusResposta és vàlid
//////////////////////////////////////////////////////////////////////
function initVisibilitatTipusResposta(oItem, sTipusResposta)
{
	try {
		// - Ocultem tots els tipus de resposta
		scoINSPQuestions.ocultaObjectsMap(oItem);

		// - Mostrem el tipus de resposta indicat
		scoGSITCamps.defVisibilitat(getObjectTipusResposta(oItem, sTipusResposta), "visible");
	} 
	catch(exc) {
		scoGSITGen.retornarExcepcio("scoINSPQuestioItem.initVisibilitatTipusResposta", exc);
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : iniObligatorietat
// Descripció: 
//////////////////////////////////////////////////////////////////////
function iniObligatorietat(oItem, sTipusResposta, bObligatori)
{
	if (scoGSITVal.isFormulariAcusament())			return;		

	if (scoINSPQuestions.isSeleccio(sTipusResposta) || scoINSPQuestions.isMultiseleccio(sTipusResposta)) {
		//console.println("obligatorietat selecció");
		scoINSPItemSeleccio.initObligatorietat(oItem, sTipusResposta, bObligatori);
	}
	else {	
		var oCamp = getCampTipusResposta(oItem, sTipusResposta);
		if (scoGSITVal.existeixObjecte(oCamp))			oCamp.mandatory = (bObligatori) ? "error" : "";
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : iniHint
// Descripció: 
//////////////////////////////////////////////////////////////////////
function iniHint(oItem)
{
	if (scoGSITVal.isFormulariAcusament())			return;		// #flat#

	var oSubTitol = getSubTitol(oItem);
	var oTxtTitol = getTitol(oItem);

	var btnHint = scoGSITPanells.obtenirObjecteFill(oSubTitol, "BTN_HINT");
	if (oTxtTitol == null || oTxtTitol == undefined || 
			btnHint == null || btnHint == undefined)			return;

	var sHint = getValueHint(oItem);	
	var bEmptyHint = scoGSITVal.isEmpty(sHint);
	scoGSITCamps.defVisibilitat(btnHint, (bEmptyHint?"hidden":"visible")); 
	oTxtTitol.w = (bEmptyHint)?"470pt":"455pt";
	if (!bEmptyHint)	{
		btnHint.assist.toolTip = sHint;		// Si no hi ha un subform intermig no funciona el tooltip desde binding
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : iniAccionsAplicables
// Descripció: Inicialitza el bloc d'accions aplicables
//////////////////////////////////////////////////////////////////////
function iniAccionsAplicables(oItem, sTipusResposta)
{
	/* NO es mostra mai per al tipusResposta camp de text lliure */
	if (scoINSPQuestions.isLliure(sTipusResposta)) {
		scoINSPAccions.defVisibilitatPanell(oItem, false);
	}	
	else {
		scoINSPAccions.mostraAccionsAplicables(oItem);
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : defCaptionAccio
// Descripció: Actualitza el caption del check passat com a paràmetre amb dades de l'esquema
//////////////////////////////////////////////////////////////////////
function defCaptionAccio(oCheck)
{

	var indexBloc = oCheck.parent.parent.parent.parent.parent.index;
	var indexItem = oCheck.parent.parent.parent.parent.index;
	var indexAccio = oCheck.parent.index;

	// ITEXT: Fent servir 
	// xfa.resolveNode(scoINSPPar.sRutaNodeXMLCheckList);
	// No funciona el aplanat amb iText!!		
	var oDesc = xfa.record.Cos.Contingut.ContingutActa.ManifestInspector.Checklist.resolveNode("Bloc[" + indexBloc + "].Item[" + indexItem + "].Pregunta.AccionsAplicables[" + indexAccio + "].Accio.Descripcio");
	if (scoGSITVal.existeixObjecte(oDesc))			oCheck.caption.value.text.value = oDesc.value;

}

///////////////////////////////////////////////////////////////////////
// Nom : obtenirTipusResposta
// Descripció: Retorna el TIPUS RESPOSTA de la qüestió
//////////////////////////////////////////////////////////////////////
function obtenirTipusResposta(oItem) 
{
	var oTipusResposta = scoGSITPanells.obtenirObjecteFill(oItem, "TIPUS_RESPOSTA");
	if (scoGSITVal.isEmpty(oTipusResposta))		return "";

	return oTipusResposta.rawValue;

}

///////////////////////////////////////////////////////////////////////
// Nom : obtenirObligatorietat
// Descripció: Retorna l'OBLIGATORIETAT de la qüestió
//////////////////////////////////////////////////////////////////////
function obtenirObligatorietat(oItem) 
{
	var oObligatori = scoGSITPanells.obtenirObjecteFill(oItem, "OBLIGATORI");
	if (scoGSITVal.isEmpty(oObligatori))		return false;  /* Si no està definit -> OPCIONAL */

	return scoINSPQuestions.isTrue(oObligatori);

}

///////////////////////////////////////////////////////////////////////
// Nom : getObjectTipusResposta
// Descripció: Retorna l'objecte associat al tipus resposta indicat de l'ítem
//////////////////////////////////////////////////////////////////////
function getObjectTipusResposta(oItem, sTipusResposta)
{
	return scoGSITPanells.obtenirObjecteFill(oItem, scoINSPQuestions.getObjectMap(sTipusResposta).camp);
}

///////////////////////////////////////////////////////////////////////
// Nom : getCampTipusResposta
// Descripció: Retorna el camp associat al tipus resposta indicat de l'ítem
//////////////////////////////////////////////////////////////////////
function getCampTipusResposta(oItem, sTipusResposta)
{
	return scoGSITPanells.obtenirObjecteFill(getObjectTipusResposta(oItem, sTipusResposta), "TXT_CAMP");
}

///////////////////////////////////////////////////////////////////////
// Nom : getSubFormResposta
// Descripció: Retorna el subormulari que conté la resposta de l'ítem
//////////////////////////////////////////////////////////////////////
function getSubFormResposta(oItem)
{
	return scoGSITPanells.obtenirObjecteFill(oItem, "S_RESPOSTA");
}


///////////////////////////////////////////////////////////////////////
// Nom : getCampResposta
// Descripció: Retorna el camp que conté la resposta de l'ítem
//////////////////////////////////////////////////////////////////////
function getCampResposta(oItem)
{
	return scoGSITPanells.obtenirObjecteFill(getSubFormResposta(oItem), "TXT_RESPOSTA");
}

///////////////////////////////////////////////////////////////////////
// Nom : getValueResposta
// Descripció: Retorna un string amb el valor camp que conté la resposta de l'ítem
//////////////////////////////////////////////////////////////////////
function getValueResposta(oItem)
{
	var oResposta = getCampResposta(oItem);
	return (scoGSITVal.isEmpty(oResposta))?"":oResposta.rawValue;
}

///////////////////////////////////////////////////////////////////////
// Nom : getNodesOpcionRespostaAccions
// Descripció: Retorna els nodes OpcioRespostaAccions d'un ítem
//////////////////////////////////////////////////////////////////////
function getNodesOpcionRespostaAccions(oItem) 
{
	var oNodeXMLPregunta = getNodeXMLPregunta(getPregunta(oItem));
	if (!scoGSITVal.existeixObjecte(oNodeXMLPregunta))			return;

	return oNodeXMLPregunta.resolveNodes("OpcionsRespostaAccions.Id[*]");
}

///////////////////////////////////////////////////////////////////////
// Nom : getNodeHint
// Descripció: Retorna el node Hint d'un ítem
//////////////////////////////////////////////////////////////////////
function getNodeHint(oItem) 
{
	if (scoGSITVal.isFormulariAcusament())			return "";

	var oPregunta = getPregunta(oItem);
	if (!scoGSITVal.existeixObjecte(oPregunta))			return null;

	return oPregunta.dataNode.resolveNode("Hint");
}

///////////////////////////////////////////////////////////////////////
// Nom : getValueHint
// Descripció: Retorna el valor del hint
//////////////////////////////////////////////////////////////////////
function getValueHint(oItem) 
{
	var oNodeHint = getNodeHint(oItem);
	if (oNodeHint == null || oNodeHint == undefined)			return "";

	return oNodeHint.value;
}

///////////////////////////////////////////////////////////////////////
// Nom : setValueResposta
// Descripció: Actualitza el valor del camp resposta d'un ítem
//////////////////////////////////////////////////////////////////////
function setValueResposta(oItem, sValor) 
{
	scoGSITVal.defValor(getSubFormResposta(oItem), "TXT_RESPOSTA", sValor);
}

///////////////////////////////////////////////////////////////////////
// Nom : getNodeXMLPregunta
// Descripció: 
//////////////////////////////////////////////////////////////////////
function getNodeXMLPregunta(oPregunta)
{
	if (scoGSITVal.isFormulariAcusament()) {
		var indexItem = oPregunta.parent.index;
		var indexBloc = oPregunta.parent.parent.index;

		return xfa.record.Cos.Contingut.ContingutActa.ManifestInspector.Checklist.resolveNode("Bloc[" + indexBloc + "].Item["+ indexItem + "].Pregunta");
	}
	else {
		return oPregunta.dataNode;
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : getNodePregunta
// Descripció: Retorna el node Pregunta d'un ítem
//////////////////////////////////////////////////////////////////////
function getNodePregunta(oItem) 
{
	var oPregunta = getPregunta(oItem);
	if (!scoGSITVal.existeixObjecte(oPregunta))			return null;

	var oXMLPregunta = getNodeXMLPregunta(oPregunta);
	return oXMLPregunta.Pregunta;	
}

///////////////////////////////////////////////////////////////////////
// Nom : getValuePregunta
// Descripció: Retorna el valor de Pregunta (títol)
//////////////////////////////////////////////////////////////////////
function getValuePregunta(oItem) 
{
	var oNodePregunta = getNodePregunta(oItem);
	if (oNodePregunta == null || oNodePregunta == undefined)			return "";
	return oNodePregunta.value;
}
///////////////////////////////////////////////////////////////////////
// Nom : getNodesOpcionResposta
// Descripció: Retorna els nodes OpcioResposta d'un ítem
//////////////////////////////////////////////////////////////////////
function getNodesOpcionResposta(oItem) 
{
	var oNodeXMLPregunta = getNodeXMLPregunta(getPregunta(oItem));
	if (!scoGSITVal.existeixObjecte(oNodeXMLPregunta))			return;

	return oNodeXMLPregunta.resolveNodes("OpcionsResposta.OpcioResposta[*]");
}


///////////////////////////////////////////////////////////////////////
// Nom : getArrayOpcionsResposta
// Descripció: Retorna un array amb les opcions de resposta d'un ítem
//////////////////////////////////////////////////////////////////////
function getArrayOpcionsResposta(oItem) 
{
	var oItems = getNodesOpcionResposta(oItem);
	if (oItems == null || oItems == undefined)			return;

	var aValors = new Array();
	for (var i = 0; i < oItems.length; i++) {
		var oOpcio = oItems.item(i);
		if (oOpcio != null && oOpcio != undefined) {
			var oNodeId = oOpcio.resolveNode("Id");
			var oNodeDesc = oOpcio.resolveNode("Descripcio");
			aValors.push([oNodeDesc.value, oNodeId.value]);
		}
	}
	return aValors;
}


///////////////////////////////////////////////////////////////////////
// Nom : setRespostaItem
// Descripció: Actualitza el node 'Resposta' d'un ítem
//////////////////////////////////////////////////////////////////////
function setRespostaItem(oItem)
{
	var sTipusResposta = obtenirTipusResposta(oItem);

	if (scoINSPQuestions.isSeleccio(sTipusResposta))					scoINSPItemSeleccio.setResposta(oItem, sTipusResposta);
	else if (scoINSPQuestions.isMultiseleccio(sTipusResposta))		scoINSPItemSeleccio.setResposta(oItem, sTipusResposta);
	else if (scoINSPQuestions.isLlista(sTipusResposta))				scoINSPItemLlista.setResposta(oItem);
	else if (scoINSPQuestions.isLliure(sTipusResposta))				scoINSPItemLliure.setResposta(oItem);
}


///////////////////////////////////////////////////////////////////////
// Nom : validaItemMultiseleccioQuestio
// Descripció: Validació d'un ítem
//////////////////////////////////////////////////////////////////////
function validaItemMultiseleccioQuestio(oItem, result)
{
	if (!scoGSITVal.existeixObjecte(oItem))			return true;

	var bOk = esSelObligSenseCapMarcat(oItem);
	var sTipusResposta = obtenirTipusResposta(oItem);
	/* 09062020 Modifiquem la funció de validació
	var bOk = true;
	var sTipusResposta = obtenirTipusResposta(oItem);
	if (obtenirObligatorietat(oItem)) {
		// - Validem obligatorietat camps multiselecció
		if (scoINSPQuestions.isMultiseleccio(sTipusResposta) || scoINSPQuestions.isSeleccio(sTipusResposta) ) {
			bOk = scoINSPItemSeleccio.algunCheckMarcat(oItem, sTipusResposta);
		}
	}
	*/

	if (!bOk) {
		var sTitol  = getValuePregunta(oItem);
		sTitol = (!scoGSITVal.isEmpty(sTitol))?sTitol:msgErrorSeleccio.value;
		var sMsg = sTitol + ((String(sTitol).charAt(sTitol.length-1) != ":") ? ": " : " ");
		var sMsgError = (scoINSPQuestions.isSeleccio(sTipusResposta))?msgErrorRBSenseMarcar.value:msgErrorMultiSelectSenseMarcar.value;

		result.validacioCorrecte = false;
		result.missatgeError = sMsg + sMsgError + "\n";

		if (result.campsIncorrectes == null)		result.campsIncorrectes = new Array();
		result.campsIncorrectes.push(getObjectTipusResposta(oItem, sTipusResposta));

		if (scoGSITNod.primerCampNoValid == "") {
			var oPrimerCheck = scoINSPItemSeleccio.getFirstCheck(oItem, sTipusResposta);
			if (scoGSITVal.existeixObjecte(oPrimerCheck))		scoGSITNod.primerCampNoValid = oPrimerCheck;
		}		
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : netejaRespostaItem
// Descripció: Actualitza el node 'Resposta' d'un ítem
//////////////////////////////////////////////////////////////////////
function netejaRespostaItem(oItem, sTipusResposta)
{
	setValueResposta(oItem, "");

	if (scoINSPQuestions.isSeleccio(sTipusResposta) || scoINSPQuestions.isMultiseleccio(sTipusResposta))					scoINSPItemSeleccio.netejaCamp(oItem, sTipusResposta);
	else if (scoINSPQuestions.isLlista(sTipusResposta))				scoINSPItemLlista.netejaCamp(oItem);
	else if (scoINSPQuestions.isLliure(sTipusResposta))				scoINSPItemLliure.netejaCamp(oItem);
}

///////////////////////////////////////////////////////////////////////
// Nom : netejaPanellItem
// Descripció: 
//////////////////////////////////////////////////////////////////////
function netejaPanellItem(oItem)
{
	if (!scoGSITVal.existeixObjecte(oItem))			return;

	var sTipusResposta = obtenirTipusResposta(oItem);	
	netejaRespostaItem(oItem, sTipusResposta);
	iniAccionsAplicables(oItem, sTipusResposta);
}


///////////////////////////////////////////////////////////////////////
// Nom : eliminarNodeDePregunta
// Descripció: Mètode que elimina del node pregunta 'oNodePregunta' el node amb nom 'nomNodeEliminar'
//////////////////////////////////////////////////////////////////////
function eliminarNodeDePregunta(oNodePregunta, nomNodeEliminar)
{
	if (!scoGSITVal.existeixObjecte(oNodePregunta))				return;

	var oNodeEliminar = oNodePregunta.resolveNode(nomNodeEliminar);
	if (!scoGSITVal.existeixObjecte(oNodeEliminar))				return;
	oNodePregunta.nodes.remove(oNodeEliminar);
}



///////////////////////////////////////////////////////////////////////
// Nom : obtenirCampPerFocus
// Descripció: Mètode que retorna el camp de l'ítem
//////////////////////////////////////////////////////////////////////
function obtenirCampPerFocus(oItem)
{
	var sTipusResposta = obtenirTipusResposta(oItem);

	if (scoINSPQuestions.isSeleccio(sTipusResposta))					return scoINSPItemSeleccio.getFirstCheck(oItem, sTipusResposta);
	else if (scoINSPQuestions.isMultiseleccio(sTipusResposta))		return scoINSPItemSeleccio.getFirstCheck(oItem, sTipusResposta);
	else if (scoINSPQuestions.isLlista(sTipusResposta))				return scoINSPItemLlista.getCampLlista(oItem);
	else if (scoINSPQuestions.isLliure(sTipusResposta))				return scoINSPItemLliure.getCampLliure(oItem);

	return null;
}

///////////////////////////////////////////////////////////////////////
// Nom : esSelObligSenseCapMarcat
// Descripció: Comprova obligatorietat i seleccionat d'un ítem SELECCIÓ/MULTISELECCIÓ
//			Retorna false si és obligatori i no hi ha res marcat, i true en cas contrari
//////////////////////////////////////////////////////////////////////
function esSelObligSenseCapMarcat(oItem)
{
	var bOk = true;
	var sTipusResposta = obtenirTipusResposta(oItem);
	if (obtenirObligatorietat(oItem)) {
		// - Validem obligatorietat camps multiselecció
		if (scoINSPQuestions.isMultiseleccio(sTipusResposta) || scoINSPQuestions.isSeleccio(sTipusResposta) ) {
			bOk = scoINSPItemSeleccio.algunCheckMarcat(oItem, sTipusResposta);
		}
	}
	return bOk;
}


