// Descripció: 
//////////////////////////////////////////////////////////////////////
function defineixPreguntaVisualitzacio(oItem)
{
	var defQuestio = getDefinicioPregunta();
	var oTitol = getTitol(oItem);	

	if (oTitol.caption)	oTitol.caption.font.size = defQuestio.CT_CAPTION_FONTSIZE;
