///////////////////////////////////////////////////////////////////////
// Nom : defineixItemVisualitzacio
// Descripció: 
//////////////////////////////////////////////////////////////////////
function defineixItemVisualitzacio(oItem)
{
	if (oItem == null || oItem == undefined)		return;

	// - Tipus resposta
	var sTipusResposta = obtenirTipusResposta(oItem);
	if (scoGSITVal.isEmpty(sTipusResposta))			return;

	defineixPreguntaVisualitzacio(oItem);
	initNormativaVisualitzacio(oItem);
	scoINSPAccions.defineixAccionsVisualitzacio(getPregunta(oItem));

	if (scoINSPQuestions.isSeleccio(sTipusResposta) || scoINSPQuestions.isMultiseleccio(sTipusResposta)) {
		scoINSPItemSeleccio.defineixChecksVisualitzacio(oItem, sTipusResposta);
	}
	else if (scoINSPQuestions.isLlista(sTipusResposta)) {
		scoINSPItemLlista.defineixLlistaVisualitzacio(oItem);
	}
	else if (scoINSPQuestions.isLliure(sTipusResposta)) {
		scoINSPItemLliure.defineixLliureVisualitzacio(oItem);
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : concatValueTextVinculatResposta
// Descripció: Mètode que retorna el text vinculat a la resposta d'un node de tipus LLISTA/SELECCIO/MULTISELECCIO
// Paràmetres d'entrada:
//	oItem
//	aOpcionsRespostes - array amb les opcions de resposta. Per multiselect pot haver-hi més d'un element.
//////////////////////////////////////////////////////////////////////
function concatValueTextVinculatResposta(oItem, aOpcionsRespostes)
{
	if (aOpcionsRespostes == null || aOpcionsRespostes == undefined)	return;

	// - Tipus resposta
	var sTipusResposta = obtenirTipusResposta(oItem);
	if (scoGSITVal.isEmpty(sTipusResposta))			return;

	if (!scoINSPQuestions.isSeleccio(sTipusResposta) && !scoINSPQuestions.isMultiseleccio(sTipusResposta) && !scoINSPQuestions.isLlista(sTipusResposta))					return;

	var nodesResposta = getNodesOpcionResposta(oItem);
	if (nodesResposta == null || nodesResposta == undefined)		return;

	var textVinculat = "";

	var n = 0;
	// - Cerquem i guardem per cada resposta el text vinculat
	for (var n=0; n<aOpcionsRespostes.length; n++)
	{
		var bTrobat = false;
		var i = 0;
		while (!bTrobat && i < nodesResposta.length)
		{
			bTrobat = (scoGSITVal.getValorNodeXML("Id", nodesResposta.item(i)) == aOpcionsRespostes[n]);
			if (bTrobat)
			{
				var textVinculatOpcio = scoGSITVal.getValorNodeXML("TextVinculat", nodesResposta.item(i));
				if (textVinculatOpcio != null && textVinculatOpcio != undefined && !scoGSITVal.isEmpty(textVinculatOpcio))
				{
					textVinculat += scoGSITVal.isEmpty(textVinculat)?textVinculatOpcio:"##" + textVinculatOpcio;
				}
			}
			i++;
		}
	}	

	// -- Concatenem el valor al camp de text 
	if (textVinculat != null && textVinculat != undefined && !scoGSITVal.isEmpty(textVinculat))
	{
		var oTxtVinculatRespostes = scoGSITPar.oPanellTextVinculat.S_TEXT.TXT_VINCULAT_RESPOSTES;
		if (oTxtVinculatRespostes == null || oTxtVinculatRespostes == undefined || scoGSITVal.isEmpty(oTxtVinculatRespostes))	oTxtVinculatRespostes.rawValue = "##";		// TODO: Afegim el separador, perquè afegint el '' deixa un null a la llista
		oTxtVinculatRespostes.rawValue += (scoGSITVal.isEmpty(oTxtVinculatRespostes))?textVinculat:"##" + textVinculat;
	}
}

