/////////////////////////////////////////////////////////////////////////////
// VARIABLES
/////////////////////////////////////////////////////////////////////////////

var mapSelectCampQuestio = {
						Seleccio: { camp: "SELECCIO" },
						Multiseleccio: { camp: "MULTISELECCIO" },
						Lliure: { camp: "LLIURE" },
						Llista: { camp: "LLISTA" },
						Literal: { camp: null }
					};


var defBlocTamanyTablet = {
		CT_FONTSIZE : '14pt',
		CT_CAPTION_FONTSIZE : '14pt'
	};

var defBlocTamanyNormal = {
		CT_FONTSIZE : '11pt',
		CT_CAPTION_FONTSIZE : '11pt',
	};	



/////////////////////////////////////////////////////////////////////////////
// MÈTODES
/////////////////////////////////////////////////////////////////////////////

///////////////////////////////////////////////////////////////////////
// Nom : initPanellQuestions
// Descripció: Inicialitza el panell dinàmic de qüestions
//////////////////////////////////////////////////////////////////////
function initPanellQuestions()
{
	if (scoGSITVal.isFormulariValidat()) return;
	//if (scoGSITVal.esFormulariGuardat() && !scoGSITVal.isFormulariAcusament())	return;

	if (scoGSITVal.esFormulariGuardat())		return;	

	var oSubBlocs = scoGSITPar.oPanellQuestions.resolveNodes(scoINSPPar.sRutaBlocs);
	if (oSubBlocs == null || oSubBlocs == undefined)			return;

	scoSBSMostra.mostrarOcultarPanell(scoGSITPanells.obtenirObjecteFill(scoGSITPar.oPanellQuestions, "S_QUESTIONS"), (oSubBlocs.length > 0));

	for (var i = 0; i < oSubBlocs.length; i++) {
		initBlocQuestions(oSubBlocs.item(i));
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : initBlocQuestions
// Descripció: Inicialitza un bloc de qüestions
//////////////////////////////////////////////////////////////////////
function initBlocQuestions(oBloc) 
{
	if (oBloc == null || oBloc == undefined)		return;

	initTitolBloc(oBloc);

	var oSubItems = oBloc.resolveNodes(scoINSPPar.sRutaItems);
	if (oSubItems == null || oSubItems == undefined) 		return;
	for (var j = 0;  j < oSubItems.length; j++) {
		scoINSPQuestioItem.initItemQuestions(oSubItems.item(j));
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : initTitolBloc
// Descripció: Inicialitza títol de bloc
//////////////////////////////////////////////////////////////////////
function initTitolBloc(oBloc)
{
	var oSTitol = oBloc.S_TITOL;
	if (!scoGSITVal.existeixObjecte(oSTitol))			return;

	var oTitol = scoGSITPanells.obtenirObjecteFill(oSTitol, "TXT_TITOL");
	scoSBSMostra.mostrarOcultarPanell(oSTitol, !scoGSITVal.isEmpty(oTitol));

	if (oSTitol.presence == "visible")
	{
		defineixBloc(oTitol);
	}
}


///////////////////////////////////////////////////////////////////////
// Nom : getObjectMap
// Descripció: Retorna l'objecte amb clau 'sKey'
//////////////////////////////////////////////////////////////////////
function getObjectMap(sKey) 
{
	return mapSelectCampQuestio[sKey];
}

///////////////////////////////////////////////////////////////////////
// Nom : ocultaObjectsMap
// Descripció: Oculta tots els objectes
//////////////////////////////////////////////////////////////////////
