}

///////////////////////////////////////////////////////////////////////
// Nom : isLlista
// Descripció: Retorna true si és Llista i false en cas contrari
//////////////////////////////////////////////////////////////////////
function isLlista(sTipusResposta) {
	return (sTipusResposta == "Llista");
}

///////////////////////////////////////////////////////////////////////
// Nom : isLliure
// Descripció: Retorna true si és Lliure i false en cas contrari
//////////////////////////////////////////////////////////////////////
function isLliure(sTipusResposta) {
