}


///////////////////////////////////////////////////////////////////////
// Nom : setRespostaQuestions
// Descripció: Recorre els nodes qüestions: fa un recorregut per bloc, i per cada bloc 
//				un recorregut pels ítems per actualitzar el node 'Resposta'
//////////////////////////////////////////////////////////////////////
function setRespostaQuestions()
{
	// - Neteja camp que conté els textos vinculats
	scoGSITGen.netejarForm(scoGSITPar.oPanellTextVinculat);

	// - Definir la resposta de cadascuna de les opcions
	var oSubBlocs = scoGSITPar.oPanellQuestions.resolveNodes(scoINSPPar.sRutaBlocs);
	if (oSubBlocs == null || oSubBlocs == undefined)			return;

	for (var i = 0; i < oSubBlocs.length; i++) {
		setRespostaBlocQuestions(oSubBlocs.item(i));
	}

	// - Filtra i endreça camp amb textos vinculats
	tractaTextosVinculatsResposta();
}


///////////////////////////////////////////////////////////////////////
// Nom : setRespostaBlocQuestions
// Descripció: Recorre els nodes ítems d'un bloc per actualitzar el node 'Resposta'
//////////////////////////////////////////////////////////////////////
function setRespostaBlocQuestions(oBloc)
{
	if (oBloc == null || oBloc == undefined)		return;

	var oSubItems = oBloc.resolveNodes(scoINSPPar.sRutaItems);
	if (oSubItems == null || oSubItems == undefined) 		return;
	for (var j = 0;  j < oSubItems.length; j++) {
		scoINSPQuestioItem.setRespostaItem(oSubItems.item(j));
	}
}


///////////////////////////////////////////////////////////////////////
// Nom : validaQuestionsMultiseleccio
// Descripció: Recorre els nodes qüestions i fa les valoracions necessàries
//////////////////////////////////////////////////////////////////////
function validaQuestionsMultiseleccio() 
{
	var result = new Array();

	if (!scoGSITCamps.esVisible(scoGSITPar.oPanellQuestions))				return result;

	var oSubItems = scoGSITPar.oPanellQuestions.resolveNodes(scoINSPPar.sRutaBlocs + "." + scoINSPPar.sRutaItems);
	if (scoGSITVal.existeixObjecte(oSubItems)) {
		for (var i = 0; i < oSubItems.length; i++) {
			var valResult = scoGSITVal.inicialitzarVariableValidacioEspecificaCorrecte();

			scoINSPQuestioItem.validaItemMultiseleccioQuestio(oSubItems.item(i), valResult);
			result.push(valResult);
		}
	}

	return scoOGEVal.validacioConjunta(result);	
}


///////////////////////////////////////////////////////////////////////
// Nom : netejaPanellQuestions
// Descripció: Mètode que neteja les dades del panell de qüestions
//////////////////////////////////////////////////////////////////////
function netejaPanellQuestions() 
{
	if (scoGSITVal.isFormulariValidat())			return;

	var oSubItems = scoGSITPar.oPanellQuestions.resolveNodes(scoINSPPar.sRutaBlocs + "." + scoINSPPar.sRutaItems);
	if (scoGSITVal.existeixObjecte(oSubItems)) {
		for (var i = 0; i < oSubItems.length; i++) {
			scoINSPQuestioItem.netejaPanellItem(oSubItems.item(i));
		}
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : eliminarNodesXmlSobrants
// Descripció: Mètode que elimina del XML els nodes sobrants (els que ens han servit per muntar el bloc de qüestions)
//			- Item.Pregunta.OpcionsResposta
//////////////////////////////////////////////////////////////////////
function eliminarNodesXmlSobrants()
{
return; // TODO
	var oSubItems = scoGSITPar.oPanellQuestions.resolveNodes(scoINSPPar.sRutaBlocs + "." + scoINSPPar.sRutaItems);
	if (scoGSITVal.existeixObjecte(oSubItems)) {
		for (var i = 0; i < oSubItems.length; i++) {
