/////////////////////////////////////////////////////////////////////////////
// Nom: posicionaPrimerCampVisible
// Descripció: Mètode que es posiciona en el primer camp de qüestions visible
/////////////////////////////////////////////////////////////////////////////
function posicionaPrimerCampVisible()
{
	var oCampFocus = obtenirCampVisiblePerFocus();
	if (scoGSITVal.existeixObjecte(oCampFocus)) xfa.host.setFocus(oCampFocus.somExpression);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: obtenirCampVisiblePerFocus
// Descripció: Retorna el primer camp del panell de Questions per posicionar el focus
// Paràmetres de sortida:
//		oCamp - Camp per posicionar el focus
/////////////////////////////////////////////////////////////////////////////
function obtenirCampVisiblePerFocus()
{
	try
	{
		var oFirstItem = scoGSITPar.oPanellQuestions.resolveNode(scoINSPPar.sRutaFirstItem);
		if (!scoGSITVal.existeixObjecte(oFirstItem))			return;

		return scoINSPQuestioItem.obtenirCampPerFocus(oFirstItem);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoINSPQuestions::obtenirCampVisiblePerFocus", exc);
	}
}


