// Nom: defineixQuestionsVisualitzacio
// Descripció:  
////////////////////////////////////////////////////////////
function defineixQuestionsVisualitzacio()
{
	var mode = scoINSPVisualitzacio.getModeVisualitzacio();

	var oBlocs = scoGSITPar.oPanellQuestions.resolveNodes(scoINSPPar.sRutaBlocs);
	if (oBlocs == null || oBlocs == undefined)	return;

	for (var nBloc = 0; nBloc < oBlocs.length; nBloc++)
	{
		var oBloc = oBlocs.item(nBloc);
		if (scoGSITVal.existeixObjecte(oBloc))
		{
			scoINSPVisualitzacio.defineixTitolPrincipal(oBloc.S_TITOL.TXT_TITOL, mode);

			var oItems = oBloc.resolveNodes(scoINSPPar.sRutaItems);
			for (var nItem = 0; nItem < oItems.length; nItem++)
			{
				var oItem = oItems.item(nItem);
				scoINSPQuestioItem.defineixItemVisualitzacio(oItem);
			}
		}
	}
}

////////////////////////////////////////////////////////////
// Nom: tractaTextosVinculatsResposta
// Descripció:  
////////////////////////////////////////////////////////////
function tractaTextosVinculatsResposta()
{
	var oTxtVinculatRespostes = scoGSITPar.oPanellTextVinculat.S_TEXT.TXT_VINCULAT_RESPOSTES;
	if (scoGSITVal.isEmpty(oTxtVinculatRespostes))	return;

	var aTxtVinculatRespostes = oTxtVinculatRespostes.rawValue.split("##");
	if (aTxtVinculatRespostes)
	{
		aTxtVinculatRespostes = scoINSPVal.sortIRemoveDuplicates(aTxtVinculatRespostes);
	}

	oTxtVinculatRespostes.rawValue = aTxtVinculatRespostes.join('\r');

	scoGSITPar.oPanellTextVinculat.presence = (scoGSITVal.isEmpty(oTxtVinculatRespostes.rawValue))?"hidden":"visible";
}


