function prepararDadesSignatura()
{
	try{
		var numSigInsp = xfa.resolveNode("ACTAINSPECCIO[0].contacteAvisos[0].BLOC[0].N_INSPECTORS[0].NUM_INSP[0]").rawValue;
		var numSigComp = xfa.resolveNode("ACTAINSPECCIO[0].contacteAvisos[0].BLOC[0].N_COMPAREIXENTS[0].NUM_INSP[0]").rawValue;

		var numSignatura = 0;

		for(var numInsp=1;numInsp<4;numInsp++){
			numSignatura++;
			var oSignatura = xfa.resolveNode("ACTAINSPECCIO[0].contacteAvisos[0].BLOC[0].S_SIGNATURE[0].S_SIGNATURE_" + numSignatura + "[0]");

			// S_INSPECTORSCOMP[0] - S_INSPECTORSCOMP[1]  <- visualizació Tablet/PC
			var oInspector = xfa.resolveNode("ACTAINSPECCIO[0].contacteAvisos[0].BLOC[0].S_INSPECTORSCOMP[0].INSPECTOR_" + numInsp + "[0]");

			if (numInsp <= numSigInsp && oInspector.F_BIOMETRICA.rawValue !== null){
				oSignatura.OrigenSignatura.rawValue = "Inspector";
				oSignatura.TipusSignatura.rawValue = oInspector.F_BIOMETRICA.rawValue;
				oSignatura.S_DadesSignatari.Nom.rawValue = oInspector.TXT_NOM.rawValue;
				oSignatura.S_DadesSignatari.Cognoms.rawValue = oInspector.TXT_COGNOM1.rawValue;
				oSignatura.S_DadesSignatari.TipusIdentificacio.rawValue = oInspector.TXT_TIPUS_IDENTIFICADOR.rawValue;
				oSignatura.S_DadesSignatari.Identificacio.rawValue = oInspector.TXT_NUM_IDENTIFICADOR.rawValue;
			}else{
				numSignatura--;
				oSignatura.TipusSignatura.rawValue = null;
				oSignatura.OrigenSignatura.rawValue = null;
				oSignatura.S_DadesSignatari.Nom.rawValue = null;
				oSignatura.S_DadesSignatari.Cognoms.rawValue = null;
				oSignatura.S_DadesSignatari.TipusIdentificacio.rawValue = null;
				oSignatura.S_DadesSignatari.Identificacio.rawValue = null;
			}		
		}

		// S_INSPECTORSCOMP[0] - S_INSPECTORSCOMP[1]  <- visualizació Tablet/PC
		for(var numCom=1;numCom<4;numCom++){
			numSignatura++;
			var oSignatura = xfa.resolveNode("ACTAINSPECCIO[0].contacteAvisos[0].BLOC[0].S_SIGNATURE[0].S_SIGNATURE_" + numSignatura + "[0]");

			// S_INSPECTORSCOMP[0] - S_INSPECTORSCOMP[1]  <- visualizació Tablet/PC
			var oCompareixent = xfa.resolveNode("ACTAINSPECCIO[0].contacteAvisos[0].BLOC[0].S_INSPECTORSCOMP[0].COMPAREIXENT_" + numCom + "[0]");

			if (numCom <= numSigComp && oInspector.F_BIOMETRICA.rawValue !== null){
				oSignatura.OrigenSignatura.rawValue = "Compareixent";
				oSignatura.TipusSignatura.rawValue = oCompareixent.F_BIOMETRICA.rawValue;
				oSignatura.S_DadesSignatari.Nom.rawValue = oCompareixent.TXT_NOM.rawValue;
				oSignatura.S_DadesSignatari.Cognoms.rawValue = oCompareixent.TXT_COGNOM1.rawValue;
				oSignatura.S_DadesSignatari.TipusIdentificacio.rawValue = oCompareixent.TXT_TIPUS_IDENTIFICADOR.rawValue;
				oSignatura.S_DadesSignatari.Identificacio.rawValue = oCompareixent.TXT_NUM_IDENTIFICADOR.rawValue;
			}else{
				numSignatura--;
				oSignatura.TipusSignatura.rawValue = null;
				oSignatura.OrigenSignatura.rawValue = null;
				oSignatura.S_DadesSignatari.Nom.rawValue = null;
				oSignatura.S_DadesSignatari.Cognoms.rawValue = null;
				oSignatura.S_DadesSignatari.TipusIdentificacio.rawValue = null;
				oSignatura.S_DadesSignatari.Identificacio.rawValue = null;
			}			
		}

		// NETAJA SIGNATURES QUE NO FAN FALTA
		var numSigTotal = (parseInt(numSigInsp) + parseInt(numSigComp));
		numSigTotal++;

		for(var numSignaturaExtra=numSigTotal;numSignaturaExtra<7;numSignaturaExtra++){
			var oSignatura = xfa.resolveNode("ACTAINSPECCIO[0].contacteAvisos[0].BLOC[0].S_SIGNATURE[0].S_SIGNATURE_" + numSignaturaExtra + "[0]");
			oSignatura.TipusSignatura.rawValue = null;
			oSignatura.OrigenSignatura.rawValue = null;
			oSignatura.x.rawValue = null;
			oSignatura.y.rawValue = null;
			oSignatura.Height.rawValue = null;
			oSignatura.Width.rawValue = null;
			oSignatura.Pagina.rawValue = null;					
			oSignatura.S_DadesSignatari.Nom.rawValue = null;
			oSignatura.S_DadesSignatari.Cognoms.rawValue = null;
			oSignatura.S_DadesSignatari.TipusIdentificacio.rawValue = null;
			oSignatura.S_DadesSignatari.Identificacio.rawValue = null;
		}
	}catch(e){
		console.println("error:prepararDadesSignatura:" + e);		
	}
}

