function attachXMLDades()
{
	try{
		var strXML = xfa.data.ACTAINSPECCIO.saveXML();
		strXML = strXML.replace(/&lt;\?xml[^&gt;]*&gt;/gi,"");			// Quitamos la referencia a xml version...

		event.target.createDataObject("dades.xml", "");	

		// Force UTF-8 conversion
		var streamXMLUTF8 = util.streamFromString(strXML,"utf-8");
		var strXMLUTF8 = util.stringFromStream(streamXMLUTF8,"utf-8");

		// Parse back into an XML document
		var xmlXFAData = XMLData.parse(strXMLUTF8, false);
		var oNodeActeInepeccio = xmlXFAData.nodes.item(0);
		var oNodes = oNodeActeInepeccio.nodes;
		var numTotalNodes = oNodes.length;
		for(var i=numTotalNodes-1;i>-1;i--){
			var oNode = oNodes.item(i);
			if (oNode.name == "Formulari"){
				eliminarSignaturaNoUtilitzada(oNode);
			}
			if (oNode.name == "Signatures" || oNode.name == "NumSignaturesInspector" || oNode.name == "NumSignaturesCompareixent"){
				eliminarNodeXml(oNode);
			}
		}
		strXFAData = xmlXFAData.saveXML();
		strXFAData = strXFAData.replace(/<xfa:data[^>]*>/gi,"");  /// <xfa:data xmlns:xfa="http://www.xfa.org/schema/xfa-data/1.0/">
		strXFAData = strXFAData.replace(/<\/xfa:data[^>]*>/gi,"");  /// </xfa:data>
		strXFAData = strXFAData.replace(/xfa:contentType/gi,"contenType");  /// El tag xfa de contentType de les imatges dona problemes a la peça intermitja quan valida l'XML
		var streamXFAData = util.streamFromString(strXFAData,"utf-8");
		event.target.setDataObjectContents("dades.xml", streamXFAData);
	}catch(e){
		console.println("error:attachXMLDades:" + e);
	}	
}

function eliminarNodeXml(oNode){
	try{
		//console.println("- eliminarNodeXml - " + oNode.name + " <--- " + oNode.parent.name);
		oNode.parent.nodes.remove(oNode);
	}catch(e){
		console.println("error:eliminarNodeXml:" + e);
	}
}

function eliminarSignaturaNoUtilitzada(oNode){
	try{
		var oSignatures = oNode.nodes.item(0);
		var oNodesSign = oSignatures.nodes;
		var numSignatures = oNodesSign.length;	
		for(var i=numSignatures-1;i>-1;i--){
			var eliminarSignatura = false;
			var oNode = oNodesSign.item(i);
			var oNodes2 = oNode.nodes;
			for(var j=0;j<oNodes2.length;j++){
				var o = oNodes2.item(j);				
				if (o.name == "origen" && (o.value == null || o.value == "")){
					eliminarSignatura = true;
				}
			}

			if (eliminarSignatura == true){
				eliminarNodeXml(oNode);
			}
			eliminarSignatura = false;			
		}
	}catch(e){
		console.println("error:eliminarSignaturaNoUsada:" + e);
	}
}

