/////////////////////////////////////////////////////////////////////////////
// Nom: validarFormulari
// Descripció: 
/////////////////////////////////////////////////////////////////////////////
function validarFormulari()
{
	scoINSPSignatures.prepararDadesSignatura();

	if (scoGSITVal.validarClausulaLOPD())
	{
		var errArray = new Array();

		// Validacions globals
		scoOGEValidacio.validarFormulari(errArray);		

		if (scoGSITVal.isFormulariValidat())	{
			scoINSPQuestions.setRespostaQuestions();
			scoINSPVal.copiarDadesLOPD();	
			scoINSPVal.copiarDadesConsentiment();
			scoINSPImatges.tancaImatgeZoom();
			scoINSPVisualitzacio.bloquejaRBMode(true);
		}
	}
}

/////////////////////////////////////////////////////////////////////////////
// Nom: inicialitzarFormulari
// Descripció: Mètode que es crida al inicialitzar-se el formulari
/////////////////////////////////////////////////////////////////////////////
function inicialitzarFormulari() 
{
	scoGSITVal.inicialitzarFormulari();

	// Inicialitzar firma Inspector
	scoINSPIdentificacio.defFirmaInspector();

	// Inicialitzar panell identificació inspector i de l'organisme
	scoINSPIdentificacio.defPanellDadesInspector();

	// Inicialitzar panell notificacions múltiples
	// 202012		Estem inicialitzant al subformulari		scoOGENotificacions.initPanellNotifMultiple();

	// Inicialitzar panell motius
	scoINSPMotius.initPanellMotius();

	// Inicialitzar panell qüestions
	scoINSPQuestions.initPanellQuestions();

	// Inicialitzar panell dades de contacte
	scoINSPDC.iniPanellDadesContacte();

	// Inicialitzar panell conformitats
	scoINSPConformitats.initPanellConformitats();

	// Inicialitzar panell imatges
	scoINSPImatges.tancaImatgeZoom();		// No té vinculació a cap camp --> deixa de mostrar-se al guardar

	if (scoGSITVal.isFormulariAcusament())			scoOGEValidacio.ocultaObjectesACK();
}

