///////////////////////////////////////////////////////////////////////
//Nom : copiarMesuresSignatures
//Descripció: Copiar del panell corresponent a les dades del xml les dades de mesures de les signatures
//////////////////////////////////////////////////////////////////////
function copiarMesuresSignatures()
{
	comprovaCreaNodeSignatures();
}


///////////////////////////////////////////////////////////////////////
//Nom : assignaMesuresSignatura
//Descripció: Assigna al node del xml els valors de signatura
//////////////////////////////////////////////////////////////////////
function assignaMesuresSignatura(oSignatura, oXMLNodeSignatura)
{
	if (!scoGSITVal.existeixObjete(oSignatura) || !scoGSITVal.existeixObjecte(oXMLNodeSignatura))		return;

	var oNodeMesures = oXMLNodeSignatura.InfoPDF.Mesures;

	oNodeMesures.X.value = oSignatura.x.rawValue;	
	oNodeMesures.Y.value = oSignatura.y.rawValue;
	oNodeMesures.Height.value = oSignatura.Height.rawValue;
	oNodeMesures.Width.value = oSignatura.Width.rawValue;
	oNodeMesures.Pagina.value = oSignatura.Pagina.rawValue;
}

///////////////////////////////////////////////////////////////////////
//Nom : comprovaCreaNodeSignatures
//Descripció: Comprova si existeix el node de signatures, si no existeix el creem
//////////////////////////////////////////////////////////////////////
function comprovaCreaNodeSignatures()
{
	var oNodoSignatures = xfa.resolveNode(scoINSPPar.sRutaNodeXMLSignatura);
	if (!scoGSITVal.existeixObjecte(oNodoSignatures)) {
		var oNode = xfa.datasets.createNode("dataGroup", "Formulari");
		xfa.record.nodes.append(oNode);
	}
}


///////////////////////////////////////////////////////////////////////
// Nom : hiHaItemsATaula
// Descripció: Mètode que comprova si a una taula hi ha items
// Paràmetres d'entrada:
//		oPanell - panell principal que conté la taula
//		sSubTaula - nom del subformulari que conté els items 0...infinit
//		sItem - nom del subform que es repeteix
//////////////////////////////////////////////////////////////////////
function hiHaItemsATaula(oPanell, sSubTaula, sItem)
{
	if (scoGSITVal.isFormulariValidat()) return;

	// El node és opcional --> pot no existir l'objecte
	if (!scoGSITVal.existeixObjecte(oPanell))			return false;

	var oTaula = oPanell.resolveNode(sSubTaula);
	if (!scoGSITVal.existeixObjecte(oTaula))			return false;

	var oItems = oTaula.resolveNodes(sItem + "[*]");
	if (oItems == null || oItems == undefined)		return false;
	return (oItems.length > 0);
}               


/////////////////////////////////////////////////////////////////////////////
// Nom: validarPlanaRequeridor
// Descripció:
/////////////////////////////////////////////////////////////////////////////
function validarPlanaRequeridor()
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		var aResults = new Array();	
		var oPanellLlocInspeccionat = scoINSPEstabliment.getPanellEstabliment(scoINSPVisualitzacio.getModeVisualitzacio());
		aResults[0] = scoOGEAdreca.validaIntentNormalitzarAdreca(scoGSITPanells.obtenirObjecteFill(oPanellLlocInspeccionat, "ADRECA_CAT_LLOGARET"), 
																 scoGSITPanells.obtenirObjecteFill(oPanellLlocInspeccionat, "NORMALITZADOR"), 
																 msgNormalitzacioEstabliment.value);

		return scoOGEVal.validacioConjunta(aResults);																											
	}
	catch(exc) 
	{
		return scoGSITGen.retornarExcepcio("scoOGEVal.validarPlanaRequeridor",exc);
	}
}

/////////////////////////////////////////////////////////////////////////////
// Nom: validarPlanaContacteAvisos
// Descripció:
/////////////////////////////////////////////////////////////////////////////
function validarPlanaContacteAvisos()
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		var aResults = new Array();		
		// 202006		Canviem la forma de mostrar el resultat de validació dels MULTISELECT (fem que sigui similar a la resta de camps)		aResults[0] = scoINSPQuestions.validaQuestionsMultiseleccio();
		var oPanellAvisos = scoINSPDC.getPanellDadesContacte(scoINSPVisualitzacio.getModeVisualitzacio());
		aResults[0] = scoOGEDC.validarInfoContacteSeccio(oPanellAvisos, msgContacte.value + "\n");
		aResults[1] = scoINSPImatges.validarImatges(msgValidacioImatges.value);

		return scoOGEVal.validacioConjunta(aResults);																											
	}
	catch(exc) 
	{
		return scoGSITGen.retornarExcepcio("scoOGEVal.validarPlanaRequeridor",exc);
	}
}

