/////////////////////////////////////////////////////////////////////////////
// Nom: copiarDadesLOPD
// Descripció: Copia les dades de la LOPD als camps ACK
/////////////////////////////////////////////////////////////////////////////
function copiarDadesLOPD()
{
	var oTitol = scoGSITPanells.obtenirObjecteFill(scoGSITPar.oPanellLOPD, "LOPD_TITOL");
	var oTitolACK = scoGSITPanells.obtenirObjecteFill(scoGSITPar.oPanellLOPD, "LOPD_TITOL_ACK");
	if (scoGSITVal.existeixObjecte(oTitol) && scoGSITVal.existeixObjecte(oTitolACK))			oTitolACK.rawValue = oTitol.rawValue;

	var oText = scoGSITPanells.obtenirObjecteFill(scoGSITPar.oPanellLOPD, "LOPD_TEXT");
	var oTextACK = scoGSITPanells.obtenirObjecteFill(scoGSITPar.oPanellLOPD, "LOPD_TEXT_ACK");
	if (scoGSITVal.existeixObjecte(oText) && scoGSITVal.existeixObjecte(oTextACK))			oTextACK.rawValue = oText.rawValue;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: copiarDadesConsentiment
// Descripció: Copia les dades del CONSENTIMENT als camps ACK
/////////////////////////////////////////////////////////////////////////////
function copiarDadesConsentiment()
{
	var oText = scoGSITPar.oPanellConsentiment.sTEXT_CONFIRMACIO_BIO.CONFIRMACIO_TEXT;
	var oTextACK = scoGSITPar.oPanellConsentiment.sTEXT_CONFIRMACIO_BIO.CONFIRMACIO_TEXT_ACK;
	if (scoGSITVal.existeixObjecte(oText) && scoGSITVal.existeixObjecte(oTextACK))			oTextACK.rawValue = oText.rawValue;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: setInfoSignatura
// Descripció: Assigna propietats per cadascuna de les signatures (11/2019)
/////////////////////////////////////////////////////////////////////////////
function setInfoSignatura(oPanell, origen, esBiometrica)
{
	if (scoGSITVal.isFormulariAcusament())			return;

	if (!scoGSITVal.existeixObjecte(oPanell))			return;

	if (origen != "") 
	{
		var oOrigen = scoGSITPanells.obtenirObjecteFill(oPanell, "OrigenSignatura");
		if (scoGSITVal.existeixObjecte(oOrigen))		oOrigen.rawValue = origen;
	}

	if (esBiometrica != "")
	{
		var oTipus = scoGSITPanells.obtenirObjecteFill(oPanell, "TipusSignatura");
		if (scoGSITVal.existeixObjecte(oTipus))		oTipus.rawValue = esBiometrica;
	}
}


/////////////////////////////////////////////////////////////////////////////
// Nom: inicialitzaCheckLOPD
// Descripció: Inicialitza el check de validació de la protecció de dades.
//				Si no precarrega text a la LOPD el fem no visible
/////////////////////////////////////////////////////////////////////////////
function inicialitzaCheckLOPD(oCheck, oPanellLOPD)
{
	if (scoGSITVal.isFormulariValidat())  		return;
	if (scoGSITVal.esFormulariGuardat())			return;

	if (!oCheck)	return;	
	var oTextLOPD = scoGSITPanells.obtenirObjecteFill(oPanellLOPD, "LOPD_TEXT");
	var bMostrar = !(scoGSITVal.isEmpty(oTextLOPD));
	if (!scoGSITVal.isFormulariAcusament())		scoGSITCamps.assignarCampObligatori(oCheck, bMostrar);
	oCheck.presence = (bMostrar)?"visible":"invisible";
}


function hiHaLOPD()
{
	var oTextLOPD = scoGSITPanells.obtenirObjecteFill(scoGSITPar.oPanellLOPD, "LOPD_TEXT");
	return (!(scoGSITVal.isEmpty(oTextLOPD)));
}

/////////////////////////////////////////////////////////////////////////////
// Nom: ocultaObjectesACK
// Descripció: Oculta blocs particulars
/////////////////////////////////////////////////////////////////////////////
function ocultaObjectesACK()
{
	// Oculta normalitzador
	var oNormalitzador = scoGSITPanells.obtenirObjecteFill(scoGSITPar.oPanellLlocInspeccionat, "NORMALITZADOR");
	if (scoGSITVal.existeixObjecte(oNormalitzador))			oNormalitzador.presence = "invisible";
}

/////////////////////////////////////////////////////////////////////////////
// Nom: sortIRemoveDuplicates
// Descripció: Ordena i elimina duplicats
/////////////////////////////////////////////////////////////////////////////
function sortIRemoveDuplicates(aOrigen) {
// console.println(aOrigen);
    aOrigen.sort();
    var i = 0;

    while(i < aOrigen.length) {
        if(aOrigen[i] === aOrigen[i+1]) {
            aOrigen.splice(i+1,1);
        }
        else {
            i += 1;
        }
    }
    return aOrigen;
}

