///////////////////////////////////////////////////////////////////////
// Nom : initMode
// Descripció: Mètode que canvia el mode de visualització
//////////////////////////////////////////////////////////////////////
function initMode(oTxtMode) 
{
	if (scoGSITVal.isFormulariValidat())			return;
	if (scoGSITVal.esFormulariGuardat())		return;
	if (scoGSITVal.isFormulariAcusament())		return;

	if (estaInicialitzat())					return;

	// Inicialitzem en mode tableta
	oTxtMode.rawValue = CT_MODE_INIT;

	canviaMode(oTxtMode.rawValue, null, true);
	setInicialitzat();
}


///////////////////////////////////////////////////////////////////////
// Nom : initModeACK
// Descripció: 
//////////////////////////////////////////////////////////////////////
function initModeACK()
{
	canviaMode(CT_INDEX_STD, null, true);
}

///////////////////////////////////////////////////////////////////////
// Nom : canviaMode
// Descripció: Mètode que canvia el mode de visualització
//////////////////////////////////////////////////////////////////////
function canviaMode(value, numPage, bInit) 
{
	if (arguments.length < 3)	bInit = false;
	// if (scoGSITVal.isFormulariValidat() && !scoGSITVal.isFormulariAcusament())			return;		// Fem el canvi abans de tancar!! amb el formulari validat!!

	var nModeActual = getModeVisualitzacio();
	if (!bInit &&  nModeActual == value)		return;		// Si ens demanen canviar al mode en que ja estem, NO cal fer res

	var oCampFocus = getCampFocusVisualitzacio(numPage);

	setModeVisualitzacio(value);	

	// Accions a realitzar quan canviem de mode de visualització (NO inici)
	if (!bInit)
	{
		defineixFontSizeTitol(value);
	}


	mostraOcultaSubforms(value, true);
	mostraOcultaSubforms((value == CT_INDEX_TBLT)?CT_INDEX_STD:CT_INDEX_TBLT, false);	

	// Mostrar/ocultar notificacions -> no sempre està visible

	// Panell d'establiment
	scoINSPEstabliment.defineixEstablimentVisualitzacio();

	// Panell de motius
	scoINSPMotius.defineixMotiusVisualitzacio();

	// Panell de qüestions
	scoINSPQuestions.defineixQuestionsVisualitzacio();

	// Panell resolució acta
	scoINSPQuestions.defineixResolucioVisualitzacio();	

	// Panell imatges
	scoINSPImatges.defineixImatgesVisualitzacio();

	// Panell conformitats
	scoINSPConformitats.initPanellConformitats();

	// Panell d'adjunts
	scoINSPAdjunts.defineixAdjuntsVisualitzacio();

	if (!scoGSITVal.isFormulariAcusament())
	{
		if (oCampFocus != null)		xfa.host.setFocus(getRutaDesti(oCampFocus.somExpression, nModeActual, value));
	}
}


///////////////////////////////////////////////////////////////////////
// Nom : getRutaDesti
// Descripció: 
//////////////////////////////////////////////////////////////////////
function getRutaDesti(sRutaOrigen, indexOrigen, indexDesti)
{
	if (sRutaOrigen == null)		return;

	var bTrobat = false;
	var i = 0;
	while (!bTrobat && i < aSubFormsInstancia.length)
	{
		bTrobat = (sRutaOrigen.indexOf(aSubFormsInstancia[i]) != -1);
		if (!bTrobat)	i++;
	}

	if (bTrobat)		return sRutaOrigen.replace(aSubFormsInstancia[i] + "[" + indexOrigen + "]", aSubFormsInstancia[i] + "[" + indexDesti + "]");
	return sRutaOrigen;
}

///////////////////////////////////////////////////////////////////////
// Nom : getCampFocusVisualitzacio
// Descripció: 
//////////////////////////////////////////////////////////////////////
function getCampFocusVisualitzacio(numPage)
{	
	if (numPage == null)		return null;

	var oCampsPagina = xfa.layout.pageContent(numPage - 1, "field");
	if (oCampsPagina == null || oCampsPagina == undefined)	return;

	var bVisible = false;
	var i = 0;
	var oCamp = null;
	while (i < oCampsPagina.length && !bVisible)
	{
		oCamp = oCampsPagina.item(i);
		if (scoGSITVal.existeixObjecte(oCamp) && oCamp.presence == "visible")
		{
			bVisible = true;
		}
		i++;
	}

	if (bVisible)	return oCamp;
	return null;
}

///////////////////////////////////////////////////////////////////////
// Nom : mostraOcultaSubforms
// Descripció: 
//////////////////////////////////////////////////////////////////////
function mostraOcultaSubforms(index, bMostra)
{
	for (var t = 0; t < aSubVisualitzacio.length; t++)
	{
		var sRuta = aSubVisualitzacio[t].replace("##INDEX##", index.toString());
		var oSubs = xfa.resolveNodes(sRuta);
		for (var r = 0; r < oSubs.length; r++)
		{
			var oSub = oSubs.item(r);
			oSub.presence = (bMostra)?"visible":"hidden";
		}
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : getObjDesti
// Descripció: 
//////////////////////////////////////////////////////////////////////
function getObjDesti(oObjOrigen, sSubPrincipal, indexOrigen, indexDesti)
{
	if (!scoGSITVal.existeixObjecte(oObjOrigen))		return;

	var sSomExpOrigen = oObjOrigen.somExpression;

	var sSomExpDesti = sSomExpOrigen.replace(sSubPrincipal + "[" + indexOrigen.toString() + "]" , sSubPrincipal + "[" + indexDesti.toString() + "]");
	return xfa.resolveNode(sSomExpDesti);
}

///////////////////////////////////////////////////////////////////////
// Nom : copiaOrigenADesti
// Descripció: 
//////////////////////////////////////////////////////////////////////
function copiaValor(oCamp, sSubInstancia, indexOrigen, indexDesti)
{
	if (scoGSITVal.isFormulariValidat())			return;

	var oCampDesti = getObjDesti(oCamp, sSubInstancia, indexOrigen, indexDesti);
	if (!scoGSITVal.existeixObjecte(oCampDesti ))			return;

	oCampDesti .rawValue = oCamp.rawValue;
}

///////////////////////////////////////////////////////////////////////
// Nom : copiaCampsValor
// Descripció: 
//////////////////////////////////////////////////////////////////////
function copiaCampsValor(aCamps, sSubInstancia, indexOrigen, indexDesti)
{
	for (var n=0;n<aCamps.length;n++)
	{
		copiaValor(aCamps[n], sSubInstancia, indexOrigen, indexDesti);
	}
}


///////////////////////////////////////////////////////////////////////
// Nom : copiaPropietatsOrigenADesti
// Descripció: 
//////////////////////////////////////////////////////////////////////
function copiaPropietats(oCamp, sSubInstancia, indexOrigen, indexDesti)
{
	if (scoGSITVal.isFormulariValidat())			return;

	var oCampDesti = getObjDesti(oCamp, sSubInstancia, indexOrigen, indexDesti);
	if (!scoGSITVal.existeixObjecte(oCampDesti))			return;

	oCampDesti.presence = oCamp.presence;

	if ( oCamp.resolveNode("ui.#button") != null ) {	// IS BUTTON
		scoGSITBot.copiarEstatBoto(oCamp, oCampDesti);
	}
	else {
		oCampDesti.access = oCamp.access;
		oCampDesti.validate.nullTest = oCamp.validate.nullTest;
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : copiaCampsPropietats
// Descripció: 
//////////////////////////////////////////////////////////////////////
function copiaCampsPropietats(aCamps, sSubInstancia, indexOrigen, indexDesti)
{
	for (var n=0;n<aCamps.length;n++)
	{
		copiaPropietats(aCamps[n], sSubInstancia, indexOrigen, indexDesti);
	}
}

