////////////////////////////////////////////////////////////
// Nom: defineixFontSizeTitol
// Descripció:  
////////////////////////////////////////////////////////////
function defineixFontSizeTitol(modeVisualitzacio)
{
    try
    {   
   		var size = ((modeVisualitzacio == CT_INDEX_TBLT)?defSizeTitol.CT_FONTSIZE_TBLT:defSizeTitol.CT_FONTSIZE_STD);

        if (scoGSITPar.arrayTitols != null)
        {
            for(var i=0; i < scoGSITPar.arrayTitols.length; i++)
            {       
                var oTitols = xfa.resolveNodes(scoGSITPar.arrayTitols[i]);
                if (oTitols != null)
                {
                    for(var j=0; j<oTitols.length;j++)
                    {
                    	var oTitol = oTitols.item(j);
                    	if (oTitol)		
                    	{
                    		oTitol.font.size = size;
                    	}
                    }           
                }                   
            }
        }
    }   
    catch(exc)
    {
        scoGSITGen.retornarExcepcio("scoINSPVisualitzacio::defineixFontSizeTitol", exc);
    }
}


