{
	if (!scoGSITVal.existeixObjecte(oLblTitol))		return;

	var size = (esModeTableta()?defSizeTitol.CT_FONTSIZE_TBLT:defSizeTitol.CT_FONTSIZE_STD);
	oLblTitol.font.size = size;
}


////////////////////////////////////////////////////////////
// Nom: accionsRBModeVisualitzacio
// Descripció:  
////////////////////////////////////////////////////////////
function accionsRBModeVisualitzacio(accio, param)
{
    try
    {   
        if (scoGSITPar.arrayBtnMode == null)		return;

        for(var i=0; i < scoGSITPar.arrayBtnMode.length; i++)
        {       
        		var oBtns = xfa.resolveNodes(scoGSITPar.arrayBtnMode[i]);
        		if (oBtns != null)
            {
            		for(var j=0; j<oBtns.length;j++)
                {
                		var oBtnMode = oBtns.item(j);
                		if (oBtnMode)	accio(oBtnMode, param);
                }                   
            }
        }
    }   
    catch(exc)
    {
        scoGSITGen.retornarExcepcio("scoINSPVisualitzacio::accionsRBModeVisualitzacio", exc);
    }
}

