/***************************************************************
 Nom: scoGSITAdj
 Descripció: Creat a partir de l'sco del FW 2.4.8 - Conté els mètodes necessaris per fer el tractament dels fitxers adjunts.
**************************************************************************/

var CT_PREFIX_ID_ADJUNT = "ACTAINSPECCIO_";

////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
// MÈTODES
////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

////////////////////////////////////////////////////////////
// Nom: accioAdjuntar
// Descripció: Mètode que realitza l'acció d'adjuntar fitxer
// Paràmetres d'entrada: 
////////////////////////////////////////////////////////////
function accioAdjuntar()
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		if (adjuntarFitxer() == 1) {
			if (!scoGSITVal.validarMidaPDF())  app.alert(scoGSITVal.getMsgErrorMidaMaxAdjuntsPDF());
			xfa.layout.relayout(); // Nomès repinta si ha afegit l'Adj
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdj.accioAdjuntar", exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: accioEliminar
// Descripció: Mètode que realitza l'acció d'eliminar fitxer
// Paràmetres d'entrada: 
//		oSubfAdjunt - Panell de l'adjunt
////////////////////////////////////////////////////////////
function accioEliminar(oSubfAdjunt)
{
	try
	{
		if (scoGSITVal.isFormulariAcusament())	return;
		if (scoGSITVal.isFormulariValidat()) return;
		if (!scoGSITVal.existeixObjecte(oSubfAdjunt)) return;

		if (xfa.host.messageBox(msgPreguntaEliminarAdjunt.value, "", 2, 1) != 1) return;		

		if (treureFitxer(oSubfAdjunt) == 1) {
			xfa.layout.relayout(); // Nomès repinta si ha tret l'Adj
		}
	}
	catch(exc) 
	{
		scoGSITGen.retornarExcepcio("scoGSITAdj.accioEliminar", exc);	
	}
}

////////////////////////////////////////////////////////////
// Nom: accioVeure	
// Descripció: Mètode que realitza l'acció de veure el fitxer
// Paràmetres d'entrada: 
//		oSubfAdjunt - Panell de l'adjunt
////////////////////////////////////////////////////////////
function accioVeure(oSubfAdjunt)
{
	try
	{
		// Mira si l'adjunt existeix (que no s'hagi eliminat amb l'assistent del Reader)	
		var oFitxersAdjuntsReader = event.target.dataObjects; 
		var iNumAdjReader = (scoGSITVal.existeixObjecte(oFitxersAdjuntsReader)) ? oFitxersAdjuntsReader.length : 0;
		var bInReader = isAdjuntReader(oSubfAdjunt, oFitxersAdjuntsReader, iNumAdjReader); 
		if (!bInReader)
		{
			xfa.host.messageBox(msgErrorVeureFitxerTretReader.value);
			return;
		}

		// Mira si l'adjunt esta definit al panell
		var bPle = (!scoGSITVal.isEmpty(getNomPDFAdjunt(oSubfAdjunt)));			
		if (bPle) event.target.exportDataObject({ cName: getIDAdjunt(oSubfAdjunt), nLaunch: 2 });
	}
	catch(exc) 
	{
		if (msgPermisosAdjunts)
			xfa.host.messageBox(msgPermisosAdjunts.value);
		else
			scoGSITGen.retornarExcepcio("scoGSITAdj.accioVeure", exc);	
	}
}

