		scoGSITGen.retornarExcepcio("scoGSITAdj.afegirSubfAdjunt", exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: esborrarSubfAdjunt
// Descripció: Mètode que esborra la instància indicada
// Paràmetres d'entrada: 
////////////////////////////////////////////////////////////
function esborrarSubfAdjunt(oSubfAdjunt)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

