////////////////////////////////////////////////////////////
// Nom: getNextIDAdjunt
// Descripció: Mètode que retorna el ID del següent adjunt a crear
// Paràmetres d'entrada: 
// Paràmetres de sortida:
////////////////////////////////////////////////////////////
function getNextIDAdjunt()
{
	try {

		if (!scoGSITVal.existeixObjecte(scoGSITPar.oPanellAdjunts))			return;

		var oTxtNextId = scoGSITPar.oPanellAdjunts.resolveNode("SUB_CAPCALERA[0].NEXT_ID[0]");
		var nNextId = (scoGSITVal.isEmpty(oTxtNextId))?0:oTxtNextId.rawValue;

		var sZeros = "00000";		
		return (CT_PREFIX_ID_ADJUNT + sZeros.substring(0, 5-(nNextId.toString()).length) + nNextId.toString());
	} 
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoGSITAdj.getNextIDAdjunt()",exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: updateNextIDAdjunt
// Descripció: Mètode que actualitza el valor del camp que conté el següent IDAdjunt
// Paràmetres d'entrada: 
// Paràmetres de sortida:
////////////////////////////////////////////////////////////
function updateNextIDAdjunt()
{
	try {
		if (!scoGSITVal.existeixObjecte(scoGSITPar.oPanellAdjunts))			return;

		var oTxtNextId = scoGSITPar.oPanellAdjunts.resolveNode("SUB_CAPCALERA[0].NEXT_ID[0]");
		var nNextId = (scoGSITVal.isEmpty(oTxtNextId))?0:oTxtNextId.rawValue;
		oTxtNextId.rawValue = nNextId + 1;
	} 
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoGSITAdj.updateNextIDAdjunt()",exc);
	}
}


////////////////////////////////////////////////////////////
// Nom: getIDAdjunt
// Descripció: Mètode que retorna el ID de l'adjunt del panell 'oAdjuntSubform'.
// Paràmetres d'entrada: 
//		oAdjuntSubform - Panell de l'adjunt
// Paràmetres de sortida:
//		string - Identificador del fitxer adjunt en el cas que existeixi, o "" en cas contrari.
////////////////////////////////////////////////////////////
function getIDAdjunt(oAdjuntSubform)
{
	if (!scoGSITVal.existeixObjecte(oAdjuntSubform)) return "";
	return (scoGSITVal.isEmpty(oAdjuntSubform.TXT_ROL.rawValue)) ? "" : oAdjuntSubform.TXT_ROL.rawValue;
}

////////////////////////////////////////////////////////////
// Nom: getNomAdjunt
// Descripció: Mètode que retorna el nom de l'adjunt del panell 'oAdjuntSubform'
// Paràmetres d'entrada: 
//		oAdjuntSubform - Panell de l'adjunt
// Paràmetres de sortida:
//		string - Nom del fitxer adjunt en el cas que existeixi, o "" en cas contrari.
////////////////////////////////////////////////////////////
function getNomAdjunt(oAdjuntSubform)
{
	if (!scoGSITVal.existeixObjecte(oAdjuntSubform)) return "";
	return (scoGSITVal.isEmpty(oAdjuntSubform.TXT_NOM_FITXER.rawValue)) ? "" : oAdjuntSubform.TXT_NOM_FITXER.rawValue;
}

////////////////////////////////////////////////////////////
// Nom: getNomPDFAdjunt
// Descripció: Mètode que retorna el nom del PDF adjunt del panell 'oAdjuntSubform'
// Paràmetres d'entrada: 
//		oAdjuntSubform - Panell de l'adjunt
// Paràmetres de sortida:
//		string - Nom del fitxer PDF adjunt en el cas que existeixi, o "" en cas contrari.
////////////////////////////////////////////////////////////
function getNomPDFAdjunt(oAdjuntSubform)
{
	if (!scoGSITVal.existeixObjecte(oAdjuntSubform)) return "";
	return (scoGSITVal.isEmpty(oAdjuntSubform.TXT_NOM_FITXER.rawValue)) ? "" : oAdjuntSubform.TXT_NOM_FITXER.rawValue;
}

////////////////////////////////////////////////////////////
// Nom: defInfoAdjunt
// Descripció:  Mètode que defineix la informació de l'adjunt del panell 'oAdjuntSubform'
// Paràmetres d'entrada: 
//		oAdjuntSubform - Panell de l'adjunt
//		nouAdjunt - Objecte de tipus adjunt que s'ha afegit
////////////////////////////////////////////////////////////
function defInfoAdjunt(oAdjuntSubform, nouAdjunt, idNouAdjunt)
{
	if (!scoGSITVal.existeixObjecte(oAdjuntSubform))			return;

	oAdjuntSubform.TXT_ROL.rawValue = idNouAdjunt;
	oAdjuntSubform.TXT_NOM_FITXER.rawValue = nouAdjunt.path;
	oAdjuntSubform.TXT_DATAC_FITXER.rawValue = String(nouAdjunt.creationDate);
	oAdjuntSubform.TXT_DATAM_FITXER.rawValue = String(nouAdjunt.modDate);
	oAdjuntSubform.TXT_MIDA_FITXER.rawValue = nouAdjunt.size;

}

////////////////////////////////////////////////////////////
// Nom: borraDescAdjunt
// Descripció: Mètode que esborra tota la informació de l'adjunt del panell 'oAdjuntSubform'
// Paràmetres d'entrada: 
//		oAdjuntSubform - Panell de l'adjunt
////////////////////////////////////////////////////////////
function borraInfoAdjunt(oAdjuntSubform)
{
	if (!scoGSITVal.existeixObjecte(oAdjuntSubform))			return;

	oAdjuntSubform.TXT_ROL.rawValue = "";
 	oAdjuntSubform.TXT_NOM_FITXER.rawValue = "";
	oAdjuntSubform.TXT_DATAC_FITXER.rawValue = "";
	oAdjuntSubform.TXT_DATAM_FITXER.rawValue = "";
	oAdjuntSubform.TXT_MIDA_FITXER.rawValue = "";
}

////////////////////////////////////////////////////////////
// Nom: compLongNom
// Descripció: Mètode que verifica la longitud del nom de l'adjunt
// Paràmetres d'entrada: 
//		nouAdjunt - Objecte de tipus adjunt que s'ha afegit
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si la longitud del nom és correcta.
////////////////////////////////////////////////////////////
function compLongNom(nouAdjunt)
{
	return (nouAdjunt.path.length < 100);
}


////////////////////////////////////////////////////////////
// Nom: compCaractersNom
// Descripció: Mètode que verifica els caràcters del nom de l'adjunt (string)
// Paràmetres d'entrada: 
//		nouAdjunt - Objecte de tipus adjunt que s'ha afegit
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si els caràcters del nom són correctes.
////////////////////////////////////////////////////////////
function compCaractersNom(nouAdjunt)
{
	var arrNom = nouAdjunt.path.split(".");
	var sNom = arrNom[0];

    var r = new RegExp("^[0-9a-zA-ZàáèéíòóúÀÁÈÉÍÒÓÚäëïöüÄËÏÖÜñÑªºçÇ·'_\\-]+$"); 
    return r.test(sNom);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: adjuntarFitxer
// Descripció: Mètode que donat el panell on s'ha creat el mòdul d'adjuntar fitxers, en mostra el diàleg d'examinar arxius i s'importa l'arxiu seleccionat dins del document.
// Paràmetres d'entrada: 
// Paràmetres de sortida:
//		 1 - En cas que tot hagi anat bé.
//		 2 - Si s'ha cancel·lat l'adjunció.
//		-1 - En cas que s'hagi produït alguna excepció.
//		-2 - Si s'ha produït algun error a l'hora d'adjuntar.
///////////////////////////////////////////////////////////////////////////// 
function adjuntarFitxer()
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;	

		var oDocument = event.target;
		var idAdjunt = getNextIDAdjunt();
		var oAdjunts;
		var nouAdjunt;
		var errCode;

		if(scoGSITVal.isEmpty(idAdjunt))
		{
			xfa.host.messageBox(msgErrorAdjuntarFitxerNoAdjunt.value);
			return -2;
		}
		var numAdjAbans = numAdjuntsReader();
		errCode = oDocument.importDataObject(idAdjunt); //obre diàleg a l'usuari per escollir fitxer
		if(errCode != true)  return 2; //si s'ha cancelat el diàleg d'adjuntar
		var numAdjDespres = numAdjuntsReader();

		if (numAdjDespres <= numAdjAbans) {
			xfa.host.messageBox(msgErrorAdjunt.value);
			return -1;
		}

		oAdjunts = oDocument.dataObjects;
		if(oAdjunts.length < 1) {
			xfa.host.messageBox(msgErrorAdjuntarFitxerNoAdjuntat.value);
			return -2;
		}

		nouAdjunt = oDocument.getDataObject(idAdjunt);
		if(nouAdjunt == null) {
			xfa.host.messageBox(msgErrorAdjuntarFitxerNoTrobat.value);
			return -2;
		}

		var errorMsg = ""; 
		if (existeixAdjuntNomIgual(nouAdjunt))
			errorMsg = msgAdjuntRepetit.value + ".\n\n";	

		if (!compLongNom(nouAdjunt))
			errorMsg = msgAdjuntNomLongMax.value + ".\n\n";	

		if (!compCaractersNom(nouAdjunt))
			errorMsg += msgAdjuntNomCharError.value + ".\n\n";				

		if (scoGSITVal.isEmpty(errorMsg))
		{
			defInfoAdjunt(afegirSubfAdjunt(), nouAdjunt, idAdjunt);
			updateNextIDAdjunt();
		}
		else 
		{
			xfa.host.messageBox(errorMsg);
			treureFitxerReader(idAdjunt);
			return -1;
		}

		return 1;
	 }
	 catch(exc)
	 {
		return scoGSITGen.retornarExcepcio("scoGSITAdj.adjuntarFitxer()",exc);
	 }
}

////////////////////////////////////////////////////////////
// Nom: treureFitxer
// Descripció: Mètode que elimina el fitxer adjunt seleccionat.
// Paràmetres d'entrada: 
//		parSubformFitxer - Referència de l'objecte subformulari on es troben tots els objectes per a adjuntar fitxers.
// Paràmetres de sortida: 	
//		 1 - En cas que tot hagi anat bé.
//		 2 - Si s'ha cancel·lat l'adjunció.
//		-1 - En cas que s'hagi produït alguna excepció.
//		-2 - Si s'ha produït algun error a l'hora d'adjuntar.
////////////////////////////////////////////////////////////
function treureFitxer(oAdjuntSubform)
{
	if (scoGSITVal.isFormulariValidat()) return;
	if (scoGSITVal.isFormulariAcusament()) return;
	if (!scoGSITVal.existeixObjecte(oAdjuntSubform)) return;

	try{
		var idAdjunt = getIDAdjunt(oAdjuntSubform);
		if(scoGSITVal.isEmpty(idAdjunt))
		{
			xfa.host.messageBox(msgErrorTreureFitxerNoAdjunt.value);
			return -2;
		}

		treureFitxerReader(idAdjunt);
	 	borraInfoAdjunt(oAdjuntSubform);
	 	esborrarSubfAdjunt(oAdjuntSubform);
	 	return 1;
	}catch(exc) 
	{
		return scoGSITGen.retornarExcepcio("scoGSITAdj.treureFitxer()",exc);
 	}
}

////////////////////////////////////////////////////////////
// Nom: treureFitxerReader
// Descripció: Mètode que elimina del Reader el fitxer adjunt seleccionat.
// Paràmetres d'entrada: 
//		idAdjunt - Identificador de l'adjunt que cal esborrar
////////////////////////////////////////////////////////////
function treureFitxerReader(idAdjunt)
{
 	event.target.removeDataObject(idAdjunt);
}

///////////////////////////////////////////////////////////////////////////// 
// Nom: delAdjuntsReader
// Descripció: Mètode que elimina tots els adjunts del Reader que no estan registrats als panells d'adjunts
// Paràmetres d'entrada: 
//		oFitxersAdjuntsReader - Fitxers adjunts que té el Reader
//		iNumAdjReader - Número de fitxers adjunts que té el Reader
//		oFitxersAdjuntsSubform - Panell els adjunts
//		bAccioEsborrar - (true|false) Indica si cal esborrar realment l'adjunt (o només missatge)
///////////////////////////////////////////////////////////////////////////// 
function delAdjuntsReader(oFitxersAdjuntsReader, iNumAdjReader, oFitxersAdjuntsSubform, bAccioEsborrar)
{
	for(var i=0; i<iNumAdjReader; i++)
	{
		var sIdAdjunt = oFitxersAdjuntsReader[i].name;  
		var sNomAdjunt = oFitxersAdjuntsReader[i].path; 
		if (!cercaAdjuntSubform(sIdAdjunt, oFitxersAdjuntsSubform))
		{
			xfa.host.messageBox(msgErrorTreureFitxerAdjuntatReader.value + "\"" + sNomAdjunt + "\"", "", 3, 0);
			if (bAccioEsborrar) {
				treureFitxerReader(sIdAdjunt);
			}
		}
	}
}

///////////////////////////////////////////////////////////////////////////// 
// Nom: midaAdjunts
// Descripció: Mètode que retorna la mida de tots els adjunts del PDF
// Paràmetres de sortida: 
//		numero - Mida dels adjunts
///////////////////////////////////////////////////////////////////////////// 
function midaAdjunts()
{
	var nMida = 0;
   	var oFitxersAdjuntsReader = event.target.dataObjects; 
	var iNumAdjReader = (scoGSITVal.existeixObjecte(oFitxersAdjuntsReader)) ? oFitxersAdjuntsReader.length : 0;

	for(var i=0; i<iNumAdjReader; i++)
	{
		nMida += oFitxersAdjuntsReader[i].size / 1024;
	}	

	return nMida;
}

///////////////////////////////////////////////////////////////////////////// 
// Nom: isAdjuntReader
// Descripció: Mètode que indica si existeix l'adjunt en el Reader
// Paràmetres d'entrada: 
//		oAdjuntSubform - Panell de l'adjunt
//		oFitxersAdjuntsReader - Fitxers adjunts que té el Reader
//		iNumAdjReader - Número de fitxers adjunts que té el Reader
///////////////////////////////////////////////////////////////////////////// 
function isAdjuntReader(oAdjuntSubform, oFitxersAdjuntsReader, iNumAdjReader)
{
	var sIdAdjunt = getIDAdjunt(oAdjuntSubform);
	var sNomPDFAdjunt = getNomPDFAdjunt(oAdjuntSubform);

	var bTrobat = (sNomPDFAdjunt == ""); // Si no te nom no cal buscar
	var n=0;
	while(n<iNumAdjReader && !bTrobat)
	{
		bTrobat = (sIdAdjunt == oFitxersAdjuntsReader[n].name);
		n++;
	}

	return bTrobat;
}

////////////////////////////////////////////////////////////
// Nom: delAdjuntsNoReader
// Descripció: Mètode que elimina tots els adjunts del panell adjunts que no estan registrats al Reader 
// Paràmetres d'entrada: 
//		oFitxersAdjuntsSubform - Fitxers adjunts que té el panell
//		iNumAdjSubform - Número de fitxers adjunts que té el panell
//		oFitxersAdjuntsReader - Fitxers adjunts que té el Reader
//		iNumAdjReader - Número de fitxers adjunts que té el Reader
//		bAccioEsborrar - (true|false) Indica si cal esborrar realment l'adjunt (o només missatge)
///////////////////////////////////////////////////////////////////////////// 
function delAdjuntsNoReader(oFitxersAdjuntsSubform, iNumAdjSubform, oFitxersAdjuntsReader, iNumAdjReader, bAccioEsborrar)
{
	for (var i=0; i<iNumAdjSubform; i++)
	{
		// S'ha de netejar el registre de l'adjunt, que ja no està al formulari
		var oAdjuntSubform = oFitxersAdjuntsSubform.item(i);
		var bTrobat = isAdjuntReader(oAdjuntSubform, oFitxersAdjuntsReader, iNumAdjReader);
		if (!bTrobat)
		{
			if (bAccioEsborrar) {
				xfa.host.messageBox(msgErrorTreureFitxerTretReader.value + "\"" + getNomAdjunt(oAdjuntSubform) + "\"", "", 3, 0);		
				treureFitxer(oAdjuntSubform);
			}
			else {
				xfa.host.messageBox(msgAvisTreureFitxerTretReader.value + "\"" + getNomAdjunt(oAdjuntSubform) + "\"", "", 3, 0);	
			}
		}
	}
}

///////////////////////////////////////////////////////////////////////
// Nom: sincronitzarAdjunts
// Descripció: Mètode que valida que la informació dels adjunts sigui correcte.
// Paràmetres d'entrada: 
//		oSufAdjunts - Panell d'adjunts com a string o objecte
//		bAccioEsborrar - (opcional xdefecte true)		(true|false) Indica si cal esborrar realment l'adjunt (o només missatge)
// Paràmetres de sortida:
//		booleà - Valor (true/false) segons si la validació és correcte o no.
//////////////////////////////////////////////////////////////////////
function sincronitzarAdjunts(oFitxersAdjuntsSubform, bAccioEsborrar)
{
	if (arguments.length < 2)		bAccioEsborrar = true;
	if (typeof(oFitxersAdjuntsSubform) == "string") oFitxersAdjuntsSubform = xfa.resolveNode(oFitxersAdjuntsSubform);
	if (!scoGSITVal.existeixObjecte(oFitxersAdjuntsSubform)) return;

   	var oFitxersAdjuntsReader = event.target.dataObjects;    
	var oFitxersAdjuntsSubform = oFitxersAdjuntsSubform.resolveNodes("ADJUNT[*]");

	var iNumAdjSubform = (scoGSITVal.existeixObjecte(oFitxersAdjuntsSubform)) ? oFitxersAdjuntsSubform.length : 0;	
	var iNumAdjReader = (scoGSITVal.existeixObjecte(oFitxersAdjuntsReader)) ? oFitxersAdjuntsReader.length : 0;
    var	iNumAdjPlens = numeroAdjuntsPlensSubform(oFitxersAdjuntsSubform);

	// Elimina tots els adjunts del Reader que no estan registrats als subformulari ADJUNTS
	delAdjuntsReader(oFitxersAdjuntsReader, iNumAdjReader, oFitxersAdjuntsSubform, bAccioEsborrar);

	// S'ha de verificar que tots els adjunts dels subformularis, realment hi són en el Reader
	if (iNumAdjPlens > 0) delAdjuntsNoReader(oFitxersAdjuntsSubform, iNumAdjSubform, oFitxersAdjuntsReader, iNumAdjReader, bAccioEsborrar);
}

///////////////////////////////////////////////////////////////////////
// Nom: numeroAdjuntsPlensSubform
// Descripció: Mètode que compta el número d'adjunts plens que hi ha dins el panell adjunts.
// Paràmetres d'entrada: 
//		oFitxersAdjuntsSubform - Panell d'adjunts com a string o objecte
// Paràmetres de sortida:
//		enter - Valor que indica el número d'adjunts plens, dins de l'estructura d'adjunts.
//////////////////////////////////////////////////////////////////////
function numeroAdjuntsPlensSubform(oFitxersAdjuntsSubform)
{
    var	iNumAdjunts = 0;
    var nAdjunts = oFitxersAdjuntsSubform.length;
    for(var n=0; n<nAdjunts; n++)
    {
		if (!scoGSITVal.isEmpty(getNomPDFAdjunt(oFitxersAdjuntsSubform.item(n)))) iNumAdjunts++;
    }
    return iNumAdjunts;
}


///////////////////////////////////////////////////////////////////////
// Nom: numAdjuntsReader
// Descripció: Mètode que retorna el número d'adjunts al Reader
//		oFitxersAdjuntsSubform - Panell d'adjunts com a string o objecte
// Paràmetres de sortida:
//		enter - Valor que indica el número d'adjunts al Reader
//////////////////////////////////////////////////////////////////////
function numAdjuntsReader()
{
	var oDocument = event.target;
	if (oDocument.dataObjects == null)			return 0;
	return oDocument.dataObjects.length;
}


///////////////////////////////////////////////////////////////////////
// Nom: cercaAdjunt
// Descripció: Mètode que cerca si el fitxer adjunt del menú indicat existeix com adjunt a la plana del formulari.
// Paràmetres d'entrada: 
//		idFitxer - ID del fitxer
//		oFitxersAdjunts - Panell d'adjunts com a string o objecte
// Paràmetres de sortida:
//		boolèa  - (true/false) true si troba l'adjunt al panell d'adjunts i false en cas contrari
//////////////////////////////////////////////////////////////////////
function cercaAdjuntSubform(idFitxer, oFitxersAdjunts)
{
	var numAdj = (scoGSITVal.existeixObjecte(oFitxersAdjunts)) ? oFitxersAdjunts.length : 0;
	var bTrobat = false;
	var n = 0;
	while (!bTrobat && n < numAdj)
    {
   		var sIdAdjunt = getIDAdjunt(oFitxersAdjunts.item(n));
		if ( (sIdAdjunt == idFitxer)) bTrobat = true;
		else n++;
    }

	return bTrobat;
}             

////////////////////////////////////////////////////////////
// Nom: veureAdjunts
// Descripció: Mètode que mostra la zona de fitxers adjunts per a versions del Reader igual o superior a 8.00.
////////////////////////////////////////////////////////////
function veureAdjunts()
{
	try{
		app.execMenuItem("ShowHideFileAttachment");
		return 1;
	}catch(exc)
	{
		return scoGSITGen.retornarExcepcio("veureAdjunts",exc);
	}
}               

////////////////////////////////////////////////////////////
// Nom: treureTotsAdjunts
// Descripció: Mètode que esborra tots els adjunts
// Paràmetres d'entrada: 
//		oSufAdjunts - Panell d'adjunts com a string o objecte
////////////////////////////////////////////////////////////
function treureTotsAdjunts(oSufAdjunts)
{
	if(scoGSITVal.isFormulariValidat()) return;

	if (typeof(oSufAdjunts) == "string") oSufAdjunts = xfa.resolveNode(oSufAdjunts);
	if (!scoGSITVal.existeixObjecte(oSufAdjunts)) return;

	var oAdjuntsSubform = oSufAdjunts.resolveNodes("ADJUNT[*]");
	var iNumAdjSubform = (scoGSITVal.existeixObjecte(oAdjuntsSubform)) ? oAdjuntsSubform.length : 0;	
	for (var n=0; n<iNumAdjSubform; n++)
	{
		treureFitxer(oAdjuntsSubform.item(n));	
	}
}

////////////////////////////////////////////////////////////
// Nom: getArrBtnVeure
// Descripció: Mètode que retorna la llista de noms dels botons 'veure' del panell d'adjunts.
// Paràmetres d'entrada: 
//		oSufAdjunts - Panell d'adjunts com a string o objecte
// Paràmetres de sortida: 
//		array - Llista de noms dels botons 'veure' del panell d'adjunts	
////////////////////////////////////////////////////////////
function getArrBtnVeure(oSufAdjunts)
{
	if (typeof(oSufAdjunts) == "string") oSufAdjunts = xfa.resolveNode(oSufAdjunts);
	if (!scoGSITVal.existeixObjecte(oSufAdjunts)) return;

	var oAdjuntsSubform = oSufAdjunts.resolveNodes("ADJUNT[*]");
	var iNumAdjSubform = (scoGSITVal.existeixObjecte(oAdjuntsSubform)) ? oAdjuntsSubform.length : 0;	

	var aBtnVeure = new Array();
	for (var n=0; n<iNumAdjSubform; n++)
	{
		var oAdj = oAdjuntsSubform.item(n);
		if (scoGSITVal.existeixObjecte(oAdj))
			aBtnVeure[n] = oAdj.BTN_VEURE_FITXER.somExpression.replace(/xfa\[0\]\.form\[0\]./gi, "");
	}

	return aBtnVeure;	
}


///////////////////////////////////////////////////////////////////////
// Nom: existeixenAdjuntsAlterats
// Descripció: Mètode que verifica que els adjunts no s'hagin alterat
// Paràmetres d'entrada: 
//		oSufAdjunts - Panell d'adjunts com a string o objecte
// Paràmetres de sortida: 
//		booleà - Valor (true/false) segons si la validació és correcte o no.
//////////////////////////////////////////////////////////////////////
function existeixenAdjuntsAlterats(oFitxersAdjuntsSubform)
{
	if (typeof(oFitxersAdjuntsSubform) == "string") oFitxersAdjuntsSubform = xfa.resolveNode(oFitxersAdjuntsSubform);
	if  (!scoGSITVal.existeixObjecte(oFitxersAdjuntsSubform)) return;

   	var oFitxersAdjuntsReader = event.target.dataObjects;    
	var oFitxersAdjuntsSubform = oFitxersAdjuntsSubform.resolveNodes("ADJUNT[*]");

	var iNumAdjSubform = scoGSITVal.existeixObjecte(oFitxersAdjuntsSubform) ? oFitxersAdjuntsSubform.length : 0;	
	var iNumAdjReader = scoGSITVal.existeixObjecte(oFitxersAdjuntsReader) ? oFitxersAdjuntsReader.length : 0;
    var	iNumAdjPlens = numeroAdjuntsPlensSubform(oFitxersAdjuntsSubform);

	return (iNumAdjReader != iNumAdjPlens);
}

////////////////////////////////////////////////////////////
// Nom: getSubAdjuntRol
// Descripció: Mètode que obté el subformulari de l'adjunt amb rol 'rol'
// Paràmetres d'entrada: 
//		oPanellAdj - Panell d'adjunts com a string o objecte
//		rol - El rol de l'adjunt
// Paràmetres de sortida: 
//		oSubfAdjunt - Panell d'un adjunt (ADJUNT[n]), null si no existeix
////////////////////////////////////////////////////////////
function getSubAdjuntRol(oPanellAdj, rol)
{
	if (typeof(oPanellAdj) == "string") oPanellAdj = xfa.resolveNode(oPanellAdj);
	if (!scoGSITVal.existeixObjecte(oPanellAdj)) return;

	var oAdjunts = oPanellAdj.resolveNodes("ADJUNT[*]");
	var nAdjunts = oAdjunts.length;
	for (var nAdj=0; nAdj<nAdjunts; nAdj++)
	{
		var oAdj = oAdjunts.item(nAdj);
		if (scoGSITVal.existeixObjecte(oAdj))
		{
			if (oAdj.TXT_ROL.rawValue == rol) return oAdj;
		}
	}

	return null;
}


///////////////////////////////////////////////////////////////////////
// Nom: nombreAdjunts
// Descripció: Mètode que retorna el nombre d'adjunts definits
// Paràmetres d'entrada: 
//		oPanellAdj - Panell d'adjunts com a string o objecte
//////////////////////////////////////////////////////////////////////
function nombreAdjunts(oPanellAdj)
{
	if (typeof(oPanellAdj) == "string") oPanellAdj = xfa.resolveNode(oPanellAdj);
	if (!scoGSITVal.existeixObjecte(oPanellAdj)) return;

	var oAdjunts = oPanellAdj.resolveNodes("ADJUNT[*]");
	return ( ((oAdjunts != null) && (oAdjunts != undefined)) ? oAdjunts.length : 0);
}

///////////////////////////////////////////////////////////////////////
// Nom: teAdjunts
// Descripció: Mètode que retorna si el panell d'adjunts te adjunts
// Paràmetres d'entrada: 
//		oPanellAdj - Panell d'adjunts com a string o objecte
//////////////////////////////////////////////////////////////////////
function teAdjunts(oPanellAdj)
{
	return (nombreAdjunts(oPanellAdj) > 0);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: existeixAdjuntNomIgual
// Descripció: Mètode que s'encarrega de mirar si ja existeix un annex amb el nom de 'nouAdjunt'
// Paràmetres d'entrada: 
//		nouAdjunt - Objecte de tipus adjunt que s'ha afegit
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si ja existeix un annex amb el mateix nom de 'nouAdjunt'
///////////////////////////////////////////////////////////////////////////// 
function existeixAdjuntNomIgual(nouAdjunt) 
{
	if (!scoGSITVal.existeixObjecte(scoGSITPar.oPanellAdjunts))			return false;

	var sNom = nouAdjunt.path;
	if (scoGSITVal.isEmpty(sNom)) return false;


	var oAdjunts = scoGSITPar.oPanellAdjunts.resolveNodes("ADJUNT[*]");
	if (!scoGSITVal.existeixObjecte(oAdjunts)) return false;		

	var nAdjunts = oAdjunts.length;
	for (var nAdj=0; nAdj<nAdjunts; nAdj++)
	{
		if (getNomPDFAdjunt(oAdjunts.item(nAdj)) == sNom) return true;
	}

	return false;
}

