var aCampsAdreca = ["TXT_TIPUS_VIA", "TXT_TIPUS_VIA_NOM", "TXT_NOM_VIA", "TXT_NUM_VIA", 
                    "TXT_BLOC", "TXT_ESCALA", "TXT_PIS", "TXT_PORTA", "TXT_CODI_POSTAL", 
					"CHK_RESIDENCIA", "TXT_PAIS", "TXT_PAIS_NOM", 
					"LLISTA_PROVINCIES", "LLISTA_PROVINCIES_NOM", "LLISTA_COMARQUES", "LLISTA_COMARQUES_NOM", 
					"LLISTA_MUNICIPIS", "LLISTA_MUNICIPIS_NOM", "LLISTA_MUNICIPIS_ESTR", "LLISTA_LLOGARETS", "LLISTA_LLOGARETS_NOM", 
					"TXT_ES_NORMALITZADA", "TXT_ARR_ADRECA", "TXT_MOSTRAR_COMARCA", "TXT_MOSTRAR_PAIS"];			  

/////////////////////////////////////////////////////////////////////////////
// MÈTODES
/////////////////////////////////////////////////////////////////////////////

/////////////////////////////////////////////////////////////////////////////
// Nom: esAdrecaEstrangeraXML
// Descripció: Mètode que verifica si el node d'adreça 'oNode' és una adreça estrangera
// Paràmetres d'entrada:
//		oNode - Node d'adreça
// Paràmetres de sortida:
//      booleà -  indica si l'adreça definida  a 'oNode' és espanyola
/////////////////////////////////////////////////////////////////////////////
function esAdrecaEstrangeraXML(oNode)
{
	if (!scoGSITVal.existeixObjecte(oNode)) return false;

	var sINE = scoGSITVal.getValueTagXML(oNode.Pais.CodiINE);
	if (scoGSITVal.isEmpty(sINE)) return false;

	return (parseInt(String(sINE), 10) != 108);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esAdrecaEspanyolaXML
// Descripció: Mètode que verifica si el node d'adreça 'oNode' és una adreça espanyola.
// Paràmetres d'entrada:
//		oNode - Node d'adreça
// Paràmetres de sortida:
//      booleà -  indica si l'adreça definida  a 'oNode' és espanyola
/////////////////////////////////////////////////////////////////////////////
function esAdrecaEspanyolaXML(oNode)
{
	if (!scoGSITVal.existeixObjecte(oNode)) return false;

	var sINE = scoGSITVal.getValueTagXML(oNode.Pais.CodiINE);
	if (scoGSITVal.isEmpty(sINE)) return false;

	return (parseInt(String(sINE), 10) == 108);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esAdrecaCatalanaXML
// Descripció: Mètode que verifica si el node d'adreça 'oNode' és una adreça catalana.
// Paràmetres d'entrada:
//		oNode - Node d'adreça
//		bBuit - Boolea que indica si retornarà 'true' en el cas que sigui buit
// Paràmetres de sortida:
//      booleà -  indica si l'adreça definida a 'oNode' és catalana
/////////////////////////////////////////////////////////////////////////////
function esAdrecaCatalanaXML(oNode, bBuit)
{
	if (!scoGSITVal.existeixObjecte(oNode)) return false;
	if (!esAdrecaEspanyolaXML(oNode)) return false;
	if (arguments.length < 2) bBuit = false;

	var sINE = scoGSITVal.getValueTagXML(oNode.Provincia.CodiINE);

	if (scoGSITVal.isEmpty(sINE)) return bBuit;

	var nINEProv = parseInt(String(sINE), 10);
	return ((nINEProv == 08) || (nINEProv == 17) || (nINEProv == 25) || (nINEProv == 43));
}

/////////////////////////////////////////////////////////////////////////////
// Nom: getNodeXMLAdreca(oAdreca)
// Descripció: Mètode que retorna el node XML de 'oAdreca'
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
// Paràmetres de sortida:
//      oNodeXML -  node XML de 'oAdreca'
/////////////////////////////////////////////////////////////////////////////
function getNodeXMLAdreca(oAdreca)
{
	var sRuta = "xfa.record." + scoGSITPanells.obtenirBindObjecte(oAdreca, "", true);
	if (new RegExp("\\*").test(sRuta)) return null;

	var oNode = xfa.resolveNode(sRuta);
	return ((!scoGSITVal.existeixObjecte(oNode)) ? null : oNode);	
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esLlistaProvCatalanes
// Descripció: Mètode que verifica si la llista de províncies del panell d'adreça és la de catalanes
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
// Paràmetres de sortida:
//      booleà -  indica si la llista de províncies del panell d'adreça és la de catalanes
/////////////////////////////////////////////////////////////////////////////
function esLlistaProvCatalanes(oAdreca)
{
	var oProvincies = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_PROVINCIES");
	return (oProvincies.length == 4);
}		


/////////////////////////////////////////////////////////////////////////////
// Nom: esPanellAdrecaCatalana
// Descripció: Mètode que verifica si el panell té dades d'un adreça catalana
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		bBuit - Boolea que indica si retornarà 'true' en el cas que sigui buit
// Paràmetres de sortida:
//      booleà -  indica si l'adreça definida al panell és catalana
/////////////////////////////////////////////////////////////////////////////
function esPanellAdrecaCatalana(oAdreca, bBuit)
{		
	if (arguments.length < 2) bBuit = false;

	return esAdrecaCatalanaXML(getNodeXMLAdreca(oAdreca), bBuit);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esPanellAdrecaEspanyola
// Descripció: Mètode que verifica si el panell té dades d'un adreça espanyola
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
// Paràmetres de sortida:
//      booleà -  indica si l'adreça definida al panell és espanyola
/////////////////////////////////////////////////////////////////////////////
function esPanellAdrecaEspanyola(oAdreca)
{
	return esAdrecaEspanyolaXML(getNodeXMLAdreca(oAdreca));
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esPanellAdrecaEstrangera
// Descripció: Mètode que verifica si el panell té dades d'un adreça estrangera
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
// Paràmetres de sortida:
//      booleà -  indica si l'adreça definida al panell és estrangera
/////////////////////////////////////////////////////////////////////////////
function esPanellAdrecaEstrangera(oAdreca)
{
	if (scoGSITVal.isFormulariAcusament()) {
		// ITEXT no funciona correctament esAdrecaEstrangeraXML
		var oPais = scoGSITPanells.obtenirObjecteFill(oAdreca, "TXT_PAIS"); 
		return (oPais.rawValue != "108");
	}
	else {
		return esAdrecaEstrangeraXML(getNodeXMLAdreca(oAdreca));
	}
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esAdrecaEspanyola
// Descripció: Mètode que verifica si el panell d'adreça 'oAdreca' és una adreça espanyola.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
/////////////////////////////////////////////////////////////////////////////
function esAdrecaEspanyola(oAdreca)
{
	if (!scoGSITVal.existeixObjecte(oAdreca)) return false;
	if (!scoGSITVal.existeixObjecte(oAdreca.TXT_PAIS)) return false;

	return (esPaisEspana(oAdreca.TXT_PAIS));
}

////////////////////////////////////////////////////////////
// Nom: esPaisEspana
// Descripció:  Mètode que verifica si el país és Espanya.
// Paràmetres d'entrada:
//		oPais - Camp de país
////////////////////////////////////////////////////////////    
function esPaisEspana(oPais)
{
	try
	{
		if (!scoGSITVal.existeixObjecte(oPais)) return false;
		var nINEPais = parseInt(String(oPais.rawValue), 10);

		return (nINEPais == 108);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::esPaisEspana", exc);
	}					
}

////////////////////////////////////////////////////////////
// Nom: obtenirCodiINEPais
// Descripció:  Mètode que obté el codi INE del país.
// Paràmetres d'entrada:
//		oPanell - Panell que conté el camp del país "TXT_PAIS"
////////////////////////////////////////////////////////////    
function obtenirCodiINEPais(oPanell)
{
	try
	{
		var oCodiINE = scoGSITPanells.obtenirObjecteFill(oPanell, "TXT_PAIS");

		if (scoGSITVal.isFormulariAcusament()){
			return scoGSITPaisInfo.obtenirCodiINEPais(oCodiINE.rawValue);
		}

		if (!scoGSITVal.esBindingCorrecte(oCodiINE, ["Pais", "CodiINE"])) oCodiINE = scoGSITPanells.obtenirObjecteFill(oPanell, "TXT_PAIS_NOM");

		if (scoGSITVal.esBindingCorrecte(oCodiINE, ["Pais", "CodiINE"]))
		{
			var sValor = scoGSITVal.trim(String(oCodiINE.rawValue)).toLowerCase();
			return (scoGSITVal.isEmpty(sValor) ? "" : sValor);
		}

		return "";
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::obtenirCodiINEPais", exc);
	}					
}

////////////////////////////////////////////////////////////
// Nom: obtenirCodiISOPaisDocument
// Descripció:  Mètode que obté el codi ISO del país document
// Paràmetres d'entrada:
//		oPanell - Panell que conté el camp del país document "TXT_PAIS_DOCUMENT"
////////////////////////////////////////////////////////////       
function obtenirCodiISOPaisDocument(oPanell)
{
	try
	{
		var oCodiINE = scoGSITPanells.obtenirObjecteFill(oPanell, "TXT_PAIS_DOCUMENT");

		if (!scoGSITVal.esBindingCorrecte(oCodiINE, ["Document", "PaisDocument", "CodiINE"]))
			oCodiINE = scoGSITPanells.obtenirObjecteFill(oPanell, "TXT_PAIS_DOCUMENT_NOM");

		if (scoGSITVal.esBindingCorrecte(oCodiINE, ["Document", "PaisDocument", "CodiINE"])) 
		{
			var sValor = scoGSITVal.trim(String(oCodiINE.rawValue)).toLowerCase();
			return (scoGSITVal.isEmpty(sValor) ? "" : sValor);
		}

		return "";
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::obtenirCodiISOPaisDocument", exc);
	}					
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esProvinciaCatalana
// Descripció: Mètode que verifica si 'oProvincia' es una província catalana.
// Paràmetres d'entrada:
//		oProvincia - Camp de la província
/////////////////////////////////////////////////////////////////////////////
function esProvinciaCatalana(oProvincia)
{
	if (!scoGSITVal.existeixObjecte(oProvincia)) return false;
	if (scoGSITVal.isEmpty(oProvincia)) return false;

	var nINEProv = parseInt(String(oProvincia.rawValue), 10);
	return ((nINEProv == 08) || (nINEProv == 17) || (nINEProv == 25) || (nINEProv == 43));
}

////////////////////////////////////////////////////////////
// Nom: defPaisEsp
// Descripció: Mètode que defineix les dades del paía d'adreça com espanyoles.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
////////////////////////////////////////////////////////////    
function defPaisEsp(oAdreca)
{
	try
	{
		var sCodiINE = "108";
		var oPais = scoGSITPanells.obtenirObjecteFill(oAdreca, "TXT_PAIS");
		var oPaisNom = scoGSITPanells.obtenirObjecteFill(oAdreca, "TXT_PAIS_NOM");

		if (oPais != null)     oPais.rawValue = sCodiINE;
		if (oPaisNom != null)  oPaisNom.rawValue = scoGSITPaisInfo.obtenirNomPaisINE(sCodiINE);	
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::defPaisEsp", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: defLlistaPaisosExt
// Descripció: Mètode que defineix a 'oPais' la llista de paisos extrangers, no defineix 'Espanya'
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
////////////////////////////////////////////////////////////   
function defLlistaPaisosExt(oAdreca)
{
	var oPais = scoGSITPanells.obtenirObjecteFill(oAdreca, "TXT_PAIS");
	if (oPais == null) return;

	if (oPais.length == 0) 
	{	
		var arrValors = scoGSITPaisInfo.getLlistaPaisosExtINE();
		scoGSITCombo.inicialitzaLlista(oPais, arrValors);
	}
}

////////////////////////////////////////////////////////////
// Nom: getCampsNoACK
// Descripció: Mètode que retorna un array amb els camps que NO s'han de mostrar en ACK
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
// Paràmetres de sortida:
//      Array -  Array amb els camps del panell 
////////////////////////////////////////////////////////////   
function getCampsNoACK(oAdreca)
{
	return scoGSITCamps.getCampsPanell(oAdreca, ["TXT_PAIS", "LLISTA_PROVINCIES", "LLISTA_COMARQUES", "LLISTA_MUNICIPIS"]);
}

////////////////////////////////////////////////////////////
// Nom: getCampsExt
// Descripció: Mètode que retorna un array amb els camps que defineixen Adreça extrangera
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
// Paràmetres de sortida:
//      Array -  Array amb els camps del panell que defineixen Adreça extrangera
////////////////////////////////////////////////////////////   
function getCampsExt(oAdreca)
{
	if (scoGSITVal.isFormulariAcusament()) {
		return scoGSITCamps.getCampsPanell(oAdreca, ["TXT_PAIS_NOM", "LLISTA_MUNICIPIS_ESTR"]);
	}
	else {
		return scoGSITCamps.getCampsPanell(oAdreca, ["TXT_PAIS", "LLISTA_MUNICIPIS_ESTR"]);
	}
}

////////////////////////////////////////////////////////////
// Nom: getCampsCatEsp
// Descripció: Mètode que retorna un array amb els camps que defineixen Adreça NO extrangera
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
// Paràmetres de sortida:
//      Array -  Array amb els camps del panell que defineixen Adreça NO extrangera
////////////////////////////////////////////////////////////   
function getCampsCatEsp(oAdreca) 
{
	var aCamps;
	if (scoGSITVal.isFormulariAcusament()) {
		aCamps = ["LLISTA_PROVINCIES_NOM", "LLISTA_MUNICIPIS_NOM"];
		if (!scoGSITVal.isEmpty(scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_COMARQUES")))		aCamps.push("LLISTA_COMARQUES_NOM");
	} 
	else {
		aCamps = ["LLISTA_PROVINCIES", "LLISTA_COMARQUES", "LLISTA_MUNICIPIS"];
	}
	if (calMostrarPais(oAdreca)) aCamps.push("TXT_PAIS_NOM");

	return scoGSITCamps.getCampsPanell(oAdreca, aCamps);
}

////////////////////////////////////////////////////////////
// Nom: obtenirNomPanellAdreca
// Descripció: Mètode que retorna el nom del panell d'adreça de 
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
////////////////////////////////////////////////////////////    
function obtenirNomPanellAdreca(oAdreca)
{
	var oCP = scoGSITPanells.obtenirObjecteFill(oAdreca, "TXT_CODI_POSTAL");
	if (scoGSITVal.existeixObjecte(oCP)) return oCP.parent.name;

	return "";
}

////////////////////////////////////////////////////////////
// Nom: esborraLlista
// Descripció: Mètode que esborra la llista i el valor de 'oLlista'.
// Paràmetres d'entrada:
//		oLlista - Camp de llista
////////////////////////////////////////////////////////////    
function esborraLlista(oLlista)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (!scoGSITVal.existeixObjecte(oLlista)) return;

		oLlista.clearItems();
		oLlista.rawValue = "";
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::esborraLlista", exc);
	}		
}

////////////////////////////////////////////////////////////
// Nom: esborraLlistes
// Descripció: Mètode que esborra els camps de 'aLlistes'
//		aLlistes - Array amb les llistes a esborrar
////////////////////////////////////////////////////////////    
function esborraLlistes(aLlistes)
{
	if (scoGSITVal.isFormulariValidat()) return;
	if (!scoGSITVal.existeixObjecte(aLlistes)) return;

	var nElemsAdreca = aLlistes.length;
	for (var n=0; n<nElemsAdreca; n++)
	{
		esborraLlista(aLlistes[n]);
	}
}

////////////////////////////////////////////////////////////
// Nom: carregaLlistaRel
// Descripció: Mètode que inicialitza 'oLListaFilla' amb els valors de l'array relacionat amb el valor seleccionat de 'oLListaPare'
//		oAdreca - Panell d'adreça
//		oLListaPare - Combo anterior
//		oLListaFilla - Combo on s'han de posar els valors
//		aValors - Array on es troben els valors
//		sModul - llibreria on es troba l'array a carregar
//		bEsborraVal - booleà que indica si volem esborrar el valor que hi podia haver definit a 'oLListaFilla'
//		bCercaArray  - booleà que indica si cercarà l'array corresponent a 'arrValors'
//		aLlistesDesti - Llista en la qual es defineix el nom de la llista carregada
//		nPosLlista - Posició de 'aLlistesDesti' a la que es guardarà el valor
////////////////////////////////////////////////////////////    
function carregaLlistaRel(oAdreca, oLListaPare, oLListaFilla, aValors, sModul, bEsborraVal, bCercaArray, aLlistesDesti, nPosLlista)                 
{
	if (!scoGSITVal.existeixObjecte(oLListaPare) || !scoGSITVal.existeixObjecte(oLListaFilla)) return;

	if (arguments.length < 5) bEsborraVal = false;
	if (arguments.length < 6) bCercaArray = false;
	if (arguments.length < 7) aLlistesDesti = null;
	if (arguments.length < 8) nPosLlista = 0;

	var bCarregaLLista = (bEsborraVal) ? true : (oLListaFilla.length == 0);
	if (bCarregaLLista)
	{	
		var sArrayCarregat = scoGSITCombo.carregaSeguentLlista(oLListaPare, oLListaFilla, aValors, sModul, bEsborraVal, bCercaArray);

		var oInfoAdreca = scoGSITPanells.obtenirObjecteFill(oAdreca, "TXT_ARR_ADRECA"); // Def l'array amb la info
		if (oInfoAdreca != null && aLlistesDesti != null)
		{
			aLlistesDesti[nPosLlista] = sArrayCarregat;
			oInfoAdreca.rawValue = String(aLlistesDesti);
		}
	}
}

////////////////////////////////////////////////////////////
// Nom: esborraElementAdreca
// Descripció: Mètode que esborra l'element 'sElementAdreca' de l'adreça comprobant primer si existeix
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		sElementAdreca - Element de l'adreça a esborrar
////////////////////////////////////////////////////////////
function esborraElementAdreca(oAdreca, sElementAdreca)
{
	var oNode = oAdreca.resolveNode(sElementAdreca);
	if (scoGSITVal.existeixObjecte(oNode))  oNode.value = "";
}

////////////////////////////////////////////////////////////
// Nom: esborraAdreca
// Descripció: Mètode que esborra tota l'adreça a l'XML i els camps
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
////////////////////////////////////////////////////////////
function esborraAdreca(oAdreca) 
{
	if (scoGSITVal.isFormulariValidat()) return;
	if (!scoGSITVal.existeixObjecte(oAdreca))  return;

	var oBind = scoGSITPanells.obtenirBindObjecte(oAdreca, "", true);

	// Si és múltiple no esborrem
	var regExp = new RegExp("[*]");
	if (regExp.test(String(oBind))) return;

	var oAdrecaNodes = xfa.resolveNode("xfa.record." + oBind);
	scoGSITNod.netejarNode(oAdrecaNodes);

	scoGSITGen.netejarForm(oAdrecaNodes);
}

////////////////////////////////////////////////////////////
// Nom: esborraAdrecaXML
// Descripció: Mètode que esborra a l'XML els elements d'adreça continguts a 'aTipusAdreca'
// Paràmetres d'entrada:
//		oBind - Bind de l'adreça Panell d'adreça
//		aTipusAdreca - Array de tipus que formen l'adreça per esborrar
////////////////////////////////////////////////////////////
function esborraAdrecaXML(oBind, aTipusAdreca)
{
	if (scoGSITVal.isFormulariValidat()) return;
	if (!scoGSITVal.existeixObjecte(aTipusAdreca))  return;

	// Si és múltiple no esborrem
	var regExp = new RegExp("[*]");
	if (regExp.test(String(oBind))) return;

	var oAdreca = xfa.resolveNode("xfa.record." + oBind);
	if ((oAdreca == null) || (oAdreca == undefined)) return;

	var nElemsAdreca = aTipusAdreca.length;
	for (var n=0; n<nElemsAdreca; n++)
	{
		esborraElementAdreca(oAdreca, (aTipusAdreca[n]+".Nom"));
		esborraElementAdreca(oAdreca, (aTipusAdreca[n]+".CodiINE"));
	}
}

////////////////////////////////////////////////////////////
// Nom: esborraInfoAdre
// Descripció: Mètode que esborra els camps de 'aLlistes' i els nodes de 'aNodes'
//		oAdreca - Panell d'adreça
//		aLlistes - Array amb les llistes a esborrar
//		aNodes - Array de nodes de l'adreça per esborrar
////////////////////////////////////////////////////////////    
function esborraInfoAdre(oAdreca, aLlistes, aNodes)
{
	if (scoGSITVal.isFormulariValidat()) return;
	if (scoGSITVal.isFormulariAcusament()) return;

	esborraLlistes(aLlistes);
	esborraAdrecaXML(scoGSITPanells.obtenirBindObjecte(oAdreca, "", true), aNodes);
}

////////////////////////////////////////////////////////////
// Nom: copyNormalizador
// Descripció: Mètode que copia els camps del panell Normalizador
// Paràmetres d'entrada:
//      oNormalizadorOri - Panell normalitzador origen
//		oNormalizadorDest - Panell normalitzador destí
////////////////////////////////////////////////////////////    
function copyNormalizador(oNormalizadorOri, oNormalizadorDest)
{
	if (scoGSITVal.isFormulariValidat()) return;
	if (scoGSITVal.isFormulariAcusament()) return;

	if (oNormalizadorOri != null && oNormalizadorDest != null)
	{
		oNormalizadorDest.TXT_RESULTAT.rawValue = oNormalizadorOri.TXT_RESULTAT.rawValue;
		oNormalizadorDest.TXT_NORMALITZADA.rawValue = oNormalizadorOri.TXT_NORMALITZADA.rawValue;
		scoGSITBot.copiarEstatBoto(oNormalizadorOri.BTN_BUSCAR, oNormalizadorDest.BTN_BUSCAR);
		scoGSITBot.copiarEstatBoto(oNormalizadorOri.BTN_ACCEPTAR, oNormalizadorDest.BTN_ACCEPTAR);
	}
}

////////////////////////////////////////////////////////////
// Nom: copyAdreces
// Descripció: Mètode que copia els camps de l'adreça de 'oAdrecaOri' a 'oAdrecaDest' i de 'oNormalizadorOri' a 'oNormalizadorDest'.
// Paràmetres d'entrada:
//		oAdrecaOri - Panell d'adreça origen
//		oAdrecaDest - Panell d'adreça destí
//      oNormalizadorOri - Panell normalitzador origen
//		oNormalizadorDest - Panell normalitzador destí
////////////////////////////////////////////////////////////    
function copyAdreces(oAdrecaOri, oAdrecaDest, oNormalizadorOri, oNormalizadorDest, bClonaAccess, bClonaPosicions)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		if (arguments.length < 3) oNormalizadorOri = null;
		if (arguments.length < 4) oNormalizadorDest = null;

		if (arguments.length < 5) bClonaAccess = false;
		if (arguments.length < 6) bClonaPosicions = true;

		esborraAdreca(oAdrecaDest);				  
		scoGSITGen.amagarRequadresForm(oAdrecaDest);
		scoGSITPanells.clonaCampsPanells(oAdrecaOri, oAdrecaDest, aCampsAdreca, bClonaAccess, bClonaPosicions); 	
		copyNormalizador(oNormalizadorOri, oNormalizadorDest);	
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::copyAdrecesCat", exc);
	}		
}


