//		oAdrecaOri - Panell d'adreça origen
//		oAdrecaDest - Panell d'adreça destí
//      oNormalizadorOri - Panell normalitzador origen
//		oNormalizadorDest - Panell normalitzador destí
////////////////////////////////////////////////////////////    
function copyAdrecesCat(oAdrecaOri, oAdrecaDest, oNormalizadorOri, oNormalizadorDest)
