//		oPanellDes - Panell d'adreça destí
//		sAdreca - Nom del panell d'adreça a copiar
////////////////////////////////////////////////////////////
function copiaAdrecesPanells(oPanellOri, oPanellDes, sAdreca)
{
	copiaAdrecesPanellsGenerica(oPanellOri, oPanellDes, sAdreca);
}

