// Nom: copiaAdrecesPanellsMultiple
// Descripció: Mètode que copia l'adreça del panell actiu del 'oPanellOri' al panell corresponent 'oPanellDes'
// Paràmetres d'entrada:
//		oPanellOriFJ - Panell d'origen
//		oPanellDesFJ - Panell d'destí
//		aDefAdreca - array amb la informació dels panells d'adreça del tipus [ ["FuncióDef adreça Física", "Nom panell física"], ["FuncióDef adreça Jurídica", "Nom panell jurídica"]];
////////////////////////////////////////////////////////////
function copiaAdrecesPanellsMultiple(oPanellOri, oPanellDes, aDefAdreca) 
{
	var sAdreca = scoGSITPanells.obtenirNomPanellAdrecaPanellMultiple(oPanellOri, aDefAdreca);
	copiaAdrecesPanellsGenerica(oPanellOri, oPanellDes, sAdreca);
}

