// Nom: copiaAdrecesPanellsFJ
// Descripció: Mètode que copia l'adreça del panell actiu del Física/Jurídica d'origen al panell de destí
// Paràmetres d'entrada:
//		oPanellOriFJ - Panell d'origen
//		oPanellDesFJ - Panell d'destí
//		aDefAdreca - array amb la informació dels panells d'adreça del tipus [ ["FuncióDef adreça Física", "Nom panell física"], ["FuncióDef adreça Jurídica", "Nom panell jurídica"]];
////////////////////////////////////////////////////////////
