{
	copiaAdrecesPanellsMultiple(oPanellOriFJ, oPanellDesFJ, aDefAdreca);
}

////////////////////////////////////////////////////////////
// Nom: copiaAdrecesPanellsGenerica
// Descripció: Mètode que copia l'adreça del panell d'origen al panell de destí per qualsevol tipus de panell
// Paràmetres d'entrada:
//		oPanellOri - Panell d'adreça origen
//		oPanellDes - Panell d'adreça destí
//		sAdreca - Nom del panell d'adreça a copiar
////////////////////////////////////////////////////////////
function copiaAdrecesPanellsGenerica(oPanellOri, oPanellDes, sAdreca)
{
	var bOriMultiple = scoGSITPanells.esPanellMultiple(oPanellOri);
	var bDesMultiple = scoGSITPanells.esPanellMultiple(oPanellDes);

	var oAdrecaOri = (bOriMultiple) ? scoGSITPanells.obtenirPanellAdrecaPanellMultiple(oPanellOri, sAdreca) : scoGSITPanells.obtenirObjecteFill(oPanellOri, sAdreca);
	var oNormOri = (bOriMultiple) ? scoGSITPanells.obtenirPanellNormalitzadorPanellMultiple(oPanellOri) : scoGSITPanells.obtenirObjecteFill(oPanellOri, "NORMALITZADOR");

	var oAdrecaDes = (bDesMultiple) ? scoGSITPanells.obtenirPanellAdrecaPanellMultiple(oPanellDes, sAdreca) : scoGSITPanells.obtenirObjecteFill(oPanellDes, sAdreca);
	var oNormDes = (bDesMultiple) ? scoGSITPanells.obtenirPanellNormalitzadorPanellMultiple(oPanellDes) : scoGSITPanells.obtenirObjecteFill(oPanellDes, "NORMALITZADOR");
	copiaDadesAdrecesPanells(oAdrecaOri, oAdrecaDes, oNormOri, oNormDes, sAdreca);
}

////////////////////////////////////////////////////////////
// Nom: copiaAdrecaContacte
// Descripció: Mètode que copia l'adreça del Presentador (si hi és, sinó del Requeridor) a l'adreça de Contacte 
// Paràmetres d'entrada:
//		sAdreca - Nom del panell d'adreça a copiar
//      bPregunta - Indica si s'ha de preguntar abans de fer la copia
////////////////////////////////////////////////////////////
function copiaAdrecaContacte(sAdreca, bPregunta) 
{
	if (scoGSITVal.isFormulariValidat()) return;
	if (arguments.length < 1) bPregunta = true;	

	var bTePresentador = scoGSITVal.existeixPresentador();
	var sMsg = (bTePresentador) ? msgPreguntaCopiarAdrecaPresentador.value : msgPreguntaCopiarAdrecaRequeridor.value;
	var sPanelOri = (bTePresentador) ? scoGSITPar.oPanellPresentador : scoGSITPar.oPanellRequeridor;

	var bCopia = (bPregunta) ? (scoGSITMissatges.MissatgePregunta(sMsg,"")) : true;
	if (bCopia)  copiaAdrecesPanells(sPanelOri, scoGSITPar.oPanellAvisos, sAdreca);
}

