	var bCopia = (bPregunta) ? (scoGSITMissatges.MissatgePregunta(sMsg,"")) : true;
	if (bCopia) copiaAdrecesPanellsMultiple(sPanelOri, scoGSITPar.oPanellAvisos, sDefAdre);
