////////////////////////////////////////////////////////////
// Nom: esPotNormalitzar
// Descripció:  Mètode que indica si l'adreça es pot normalitzar amb ICC nomes catalanes
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
// Paràmetres de sortida:
//		booleà - Valor (true/false) segons si l'adreça es pot normalitzar
////////////////////////////////////////////////////////////    
function esPotNormalitzar(oAdreca) 
{
	return esPanellAdrecaCatalana(oAdreca); // ICC nomes normalitza catalanes
}

////////////////////////////////////////////////////////////
// Nom: modifAdreca
// Descripció:  Mètode que aplica les accions necessaris quan es modifica un camp d'una adreça (no normalitzada i esborra Txt normalizador).
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
////////////////////////////////////////////////////////////    
function modifAdreca(oAdreca)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (scoGSITVal.isFormulariAcusament()) return;

		var oEsNorm = scoGSITPanells.obtenirObjecteFill(oAdreca, "TXT_ES_NORMALITZADA");
		if (oAdreca != null && oEsNorm != null)
		{
			if (oEsNorm.rawValue != "false") oEsNorm.rawValue = "false";

			var oPanellNormalitzador = scoGSITCamps.obtenirValorVariable(oAdreca, "oPanellNormalitzador");
			if (oPanellNormalitzador != null)
			{
				if (typeof(oPanellNormalitzador ) == "string") oPanellNormalitzador = xfa.resolveNode(oPanellNormalitzador);
			}

			if (oPanellNormalitzador == null) return;

			// Modificada l'adreca ho indiquem al Normalitzador 
			var oTxtResultat = scoGSITPanells.obtenirObjecteFill(oPanellNormalitzador, "TXT_RESULTAT");
			if (oTxtResultat != null)
			{
				if (oTxtResultat.rawValue != "") oTxtResultat.rawValue = "";
			}
			else 
				app.alert("ATENCIÓ FACTORIA, el panell de normalització d'adreces no està ben definit o aquest no conté el camp TXT_RESULTAT. Reviseu-lo.");

			var oTxtNormalitzada = scoGSITPanells.obtenirObjecteFill(oPanellNormalitzador, "TXT_NORMALITZADA");
			if (oTxtNormalitzada != null)
			{
				if (oTxtNormalitzada.rawValue != "") oTxtNormalitzada.rawValue = "";
			}
			else 
				app.alert("ATENCIÓ FACTORIA, el panell de normalització d'adreces no està ben definit o aquest no conté el camp TXT_NORMALITZADA. Reviseu-lo.");

			scoGSITBot.canviEstatAcceptar(0, null, oPanellNormalitzador.BTN_ACCEPTAR);
			scoGSITBot.canviEstatAcceptar(1, "0,0,0", oPanellNormalitzador.BTN_BUSCAR);
			oPanellNormalitzador.TXT_VERIFICAT = "0";

			if (!esPotNormalitzar(oAdreca)) scoGSITBot.canviEstatAcceptar(0, null, oPanellNormalitzador.BTN_BUSCAR);

		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::modifAdreca", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: esNormalitzada
// Descripció: Mètode que verifica si el panell d'adreça està normalitzada.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
// Paràmetres de sortida:
//		booleà - Valor (true/false) segons si l'adreça està normalitzada
////////////////////////////////////////////////////////////    
function esNormalitzada(oAdreca)
{
	try
	{
		var esNomalitzada = scoGSITVal.isEmpty(oAdreca.TXT_ES_NORMALITZADA) ? null : oAdreca.TXT_ES_NORMALITZADA.rawValue;
		esNomalitzada = ((esNomalitzada == null) || (esNomalitzada == undefined)) ? "FALSE" : esNomalitzada.toUpperCase();

		return ((esNomalitzada == "FALSE") ? false : true);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::esNormalitzada", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: defProvinciaCat
// Descripció: Mètode que inicialitza la llista de províncies catalanes de 'oAdreca'.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
////////////////////////////////////////////////////////////    
function defProvinciaCat(oAdreca)   
{
	try
	{ 
		var oProvincies = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_PROVINCIES");
		var arrValors = scoGSITProvInfo.arrProvinciesCat;
		scoGSITCombo.inicialitzaLlistaSiBuida(oProvincies, arrValors);	
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::initProvinciaCat", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: defComarcaCat
// Descripció: Mètode que inicialitza la llista de comarques catalanes de 'oAdreca'.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
////////////////////////////////////////////////////////////    
function defComarcaCat(oAdreca)   
{
	try
	{ 
		var oComarques = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_COMARQUES");
		var oProvincies = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_PROVINCIES");

		var arrValors = eval("scoGSITComInfo.arr" + oProvincies.rawValue);
		scoGSITCombo.inicialitzaLlistaSiBuida(oComarques, arrValors);	
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::initProvinciaCat", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: initProvinciaCat
// Descripció: Mètode que inicialitza la llista de províncies catalanes i si cal també la de comarques del panell 'oAdreca'.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		aLlistesDesti - Llista en la qual hi ha definides les províncies
//		bTeComarca - Indica si a les adreces catalanes es mostrarà la comarca, si no s'especifica és 'false'
////////////////////////////////////////////////////////////    
function initProvinciaCat(oAdreca, aLlistesDesti, bTeComarca)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		if (arguments.length < 3) bTeComarca = mostrarComarcaPanell(oAdreca, true);

		var arrValors = scoGSITProvInfo.arrProvinciesCat;
		var oProvincies = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_PROVINCIES");
		var oComarques = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_COMARQUES");
		var oMunicipis = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_MUNICIPIS");	

		defPaisEsp(oAdreca);
		scoGSITCombo.inicialitzaLlistaSiBuida(oProvincies, arrValors);		

		if (!scoGSITVal.isEmpty(oProvincies.editValue) && (esProvinciaCatalana(oProvincies)))
		{	
			if (bTeComarca)
			{
				carregaLlistaRel(oAdreca, oProvincies, oComarques, arrValors, "scoGSITComInfo", false, bTeComarca, aLlistesDesti, 0);
				oMunicipis.clearItems();
				carregaLlistaRel(oAdreca, oComarques, oMunicipis, eval(aLlistesDesti[0]), "scoGSITMunCatInfo", false, bTeComarca, aLlistesDesti, 1);
			}				
			else
			{		
				esborraInfoAdre(oAdreca, [oComarques], ["Comarca"]);
				carregaLlistaRel(oAdreca, oProvincies, oMunicipis, arrValors, "scoGSITMunCatInfo", false);
			}
		}
		else
		{
			esborraInfoAdre(oAdreca, [oComarques, oMunicipis], ["Comarca", "Municipi", "UnitatPoblacional"]);
		}		
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::initProvinciaCat", exc);
	}	
}


////////////////////////////////////////////////////////////
// Nom: initProvinciaEsp
// Descripció: Mètode que inicialitza la llista de províncies espanyoles i si cal també la de municipis del panell 'oAdreca'.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
////////////////////////////////////////////////////////////    
function initProvinciaEsp(oAdreca)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		var arrValors = scoGSITProvInfo.arrProvinciesEsp;
		var oProvincies = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_PROVINCIES");
		var oMunis = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_MUNICIPIS");			

		defPaisEsp(oAdreca);
		scoGSITCombo.inicialitzaLlistaSiBuida(oProvincies, arrValors);		

		if (!scoGSITVal.isEmpty(oProvincies.editValue) && esAdrecaEspanyola(oAdreca))
			carregaLlistaRel(oAdreca, oProvincies, oMunis, arrValors, "scoGSITMunEspInfo", false);
		else
			esborraInfoAdre(oAdreca, [oMunis], ["Comarca", "Municipi", "UnitatPoblacional"]);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::initProvinciaEsp", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: pintaCampsExt
// Descripció: Mètode que pinta els camps d'adreça extragera
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
////////////////////////////////////////////////////////////    
function pintaCampsExt(oAdreca)
{
	var oPais = scoGSITPanells.obtenirObjecteFill(oAdreca, "TXT_PAIS");
	var oMuni = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_MUNICIPIS_ESTR");

	if (scoGSITVal.existeixObjecte(oPais))
	{
		oPais.x = "124.8mm";
		oPais.w = "41mm";
		if (!scoGSITVal.isFormulariAcusament())
		{
			oPais.access = "open";  // Para mantener versiones anteriores   
			oPais.validate.nullTest = "error";
		}
	}

	if (scoGSITVal.existeixObjecte(oMuni))
	{
		oMuni.x = "0mm";
		oMuni.w = "124mm";
	}	
}

////////////////////////////////////////////////////////////
// Nom: pintaCampsComarcaMuniPais
// Descripció: Mètode que pinta els camps Comarca, Municipi i Pais si cal i de la mida i a la posició necesària
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		bBuit - Boolea que indica si el camp de província pot ser buit i mostrar comarca 
////////////////////////////////////////////////////////////    
function pintaCampsComarcaMuniPais(oAdreca, bBuit) 
{
	if (arguments.length < 2) bBuit = false;

	var oProvincies = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_PROVINCIES");
	var oComarca = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_COMARQUES");
	var oMunis = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_MUNICIPIS");
	var oPaisNom = scoGSITPanells.obtenirObjecteFill(oAdreca, "TXT_PAIS_NOM");

	var bMostraComarca = mostrarComarcaPanell(oAdreca, bBuit);
	var bMostraPais = calMostrarPais(oAdreca);

	if (scoGSITVal.existeixObjecte(oProvincies)) 
	{
		oProvincies.x = "0mm";
		oProvincies.w = "44mm";
	}

	if (scoGSITVal.existeixObjecte(oComarca))
	{
		oComarca.presence = ((bMostraComarca) ?  "visible" : "hidden");
		oComarca.x = "45mm";
		oComarca.w = "37mm";
	}

	if (scoGSITVal.existeixObjecte(oMunis))
	{
		oMunis.x = 45 + ((bMostraComarca) ? 38 : 0) + "mm";
		oMunis.w = (120.65 - ((bMostraPais) ? 18 : 0) - ((bMostraComarca) ? 38 : 0)) + "mm";
	}

	if (scoGSITVal.existeixObjecte(oPaisNom))
	{	
		oPaisNom.x = "148.8mm";
		oPaisNom.w = "17mm";
		oPaisNom.presence = (bMostraPais) ? "visible" : "hidden";
	}
}

////////////////////////////////////////////////////////////
// Nom: initProvinciaCatEsp
// Descripció: Mètode que inicialitza la llista de províncies, i si cal la de comarques per CA i la de municipis per ES del panell 'oAdreca'.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
////////////////////////////////////////////////////////////    
function initProvinciaCatEsp(oAdreca)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		pintaCampsComarcaMuniPais(oAdreca, false);

		// TODO		if (scoGSITVal.isFormulariAcusament())  return;

		initProvinciaEsp(oAdreca);

		var bMostraComarca = mostrarComarcaPanell(oAdreca, false);
		if (bMostraComarca)
		{
			var arrAdrecaCat = scoGSITPanells.obtenirArrAdreca(oAdreca);
			initProvinciaCat(oAdreca, arrAdrecaCat, bMostraComarca);
			initComarcaCat(oAdreca, arrAdrecaCat, bMostraComarca);
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::initProvinciaCatEsp", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: canviProvinciaCatEsp
// Descripció: Mètode que aplica les modificacions necessàries quan es canvia una província depenent de si és CAT o ESP
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		bModifAdreca - Indica si aquest canvi s'ha de reflexar al Normalitzador
////////////////////////////////////////////////////////////   		
function canviProvinciaCatEsp(oAdreca, bModifAdreca)
{
	if (scoGSITVal.isFormulariValidat()) return;
	if (arguments.length <2) bModifAdreca = true;

	if (mostrarComarcaPanell(oAdreca, false))  canviProvinciaCat(oAdreca, bModifAdreca);
	else                                       canviProvinciaEsp(oAdreca, bModifAdreca);

	pintaCampsComarcaMuniPais(oAdreca, false);
}

////////////////////////////////////////////////////////////
// Nom: initComarcaCat
// Descripció: Mètode que inicialitza la llista de comarques catalanes.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		aLlistesDesti - Llista en la qual hi han definides les comarques.
//		bTeComarca - Indica si a les adreces catalanes es mostrarà la comarca, si no s'especifica és 'false'
////////////////////////////////////////////////////////////    
function initComarcaCat(oAdreca, aLlistesDesti, bTeComarca) 
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (arguments.length < 3) bTeComarca = false;

		var oProvincies = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_PROVINCIES");
		var oComarques = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_COMARQUES");
		var oMunicipis = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_MUNICIPIS");		

		if (!scoGSITVal.isEmpty(oComarques.editValue) && (esProvinciaCatalana(oProvincies)))
			carregaLlistaRel(oAdreca, oComarques, oMunicipis, eval(aLlistesDesti[0]), "scoGSITMunCatInfo", false, bTeComarca, aLlistesDesti, 1);
		else
			esborraInfoAdre(oAdreca, [oMunicipis], ["Municipi", "UnitatPoblacional"]);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::initComarcaCat", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: initMunicipisCatLlogUnitPob
// Descripció: Mètode que inicialitza la llista de llogarets a partir dels municipis tenint en compte que el següent camp pot se un llogaret o una unitat poblacional
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		aLlistesDesti - Llista en la qual hi han definits els llogarets.
//		bUnitatPob - Booleà que indica si és una Unitat poblacional (true) o un LLogaret (false)
////////////////////////////////////////////////////////////    
function initMunicipisCatLlogUnitPob(oAdreca, aLlistesDesti, bUnitatPob)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		var sModul = (bUnitatPob) ? "scoGSITUnitatPobInfo" : "scoGSITLlogInfo";
		var oProvincies = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_PROVINCIES");
		var oMunicipis = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_MUNICIPIS");
		var oLlogarets = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_LLOGARETS");

		if (!scoGSITVal.isEmpty(oMunicipis.editValue) && (esProvinciaCatalana(oProvincies)))
			carregaLlistaRel(oAdreca, oMunicipis, oLlogarets, eval(aLlistesDesti[1]), sModul, false, false);
		else
			esborraInfoAdre(oAdreca, [oLlogarets], ["UnitatPoblacional"]);

	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::initMunicipisCatLlogUnitPob", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: initMunicipisCat
// Descripció: Mètode que inicialitza la llista de llogarets a partir dels municipis.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		aLlistesDesti - Llista en la qual hi han definits els llogarets.
////////////////////////////////////////////////////////////    
function initMunicipisCat(oAdreca, aLlistesDesti)
{
	initMunicipisCatLlogUnitPob(oAdreca, aLlistesDesti, false);
}

////////////////////////////////////////////////////////////
// Nom: canviValorCombo
// Descripció: Mètode que mira si s'ha canviat la selecció del combo
// Paràmetres d'entrada:
//		oCombo - Camp de combo
//		oNom - Camp on es guarda el nom del valor del combo
////////////////////////////////////////////////////////////    
function canviValorCombo(oCombo, oNom)
{
	var sCombo = scoGSITVal.isEmpty(oCombo.editValue) ? "" : oCombo.editValue;
	var sTxt = scoGSITVal.isEmpty(oNom.rawValue) ? "" : oNom.rawValue;
	return (sCombo.toUpperCase() != sTxt.toUpperCase());
}		

////////////////////////////////////////////////////////////
// Nom: canviComboProvinciaCatalana
// Descripció: Mètode que aplica les modificacions necessàries quan es canvia una província catalana.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		bModifAdreca - Indica si aquest canvi s'ha de reflexar al Normalitzador
//		bTeComarca - Indica si a les adreces catalanes es mostrarà la comarca, si no s'especifica és 'false'
//		sModul - llibreria on es troba l'array a carregar
//		sCombo - Nom del combo on es carregarà la llista
//		aLlistesDesti - Llista en la qual es defineix el nom de la llista carregada
//		nPosLlista - Posició de 'aLlistesDesti' a la que es guardarà el valor
//		aLlistes - Array amb les llistes a esborrar
//		aNodes - Array de nodes de l'adreça per esborrar
////////////////////////////////////////////////////////////    
function canviComboProvinciaCatalana(oAdreca, bModifAdreca, bTeComarca, sModul, sCombo, aLlistesDesti, nPosLlista, sLlistes, aNodes)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		if (arguments.length < 2) bModifAdreca = true;
		if (arguments.length < 3) bTeComarca = mostrarComarcaPanell(oAdreca, true);

		var oProvincies = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_PROVINCIES"); // S'han de definir tots pq poden estar a sLlistes
		var oProvNom = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_PROVINCIES_NOM");
		var oComarques = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_COMARQUES");
		var oMunicipis = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_MUNICIPIS");
		var oLlogarets = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_LLOGARETS");

		var oLlista = scoGSITPanells.obtenirObjecteFill(oAdreca, sCombo);

		if (scoGSITVal.isEmpty(oProvincies.editValue)) return;

		if (canviValorCombo(oProvincies, oProvNom))
		{	
			oProvNom.rawValue = oProvincies.editValue;	
			carregaLlistaRel(oAdreca, oProvincies, oLlista, scoGSITProvInfo.arrProvinciesCat, sModul, true, bTeComarca, aLlistesDesti, nPosLlista);

			esborraInfoAdre(oAdreca, eval(sLlistes), aNodes);
			if (bModifAdreca) modifAdreca(oAdreca);
		}	
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::canviProvinciaCat", exc);
	}	
}


////////////////////////////////////////////////////////////
// Nom: canviComboProvCat
// Descripció: Mètode que aplica les modificacions necessàries quan es canvia una província catalana
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		bModifAdreca - Indica si aquest canvi s'ha de reflexar al Normalitzador
//		bTeComarca - Indica si a les adreces catalanes es mostrarà la comarca, si no s'especifica és 'false'
////////////////////////////////////////////////////////////    
function canviComboProvCat(oAdreca, bModifAdreca, bTeComarca)
{
	try 
	{
		if (scoGSITVal.isFormulariValidat()) return;

		if (arguments.length < 2) bModifAdreca = true;
		if (arguments.length < 3) bTeComarca = mostrarComarcaPanell(oAdreca, true);

		var oProvincies = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_PROVINCIES");
		var oProvNom = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_PROVINCIES_NOM");
		var oComarques = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_COMARQUES");
		var oMunicipis = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_MUNICIPIS");
		var oLlogarets = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_LLOGARETS");

		if (scoGSITVal.isEmpty(oProvincies.editValue)) return;

		if (canviValorCombo(oProvincies, oProvNom))
		{	
			oProvNom.rawValue = oProvincies.editValue;	
			if (bModifAdreca) modifAdreca(oAdreca);	

			if (bTeComarca)
			{
				carregaLlistaRel(oAdreca, oProvincies, oComarques, scoGSITProvInfo.arrProvinciesCat, "scoGSITComInfo", true, bTeComarca, scoGSITPanells.obtenirArrAdreca(oAdreca), 0);
				esborraInfoAdre(oAdreca, [oMunicipis, oLlogarets], ["Comarca", "Municipi", "UnitatPoblacional"]);
			}
			else
			{
				carregaLlistaRel(oAdreca, oProvincies, oMunicipis, scoGSITProvInfo.arrProvinciesCat, "scoGSITMunCatInfo", true, false);
				esborraInfoAdre(oAdreca, [oComarques, oLlogarets], ["Comarca", "Municipi", "UnitatPoblacional"]);
			}
		}		
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::canviProvinciaCat", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: canviProvinciaCat
// Descripció: Mètode que aplica les modificacions necessàries quan es canvia una província catalana.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		bModifAdreca - Indica si aquest canvi s'ha de reflexar al Normalitzador
//		bTeComarca - Indica si a les adreces catalanes es mostrarà la comarca, si no s'especifica és 'false'
////////////////////////////////////////////////////////////    
function canviProvinciaCat(oAdreca, bModifAdreca, bTeComarca)
{
	canviComboProvCat(oAdreca, bModifAdreca, true);
}

////////////////////////////////////////////////////////////
// Nom: canviProvinciaCatNoComarca
// Descripció: Mètode que aplica les modificacions necessàries quan es canvia una província catalana i no es defineix comarcas
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		bModifAdreca - Indica si aquest canvi s'ha de reflexar al Normalitzador
////////////////////////////////////////////////////////////    
function canviProvinciaCatNoComarca(oAdreca, bModifAdreca)
{
	canviComboProvCat(oAdreca, bModifAdreca, false);
}

////////////////////////////////////////////////////////////
// Nom: canviProvinciaCatalana
// Descripció: Mètode que aplica les modificacions necessàries quan es canvia una província catalana controlant si té o no comarca
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		bModifAdreca - Indica si aquest canvi s'ha de reflexar al Normalitzador
////////////////////////////////////////////////////////////    
function canviProvinciaCatalana(oAdreca, bModifAdreca)  
{
	if (arguments.length < 2) bModifAdreca = true;

	defPaisEsp(oAdreca);

	var bDefComarca = scoGSITVal.existeixObjecteFill(oAdreca, "TXT_MOSTRAR_COMARCA");
	var bMostraComarca = (bDefComarca) ? mostrarComarcaPanell(oAdreca, true) : true;

	if (bMostraComarca) canviProvinciaCat(oAdreca, bModifAdreca, true);
	else                canviProvinciaCatNoComarca(oAdreca, bModifAdreca);
}


////////////////////////////////////////////////////////////
// Nom: canviProvinciaEsp
// Descripció: Mètode que aplica les modificacions necessàries quan es canvia el valor d'una província espanyola.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		bModifAdreca - Indica si aquest canvi s'ha de reflexar al Normalitzador
////////////////////////////////////////////////////////////    
function canviProvinciaEsp(oAdreca, bModifAdreca)
{
	try 
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (arguments.length < 2) bModifAdreca = true;

		var oProvincies = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_PROVINCIES");
		var oProvNom = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_PROVINCIES_NOM");
		var oMunis = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_MUNICIPIS");

		if (scoGSITVal.isEmpty(oProvincies.editValue)) return;

		if (canviValorCombo(oProvincies, oProvNom))
		{	
			oProvNom.rawValue = oProvincies.editValue;	
			if (bModifAdreca) modifAdreca(oAdreca);	

			carregaLlistaRel(oAdreca, oProvincies, oMunis, scoGSITProvInfo.arrProvinciesEsp, "scoGSITMunEspInfo", true, true);
			esborraInfoAdre(oAdreca, [], ["Comarca", "Municipi", "UnitatPoblacional"]);
		}				
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::canviProvinciaEsp", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: canviComarcaCat
// Descripció: Mètode que aplica les modificacions necessàries quan es canvia el valor d'una comarca catalana.
// Paràmetres d'entrada:
//		oAdreca - Panell d'dreça
//		bModifAdreca - Indica si aquest canvi s'ha de reflexar al Normalitzador
////////////////////////////////////////////////////////////    
function canviComarcaCat(oAdreca, bModifAdreca)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (arguments.length < 2) bModifAdreca = true;

		var oComarques = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_COMARQUES");
		var oComarNom = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_COMARQUES_NOM");
		var oMunicipis = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_MUNICIPIS");
		var oLlogarets = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_LLOGARETS");

		if (scoGSITVal.isEmpty(oComarques.editValue)) return;

		if (canviValorCombo(oComarques, oComarNom))
		{	
			oComarNom.rawValue = oComarques.editValue;
			if (bModifAdreca) modifAdreca(oAdreca);

			var	aLlistesDesti = scoGSITPanells.obtenirArrAdreca(oAdreca);	
			carregaLlistaRel(oAdreca, oComarques, oMunicipis, eval(aLlistesDesti[0]), "scoGSITMunCatInfo", true, false, aLlistesDesti, 1);

			esborraInfoAdre(oAdreca, [oLlogarets], ["Municipi", "UnitatPoblacional"]);
		}	
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::canviComarcaCat", exc);
	}	
}


////////////////////////////////////////////////////////////
// Nom: canviMunicipiCatLlogUnitPob
// Descripció: Mètode que aplica les modificacions necessàries quan es canvia el valor d'un municipi català tenint en compte que el següent camp pot se un llogaret o una unitat poblacional
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		bUnitatPob - Booleà que indica si és una Unitat poblacional (true) o un LLogaret (false)
//		bModifAdreca - Indica si aquest canvi s'ha de reflexar al Normalitzador
////////////////////////////////////////////////////////////    
function canviMunicipiCatLlogUnitPob(oAdreca, bUnitatPob, bModifAdreca)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (arguments.length < 3) bModifAdreca = true;

		var oMunicipis = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_MUNICIPIS");
		var oMuniNom = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_MUNICIPIS_NOM");
		var oLlogarets = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_LLOGARETS");

		if (scoGSITVal.isEmpty(oMunicipis.editValue)) return;

		if (canviValorCombo(oMunicipis, oMuniNom))
		{
			oMuniNom.rawValue = oMunicipis.editValue;
			if (bModifAdreca) modifAdreca(oAdreca);

			if (scoGSITVal.existeixObjecte(oLlogarets))
			{
				var aLlistesDesti = scoGSITPanells.obtenirArrAdreca(oAdreca);
				var sModul = (bUnitatPob) ? "scoGSITUnitatPobInfo" : "scoGSITLlogInfo";
				scoGSITCombo.carregaSeguentLlista(oMunicipis, oLlogarets, eval(aLlistesDesti[1]), sModul, true);	
			}

			esborraAdrecaXML(scoGSITPanells.obtenirBindObjecte(oAdreca, "", true), ["UnitatPoblacional"]);
		}		
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::canviMunicipiCat", exc);
	}	
}


////////////////////////////////////////////////////////////
// Nom: canviMunicipiCat
// Descripció: Mètode que aplica les modificacions necessàries quan es canvia el valor d'un municipi català.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
////////////////////////////////////////////////////////////    
function canviMunicipiCat(oAdreca)
{
	canviMunicipiCatLlogUnitPob(oAdreca, false);
}

////////////////////////////////////////////////////////////
// Nom: canviMunicipiCatUnitatPob
// Descripció: Mètode que aplica les modificacions necessàries quan es canvia el valor d'un municipi català i el següent és unitat poblacional
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
////////////////////////////////////////////////////////////    
function canviMunicipiCatUnitatPob(oAdreca)
{
	canviMunicipiCatLlogUnitPob(oAdreca, true);
}

////////////////////////////////////////////////////////////
// Nom: canviMunicipiEsp
// Descripció: Mètode que aplica les modificacions necessàries quan es canvia el valor d'un municipi espanyol.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		bModifAdreca - Indica si aquest canvi s'ha de reflexar al Normalitzador
////////////////////////////////////////////////////////////    
function canviMunicipiEsp(oAdreca, bModifAdreca)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (arguments.length < 2) bModifAdreca = true;

		var oMunicipis = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_MUNICIPIS");
		if (scoGSITVal.existeixObjecte(oMunicipis)) scoGSITVal.defValor(oAdreca, "LLISTA_MUNICIPIS_NOM", oMunicipis.editValue);

		var aNodos = (mostrarComarcaPanell(oAdreca) ? ["UnitatPoblacional"] : ["Comarca", "UnitatPoblacional"]);
		esborraAdrecaXML(scoGSITPanells.obtenirBindObjecte(oAdreca, "", true), aNodos);

		if (bModifAdreca) modifAdreca(oAdreca);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::canviMunicipiEsp", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: canviLlogaretCat
// Descripció: Mètode que aplica les modificacions necessàries quan es canvia el valor d'un llogaret d'un municipi català.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		bModifAdreca - Indica si aquest canvi s'ha de reflexar al Normalitzador
////////////////////////////////////////////////////////////    
function canviLlogaretCat(oAdreca, bModifAdreca)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (arguments.length < 2) bModifAdreca = true;		

		var oLlogarets = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_LLOGARETS");
		if (scoGSITVal.existeixObjecte(oLlogarets)) scoGSITVal.defValor(oAdreca, "LLISTA_LLOGARETS_NOM", oLlogarets.editValue);
		if (bModifAdreca) modifAdreca(oAdreca);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::canviLlogaretCat", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: canviPais
// Descripció : Mètode que aplica les modificacions necessàries quan es canvia el valor d'un país d'un panell d'adreça.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		bEstrangera - Valor (true/false) que indica si l'adreça definida és estrangera
//		aEstranger - Llista de camps propis d'adreça estrangera
//		aEspanyol - Llista de camps propis d'adreça espanyola
////////////////////////////////////////////////////////////    
function canviPais(oAdreca, bEstrangera, aEstranger, aEspanyol)
{
	try
	{
		scoGSITGen.netejarForm(oAdreca);

		var aEstranger = [oAdreca.TXT_PAIS, oAdreca.TXT_MUNICIPI_EXT];
		var aEspanyol = [oAdreca.LLISTA_PROVINCIES, oAdreca.LLISTA_MUNICIPIS];

		if (bEstrangera)
		{
			scoGSITPanells.defCampsPropietats(aEstranger, "open", "error", "visible", "");
			scoGSITPanells.defCampsPropietats(aEspanyol, "protected", "", "hidden", "");
		}
		else
		{
			scoGSITPanells.defCampsPropietats(aEspanyol, "open", "error", "visible", "");
			scoGSITPanells.defCampsPropietats(aEstranger, "protected", "", "hidden", "");
			defPaisEsp(oAdreca);
			initProvinciaEsp(oAdreca);
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::canviPais", exc);
	}	
}               

////////////////////////////////////////////////////////////
// Nom: canviNacionalitatIDParticularNac
// Descripció: Mètode que aplica les modificacions necessàries quan es canvia el valor del lloc de naixement de la persona, entre espanyola i estrangera
// Paràmetres d'entrada:
//		oChkEsEspanyol - Camp de selecció que indica si la persona es espanyola o estrangera
////////////////////////////////////////////////////////////    
function canviNacionalitatIDParticularNac(oChkEsEspanyol)
{
	try
	{
		var oAdreca = oChkEsEspanyol.parent.NAIXEMENT.LOCALITAT;
		var bEstrangera = (oChkEsEspanyol.rawValue == '1');

		var aEstranger = [oAdreca.TXT_PAIS, oAdreca.TXT_MUNICIPI_EXT];
		var aEspanyol = [oAdreca.LLISTA_PROVINCIES, oAdreca.LLISTA_MUNICIPIS];
		canviPais(oAdreca, bEstrangera, aEstranger, aEspanyol);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::canviNacionalitatIDParticularNac", exc);
	}	
}   

////////////////////////////////////////////////////////////
// Nom: initPaisIDParticularNac
// Descripció: Mètode que aplica les modificacions necessàries al inicialitzar una adreça del panell: DADES_IDENTIFICACIO_PARTICULAR_NAC.
// Paràmetres d'entrada:
//		oPais - Camp llista de països
////////////////////////////////////////////////////////////    
function initPaisIDParticularNac(oPais)
{
	try
	{
		if (!scoGSITVal.existeixObjecte(oPais)) return;

		if (oPais.length == 0)
		{
			var arrValors = scoGSITPaisInfo.getLlistaPaisosINE();
			scoGSITCombo.inicialitzaLlista(oPais, arrValors);
		}

		var oAdreca = oPais.parent;	
		var aExtranger = [oAdreca.TXT_PAIS, oAdreca.TXT_MUNICIPI_EXT];
		var aEspanyol = [oAdreca.LLISTA_PROVINCIES, oAdreca.LLISTA_MUNICIPIS];

		if(!scoGSITVal.isEmpty(oPais))
		{
			if (!esPaisEspana(oPais))
			{
				var aExtrangerVal = [oAdreca.TXT_PAIS.rawValue, oAdreca.TXT_MUNICIPI_EXT.rawValue];			
				oPais.parent.parent.parent.CHK_ES_ESPANYOL.rawValue = "1";
				scoGSITPanells.defCampsPropietatsValors(aExtranger, "open", "error", "visible", aExtrangerVal);
				scoGSITPanells.defCampsPropietats(aEspanyol, "protected", "", "hidden", "");	
			}
			else
			{
				initProvinciaEsp(oAdreca);			
			}
		}
		else
		{
			scoGSITPanells.defCampsPropietats(aEspanyol, "open", "error", "visible", "");
			scoGSITPanells.defCampsPropietats(aExtranger, "protected", "", "hidden", "");		
			initProvinciaEsp(oAdreca);	
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::initPaisIDParticularNac", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: compPaisEstranger
// Descripció: Mètode que aplica les modificacions necessàries quan es canvia el valor d'una país d'un panell d'adreça.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		bEstrangera - Valor (true/false) que indica si l'adreça definida és estrangera
////////////////////////////////////////////////////////////    
function compPaisEstranger(oAdreca, bEstrangera)
{
	if (scoGSITVal.isEmpty(oAdreca.TXT_PAIS)) return;

	if ((esPaisEspana(oAdreca.TXT_PAIS)) && bEstrangera)
	{
		xfa.host.messageBox(msgErrorPaisEstrangerNac.value);
		oAdreca.TXT_PAIS.rawValue = "";
	}

	oAdreca.TXT_PAIS_NOM.rawValue = oAdreca.TXT_PAIS.editValue;
}

////////////////////////////////////////////////////////////
// Nom: defCheckPais
// Descripció: Mètode que marca o no el check d'adreça estrangera depenent del pais seleccionat
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça estrangera
////////////////////////////////////////////////////////////   
function defCheckPais(oAdreca, bAdreEstrangera)
{
	var oChk = scoGSITPanells.obtenirObjecteFill(oAdreca, "CHK_RESIDENCIA");
	if (oChk == null) return;

	if (arguments.length < 2) bAdreEstrangera = esPanellAdrecaEstrangera(oAdreca);

	oChk.rawValue = (bAdreEstrangera) ? "1" : "0";
}

////////////////////////////////////////////////////////////
// Nom: calMostrarCamp
// Descripció: Mètode que indica si s'ha de mostrar un camp del panell depenent de 'sCamp'
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça estrangera
//		sCamp - Camp que indica si s'ha de mostrar o no 
// Paràmetres de sortida:
//      booleà -  retorna si s'ha de mostrar el camp de comarca en funció de lo definit a 'sCamp', si no existeix retorna 'true'
////////////////////////////////////////////////////////////   
function calMostrarCamp(oAdreca, sCamp)
{
	var oMostrarCamp = scoGSITPanells.obtenirObjecteFill(oAdreca, sCamp);
	return (scoGSITVal.getValor(oMostrarCamp).toUpperCase() == "TRUE");
}

////////////////////////////////////////////////////////////
// Nom: calMostrarPais
// Descripció: Mètode que indica si cal mostrar el camp de Pais del panell a partir del valor de 'TXT_MOSTRAR_PAIS'
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça estrangera
// Paràmetres de sortida:
//      booleà -  retorna si s'ha de mostrar el camp de comarca en funció de lo definit a 'TXT_MOSTRAR_PAIS', si no existeix retorna 'false'
////////////////////////////////////////////////////////////   
function calMostrarPais(oAdreca)
{
	return  calMostrarCamp(oAdreca, "TXT_MOSTRAR_PAIS");
}

////////////////////////////////////////////////////////////
// Nom: calMostrarComarca
// Descripció: Mètode que indica si cal mostrar el camp de Comarca del panell a partir del valor de 'TXT_MOSTRAR_COMARCA'
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
// Paràmetres de sortida:
//      booleà -  retorna si s'ha de mostrar el camp de comarca en funció de lo definit a 'TXT_MOSTRAR_COMARCA', si no existeix retorna 'true'
////////////////////////////////////////////////////////////   
function calMostrarComarca(oAdreca)
{
	return  calMostrarCamp(oAdreca, "TXT_MOSTRAR_COMARCA");
}

////////////////////////////////////////////////////////////
// Nom: mostrarComarca
// Descripció: Mètode que indica si cal mostrar el camp de Comarca del panell a partir del valor de 'TXT_MOSTRAR_COMARCA' i de la província definida
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
//		bBuit - Boolea que indica si retornarà 'true' en el cas que sigui buit
// Paràmetres de sortida:
//      booleà -  retorna si s'ha de mostrar el camp de comarca en funció de 'TXT_MOSTRAR_COMARCA' i de si és província CAT 
function mostrarComarcaPanell(oAdreca, bBuit)
{
	if (arguments.length < 2) bBuit = false;

	var bExisteixCamp = scoGSITVal.existeixObjecteFill(oAdreca, "LLISTA_COMARQUES");
 	return (esPanellAdrecaCatalana(oAdreca, bBuit) && calMostrarComarca(oAdreca) && bExisteixCamp);
}

////////////////////////////////////////////////////////////
// Nom: pintaPanellAdrecaEstr
// Descripció: Mètode que mostra els camps que calgui del panell d'adreça estrangera.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça estrangera
////////////////////////////////////////////////////////////   
function pintaPanellAdrecaEstr(oAdreca)  
{    
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		var oChk = scoGSITPanells.obtenirObjecteFill(oAdreca, "CHK_RESIDENCIA");
		if (oChk == null) return;

		var bAdreEstrangera = oChk.rawValue == '1';
		var oCodiPostal = scoGSITPanells.obtenirObjecteFill(oAdreca, "TXT_CODI_POSTAL");
		scoGSITCamps.assignarCampObligatori(oCodiPostal, (!bAdreEstrangera && !scoGSITVal.isFormulariAcusament()));		

		if (bAdreEstrangera) 
		{
			scoGSITCamps.defCampsVisibilitat(getCampsExt(oAdreca), "visible");
			scoGSITCamps.defCampsVisibilitat(getCampsCatEsp(oAdreca), "hidden");
			if (scoGSITVal.isFormulariAcusament()){
				scoGSITCamps.defCampsVisibilitat(getCampsNoACK(oAdreca), "hidden");
			}
			pintaCampsExt(oAdreca);			

			if (!scoGSITVal.isFormulariAcusament()) {
				defLlistaPaisosExt(oAdreca);
				esborraAdrecaXML(scoGSITPanells.obtenirBindObjecte(oAdreca, "", true), ["Comarca", "UnitatPoblacional"]);
			}
		}
		else
		{	
			scoGSITCamps.defCampsVisibilitat(getCampsExt(oAdreca), "hidden");
			scoGSITCamps.defCampsVisibilitat(getCampsCatEsp(oAdreca), "visible"); 
			if (scoGSITVal.isFormulariAcusament()){
				scoGSITCamps.defCampsVisibilitat(getCampsNoACK(oAdreca), "hidden");
			}

			if (!scoGSITVal.isFormulariAcusament()) {			
				defPaisEsp(oAdreca);
				initProvinciaCatEsp(oAdreca);

				var aNodos = (mostrarComarcaPanell(oAdreca, false) ? ["UnitatPoblacional"] : ["Comarca", "UnitatPoblacional"]); 
				esborraAdrecaXML(scoGSITPanells.obtenirBindObjecte(oAdreca, "", true), aNodos);
			}
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::pintaPanellAdrecaEstr", exc);
	}			
}     

////////////////////////////////////////////////////////////
// Nom: defPanellAdrecaCat
// Descripció: Mètode que aplica les modificacions necessàries per inicialitzar el panell d'adreça CAT sense Unitats poblacionals ni Llogarets
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça CAT
////////////////////////////////////////////////////////////   
function defPanellAdrecaCat(oAdreca)    
{	
	if (!esPanellAdrecaCatalana(oAdreca))  scoGSITGen.netejarForm(oAdreca, false);

	defPaisEsp(oAdreca);

	var arrAdrecaCat = scoGSITPanells.obtenirArrAdreca(oAdreca);
	var bDefComarca = scoGSITVal.existeixObjecteFill(oAdreca, "TXT_MOSTRAR_COMARCA");
	var bMostraComarca = (bDefComarca) ? mostrarComarcaPanell(oAdreca, true) : true;

	initProvinciaCat(oAdreca, arrAdrecaCat, bMostraComarca);
	if (bMostraComarca) initComarcaCat(oAdreca, arrAdrecaCat, bMostraComarca);
	else                canviProvinciaCatNoComarca(oAdreca);

	if (bDefComarca) pintaCampsComarcaMuniPais(oAdreca, true);
}

////////////////////////////////////////////////////////////
// Nom: defPanellAdrecaEsp
// Descripció: Mètode que aplica les modificacions necessàries per inicialitzar el panell d'adreça ESP
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça ESP
////////////////////////////////////////////////////////////   
function defPanellAdrecaEsp(oAdreca)  
{
	if (scoGSITVal.isFormulariValidat()) return;  
	if (!esPanellAdrecaEspanyola(oAdreca))  scoGSITGen.netejarForm(oAdreca, false);

	modifAdreca(oAdreca);
	initProvinciaCatEsp(oAdreca);
}

////////////////////////////////////////////////////////////
// Nom: defPanellAdrecaEstr
// Descripció: Mètode que aplica les modificacions necessàries per inicialitzar el panell d'adreça estrangera.
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça estrangera
////////////////////////////////////////////////////////////   
function defPanellAdrecaEstr(oAdreca) 
{
	if (scoGSITVal.isFormulariValidat()) return;  
	if (!esNormalitzada(oAdreca)) modifAdreca(oAdreca);

	defCheckPais(oAdreca);  // Definim check depenen del Pais
	pintaPanellAdrecaEstr(oAdreca);
}

////////////////////////////////////////////////////////////
// Nom: defPanellAdrecaEstrMultiple
// Descripció: Mètode que aplica les modificacions necessàries per inicialitzar el panell d'adreça estrangera d'una panell múltiple
// Paràmetres d'entrada:
//		oPanellFJ - Panell a definir
////////////////////////////////////////////////////////////   
function defPanellAdrecaEstrMultiple(oPanell)
{
	defPanellAdrecaEstr(scoGSITPanells.obtenirPanellAdrecaPanellMultiple(oPanell, "ADRECA_ESTR"));
}

////////////////////////////////////////////////////////////
// Nom: defPanellAdrecaEstrFJ
// Descripció: Mètode que aplica les modificacions necessàries per inicialitzar el panell d'adreça estrangera d'una panell de física/jurídica.
// Paràmetres d'entrada:
//		oPanellFJ - Panell 'física/jurídica' a definir
////////////////////////////////////////////////////////////   
function defPanellAdrecaEstrFJ(oPanellFJ)
{
	defPanellAdrecaEstrMultiple(oPanellFJ);
}

////////////////////////////////////////////////////////////
// Nom: canviPanellAdrecaEstr
// Descripció: Mètode que aplica les modificacions necessàries per inicialitzar el panell d'adreça estrangera quan marca/desmarca check EXT
// Paràmetres d'entrada:
//		oChk - Camp de selecció d'adreça estrangera
////////////////////////////////////////////////////////////   
function canviPanellAdrecaEstr(oChk)  
{    
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		var oAdreca = scoGSITPanells.obtenirObjectePare(oChk, "ADRECA_ESTR");
		if (oAdreca == null) return;	

		esborraAdreca(oAdreca);
		modifAdreca(oAdreca);	
		pintaPanellAdrecaEstr(oAdreca);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITAdreca::canviPanellAdrecaEstr", exc);
	}			
}               

////////////////////////////////////////////////////////////
// Nom: assignarPaisNom
// Descripció: Mètode que assigna de forma automàtica el nom del país al respectiu camp
// Paràmetres d'entrada:
//		oCamp - Camp de país "TXT_PAIS"
//////////////////////////////////////////////////////////// 
function assignarPaisNom(oCamp)
{
	var sValor = oCamp.parent.TXT_PAIS.editValue;
	oCamp.parent.TXT_PAIS_NOM.rawValue = scoGSITVal.isEmpty(sValor) ? "" : sValor;
}

