/////////////////////////////////////////////////////////////////////////////
function desarFormulari()
{	
	app.execMenuItem("SaveAs");
}                    

////////////////////////////////////////////////////////////
// Nom: canviEstatAcceptar
// Descripció: Mètode que modifica l'estat de l'objecte a (Obert / protegit)
// Paràmetres d'entrada:
//		estat - "1" obert, "0" protegit
//		color - Color de la font del botó.
//		objBoto - Objecte botó al que se l'hi ha de canviar l'aspecte visual
////////////////////////////////////////////////////////////
function canviEstatAcceptar(estat,color,objBoto)
{
	try
	{
		if (!scoGSITVal.isFormulariAcusament())
		{
			if(estat)
				objBoto.access = "open";
			else
				objBoto.access = "protected";

			if(color!= "" && color!= null && color!= "undefined")
				objBoto.caption.font.fill.color.value = color;
			else
				objBoto.caption.font.fill.color.value = "125,125,125";
		}
	}catch(exc){
		return scoGSITGen.retornarExcepcio("scoGSITBot.canviEstatAcceptar() : \n", exc);
	}	
}    

////////////////////////////////////////////////////////////
// Nom: activaDesactivaBtn
// Descripció: Mètode que activa o desactiva 'oBtn'
// Paràmetres d'entrada: 
//		oBtn - Botó
// 		bActiva - Booleà que indica si es vol activar (true) o desactivar (false)
/////////////////////////////////////////////////////////////
function activaDesactivaBtn(oBtn, bActiva)
{
	if (scoGSITVal.isFormulariValidat())   return;
	if (!scoGSITVal.existeixObjecte(oBtn)) return;
	if(arguments.lenght < 2) bActiva = true;

	if (bActiva) 
		scoGSITBot.canviEstatAcceptar(1, "0,0,0", oBtn);			
	else 
		scoGSITBot.canviEstatAcceptar(0, null, oBtn);	
}

////////////////////////////////////////////////////////////
// Nom: copiarEstatBoto
// Descripció: Mètode que copia l'estat del botó origen cap al botó destí
// Paràmetres d'entrada:
//		oBtnOrigen - Objecte botó origen
//		oBtnDesti - Objecte botó destí
//////////////////////////////////////////////////////////// 
function copiarEstatBoto(oBtnOrigen, oBtnDesti)
{
	if (!scoGSITVal.isFormulariAcusament())
	{
		if (oBtnOrigen.access == "protected") 
			scoGSITBot.canviEstatAcceptar(0, null, oBtnDesti);
		else
			scoGSITBot.canviEstatAcceptar(1, "0,0,0", oBtnDesti);	
	}
}

////////////////////////////////////////////////////////////
// Nom: esborrarTextTramitValidat
// Descripció: Mètode que esborra el text que es mostra al validar el formulari en el panell de validació.
////////////////////////////////////////////////////////////
function esborrarTextTramitValidat()
{
	var oPanellValidacio = scoGSITPanells.obtenirPanellValidacio();
	if (oPanellValidacio == null) return;

	var txtXmlBuit = "<body xmlns=\"http:\/\/www.w3.org/1999/xhtml\" xmlns:xfa=\"http:\/\/www.xfa.org/schema/xfa-data/1.0/\">" + 
				"<p></p></body>";

	oPanellValidacio.TEXT_MSG_VALIDACIO.value.exData.loadXML(txtXmlBuit);
}


////////////////////////////////////////////////////////////
// Nom: definicioTextTramitInfoTramitacio
// Descripció: Mètode que composa el text que es mostra el formulari en el panell de validació per indicar com tramitar
////////////////////////////////////////////////////////////
function definicioTextTramitInfoTramitacio()
{
	try
	{
		if (scoGSITVal.esFormulariEACAT()) return;

		var sLink = scoGSITExData.maquetaLink(getURLTramit(), msgTramitEnLinia.value);	
		var sPunt1 = msgValidacioPunt1NoSignatura.value;			
		var sPunt2 = msgValidacioPunt2Ini.value + " " + sLink + msgValidacioPunt2Fi.value;

		var sEstils = "letter-spacing:0in;font-family:Arial;font-size:" + obtenirMidaText() + "pt";
		var txtInfo = scoGSITExData.maquetaParagraf(msgValidacioInfo.value, sEstils);
		var txtPunt1 = scoGSITExData.maquetaParagraf(sPunt1, sEstils);
		var txtPunt2 = scoGSITExData.maquetaParagraf(sPunt2, sEstils);

		scoGSITExData.defValueCampRichText(scoGSITPar.oPanellValidacio.TEXT_MSG_VALIDACIO, 
										   scoGSITExData.maquetaRichTextCamp((txtInfo + txtPunt1 + txtPunt2)), sEstils);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITBot::definicioTextTramitInfoTramitacio", exc);
	}										   
}


////////////////////////////////////////////////////////////
// Nom: definicioTextTramitValidat
// Descripció: Mètode que composa el text que es mostra al validar el formulari en el panell de validació.
// Paràmetres d'entrada:
//		bEstaFirmat: Valor (true/false) segons si el formulari està firmat o no
////////////////////////////////////////////////////////////
function definicioTextTramitValidat(bEstaFirmat)
{
	definicioTextTramitInfoTramitacio();

	if (scoGSITPar.bMostrarMarcaAigues)		scoGSITPanells.assignaMarcaAiguaFulls("");
}


////////////////////////////////////////////////////////////
// Nom: obtenirMidaText
// Descripció: Mètode que obté la mida de font definida per mostrar el missatge de formulari validat.
// Paràmetres de sortida:
//		Decimal - Valor de la mida de la font predefinidica en el scoGSITPar.midaTextValidacio
////////////////////////////////////////////////////////////
function obtenirMidaText()
{
	var sRetVal = 8;

	try
	{
		if (scoGSITPar.midaTextValidacio)
		{
			var midaText = "" + scoGSITPar.midaTextValidacio;
			if (scoGSITVal.isEmpty(midaText)) return sRetVal;

			var re = new RegExp("^[0-9]+$");
			if (re.test(midaText)) return midaText;
		 }
		 return sRetVal;
	}
	catch(e)
	{
		return sRetVal;
	}		
}



////////////////////////////////////////////////////////////
// Nom: definicioTextLOPD
// Descripció: Mètode que composa el text de LOPD que es mostra a partir del que arriba al XML precarregat
// Paràmetres d'entrada:
//		oPanellLOPD - Panell del text LOPD
//		sRutaXML - Ruta del XML on es troba el node Conformitats
////////////////////////////////////////////////////////////
function definicioTextLOPD(oPanellLOPD, sRutaXML, bMostrar)
{  
	try
	{

		var oTitol = oPanellLOPD.LOPD_TITOL;
		var oText = oPanellLOPD.LOPD_TEXT;
		var oTitolACK = oPanellLOPD.LOPD_TITOL_ACK;
		var oTextACK = oPanellLOPD.LOPD_TEXT_ACK;			

		oTitol.presence = (scoGSITVal.isFormulariAcusament())?"hidden":"visible";
		oText.presence = (scoGSITVal.isFormulariAcusament())?"hidden":"visible";
		oTitolACK.presence = (!scoGSITVal.isFormulariAcusament())?"hidden":"visible";
		oTextACK.presence = (!scoGSITVal.isFormulariAcusament())?"hidden":"visible";

		var bMostrarLOPD;
		if (scoGSITVal.isFormulariAcusament()) {
			bMostrarLOPD = !scoGSITVal.isEmpty(oTextACK);
		}
		else {
			if (arguments.length < 2) sRutaXML = "";
			sRutaXML = (sRutaXML == "") ? "xfa.record" : ("xfa.record." + sRutaXML);	

			var sRutaTitol = sRutaXML + ".Conformitats.Conformitat[0].Nom";
			var sRutaText =  sRutaXML + ".Conformitats.Conformitat[0].Descripcio";

			scoGSITExData.defRichTextVariesLiniesXML(oTitol, sRutaTitol, true, false, true);
			scoGSITExData.defRichTextVariesLiniesXML(oText, sRutaText, true, false, true);

			// Si títol buit --> posem valor per defecte
			if (scoGSITVal.isEmpty(oTitol))			oTitol.rawValue = msgTitolRGPD.value;
			bMostrarLOPD = !scoGSITVal.isEmpty(oText);
		}
		oPanellLOPD.presence = (!bMostrarLOPD) ? "hidden": "visible";	
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITBot::definicioTextLOPD", exc);
	}		
}

////////////////////////////////////////////////////////////
// Nom: definicioTextLOPD
// Descripció: Mètode que composa el text de LOPD que es mostra a partir del que arriba al XML precarregat als PDF del tramit
// Paràmetres d'entrada:
//		oPanellLOPD - Panell del text LOPD
////////////////////////////////////////////////////////////
function definicioTextLOPD_Tramit(oPanellLOPD, bMostrar)
{  
	definicioTextLOPD(oPanellLOPD, "DadesForm", bMostrar);
}

/*************************************************************************************************************
 Nom : scoGSITBotonera
 Descripció : Funcions relacionades amb les botoneres del PDF
**************************************************************************************************************/

///////////////////////////////////////////
// MÈTODES
///////////////////////////////////////////

/////////////////////////////////////////////////////////////////////////////
// Nom: posPagina
// Descripció: Retorna la posició de la pàgina a l'array scoGSITPar.arrayPagines
// Paràmetres d'entrada:
//		sPagina - Nom de la pàgina 
// Paràmetres de sortida:
//		integer - Posició de la pàgina a l'array scoGSITPar.arrayPagines
/////////////////////////////////////////////////////////////////////////////
function posPagina(sPagina)
{
	return (scoGSITPar.arrayPagines.indexOf(sPagina));
}

////////////////////////////////////////////////////////////
// Nom: errorPagina
// Descripció: Mètode que indica que hi ha hagut un error amb les pàgines 
// Paràmetres d'entrada:
//		nPagActual - Índex de la pàgina actual a l'array scoGSITPar.arrayPagines
////////////////////////////////////////////////////////////
function errorPagina(sMissatgeError)
{
	console.println(sMissatgeError);
	return null;	
}

/////////////////////////////////////////////////////////////////////////////
// Nom: paginaVisible
// Descripció: Retorna la pàgina 'nPag' si és una pàgina visible del formulari
// Paràmetres d'entrada:
//		nPag - Índex de la pàgina a l'array scoGSITPar.arrayPagines
// Paràmetres de sortida:
//		oPagina - La pàgina si és visible al formulari sinò null
/////////////////////////////////////////////////////////////////////////////
function paginaVisible(nPag)
{
	var sPagina = scoGSITPar.arrayPagines[nPag];
	var oPagina = xfa.resolveNode(scoGSITPar.nomFormulari + "." + sPagina);
	if (!scoGSITVal.existeixObjecte(oPagina))  return errorPagina("ERROR, No existeix la pàgina " + sPagina + ". Revisi scoGSITPar.arrayPagines");

	return ( (oPagina.presence == "visible") ? oPagina : null);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: obtenirPlanaAnteriorVisible
// Descripció: Retorna la pàgina anterior visible de 'nPagActual' a l'array scoGSITPar.arrayPagines
// Paràmetres d'entrada:
//		nPagActual - Índex de la pàgina actual a l'array scoGSITPar.arrayPagines
// Paràmetres de sortida:
//		oPagina - Pàgina anterior visible
/////////////////////////////////////////////////////////////////////////////
function obtenirPlanaAnteriorVisible(nPagActual)
{
	for (var nPag = (nPagActual-1); nPag >= 0; nPag--)
	{
		var oPagina = paginaVisible(nPag);
		if (oPagina != null) return oPagina;
	}

	return null;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: obtenirPlanaSeguentVisible
// Descripció: Retorna la pàgina següent visible de 'sPagina' a l'array scoGSITPar.arrayPagines
// Paràmetres d'entrada:
//		nPagActual - Índex de la pàgina actual a l'array scoGSITPar.arrayPagines
// Paràmetres de sortida:
//		oPagina - Pàgina següent visible
/////////////////////////////////////////////////////////////////////////////
function obtenirPlanaSeguentVisible(nPagActual)
{
	var nPagines = scoGSITPar.arrayPagines.length;
	for (var nPag = (nPagActual+1); nPag < nPagines; nPag++)
	{
		var oPagina = paginaVisible(nPag);
		if (oPagina != null) return oPagina;
	}

	return null;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: obtenirCampVisiblePerFocus
// Descripció: Retorna el nom del camp de la plana 'sPlana' per posicionar el focus
// Paràmetres d'entrada:
//		oPlana - Pàgina de la que es vol el camp
// Paràmetres de sortida:
//		oCamp - Camp de la pàgina visible per posicionar el focus
/////////////////////////////////////////////////////////////////////////////
function obtenirCampVisiblePerFocus(oPlana)
{
	try
	{
		if ((oPlana.className != "subform") && (oPlana.className != "field")) return null;

		var oCamps = oPlana.nodes; 		
		var numCamps = oCamps.length;
		for (var nCamp = 0; nCamp < numCamps; nCamp++)
		{
			var oCamp = oCamps.item(nCamp);
			if (oCamp.className == "subform")  oCamp = obtenirCampVisiblePerFocus(oCamp);		

			if (scoGSITNod.esObjeteTipusCamp(oCamp) && scoGSITCamps.esVisibleParents(oCamp)) return(oCamp);
		}

		return null;
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITBotonera::obtenirCampVisiblePerFocus", exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: posicionaPagina
// Descripció: Mètode que es posiciona a la pàgina anterior o seguent del PDF segons 'bAnterior'
// Paràmetres d'entrada:
//		sPagina - Nom de la pàgina 
//		bAnterior - Booleà ndica si es vol l'anterior o la següent
//////////////////////////////////////////////////////////// 
function posicionaPagina(sPagina, bAnterior)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		var nPagina = posPagina(sPagina);
		if (nPagina == -1) return errorPagina("ERROR, No s'ha trobat el nom de la pàgina: " + sPagina + ". Revisi scoGSITPar.arrayPagines");

		var oPlana = (bAnterior) ? obtenirPlanaAnteriorVisible(nPagina) : obtenirPlanaSeguentVisible(nPagina);
		if (oPlana == null) return errorPagina("ERROR, No s'ha trobat " + (bAnterior?"l'anterior ":"la següent") + " pàgina visible a la pàgina: " + sPagina + ". Revisi scoGSITPar.arrayPagines");

		var oCampFocus = obtenirCampVisiblePerFocus(oPlana);
		if (scoGSITVal.existeixObjecte(oCampFocus)) xfa.host.setFocus(oCampFocus.somExpression);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITBotonera::posicionaPagina " + sPagina, exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: paginaDelCamp
// Descripció: Mètode que retorna el nom de la pàgina a la que pertany 'oCamp'
// Paràmetres d'entrada:
//		oCamp - Camp de la pàgina 
// Paràmetres de sortida:
//		sPagina - Nom de la pàgina a la que pertany 'oCamp'
//////////////////////////////////////////////////////////// 
function paginaDelCamp(oCamp)
{
	try
	{
		var aRuta = oCamp.somExpression.split("[0].");	
		return aRuta[3];
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITBotonera::paginaDelCamp ", exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: planaAnterior
// Descripció: Mètode que posiciona el focus del PDF a la pàgina anterior
// Paràmetres d'entrada:
//		oCamp - Camp de la pàgina 
//		sFuncio - Opcional. Funció a executar al fer canvi de pàgina si cal. S'ha de definir en format String, per exemple: "scoGSITAdreca.copiaAdrecaContacteRequeridorPanellsMultiples(true);"
//////////////////////////////////////////////////////////// 
function planaAnterior(oCamp, sFuncio)
{		
	if (scoGSITVal.isFormulariValidat()) return;
	posicionaPagina(paginaDelCamp(oCamp), true);
	if ( (arguments.length > 1) && (!scoGSITVal.isEmpty(sFuncio)) ) eval(sFuncio); 
}

////////////////////////////////////////////////////////////
// Nom: planaSeguent
// Descripció: Mètode que posiciona el focus del PDF a la següent pàgina
// Paràmetres d'entrada:
//		oCamp - Camp de la pàgina 
//		sFuncio - Opcional. Funció a executar al fer canvi de pàgina si cal. S'ha de definir en format String, per exemple: "scoGSITAdreca.copiaAdrecaContacteRequeridorPanellsMultiples(true);"
//////////////////////////////////////////////////////////// 
function planaSeguent(oCamp, sFuncio)
{
	if (scoGSITVal.isFormulariValidat()) return;

	var sPagina = paginaDelCamp(oCamp);
	var result = scoGSITVal.validarPlana(sPagina);
	if (result.returnStatus == 1)
	{
		posicionaPagina(sPagina, false);
		if ( (arguments.length > 1) && (!scoGSITVal.isEmpty(sFuncio)) ) eval(sFuncio); 
	}
	else                          
		xfa.host.messageBox(result.missatge); 
}

/***************************************************************
 Nom: scoGSITCamps
 Descripció: Creat a partir de l'sco del FW 2.4.8 - Conté els mètodes necessaris per gestionar els camps del formulari
**************************************************************************/

/////////////////////////////////////////////////////////////////////////////
// MÈTODES
