////////////////////////////////////////////////////////////
// Nom: remarcarCampNoValid
// Descripció: Mètode que marca el requadre de obj com vàlid.
// Paràmetres d'entrada:
//		obj - Camp a remarcar com a no vàlid
////////////////////////////////////////////////////////////
function remarcarCampNoValid(obj)
{
	if (scoGSITNod.primerCampNoValid == "") 
	{
		if ( (obj.className == "subform") && (obj.name == "SELECCIO" || obj.name == "MULTISELECCIO") )
		{
			scoGSITNod.primerCampNoValid = obj.CHECK.TXT_CAMP.somExpression;	
		}
		else
		{
			scoGSITNod.primerCampNoValid = obj.somExpression;
		}
	}
	if ((obj.className == "exclGroup") && (obj.parent.name == "sRB")) obj = obj.parent;
	obj.border.edge.presence = "visible";
	obj.borderColor = scoGSITPar.colorRequadreNoValid;	
}



////////////////////////////////////////////////////////////
// Nom: remarcarCampValid
// Descripció: Mètode que marca el requadre de obj com no vàlid.
// Paràmetres d'entrada:
//		obj - Camp a remarcar com a vàlid
////////////////////////////////////////////////////////////
function remarcarCampValid(obj)
{
	if ((obj.className == "exclGroup") && (obj.parent.name == "sRB")) obj = obj.parent;

	obj.border.edge.presence = "hidden";
	obj.borderColor = scoGSITPar.colorRequadreValid;
}

////////////////////////////////////////////////////////////
// Nom: remarcarCampsNoValids
// Descripció: Mètode que marca el requadre dels objs de 'aObjectes' com no vàlid.
// Paràmetres d'entrada:
//		aObjectes - Array de camps a remarcar com a no vàlid
////////////////////////////////////////////////////////////
function remarcarCampsNoValids(aObjectes)
{
	if (!scoGSITVal.existeixObjecte(aObjectes)) return;
	var nObjectes = aObjectes.length;
	for(var nObj=0; nObj<nObjectes; nObj++) remarcarCampNoValid(aObjectes[nObj]);	
}

////////////////////////////////////////////////////////////
// Nom: remarcarCampsValids
// Descripció: Mètode que marca el requadre dels objs de 'aObjectes' com no vàlid.
// Paràmetres d'entrada:
//		aObjectes -  Array de camps a remarcar com a vàlid
////////////////////////////////////////////////////////////
function remarcarCampsValids(aObjectes)
{
	if (!scoGSITVal.existeixObjecte(aObjectes)) return;
	var nObjectes = aObjectes.length;
	for(var nObj=0; nObj<nObjectes; nObj++) remarcarCampValid(aObjectes[nObj]);	
}

////////////////////////////////////////////////////////////
// Nom: comprovaVisibleParent
// Descripció: Mètode que donat un objecte retorna false si algun dels seus pares no és visible.
// Paràmetres d'entrada: 
//		obj - Paràmetre amb la referència a l'objecte per al que s'ha de comprobar la visibilitat
// Paràmetres de sortida: 
//		enter - Valor (0/1) segons si algún dels seus parents no és visible
////////////////////////////////////////////////////////////
function comprovaVisibleParent(obj) 
{
	try{

		if(obj.presence != "visible")
			return 0;

		var frm = obj.parent;
		while((frm.parent != null)&&(frm.className == "subform")) {
			if(frm.presence != "visible") 
				return 0;
			frm = frm.parent;
		}	
		return 1;
	}catch(exc) {
		return scoGSITGen.retornarExcepcio("scoGSITCamps.comprovaVisibleParent()",exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: campLocalNoValid
// Descripció:  Mètode que verifica si el camp ha passat la validació local, en cas que l'hagi passat retornarà un 1 i en cas que no l'haig passat possarà el focus en aquell camp.
// Paràmetres d'entrada:
//		objCamp - Camp o la seva somExpression.
//		estatValidacio - Valor (true/false) segons si el contingut del camp és correcte
// Paràmetres de sortida:
//		 1 - en cas de que tot hagi anat bé i la validació hagi estat correcte, 
//		 0 - en cas de que no s'hagi superat la validació.
//		-1 - en cas d'haver produït alguna excepció.
//		-2 - Si no rep com a mínim 4 arguments
//		-3 - Si algun argument és nul i no podía ser-ho
//		-4 - Si el primer argument no correspon a un objecte del document
//		-5 - Si els arguments que han de ser booleans no ho són.
//		-6 - Si la funció no es cridada desde l'event exit.
////////////////////////////////////////////////////////////
function campLocalNoValid(objCamp, estatValidacio)
{
	try
	{	
		var objForm = objCamp;

		if(estatValidacio== null || estatValidacio=="undefined") 
		{
			xfa.host.messageBox(msgErrorParametres.value);
			return -3;
		}		
		if(estatValidacio.constructor != Boolean)
		{	
			xfa.host.messageBox(msgErrorParametres.value);
			return -5;
		}
		if(objForm.rawValue=="" || objForm.rawValue=="undefined" || objForm.rawValue==null)
		{
			return 1;
		}
		else
		{ 
			if(xfa.event.name!="exit")
			{
				xfa.host.messageBox(msgErrorParametres.value);			
				return -6;
			}
			else
			{
				if(!estatValidacio)
				{
					xfa.host.setFocus(objForm.somExpression);
					return 0;			
				}
				else
					return 1;
			}
		}

	}catch(exc) {
			return scoGSITGen.retornarExcepcio("scoGSITCamps.campLocalNoValid() : \n", exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: validarGlobal
// Descripció: Mètode que s'encarrega de validar tot el formulari.
////////////////////////////////////////////////////////////
function validarGlobal(subformName,visibles)
{
	try
	{			
	return 1;

		var result = validarLocals(subformName,visibles);
		var result2 = validarObligatorietatFormularis(subformName,visibles);
		if(result!=1)
			return result;
		else 
		{
			if(result2!=1)
				return result2;
			else
				return 1;
		}

	}catch(exc) {
			return scoGSITGen.retornarExcepcio("scoGSITCamps.ValidarGlobal() : \n", exc);
	}
}               

////////////////////////////////////////////////////////////
// Nom: campLocalValidat
// Descripció:  La funció rebrà un objecte del document i un valor de si ha passat la validació local.
//				En cas que l'hagi passat ocultarà el border del camp. 
//				En cas que no l'hagi passat posarà el requadre sempre visible amb el color scoGSITPar.colorRequadreNoValid.
// Paràmetres d'entrada:
//		oCamp - Serà la referència a l'objecte o la somExpression del camp a validar.
//		esValidacioCorrecte - Serà un valor booleà que ens dirà si la validació ha esta OK = CERT o no = FALS
////////////////////////////////////////////////////////////
function campLocalValidat(oCamp, esValidacioCorrecte)
{
	try
	{
		if (!scoGSITVal.existeixObjecte(oCamp)) return;	

		if (!esObjecteMateixEventValid(oCamp)) return;

		if (esEventValid())
		{
			if(esValidacioCorrecte)
				remarcarCampValid(oCamp);
			else
			{
				remarcarCampNoValid(oCamp);
				missatgeError(oCamp);
			}
		}
		else
		{
			if(esValidacioCorrecte && !scoGSITVal.isEmpty(oCamp))
				remarcarCampValid(oCamp);
			else
			{
				if ((oCamp.mandatory == "error") || (!esValidacioCorrecte))
				{
					remarcarCampNoValid(oCamp);
				}
			}
		}	
	}catch(exc) {
			scoGSITGen.retornarExcepcio("scoGSITCamps.campLocalValidat() : \n", exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: campLocalValidatEspecific
// Descripció:  La funció rebrà un objecte del document i un valor de si ha passat la validació local.
//				En cas que l'hagi passat ocultarà el border del camp. 
//				En cas que no l'hagi passat posarà el requadre sempre visible amb el color scoGSITPar.colorRequadreNoValid.
// Paràmetres d'entrada:
//		oCamp - Serà la referència a l'objecte o la somExpression del camp a vallidar.
//		estatValidacio - Serà un valor booleà que ens dirà si la validació ha esta OK = CERT o no = FALS
////////////////////////////////////////////////////////////
function campLocalValidatEspecific(oCamp, estatValidacio)
{
	try
	{
		if (!scoGSITVal.existeixObjecte(oCamp)) return;	

		if(estatValidacio) remarcarCampValid(oCamp);
		else remarcarCampNoValid(oCamp);

	}catch(exc) {
			scoGSITGen.retornarExcepcio("scoGSITCamps.campLocalValidatEspecific() : \n", exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: missatgeError
// Descripció:  La funció rebrà un objecte del qual se'n verifica la correctesa del seu contingut i si s'ha de mostrar el missatge d'error
// Paràmetres d'entrada:
//		oCamp - Serà la referència a l'objecte o la somExpression del camp a validar.
////////////////////////////////////////////////////////////
function missatgeError(oCamp)
{
	//S'Agafa el missatge d'error definit en el camp
	var sMsgErrorValidacioCamp = missatgeErrorDefinitEnCamp(oCamp);

	if (esEventValid()) 
	{
		app.alert(sMsgErrorValidacioCamp);
		if(scoGSITPar.bTabTornaCampValidatIncorrecte)
            xfa.host.setFocus(oCamp.somExpression);
	}	
}

////////////////////////////////////////////////////////////
// Nom: missatgeErrorDefinitEnCamp
// Descripció:  Es recupera el missatge d'error definit en el camp
// Paràmetres d'entrada:
//		oCamp - Objecte validat que se n'ha de recuperar el missatge d'error a mostrar
////////////////////////////////////////////////////////////
function missatgeErrorDefinitEnCamp(oCamp)
{
	var msgError = "";
	var msgErrorScript = "";
	var bTrobat = false;

	if (!scoGSITVal.existeixObjecteFill(oCamp, "validate.message")) return "";

	if (scoGSITVal.existeixPropietat1Nivell(oCamp.validate.message, "scriptTest"))
		msgErrorScript = oCamp.validate.message.scriptTest.value;

	if (scoGSITVal.isEmpty(msgErrorScript))
	{
		if (scoGSITVal.existeixObjecteFill(oCamp, "caption.value.text"))
			msgError = oCamp.caption.value.text.value + ": " + msgErrorValidacio.value +"\n";
		else if (scoGSITVal.existeixObjecteFill(oCamp, "assist.toolTip"))
		{
			msgError = oCamp.assist.toolTip + ": " + msgErrorValidacio.value +"\n";
		}	
		else 	
			msgError = oCamp.name + ": " + msgErrorValidacio.value +"\n";
	}	
	else
		msgError = msgErrorScript +"\n";


	return msgError;
}

////////////////////////////////////////////////////////////
// Nom: esEventValid
// Descripció:  Es recupera l'event que ha llençat la validació de l'objecte
////////////////////////////////////////////////////////////
function esEventValid()
{	
	if (xfa.event.name == "other" && xfa.event.target == null) return true;

	return false;
}

////////////////////////////////////////////////////////////
// Nom: esObjecteMateixEventValid
// Descripció:  Es recupera l'event que ha llençat la validació de l'objecte
////////////////////////////////////////////////////////////
function esObjecteMateixEventValid(oCamp)
{	
	if (xfa.event.target != null && xfa.event.name != "other")
	{		
		var sEvent = xfa.event.target.name;
		if (sEvent == "BTN_VALIDAR" || sEvent == "BTN_SEGUENT" || sEvent == "BTN_ANTERIOR") return true;
		else return (oCamp.somExpression == xfa.event.target.somExpression);
	}	

	return true;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: canviColorFonsCampsOblig
// Descripció: Funció que canvia el color de fons dels camps obligatoris del formulari amb el color definit a scoGSITPar.colorFonsObligatori
/////////////////////////////////////////////////////////////////////////////
function canviColorFonsCampsOblig()
{
	if ((scoGSITVal.isFormulariAcusament() || xfa.host.name == "XFAPresentationAgent"))  return;

	try{
		if (scoGSITPar.bResaltarCampsFormulari)
		{
			var aColor = scoGSITPar.colorFonsObligatori.split(",");
			var color1 = scoGSITVal.trim(aColor[0]);
			var color2 = scoGSITVal.trim(aColor[1]);
			var color3 = scoGSITVal.trim(aColor[2]);
			app.runtimeHighlightColor = ["RGB",(parseFloat(color1,10)/255),(parseFloat(color2,10)/255),(parseFloat(color3,10)/255)];		
		}
	}
	catch(e)
	{
		app.runtimeHighlightColor = ["RGB",0.8,0.8,1];		
	}
}

////////////////////////////////////////////////////////////
// Nom: marcaErrorCamp
// Descripció: Marca el recuadre del camp com error i situa el focus al camp
// Paràmetres d'entrada:
//		oCamp - camp a marcar
////////////////////////////////////////////////////////////
function marcaErrorCamp(oCamp)
{
	remarcarCampNoValid(oCamp);
	xfa.host.setFocus(oCamp.somExpression);
}               

/////////////////////////////////////////////////////////////////////////////
// Nom: unProtectAllFields
// Descripció: Desbloqueja tots els camps que se li passen per paràmetre en la llista de camps
// Paràmetres d'entrada:
//		sList - Element que conté els camps que no hem de desprotegir
/////////////////////////////////////////////////////////////////////////////
function unProtectAllFields(sList) {
	sList = sList.substring(1);
	if ( sList!= null && sList != "" ) {
		// Unprotect the fields that were previously protected
		var sArray = "new Array(" + sList + ")";	// Build the string representation of the array.
		var newArray = eval(sArray);				// Evaluate the string.

		for (i = 0; i < newArray.length; i++) {
			var oItem = xfa.resolveNode("xfa[0].form[0]." + scoGSITPar.nomFormulari + "[0]." + newArray[i]);
			if ( oItem != null )
			{
				oItem.access = "open";
				if ( oItem.resolveNode("ui.#button") != null ) {
					scoGSITBot.canviEstatAcceptar(1,"0,0,0",oItem);
				}
			}
		}
	} else {
		console.println("can't unprotect - list of protected fields was not saved properly.");
	}
}               

/////////////////////////////////////////////////////////////////////////////
// Nom: protectAllFields
// Descripció: Bloqueja tots els camps que se li passen per paràmetre en la llista de camps 
// Paràmetres d'entrada:
//		sList - Element que conté els camps que no hem de protegir
/////////////////////////////////////////////////////////////////////////////
function protectAllFields(sList){
	sList = sList.substring(1);
	if ( sList!= null && sList != "" ) {
		// Unlock the fields that were previously locked
		var sArray = "new Array(" + sList + ")";	// Build the string representation of the array.
		var newArray = eval(sArray);				// Evaluate the string.

		for (i = 0; i < newArray.length; i++) {
			var oItem = xfa.resolveNode("xfa[0].form[0]." + scoGSITPar.nomFormulari + "[0]." + newArray[i]);
			if ( oItem != null )
			{
				oItem.access = "protected";
				if ( oItem.resolveNode("ui.#button") != null ) {
					scoGSITBot.canviEstatAcceptar(0,null,oItem);
				}
			}
		}
	} else {
		console.println("can't protect - list of protected fields was not saved properly.");
	}
}               

////////////////////////////////////////////////////////////
// Nom: assignarValorVariable
// Descripció: Funció que guarda en un camp el valor de la variable
// Paràmetres d'entrada:
//      oSub - Objecte on estava definida la variable
//      nomVariable - Nom de la variable
//      valorVariable -  Valor de la variable
//		objecteTipus - Tipus de variable a assignar. Els valors permesos són: string, objecte, arrayStrings, arrayObjectes
////////////////////////////////////////////////////////////
function assignarValorVariable(oSub, nomVariable, valorVariable, objecteTipus)
{
	try
	{
		if(arguments.length < 4) objecteTipus = "string";

		var sExpression = (typeof(oSub)=="string") ? oSub : oSub.somExpression;

		var aValorPermesos = new Array("string","objecte","arrayObjectes","arrayStrings");

		var bValorCorrecte = false;
		for(var t=0;t<aValorPermesos.length;t++)
			if(aValorPermesos[t] == objecteTipus) bValorCorrecte = true;


		if(!bValorCorrecte)
		{
			app.alert("ATENCIÓ factoria, el objecteTipus de la variable " + nomVariable + " de l'objecte " + sExpression + " no està correctamente assignada en la funció 'assignarValorVariable'");
			return;
		}

		guardaValorVariableEnCamp(sExpression, nomVariable, valorVariable, objecteTipus);
	}
	catch(exc) 
	{
		return scoGSITGen.retornarExcepcio("scoGSITCamps.assignarValorVariable()" , exc);
	}			
}

////////////////////////////////////////////////////////////
// Nom: guardaValorVariableEnCamp
// Descripció: Funció que guarda en un camp el valor de la variable
// Paràmetres d'entrada:
//      sExpression - Valor de la somExpression de l'objecte on estava definida la variable
//      nomVariable - Nom de la variable
//      valorVariable - Valor de la variable
//		objecteTipus - Tipus de la variable a guardar. Els valors permesos són: string, objecte, arrayStrings, arrayObjectes
////////////////////////////////////////////////////////////
function guardaValorVariableEnCamp(sExpression , nomVariable, valorVariable, objecteTipus)
{
	try
	{

		if(scoGSITVal.isEmpty(sExpression) || scoGSITVal.isEmpty(nomVariable) || scoGSITVal.isEmpty(objecteTipus))
		{
			app.alert("ATENCIÓ factoria, la variable " + nomVariable + " de l'objecte " + sExpression + " no està correctamente assignada en la funció 'assignarValorVariable'");
			return;
		}

		var oVariables = obtenirCampVariables(); 
		var sValorVariable = obtenirStringAGuardarVariableEnCamp(valorVariable, objecteTipus);

		var aValors = obtenirArrayVariableEnCamp(oVariables);
		var aValors = afegirValorArrayVariableEnCamp(aValors, sExpression, nomVariable, sValorVariable, objecteTipus);

		guardaArrayVariableEnCamp(aValors, oVariables);
    }
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("guardaValorVariableEnCamp", exc);
	}
}  

////////////////////////////////////////////////////////////
// Nom: guardaArrayVariableEnCamp
// Descripció: Funció que guarda en oVariables l'array definit en aValors
// Paràmetres d'entrada:
//      aValors - Array a guardar
//      oVariables - Objecte de tipus camp on es guarda l'array
////////////////////////////////////////////////////////////
function guardaArrayVariableEnCamp(aValors, oVariables)
{
	var sArray = "";
    for (var x=0;x<aValors.length;x++)
    {
        sArray = sArray + "[";
        for(var i=0; i<aValors[x].length; i++)
        {
            sArray = sArray + '"' + aValors[x][i] + '"';
            if(i != aValors[x].length-1) sArray = sArray + ",";
        }

        if(x == aValors.length-1) sArray = sArray +  "]";
            else sArray = sArray + "],";
    }

    oVariables.rawValue = sArray;

}

////////////////////////////////////////////////////////////
// Nom: stringCreacioArray
// Descripció: Funció que guarda en format string la creació de l'array aValors
// Paràmetres d'entrada:
//      aValors - Array a guardar
//      sArray - Variable per a la recursivitat
////////////////////////////////////////////////////////////
function stringCreacioArray(aValors, sArray)
{
	if(arguments.length < 2)  sArray = "";

    for (var x=0;x<aValors.length;x++)
    {              
		if(typeof(aValors[x]) == "string")
		{	
			sArray = sArray + "'" + aValors[x] + "'";
		}
		else
		{
	        for(var i=0; i<aValors[x].length; i++)
	        {
	        	if(i==0) sArray = sArray + "[";
	        	if(aValors[x][i].length == 0 || typeof(aValors[x][i]) == "string")
	        	{	        	
		            sArray = sArray + "'" + aValors[x][i] + "'";
		            if(i != aValors[x].length-1) sArray = sArray + ",";
		        }
		        else
		        {
		        	sArray = sArray + "[";
		        	sArray =  stringCreacioArray(aValors[x][i], sArray);
		        	sArray = sArray + "]";
				}
				 if(i == aValors[x].length-1) sArray = sArray +  "]";
	        }
        }

        if(x != aValors.length-1) sArray = sArray + ",";
    }	


	return(sArray);
}

////////////////////////////////////////////////////////////
// Nom: obtenirArrayVariableEnCamp
// Descripció: Funció que obté l'array guardat en el camp oVariables
// Paràmetres d'entrada:
//      oVariables - Objecte de tipus camp on es guarda l'array
////////////////////////////////////////////////////////////
function obtenirArrayVariableEnCamp(oVariables)
{
	var aValors = eval("new Array(" + oVariables.rawValue + ")"); 	
	return(aValors);
}

////////////////////////////////////////////////////////////
// Nom: afegirValorArrayVariableEnCamp
// Descripció: Funció afegeix a l'array una nova variable
// Paràmetres d'entrada:
//		aValors - Array on afegim la nova variable
//		sExpression - Valor de la somExpression del subform on està definida la variable
//		nomVariable - Nom de la variable
//		sValorVariable - String amb el valor de la variable 
//      objecteTipus - Tipus de la variable que es guarda.  Els valors permesos són: string, objecte, arrayStrings, arrayObjectes
////////////////////////////////////////////////////////////
function afegirValorArrayVariableEnCamp(aValors, sExpression, nomVariable, sValorVariable, objecteTipus)
{
	var nPos = posicioValorVariableEnCamp(aValors, sExpression,nomVariable); 
    if(nPos == -1)
        aValors.push([sExpression, nomVariable, sValorVariable, objecteTipus]);
    else
        aValors[nPos] = ([sExpression, nomVariable, sValorVariable, objecteTipus]);

	return(aValors);

}

////////////////////////////////////////////////////////////
// Nom: posicioValorVariableEnCamp
// Descripció: Funció que retorna -1 si es tracta d'una nova variable a afegir, o la posició en l'array si aquesta variable ja es troba guardada
// Paràmetres d'entrada:
//		aValors - Array on afegim la nova variable
//		sExpression - Valor de la somExpression del subform on està definida la variable
//		nomVariable - Nom de la variable
////////////////////////////////////////////////////////////
function posicioValorVariableEnCamp(aValors, sExpression, nomVariable)
{
    for (var x=0;x<aValors.length;x++)
        if(aValors[x][0] == sExpression && aValors[x][1] == nomVariable) return x;

	return -1;
}

////////////////////////////////////////////////////////////
// Nom: obtenirStringAGuardarVariableEnCamp
// Descripció: Funció que retorna la nova variable a guardar però sempre en format string
// Paràmetres d'entrada:
//		valorVariable - Valor de la variable
//		objecteTipus - Tipus d'objtecte de la variable que es guarda
////////////////////////////////////////////////////////////
function obtenirStringAGuardarVariableEnCamp(valorVariable, objecteTipus)
{
	if(objecteTipus == "string")
	{
		return(valorVariable);
	}
	else
	{
		if(objecteTipus == "objecte") return(valorVariable.somExpression);
		if(objecteTipus.substring(0,5).toUpperCase() == "ARRAY")
		{
			if(objecteTipus == "arrayStrings") return(stringCreacioArray(valorVariable));
			if(objecteTipus == "arrayObjectes")
			{
				var aStrings = obtenirStringArray(valorVariable);
				return(stringCreacioArray(aStrings));

			}
		}
	}

	return(valorVariable);
}   

////////////////////////////////////////////////////////////
// Nom: obtenirStringArray
// Descripció: Funció que donat un array aObjecte amb objectes
// Paràmetres d'entrada:
//		aResult - Llista que conté els objectes
// Paràmetres de sortida:
//		array - Llista amb les somExpressions
////////////////////////////////////////////////////////////
function obtenirStringArray(aResult)
{
		try
	{	
		for(var x=0; x<aResult.length; x++)
		{
			if(aResult[x].length > 1) 
			{
				obtenirStringArray(aResult[x],true);
			}
			else 
			{
				aResult[x] = aResult[x].somExpression;
			}
		}	

	    return(aResult);	

	}catch(exc) {
		return scoGSITGen.retornarExcepcio("scoGSITCamps.obtenirStringArray()",exc);
	}
}


////////////////////////////////////////////////////////////
// Nom: recuperaObjecteVariableEnCamp
// Descripció: Funció que recupera la variable segons el tipusObjecte
// Paràmetres d'entrada:
//		sObj - String que conté la variable
//		objecteTipus - Tipus de la variable que guarda sObj
// Paràmetres de sortida:
//		array - Llista d'objectes
////////////////////////////////////////////////////////////
function recuperaObjecteVariableEnCamp(sObj, tipusObjecte)
{

    if(tipusObjecte == "string") return(sObj);
    else{
    	if(tipusObjecte == "objecte") return(xfa.resolveNode(sObj));
    	if(tipusObjecte == "arrayStrings")
    	{ 
    		return(eval("new Array(" + sObj + ")"));	
		}	
    	if(tipusObjecte == "arrayObjectes")
    	{
    		var aExpression = eval("new Array(" + sObj + ")");
    		var aObjectes = obtenirObjecteArray(aExpression);

    		return(aObjectes);
		}
	} 
}   

////////////////////////////////////////////////////////////
// Nom: obtenirObjecteArray
// Descripció: Mètode que obté una llista 'aResult' amb somExpressions
// Paràmetres d'entrada:
//		aResult- Llista que conté les somExpressions
// Paràmetres de sortida:
//		array - Llista amb les somExpressions
////////////////////////////////////////////////////////////
function obtenirObjecteArray(aResult, bRecursiu)
{
	try
	{
		for(var x=0; x<aResult.length; x++)
		{
			if(typeof(aResult[x]) != "string") 
			{
				obtenirObjecteArray(aResult[x],true);
			}
			else 
			{
				aResult[x] = xfa.resolveNode(aResult[x]);
			}
		}

	    return(aResult);	

	}catch(exc) {
		return scoGSITGen.retornarExcepcio("scoGSITCamps.obtenirObjecteArray()",exc);
	}
} 


////////////////////////////////////////////////////////////
// Nom: obtenirValorVariable
// Descripció: Funció que obté d'un camp el valor de la variable
// Paràmetres d'entrada:
//      oSub - Objecte on estava definida la variable
//      nomVariable - Nom de la variable
// Paràmetres de sortida:
//      valorVariable - Valor de la variable
////////////////////////////////////////////////////////////        
function obtenirValorVariable(oSub, nomVariable)
{
	var sExpression = "";

    if (typeof(oSub)=="string") 
		sExpression = oSub;
    else 
		sExpression = oSub.somExpression;        

    if(scoGSITVal.isEmpty(sExpression) || scoGSITVal.isEmpty(nomVariable))
    {
        app.alert("ATENCIÓ factoria, els paràmetres passats en aquesta funció 'obtenirValorVariable', no tenen un contingut acceptat");
        return null;
    }

    var oVariables = obtenirCampVariables();
	var valor = String(oVariables.rawValue);

    if(valor.indexOf(sExpression) != -1)
    {   
   		var aValors = obtenirArrayVariableEnCamp(oVariables);

    	for (var x=0;x<aValors.length;x++) 
		{ 		
        	if(aValors[x][0] == sExpression && aValors[x][1] == nomVariable)
            	return(recuperaObjecteVariableEnCamp(aValors[x][2], aValors[x][3]));
		}
    }

	if(!scoGSITPar.bUsEnforceStrict)
	{
		var o = eval("xfa.resolveNode(\"" + sExpression + "\")." + nomVariable);
		return o;
	}

    return null;
}

////////////////////////////////////////////////////////////
// Nom: obtenirCampVariables
// Descripció: Funció que retorna el camp on es guarda els valors de les variables locals de subforms
// Paràmetres de sortida:
//      oVariables - Objecte de tipus camp
////////////////////////////////////////////////////////////        
function obtenirCampVariables()
{
    var oVariables = scoGSITPar.oDadesCFGTramit.parent.VALIDACIO.TXT_VARIABLES;

    if(!scoGSITVal.existeixObjecte(oVariables))
    {
        console.println("No está correctament creat el camp TXT_VARIABLES en PLANA_CFG_TRAMIT.VALIDACIO.TXT_VARIABLES");
        return null;
    }

	if(scoGSITVal.isEmpty(oVariables)) oVariables.rawValue = "";

    return(oVariables);
}

////////////////////////////////////////////////////////////
// Nom: obtenirValorRelacionatTipusUsuari
// Descripció: Funció que retorna el valor del camp TIPUS_USUARI del panell relacionat
// Paràmetres d'entrada:
//      oCamp -  Objecte de tipus camp
// Paràmetres de sortida:
//      string -  Valor / contingut del camp relacionat
////////////////////////////////////////////////////////////   
function obtenirValorRelacionatTipusUsuari(oCamp)
{
	try
	{
		var oContacte = scoGSITPanells.obtenirObjecteFill(oCamp.parent, "CONTACTE");
		var oPanRel = obtenirValorVariable(oContacte, "oPanellRel");
		if (oPanRel == null) 
		{
			app.alert("ATENCIÓ factoria, el Panell Relacionat del camp: \n\n" + oCamp.somExpression + "\n\nno està correctament definit. \n\nReviseu la seva funció 'scoGSITPanells.assignarPanellRelacionatContacte' i que el panell relacionat estigui correctament definit al mòdul 'scoGSITPar'");
			return;
		}		

		if(typeof(oPanRel)=="string") oPanRel = xfa.resolveNode(oPanRel);
		var o = scoGSITPanells.obtenirObjectePare(oPanRel, "TIPUS_USUARI");
		if (o != null) return o.rawValue;
		return "";
	}
	catch(exc) 
	{
		return scoGSITGen.retornarExcepcio("scoGSITCamps.obtenirValorRelacionatTipusUsuari()" , exc);
	}			
}

////////////////////////////////////////////////////////////
// Nom: obtenirValorPanellRelacionat
// Descripció: Funció que retorna el valor del mateix camp del panell relacionat
// Paràmetres d'entrada:
//      oCamp - Objecte de tipus camp
//		nomCamp - (Opcional) Nom del camp relacionat, sempre que sigui diferent del oCamp
// Paràmetres de sortida:
//      string -  Valor / contingut del camp relacionat
////////////////////////////////////////////////////////////   
function obtenirValorPanellRelacionat(oCamp, nomCamp)
{
	if (scoGSITVal.isFormulariAcusament()) return;
	if (scoGSITVal.isFormulariValidat()) return;

	if (arguments.length<2) nomCamp = oCamp.name;
	return obtenirValorRelacionat(oCamp, "oPanellRel", nomCamp);
}

////////////////////////////////////////////////////////////
// Nom: obtenirValorRelacionat
// Descripció: Funció que retorna el valor del mateix camp del panell relacionat
// Paràmetres d'entrada:
//      oCamp -  Objecte de tipus camp
//		nomVariablePanellRelacionat - Nom de la variable que conté la somExpression del panell relacionat
//		nomCamp - (Opcional) Nom del camp relacionat, sempre que sigui diferent del oCamp
// Paràmetres de sortida:
//      String -  Valor / contingut del camp relacionat
////////////////////////////////////////////////////////////   
function obtenirValorRelacionat(oCamp, nomVariablePanellRelacionat, nomCamp)
{
	var oCamp = obtenirCampRelacionat(oCamp, nomVariablePanellRelacionat, nomCamp);
	if (oCamp != null) return oCamp.rawValue;

	return "";	
}

////////////////////////////////////////////////////////////
// Nom: obtenirCampRelacionat
// Descripció: Funció que retorna el mateix camp del panell relacionat
// Paràmetres d'entrada:
//      oCamp -  Objecte de tipus camp
//		nomCamp - (Opcional) Nom del camp relacionat, sempre que sigui diferent del oCamp
// Paràmetres de sortida:
//      oCamp -  Objecte de tipus camp
////////////////////////////////////////////////////////////   
function obtenirCampPanellRelacionat(oCamp, nomCamp)
{
	if (arguments.length<2) nomCamp = oCamp.name;
	return obtenirCampRelacionat(oCamp, "oPanellRel", nomCamp);
}

////////////////////////////////////////////////////////////
// Nom: obtenirCampRelacionat
// Descripció: Funció que retorna el mateix camp del panell relacionat
// Paràmetres d'entrada:
//      oCamp -  Objecte de tipus camp
//		nomVariablePanellRelacionat - Nom de la variable que conté la somExpression del panell relacionat
//		nomCamp - (Opcional) Nom del camp relacionat, sempre que sigui diferent del oCamp
// Paràmetres de sortida:
//      oCamp -  Objecte de tipus camp
////////////////////////////////////////////////////////////   
function obtenirCampRelacionat(oCamp, nomVariablePanellRelacionat, nomCamp)
{
	var oPanellRel = obtenirValorVariable(oCamp.parent, nomVariablePanellRelacionat);
	if (scoGSITVal.isEmpty(oPanellRel)) oPanellRel = obtenirValorVariable(oCamp.parent.parent, nomVariablePanellRelacionat);

	if (!scoGSITVal.isEmpty(oPanellRel))
	{
		if (arguments.length<3) nomCamp = oCamp.name;

		if(typeof(oPanellRel)=="string") oPanellRel = xfa.resolveNode(oPanellRel);
		var o = scoGSITPanells.obtenirObjecteFill(oPanellRel, nomCamp);
		if (o != null) return o;
	}

	return null;	
}

////////////////////////////////////////////////////////////
// Nom: defVisibilitat
// Descripció: Funció que assigna la visibilitat 'sVisibilitat' al camp 'oObjecte' si aquest existeix i 'sVisibilitat' té un valor correcte, sino no farà res
// Paràmetres d'entrada:
//      oObjecte -  Objecte del que es vol definir la visibilitat (camp, subformulari,...)
//		sVisibilitat - (Opcional) String que defineix la visibilitat que es vol definir: 'visible', 'invisible' o 'hidden', si no es defineix serà 'visible' 
////////////////////////////////////////////////////////////   
function defVisibilitat(oObjecte, sVisibilitat)
{
	if (scoGSITVal.isFormulariValidat()) return;
	if (!scoGSITVal.existeixObjecte(oObjecte)) return;
	if (arguments.length<2) sVisibilitat = 'visible';

	if (sVisibilitat != 'visible' && sVisibilitat != 'invisible' && sVisibilitat != 'hidden') return;

	oObjecte.presence = sVisibilitat;
}

////////////////////////////////////////////////////////////
// Nom: assignarVisibilitatCampRelacionat
// Descripció: Funció que assigna la visibilitat del camp del panell relacionat
// Paràmetres d'entrada:
//      oCamp -  Objecte de tipus camp
//		nomCamp - (Opcional) Nom del camp relacionat, sempre que sigui diferent del oCamp
////////////////////////////////////////////////////////////   
function assignarVisibilitatCampRelacionat(oCamp, nomCamp)
{
	if (scoGSITVal.isFormulariValidat()) return;
	if (arguments.length<2) nomCamp = oCamp.name;

	var oCampRel = obtenirCampPanellRelacionat(oCamp);
	defVisibilitat(oCamp, oCampRel.presence);
}

////////////////////////////////////////////////////////////
// Nom: defCampsVisibilitat
// Descripció: Mètode de definició de la propietat 'presence' dels camps de l'array
// Paràmetres d'entrada:  
//		aCamps - Llista de camps a definir
//		sVisibilitat - (Opcional) String que defineix la visibilitat que es vol definir: 'visible', 'invisible' o 'hidden', si no es defineix serà 'visible' 
////////////////////////////////////////////////////////////
function defCampsVisibilitat(aCamps, sVisibilitat)
{
	try
	{
		for (var n=0; n<aCamps.length; n++)  defVisibilitat(aCamps[n], sVisibilitat);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("defCampsVisibilitat", exc);
	}				
} 

////////////////////////////////////////////////////////////
// Nom: defCampsPanellVisibilitat
// Descripció: Mètode de definició de la propietat 'presence' dels camps de oPanell definits a l'array
// Paràmetres d'entrada:  
//      oPanell - Panell
//		aCamps - Llista de camps a definir
//		sVisibilitat - (Opcional) String que defineix la visibilitat que es vol definir: 'visible', 'invisible' o 'hidden', si no es defineix serà 'visible' 
////////////////////////////////////////////////////////////
function defCampsPanellVisibilitat(oPanell, aCamps, sVisibilitat)
{
	try
	{
		for (var n=0; n<aCamps.length; n++)  defVisibilitat(scoGSITPanells.obtenirObjecteFill(oPanell, aCamps[n]), sVisibilitat);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("defCampsPanellVisibilitat", exc);
	}				
} 

////////////////////////////////////////////////////////////
// Nom: defAllCampsPanellVisibilitat
// Descripció: Mètode de definició de la propietat 'presence' dels tots els camps de oPanell 
// Paràmetres d'entrada:  
//      oPanell - Panell
//		aCamps - Llista de camps a definir
//		sVisibilitat - (Opcional) String que defineix la visibilitat que es vol definir: 'visible', 'invisible' o 'hidden', si no es defineix serà 'visible' 
////////////////////////////////////////////////////////////
function defAllCampsPanellVisibilitat(oPanell, sVisibilitat)
{
	try
	{
		if ((oPanell.className != "subform") && (oPanell.className != "field")) return null;

		var oCamps = oPanell.nodes; 		
		var numCamps = oCamps.length;
		for (var nCamp = 0; nCamp < numCamps; nCamp++)
		{
			var oCamp = oCamps.item(nCamp);
			if (oCamp.className == "subform") defAllCampsPanellVisibilitat(oCamp, sVisibilitat);		

			if (scoGSITNod.esObjeteTipusCamp(oCamp)) defVisibilitat(oCamp, sVisibilitat);
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoOGEBotonera::obtenirCampVisiblePerFocus", exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: esVisibleCampPanell
// Descripció:  Mètode que verifica si el camp 'sCamp' de 'oPanell' és visible o no 
// Paràmetres d'entrada:
//      oPanell - Panell
//      sCamp - Nom del Camp a verificar
// Paràmetres de sortida:
//      booleà -  Valor (true/false) que indica si el camp 'sCamp' de 'oPanell' és visible o no 
////////////////////////////////////////////////////////////   
function esVisibleCampPanell(oPanell, sCamp)
{
	var oCamp = scoGSITPanells.obtenirObjecteFill(oPanell, sCamp);
	if (!scoGSITVal.existeixObjecte(oCamp)) return false;

	return (oCamp.presence == "visible");
}

////////////////////////////////////////////////////////////
// Nom: esVisible
// Descripció:  Mètode que verifica si el camp 'oCamp' és visible o no 
// Paràmetres d'entrada:
//      oCamp - Camp a verificar
// Paràmetres de sortida:
//      booleà -  Valor (true/false) que indica si el camp 'oCamp' és visible o no  
////////////////////////////////////////////////////////////   
function esVisible(oCamp)
{
	if (!scoGSITVal.existeixObjecte(oCamp)) return false;

	return (oCamp.presence == "visible");
}

////////////////////////////////////////////////////////////
// Nom: esVisibleParents
// Descripció: Mètode que donat un objecte retorna false si algun dels seus pares no és visible.
// Paràmetres d'entrada: 
//      oCamp - Camp a verificar
// Paràmetres de sortida: 
//		enter - Valor (true/false) segons si algún dels seus parents no és visible
////////////////////////////////////////////////////////////
function esVisibleParents(obj) 
{
	return (comprovaVisibleParent(obj) == 1);
}

////////////////////////////////////////////////////////////
// Nom: esObligatori
// Descripció: Mètode que verifica si el camp és obligatori o no
// Paràmetres d'entrada:
//      obj -  Objecte a verificar
// Paràmetres de sortida:
//      booleà -  Valor (true/false) que indica si el camps és obligatori
////////////////////////////////////////////////////////////   
function esObligatori(obj)
{
	if (!scoGSITVal.existeixObjecte(obj)) return;
	if (obj.validate.nullTest == "error") return true;

	return false;
}

////////////////////////////////////////////////////////////
// Nom: assignarPropietatCampsObligatoris
// Descripció: Mètode que assigna la propietat de camp obligatori als camps de l'array 'scoGSITNod.arrCampsObligatoris'
////////////////////////////////////////////////////////////   
function assignarPropietatCampsObligatoris()
{
	if (scoGSITNod.arrCampsObligatoris == null) return;

	for(var i=0; i<scoGSITNod.arrCampsObligatoris.length;i++)
	{
		var o = xfa.resolveNode(scoGSITNod.arrCampsObligatoris[i]);
		if (o != null) o.validate.nullTest = "error";
	}	
}

////////////////////////////////////////////////////////////
// Nom: assignarCampObligatori
// Descripció: Mètode que assigna la propietat de camp obligatori segons 'valor'
// Paràmetres d'entrada:
//      oCamp - Camp a modificar-ne la propietat
//		bObligatori - true/false que indica si el camp ha de ser obligatori
////////////////////////////////////////////////////////////   
function assignarCampObligatori(oCamp, bObligatori)
{
	if (!scoGSITVal.existeixObjecte(oCamp)) return;
	oCamp.validate.nullTest = (bObligatori) ? "error" : ""; 
}

////////////////////////////////////////////////////////////
// Nom: assignarCampOblogatori
// Descripció: Mètode que assigna la propietat de camp obligatori segons 'valor'
// Paràmetres d'entrada:
//      oCamp - Camp a modificar-ne la propietat
//		bObligatori - true/false que indica si el camp ha de ser obligatori
////////////////////////////////////////////////////////////   
function assignarCampOblogatori(oCamp, bObligatori)
{
	assignarCampObligatori(oCamp, bObligatori); // S'ha de mantenir pq algunes versions del FW tenen la crida a aquesta funció
}

////////////////////////////////////////////////////////////
// Nom: defCampObligatori
// Descripció: Mètode que defineix la propietat de camp obligatori i comprova si cal que el camp tingui el requadre d'error
// Paràmetres d'entrada:
//      oCamp - Camp a modificar-ne la propietat
//		sEstat - Valor 'error' o '' que indica si el camp ha de ser obligatori
////////////////////////////////////////////////////////////   
function defCampObligatori(oCamp, sEstat)
{
	if (!scoGSITVal.existeixObjecte(oCamp)) return;

	oCamp.validate.nullTest = sEstat;
	if (scoGSITVal.isEmpty(oCamp) && (sEstat == ""))   scoGSITVal.amagarRequadre(oCamp);
}

////////////////////////////////////////////////////////////
// Nom: defCampEditable
// Descripció: Mètode que defineix un camp com a Editable o Bloquejat depenent de 'sAcces' i defineix la propietat de camp obligatori i comprova si cal que el camp tingui el requadre d'error
// Paràmetres d'entrada:
//      oCamp - Camp a modificar-ne la propietat
//      sAcces - Valor a assignar a la propietat: 'open' 'protected'
//		sEstat - Valor 'error' o '' que indica si el camp ha de ser obligatori
////////////////////////////////////////////////////////////   
function defCampEditable(oCamp, sAcces, sEstat)
{
	if (!scoGSITVal.existeixObjecte(oCamp)) return;

	oCamp.access = sAcces;
	defCampObligatori(oCamp, sEstat);
}

////////////////////////////////////////////////////////////
// Nom: defCampValorVisibilitat
// Descripció: Mètode que defineix el valor de 'oCamp' la propietat de camp obligatori i comprova si cal que el camp tingui el requadre d'error
// Paràmetres d'entrada:
//		oCamp - Camp a definir
//		sValor - Valor a assignar a 'oCamp'
//		sPresencia - Valor a assignar a la propietat 'presence' de 'oCamp'
////////////////////////////////////////////////////////////   
function defCampValorVisibilitat(oCamp, sValor, sPresencia)
{
	try
	{			
		if (!scoGSITVal.existeixObjecte(oCamp)) return;

		oCamp.rawValue = sValor;
		oCamp.presence = sPresencia;	
		if (scoGSITVal.esCombo(oCamp) && scoGSITVal.isEmpty(sValor)) oCamp.editValue = sValor;
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("defCampValorVisibilitat", exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: defCampsValorVisibilitat 
// Descripció: Mètode de defineix dels camps de 'oPanell' definits a l'array 'aCamps' el valor 'sValor' i la visibilitat 'sVisibilitat'
// Paràmetres d'entrada:  
//		aCamps - Llista de camps a definir
//		sValor - Valor a definir 
//		sVisibilitat - Visibilitat que es vol definir: 'visible', 'invisible' o 'hidden'
////////////////////////////////////////////////////////////
function defCampsValorVisibilitat(aCamps, sValor, sVisibilitat)
{
	try
	{
		for (var n=0; n<aCamps.length; n++) defCampValorVisibilitat(aCamps[n], sValor, sVisibilitat);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("defCampsPanellValorVisibilitat", exc);
	}				
} 

////////////////////////////////////////////////////////////
// Nom: defCampsPanellValorVisibilitat 
// Descripció: Mètode de defineix dels camps de 'oPanell' definits a l'array 'aCamps' el valor 'sValor' i la visibilitat 'sVisibilitat'
// Paràmetres d'entrada:  
//      oPanell - Panell
//		aCamps - Llista de camps a definir
//		sValor - Valor a definir 
//		sVisibilitat - Visibilitat que es vol definir: 'visible', 'invisible' o 'hidden'
////////////////////////////////////////////////////////////
function defCampsPanellValorVisibilitat(oPanell, aCamps, sValor, sVisibilitat)
{
	try
	{
		for (var n=0; n<aCamps.length; n++)  defCampValorVisibilitat(scoGSITPanells.obtenirObjecteFill(oPanell, aCamps[n]), sValor, sVisibilitat);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("defCampsPanellValorVisibilitat", exc);
	}				
} 

////////////////////////////////////////////////////////////
// Nom: defCampsPanellValorVisibilitat 
// Descripció: Mètode de defineix dels camps de 'oPanell' definits a l'array 'aCamps' el valor 'sValor'
// Paràmetres d'entrada:  
//      oPanell - Panell
//		aCamps - Llista de camps a definir
//		sValor - Valor a definir 
////////////////////////////////////////////////////////////
function defCampsPanellValor(oPanell, aCamps, sValor)
{
	try
	{
		for (var n=0; n<aCamps.length; n++)
		{
			var oCamp = scoGSITPanells.obtenirObjecteFill(oPanell, aCamps[n]);
			if (scoGSITVal.existeixObjecte(oCamp)) defCampValorVisibilitat(oCamp, sValor, oCamp.presence);
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("defCampsPanellValorVisibilitat", exc);
	}				
} 

////////////////////////////////////////////////////////////
// Nom: clonaCamp
// Descripció: Mètode que defineix les propietats (posició, mida, margins, font, color, caption) del camp 'oCampDesti' amb les propietats de 'oCampOrigen'
// Paràmetres d'entrada:
//      oCampDesti - Camp al que es copiaran les propietats de 'oCampOrigen'
//		oCampOrigen - Camp del que es copiaran les propietats de 'oCampDesti'
//		bClonaAccess - (opcional, xdefecte = false) Indica si volem clonar també la propietat 'access'
////////////////////////////////////////////////////////////   
function clonaCamp(oCampDesti, oCampOrigen, bClonaAccess, bClonaPosicions)
{
	try
	{
		if (arguments.length < 3)			bClonaAccess = false;
		if (arguments.length < 4)			bClonaPosicions = true;			

		if (bClonaPosicions)
		{
			oCampDesti.x = oCampOrigen.x;
			oCampDesti.y = oCampOrigen.y;
			oCampDesti.w = oCampOrigen.w;
			oCampDesti.h = oCampOrigen.h;
			oCampDesti.margin.topInset = oCampOrigen.margin.topInset;
			oCampDesti.margin.bottomInset = oCampOrigen.margin.bottomInset;
			oCampDesti.margin.leftInset = oCampOrigen.margin.leftInset;
			oCampDesti.margin.rightInset = oCampOrigen.margin.rightInset;
			oCampDesti.caption.reserve = oCampOrigen.caption.reserve;
			oCampDesti.caption.font.size = oCampOrigen.caption.font.size;
			oCampDesti.caption.font.typeface = oCampOrigen.caption.font.typeface;
			oCampDesti.font.size = oCampOrigen.font.size;
			oCampDesti.font.typeface = oCampOrigen.font.typeface;
		}	
		oCampDesti.caption.font.fill.color.value = oCampOrigen.caption.font.fill.color.value;		
		oCampDesti.caption.value.text.value = oCampOrigen.caption.value.text.value;
		oCampDesti.font.fill.color.value = oCampOrigen.font.fill.color.value;
		oCampDesti.presence = oCampOrigen.presence;
		oCampDesti.validate.nullTest = oCampOrigen.validate.nullTest; 
		if (bClonaAccess)		oCampDesti.access = oCampOrigen.access;
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITCamps::clonaCamp", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: obtenirObjecteRelacionat
// Descripció: Funció que retorna l'objecte relacionat a 'oPanell' amb el nom definit a 'sObjRel'
// Paràmetres d'entrada:
//      oPanell - Panell
//		sObjRel - Nom de la variable que conté la somExpression de l'objecte relacionat
// Paràmetres de sortida:
//      Objecte -  Objecte relacionat
////////////////////////////////////////////////////////////   
function obtenirPanellRelacionat(oPanell, sObjRel)
{
	var oObjRel = obtenirValorVariable(oPanell, sObjRel);
	if (oObjRel != null)
	{
		if (typeof(oObjRel) == "string") oObjRel = xfa.resolveNode(oObjRel);
	}	
	return oObjRel;
}

////////////////////////////////////////////////////////////
// Nom: getCampsPanell
// Descripció: Mètode que retorna un array amb tots els camps de 'oPanell' amb els noms definits a 'aCampsNom'
// Paràmetres de sortida:
//      array -  Array dels camps trobats
////////////////////////////////////////////////////////////   
function getCampsPanell(oPanell, aCampsNom)
{
	if (oPanell == null) return;
	if (aCampsNom == null) return;

	var aCampsPanell = []; 
	var numCamps = aCampsNom.length;
	for(var n=0; n<numCamps; n++)
	{
		var oCamp = scoGSITPanells.obtenirObjecteFill(oPanell, aCampsNom[n]);
		if (oCamp != null) aCampsPanell.push(oCamp);
	}	

	return aCampsPanell;
}

/***************************************************************
 Nom: scoGSITCombo
 Descripció: FW 2.4.8 - Conté les funcions necessàries per al correcte funcionament de les llistes desplegables.
**************************************************************************/
/////////////////////////////////////////////////////////////////////////////
// MÈTODES
/////////////////////////////////////////////////////////////////////////////

////////////////////////////////////////////////////////////
// Nom: canviValorLlista
// Descripció: Mètode que mira si s'ha canviat la selecció de la Llista
// Paràmetres d'entrada:
//		oLlista - Camp de Llista
//		oValorLlista - Camp on es guarda el valor de la Llista
////////////////////////////////////////////////////////////    
function canviValorLlista(oLlista, oValorLlista)
{
	var sllista = scoGSITVal.isEmpty(oLlista.editValue) ? "" : oLlista.editValue;
	var sTxt = scoGSITVal.isEmpty(oValorLlista.rawValue) ? "" : oValorLlista.rawValue;
	return (sllista.toUpperCase() != sTxt.toUpperCase());
}

/////////////////////////////////////////////////////////////////////////////
// Nom: inicialitzaLlista
// Descripció: Mètode que inicialitza un combo 'oLlista' amb els valors d'un array donat 'arrValors'
// Paràmetres d'entrada: 
//		oLlista - Combo on s'han de posar els valors
//		arrValors - Array on es troben els valors
///////////////////////////////////////////////////////////////////////////// 
function inicialitzaLlista(oLlista, arrValors)
{
	if (!scoGSITVal.existeixObjecte(oLlista)) return;	

	oLlista.clearItems();

	var nValores = arrValors.length; 
	for(i=0; i<nValores; i++) 
	{
		if ( (!scoGSITVal.isEmpty(arrValors[i][0])) && (!scoGSITVal.isEmpty(arrValors[i][1])) )
			oLlista.addItem(arrValors[i][0], arrValors[i][1]);
	}
}

/////////////////////////////////////////////////////////////////////////////
// Nom: inicialitzaLlistaSiBuida
// Descripció: Mètode que inicialitza un combo 'oLlista' amb els valors d'un array donat 'arrValors' si està buida
// Paràmetres d'entrada: 
//		oLlista - Combo on s'han de posar els valors
//		arrValors - Array on es troben els valors
///////////////////////////////////////////////////////////////////////////// 
function inicialitzaLlistaSiBuida(oLlista, arrValors)
{
	if (!scoGSITVal.existeixObjecte(oLlista)) return;	

	if (oLlista.length == 0) inicialitzaLlista(oLlista, arrValors);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: cercaPosicioArray
// Descripció: Mètode que cerca la posició a 'arrValors' de 'objEscollit'. 
// Paràmetres d'entrada:
//		arrValors - Array on es troben els valors
//		sValor - Valor que cercarà
// Paràmetres de sortida:
//		Integer - Retorna la posició on l'ha trobat. Si no el el troba retorna -1
///////////////////////////////////////////////////////////////////////////// 
function cercaPosicioArray(arrValors, sValor)
{
	var nElems = arrValors.length;
	for (var nPosicio=0;nPosicio<nElems;nPosicio++)
		if (arrValors[nPosicio][1]== sValor) return nPosicio;

	return -1;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: cercaPosicioLlista
// Descripció: Mètode que cerca la posició a 'oLLista' de 'sValor'. 
// Paràmetres d'entrada:
//		oLLista - Llista
//		sValor - Valor que cercarà
// Paràmetres de sortida:
//		Integer - Retorna la posició on l'ha trobat. Si no el el troba retorna -1
///////////////////////////////////////////////////////////////////////////// 
function cercaPosicioLlista(oLLista, sValor)
{
	var oItems = oLLista.resolveNode("#items[1]"); 
	if (oItems == null) oItems = oLLista.resolveNode("#items[0]"); 
	if (oItems == null) return;

	var nNumValors = oItems.nodes.length; 
	for (nItem = 0; nItem < nNumValors; nItem++)
	{ 
		if (oItems.nodes.item(nItem).value == sValor) return nItem;
	}

	 return -1;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: carregaSeguentLlista
// Descripció: Mètode que inicialitza un combo amb els valors d'un array donat
// Paràmetres d'entrada:
//		objEscollit - Combo anterior
//		oLlista - Combo on s'han de posar els valors
//		arrValors - Array on es troben els valors
//		llibreria - llibreria on es troben els array a carregar
//		esborraValor - booleà que indica si volem esborrar el valor que hi podia haver carregat
//		bCercaArray  - booleà que indica si cercarà l'array corresponent a 'arrValors'
// Paràmetres de sortida:
//		string - Retorna el nom del darrer array carregat
///////////////////////////////////////////////////////////////////////////// 
function carregaSeguentLlista(objEscollit, oLlista, arrValors, llibreria, esborraValor, bCercaArray)
{
	if (!scoGSITVal.existeixObjecte(objEscollit)) return;
	if (!scoGSITVal.existeixObjecte(oLlista)) return;

	if (!scoGSITVal.isEmpty(objEscollit.rawValue))
	{
		if (arguments.length < 6) bCercaArray = false;
		if (esborraValor) oLlista.rawValue = "";	

		var pos = (bCercaArray) ? cercaPosicioArray(arrValors, objEscollit.rawValue) : objEscollit.selectedIndex;
		if (pos == -1) return;

		var arrayEscollit = llibreria + "." + arrValors[pos][2];
		var arrFill = eval(arrayEscollit);

		inicialitzaLlista(oLlista, arrFill);
		return arrayEscollit;
	}	
}

