////////////////////////////////////////////////////////////
// Nom: obtenirNomComarca
// Descripció: Mètode que recupera el nom d'una comarca a partir del seu codi.
// Paràmetres d'entrada:
//		codiComarca - Codi de la comarca
// Paràmetres de sortida:
//		string - Nom de la comarca
////////////////////////////////////////////////////////////               
function obtenirNomComarca(codiComarca)
{
	var arrComarca = obtenirArrayComarca(codiComarca);

	if (arrComarca != "")
	{
		for(var i=0; i<arrComarca.length; i++)
		{
			if (arrComarca[i][1] == codiComarca) return arrComarca[i][0];
		}
	}	

	return "";
}             

////////////////////////////////////////////////////////////
// Nom: obtenirIdArrayPoblacionsComarca
// Descripció: Mètode que recupera l'identificador de la llista de poblacions de la comarca, a partir del codi de la comarca
// Paràmetres d'entrada:
//		codiComarca - Codi de la comarca
// Paràmetres de sortida: 
//		string - Identificador de la llista que conté les poblacions de la comarca
////////////////////////////////////////////////////////////                       
function obtenirIdArrayPoblacionsComarca(codiComarca)
{
	var arrComarca = obtenirArrayComarca(codiComarca);

	if (arrComarca != "")
	{
		for(var i=0; i<arrComarca.length; i++)
		{
			if (arrComarca[i][1] == codiComarca) return arrComarca[i][2];
		}
	}
	return "";
} 


////////////////////////////////////////////////////////////
// Nom: obtenirArrayComarca
// Descripció: Mètode que recupera una llista amb les comarques d'una província a partir del codi de la comarca.
// Paràmetres d'entrada:
//		codiComarca - Codi de la comarca
// Paràmetres de sortida:
// 		array - Llista amb les comarques de la respectiva província
////////////////////////////////////////////////////////////                       
function obtenirArrayComarca(codiComarca)
{	
	// Barcelona
	for(var i=0; i<arrBARCELONA.length; i++)
	{
		if (arrBARCELONA[i][1] == codiComarca) return arrBARCELONA;
	}

	// Girona
	for(var i=0; i<arrGIRONA.length; i++)
	{
		if (arrGIRONA[i][1] == codiComarca) return arrGIRONA;
	}

	// Lleida
	for(var i=0; i<arrLLEIDA .length; i++)
	{
		if (arrLLEIDA [i][1] == codiComarca) return arrLLEIDA ;
	}

	// Tarragona
	for(var i=0; i<arrTARRAGONA.length; i++)
	{
		if (arrTARRAGONA[i][1] == codiComarca) return arrTARRAGONA;
	}

	return "";
}

/***************************************************************
 Nom: scoGSITEsborrar
 Descripció: FW 2.4.8 - Conté el mètodes relacionats amb esborrar les dades dels panells del FW
**************************************************************************/

/////////////////////////////////////////////////////////////////////////////
// MÈTODES
/////////////////////////////////////////////////////////////////////////////

////////////////////////////////////////////////////////////
// Nom: esborraDadesPanellMultiple
// Descripció:  Mètode que esborra les dades del panell de múltiple
// Paràmetres d'entrada:
//		oPanell - Panell de selecció múltiple (Física/Jurídica, Física/Jurídica/Organisme)
//		bModifAvisos - Valor (true/false) que indica si s'ha de modificar el panell d'avisos
//		sTipusUsuariDef - Tipus d'usuari que es definirà per defecte
////////////////////////////////////////////////////////////
function esborraDadesPanellMultiple(oPanell, bModifAvisos, sTipusUsuariDef)
{
	if (!scoGSITVal.existeixObjecte(oPanell)) return;

	if (arguments.length < 2) bModifAvisos = scoGSITPanells.esPanellRequeridor(oPanell); // Per defecte el requeridor relacionat amb avisos
	if (arguments.length < 3) 
	{
		var aTipusUsuari = ["particular", "entitat_privada", "organisme"];
		sTipusUsuariDef = aTipusUsuari[scoGSITVal.numeroPanell(oPanell)];
	}

	scoGSITGen.netejarForm(oPanell, scoGSITPanells.esPanellPreOmplert(oPanell));  
	oPanell.BTN_PERSONA.rawValue = String(scoGSITVal.numeroTipoPersona(sTipusUsuariDef)+1);

	if (sTipusUsuariDef == "particular")            scoGSITVal.canviFisica(oPanell, true, bModifAvisos);
	else if (sTipusUsuariDef == "entitat_privada")  scoGSITVal.canviJuridica(oPanell, true, bModifAvisos);
	else if (sTipusUsuariDef ==  "organisme")       scoGSITVal.canviOrganisme(oPanell, true, bModifAvisos);	
}

////////////////////////////////////////////////////////////
// Nom: esborraDadesPanellMultipleContacte
// Descripció:  Mètode que esborra les dades del panell de múltiple de contacte
// Paràmetres d'entrada:
//		oPanell - Panell de contacte múltiple (Física/Jurídica, Física/Jurídica/Organisme)
//		sTipusUsuariDef - Tipus d'usuari que es definirà per defecte
////////////////////////////////////////////////////////////
function esborraDadesPanellMultipleContacte(oPanell, sTipusUsuariDef)
{
	if (!scoGSITVal.existeixObjecte(oPanell)) return;
	if (arguments.length < 2)  sTipusUsuariDef = scoGSITVal.tipusUsuariPanell(oPanell);

	var aRols = [scoGSITPar.nRolAcrePFContacte, scoGSITPar.nRolAcrePJContacte, scoGSITPar.nRolAcreORContacte];
	var nPersona = scoGSITVal.numeroTipoPersona(sTipusUsuariDef);

	var oAvisosAct = scoGSITPanells.obtenirPersonaPanellMultiple(oPanell);

	bPrecarrega = scoGSITPanells.esPanellPreOmplert(oPanell);
	scoGSITGen.netejarForm(oPanell, bPrecarrega);  
	scoGSITPanells.defDadesIdent(oAvisosAct, sTipusUsuariDef, aRols[nPersona], true);

	if (scoGSITVal.existeixObjecte(scoGSITPar.defAdrecaAvisos))
	{
		if (scoGSITPar.defAdrecaAvisos.length >= nPersona) scoGSITPanells.defAdrecaPanell(oAvisosAct, scoGSITPar.defAdrecaAvisos[nPersona], true);		
	}

}

////////////////////////////////////////////////////////////
// Nom: esborraDadesPanellFisicaJuridica
// Descripció:  Mètode que esborra les dades del panell de física o jurídica
// Paràmetres d'entrada:
//		oPanell - Panell de físisica_o_juridica que s'han d'esborrar les dades
//		bModifAvisos - Valor (true/false) que indica si s'ha de modificar el panell d'avisos
////////////////////////////////////////////////////////////
function esborraDadesPanellFisicaJuridica(oPanell, bModifAvisos)
{
	if (arguments.length == 2) 
		esborraDadesPanellMultiple(oPanell, bModifAvisos);
	else
		esborraDadesPanellMultiple(oPanell);
}

////////////////////////////////////////////////////////////
// Nom: esborraDadesPanellDadesIDParticular
// Descripció:  Mètode que esborra les dades del panell DADES_IDENTIFICACIO_PARTICULAR
// Paràmetres d'entrada:
//		oPanell - Panell DADES_IDENTIFICACIO_PARTICULAR del que s'han d'esborrar les dades
//		aEsbAdreca - Array amb la info x esborrar l'adreça : ["Funció x esborrar adreça", "Nom panell adreca", "Altres paràmetres x la crida (OPCIONALS)"]
////////////////////////////////////////////////////////////
function esborraDadesPanellDadesIDParticular(oPanell, aEsbAdreca)
{
	bPrecarrega = scoGSITPanells.esPanellPreOmplert(oPanell);
	bEsSignatari = scoGSITPanells.esPanellEsSignatari(oPanell);

	scoGSITGen.netejarForm(oPanell, bPrecarrega);
	if (arguments.length == 2) scoGSITPanells.esborraAdrecaPanell(oPanell, aEsbAdreca);	

	oPanell.CONTACTE.ES_SIGNATARI.rawValue = bEsSignatari;
	oPanell.CONTACTE.TXT_ROL_ACREDITACIO.rawValue = "1";
	oPanell.TIPUS_USUARI.rawValue = "particular";	
	scoGSITVal.controlPassaport(oPanell.CONTACTE.TXT_TIPUS_IDENTIFICADOR);
}			   

////////////////////////////////////////////////////////////
// Nom: esborraDadesPanellDadesIDParticularNac
// Descripció:  Mètode que esborra les dades del panell DADES_IDENTIFICACIO_PARTICULAR_NAC
// Paràmetres d'entrada:
//		oPanell - Panell DADES_IDENTIFICACIO_PARTICULAR_NAC del que s'han d'esborrar les dades
//		aEsbAdreca - Array amb la info x esborrar l'adreça : ["Funció x esborrar adreça", "Nom panell adreca", "Altres paràmetres x la crida (OPCIONALS)"]
////////////////////////////////////////////////////////////
function esborraDadesPanellDadesIDParticularNac(oPanell, aEsbAdreca)
{
	bPrecarrega = scoGSITPanells.esPanellPreOmplert(oPanell);
	bEsSignatari = scoGSITPanells.esPanellEsSignatari(oPanell);

	scoGSITGen.netejarForm(oPanell, bPrecarrega);
	if (arguments.length == 2) scoGSITPanells.esborraAdrecaPanell(oPanell, aEsbAdreca);

	oPanell.CONTACTE.ES_SIGNATARI.rawValue = bEsSignatari;
	oPanell.CONTACTE.TXT_ROL_ACREDITACIO.rawValue = "1";
	oPanell.TIPUS_USUARI.rawValue = "particular";	

	var oIdentificador = scoGSITPanells.obtenirObjecteFill(oPanell, "TXT_TIPUS_IDENTIFICADOR");
	scoGSITVal.controlPassaport(oIdentificador);
	scoGSITPanells.defNacionalitat(oPanell, oIdentificador);
	scoGSITAdreca.canviNacionalitatIDParticularNac(scoGSITPanells.obtenirObjecteFill(oPanell, "CHK_ES_ESPANYOL"));
}	

