////////////////////////////////////////////////////////////
// Nom: codificaHTML
// Descripció: Mètode que codififica els 5 caràcters especials per l'HTML en la seva entitat
////////////////////////////////////////////////////////////
function codificaHTML(sTxt) 
{
	if (!scoGSITVal.existeixObjecte(sTxt)) return "";
    return String(sTxt).replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/'/g, '&#39;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

///////////////////////////////////////////////////////////////////////////// 
// Nom: defEstils
// Descripció: Genera el texte per definir els estils de qualsevol tipus de maquetació (paràgraf, link, text)
// Paràmetres d'entrada: 
//		sFont - Font de text
//		sMidaText - Mida del text
//		bEspaisBlancs - (true/false) per indicar si el text pot definir espais en blanc
//		nEspaiLletres - Mida de l'espai entre lletres
///////////////////////////////////////////////////////////////////////////// 
function defEstils(sFont, sMidaText, bEspaisBlancs, nEspaiLletres)
{
	if (arguments.length < 1) sFont = "";
	if (arguments.length < 2) sMidaText = "";
	if (arguments.length < 3) bEspaisBlancs = true;
	if (arguments.length < 4) nEspaiLletres = "";

	sFont = (sFont == "") ? "Arial" : sFont;
	sMidaText = (sMidaText == "") ? "8" : sMidaText;
	sEspaisBlans = (bEspaisBlancs) ? "yes" : "no";
	sEspaiLletres = (nEspaiLletres == "") ? "0" : sEspaiLletres;
	return ("font-family:" + sFont + ";font-size:" + sMidaText + "pt;xfa-spacerun:" + sEspaisBlans + ";letter-spacing:" + sEspaiLletres + "in");
}


///////////////////////////////////////////////////////////////////////////// 
// Nom: maquetaTag
// Descripció: Mètode que maqueta el 'sText' en un tag 'sTag' amb els 'sEstils'
// Paràmetres d'entrada: 
//		sTag - Tag que es maquestarà
//		sText - Text que es mostrarà al tag 'sTag'
//		sEstils - Estils que es definiran per al tag 'sTag'
///////////////////////////////////////////////////////////////////////////// 
function maquetaTag(sTag, sText, sEstils)
{
	if (arguments.length < 3) sEstils = "";
	return "<" + sTag + " style=\"" + sEstils + "\">" + sText + "</" + sTag + ">";
}

///////////////////////////////////////////////////////////////////////////// 
// Nom: maquetaParagraf
// Descripció: Mètode que maqueta el 'sText' en un tag 'P' amb els 'sEstils'
// Paràmetres d'entrada: 
//		sText - Text que es mostrarà al tag 'P'
//		sEstils - Estils que es definiran per al tag 'P'
///////////////////////////////////////////////////////////////////////////// 
function maquetaParagraf(sText, sEstils)
{
	if (arguments.length < 2) sEstils = "";
	return maquetaTag("p", sText, sEstils);
}

///////////////////////////////////////////////////////////////////////////// 
// Nom: maquetaText
// Descripció: Mètode que maqueta el 'sText' en un tag 'SPAN' amb els 'sEstils'
// Paràmetres d'entrada: 
//		sText - Text que es mostrarà al tag 'SPAN'
//		sEstils - Estils que es definiran per al tag 'SPAN'
///////////////////////////////////////////////////////////////////////////// 
function maquetaText(sText, sEstils)
{
	if (arguments.length < 2) sEstils = "";
	return maquetaTag("span", sText, sEstils);
}

///////////////////////////////////////////////////////////////////////////// 
// Nom: maquetaLink
// Descripció: Mètode que maqueta el 'sText' en un tag 'A' amb els 'sEstils'
// Paràmetres d'entrada: 
//		sURL - URL del link
//		sText - Text que mostrarà el link
///////////////////////////////////////////////////////////////////////////// 
function maquetaLink(sURL, sText)
{
	return "<a href=\""+ sURL + "\">" + sText + "</a>";
}

///////////////////////////////////////////////////////////////////////////// 
// Nom: maquetaRichTextCamp
// Descripció: Mètode que maqueta el 'sText' en un tag 'P' amb els 'sEstils'
// Paràmetres d'entrada: 
//		sText - Text que es mostrarà
//		sEstils - Estils que es definiran 
//		bParagraf - Indica si s'ha de definir el paragram
///////////////////////////////////////////////////////////////////////////// 
function maquetaRichTextCamp(sText, sEstils, bParagraf)
{
	if (arguments.length < 2) sEstils = defEstils();
	if (arguments.length < 3) bParagraf = true;

	var txtIni = "<body xmlns=\"http:\/\/www.w3.org/1999/xhtml\" xmlns:xfa=\"http:\/\/www.xfa.org/schema/xfa-data/1.0/\">";
	var pIni = (bParagraf) ? "<p style=\"" + sEstils + "\">" : "";
	var pFi =  (bParagraf) ? "</p>" : "";
	var txtFi = "</body>";

	return (txtIni + pIni + sText + pFi + txtFi);
}

///////////////////////////////////////////////////////////////////////////// 
// Nom: defValueCampRichText
// Descripció: Mètode que assigna el valor a un camp de Rich Text
// Paràmetres d'entrada: 
//		oCamp - Camp a assignar el valor
//		sValor - Valor que s'assignarà al camp. Ha d'estar maquetat com Rich text
///////////////////////////////////////////////////////////////////////////// 
function defValueCampRichText(oCamp, sValorXML)
{
	if (!scoGSITVal.existeixObjecte(oCamp)) return;	

	var objClassName = oCamp.ui.oneOfChild.className;
	if (objClassName != "textEdit") return;

	if (!scoGSITVal.existeixObjecte(oCamp.ui.textEdit)) return;		
	oCamp.resolveNode("ui.#textEdit").allowRichText = "1";

	if (!scoGSITVal.existeixObjecteFill(oCamp, "value.exData"))
	{
		oCamp.value.nodes.remove(oCamp.value.oneOfChild);
		var theNode = xfa.form.createNode("exData")
		oCamp.value.nodes.append(theNode);
	}

	oCamp.resolveNode("value.#exData").contentType = "text/html";
	oCamp.value.exData.loadXML(sValorXML);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: defRichTextVariesLinies
// Descripció: Mètode que s'encarrega de definir 'oCamp' en funció del seu PV relacionat, si aquest està definit, sinò el defineix a buit
// Paràmetres d'entrada:
//		oCamp - Camp a definir
//		sValor - Valor a definir al camp
//		bBorrar - Indica si esborrar el camp quan 'sPV' es buit
//		bParagraf - Indica si s'ha de definir el paragram
///////////////////////////////////////////////////////////////////////////// 
function defRichTextVariesLinies(oCamp, sValor, bBorrar, bParagraf, bMantenirEspais)
{
	if (arguments.length < 3) bBorrar = false;
	if (arguments.length < 4) bParagraf = true;	
	if (arguments.length < 5) bMantenirEspais = false;
	if (scoGSITVal.isEmpty(sValor) && !bBorrar) return;

	sValor = scoGSITVal.isEmpty(sValor) ? " " : sValor;
	var sValorXML = "";
	var sEstils = (bMantenirEspais) ? "xfa-spacerun:yes" : "";

	var aPararagrafs = sValor.split("\n");
	var nPars = aPararagrafs.length;
	for (var n=0; n<nPars; n++)
	{
		var sText = aPararagrafs[n];
		sText = scoGSITVal.isEmpty(sText) ? " " : sText;  // PQ pinti els paràgrafs buits
		var sParagraf = maquetaParagraf(maquetaTag("span", sText, ""), sEstils);
		sValorXML += sParagraf;
	}

	sValorXML = maquetaRichTextCamp(scoTextEnriquit.obtenirTextLiteral(sValorXML), "padding:0; margin:0", bParagraf);
	defValueCampRichText(oCamp, sValorXML);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: defRichTextVariesLiniesXML
// Descripció: Mètode que s'encarrega de definir 'oCamp' en funció del seu PV relacionat, si aquest està definit, sinò el defineix a buit
// Paràmetres d'entrada:
//		oCamp - Camp a definir
//		sTag - Tag del XML del que agafarà el valor
//		bBorrar - Indica si esborrar el camp quan 'sPV' es buit
//		bParagraf - Indica si s'ha de definir el paragram
///////////////////////////////////////////////////////////////////////////// 
function defRichTextVariesLiniesXML(oCamp, sTag, bBorrar, bParagraf, bMantenirEspais)
{
	var oTag = xfa.resolveNode(sTag); 
	defRichTextVariesLinies(oCamp, scoGSITVal.getValueTagXML(oTag), bBorrar, bParagraf, bMantenirEspais);
}

