/////////////////////////////////////////////////////////////////////////////
// Nom: invocarServeiNegoci
// Descripció: Mètode que invoca al servei de negoci
// Paràmetres d'entrada:
//		xmlDades - XML de petició
//      bWireDump - (true/false) per indicar si cal mostrar tots els missatges de la conexio per consola
// Paràmetres de sortida:
//		resultat - Objecte que s'obté de la invocació
///////////////////////////////////////////////////////////////////////////// 
function invocarServeiNegoci(xmlDades, bWireDump)
{
	SOAP.wireDump = ((arguments.length < 2) ? false : bWireDump);

	var oDadesTramit = scoGSITPar.oDadesCFGTramit.DADES_TRAMIT;
	if (!scoGSITVal.compPanell(oDadesTramit, "Dades de configuració del tràmit: Dades Tràmit")) return -1;	

	if (scoGSITVal.isEmpty(scoGSITPar.URLWebService)) return -1;	

	var result = null;
	try{	
		var myProxy = Net.SOAP.connect(scoGSITPar.URLWebService);
		if(myProxy == null)
			app.alert(msgErrorConnexio.value);
		else
			result = myProxy.invocarServei(xmlDades);
	} catch(exc){
		app.alert(msgErrorConnexio.value);
	}
	return result;
}

