/////////////////////////////////////////////////////////////////////////////
// Nom: isComboPrecargat
// Descripció: Mètode que comprova si 'oCamp' es un combo precarregat
// Paràmetres d'entrada:
//		Camp - Camp en el que se'n verifica si el combo està carregat
// Paràmetres de sortida:
//		booleà - Valor (true/false) segons si el camp de tipus llista està carregat
/////////////////////////////////////////////////////////////////////////////
function isComboPrecargat(oCamp)
{
	try
	{
		var aCamps = ["LLISTA_COMARQUES", "LLISTA_MUNICIPIS", "LLISTA_LLOGARETS"]; // LLISTA_PROVINCIES no se borra siempre es la misma

		if ( (oCamp.ui == null) || (oCamp.ui == undefined) ) return false;
		if ((oCamp.ui.oneOfChild == null) || (oCamp.ui.oneOfChild == undefined)) return false;

		if (oCamp.ui.oneOfChild.className == "choiceList")
		{
			var nNums = aCamps.length;
			for (var n=0; n<nNums; n++)   if (oCamp.name == aCamps[n]) return true;
		}

		return false;
	}
	catch(exc) 
	{
		return retornarExcepcio("scoGSITGEn.isComboPrecargat()",exc);
	}	
}

/////////////////////////////////////////////////////////////////////////////
// Nom: isCheckButton
// Descripció:  Mètode que verifica si 'oCamp' és un camp de tipus isCheckButton
// Paràmetres d'entrada:
//		oCamp - Camp que se'n verifica si és de tipus checkButon
// Paràmetres de sortida:
//		booleà - Valor (true/false) segons si el camp és de tipus 'CheckButton' o no.
/////////////////////////////////////////////////////////////////////////////
function isCheckButton(oCamp)
{
    try
    {
        if (oCamp == null) return false;
        if ( (oCamp.ui == null) || (oCamp.ui == undefined) ) return false;

        if(existeixPropietat(oCamp.ui, "checkButton"))
        {
            if ((oCamp.ui.checkButton == null) || (oCamp.ui.checkButton == undefined)) return false;

            return (oCamp.ui.checkButton.className == "checkButton");
        }

        return false;
    }
    catch(exc) 
    {
        return retornarExcepcio("scoGSITGEn.isCheckButton()",exc);
    }       	
}

////////////////////////////////////////////////////////////
// Nom: existeixPropietat
// Descripció: Mètode que comprova que existeixi la propietat sPropietat del paràmetre oNod
// Paràmetres d'entrada:
//		oNod - Objecte del qual volem comprovar si existeix la propietat
//		sPropietat - Nom de la propietat	
// Paràmetres de sortida:
//		booleà - Valor (true/false) en cas que existeixi o no la propietat
////////////////////////////////////////////////////////////
function existeixPropietat(oNod, sPropietat)
{
	var oNodes = oNod.nodes;
	var nodesLength = oNodes.length; 

	for (var i = 0; i < nodesLength; i++) 
	{
		if(oNodes.item(i).className == sPropietat || oNodes.item(i).name == sPropietat)
		{
			 return true;
		}
	}
	return false;
}


/////////////////////////////////////////////////////////////////////////////
// Nom: netejarForm
// Descripció: Mètode encarregat d'esborrar tots els camps d'un form o subform
// Paràmetres d'entrada:
//		myParentObject - Formulari o panell a esborrar
//		bPrecarrega - Indica si s'ha de tenir en compte la precarrega al esborrar
/////////////////////////////////////////////////////////////////////////////
function netejarForm(myParentObject, bPrecarrega)
{
	if (myParentObject == null) return; 

	if (arguments.length < 2) bPrecarrega = false;

	var allChildElements = myParentObject.nodes; 	//Llegeix els nodes del form
	var intNumElements = allChildElements.length;	//Número de nodes del form

	var oTipusUsuari = scoGSITPanells.obtenirObjecteFill(myParentObject, "TIPUS_USUARI");
	if (oTipusUsuari == null) oTipusUsuari = scoGSITPanells.obtenirObjectePare(myParentObject, "TIPUS_USUARI");
	var sUsuari = (oTipusUsuari == null)  ? "" : oTipusUsuari.rawValue; 

	//Depenent del tipus d'element fem un tractament.
	//Subform: Es torna a cridar al mateix mètode per tractar els seus nodes
	for(var j=0; j< intNumElements;j++)
	{
		var currentElement = allChildElements.item(j);
		if(currentElement.className == "subform")  netejarForm(currentElement, bPrecarrega); 			

		var sName = currentElement.name;
		if(currentElement.className == "field") //Desactivem Fields
		{ 			
			if ( (sName != "TIPUS_USUARI") && (sName != "TXT_MOSTRAR_COMARCA") && (sName != "TXT_MOSTRAR_PAIS"))
			{
				// currentElement.rawValue = (isCheckButton(currentElement)) ? "0" : ""; // Verificar si es tracta d'un "checkButton"

				if (isCheckButton(currentElement))
				{
					currentElement.rawValue = 0; // si te un valor definit x defecte x check off el redefinim
					var oNode = currentElement.resolveNode("#items[0]");
					if (oNode != null)
					{	
						if (oNode.nodes.item(1) != null) currentElement.rawValue = oNode.nodes.item(1).value; // Valor definit x check off
					}					
				}
				else
					currentElement.rawValue = "";

				if (isComboPrecargat(currentElement)) currentElement.clearItems();    // Esborra llista del combo

				if (currentElement.className == "field") // Amaguem els recuadres d'error
				{
					var bAmagarRecuadre = true;
					if (existeixPropietat(currentElement, "ui"))
					{				
						if (existeixPropietat(currentElement.ui, "button"))					
							bAmagarRecuadre = (currentElement.ui.button.className != "button");
					}

					if (bAmagarRecuadre) scoGSITVal.amagarRequadre(currentElement);	
				}
			}
		} 
		else if(currentElement.className == "exclGroup") //Desactivem RadioButton
		{
			if (sName != "BTN_PERSONA")
			{
				for(k=0; k<currentElement.nodes.length;k++)
				{ 
					if(currentElement.nodes.item(k).className == "field")  currentElement.rawValue = ""; 
				}
			}
		}
	}
}


/////////////////////////////////////////////////////////////////////////////
// Nom: amagarRequadresForm
// Descripció: Mètode encarregat d'esborrar tots els requedres d'error dels camps d'un form o subform
// Paràmetres d'entrada:
//		myParentObject - Formulari o panell a esborrar els requadres
/////////////////////////////////////////////////////////////////////////////
function amagarRequadresForm(myParentObject)
{
	if (myParentObject == null) return; 

	var allChildElements = myParentObject.nodes; 	//Llegeix els nodes del form
	var intNumElements = allChildElements.length;	//Número de nodes del form

	//Subform: Es torna a cridar al mateix mètode per tractar els seus nodes
	for(var j=0; j< intNumElements;j++)
	{
		var currentElement = allChildElements.item(j);
		if(currentElement.className == "subform")  amagarRequadresForm(currentElement); 			

		if(currentElement.className == "field") //Desactivem Fields
		{ 		
			var bAmagarRecuadre = true;
			if (existeixPropietat(currentElement, "ui"))
			{				
				if (existeixPropietat(currentElement.ui, "button"))					
					bAmagarRecuadre = (currentElement.ui.button.className != "button");
			}

			if (bAmagarRecuadre) scoGSITVal.amagarRequadre(currentElement);	
		} 
	}
}

////////////////////////////////////////////////////////////
// Nom: retornarExcepcio
// Descripció: Mètode que es cridarà des de qualsevol punt del codi on es produeixi una excepció.
//			   El que farà la funció és mostrar un missatge d'error amb el nom de la funció o objecte que l'ha provocat amb informació de la excepció.
// Paràmetres d'entrada:
//		nom - El nom de la funció o objecte on s'ha produït l'excepció.
//		exc - Contingut de la excepció.
// Paràmetres de sortida:
//		-1 - Aquest mètode sempre retornarà aquest valor.
////////////////////////////////////////////////////////////
function retornarExcepcio(nom,exc)
{
	if (xfa.host.name == "Acrobat") 
	{	
		var missatgeError = "";
		if(exc["name"].indexOf("NotAllowed")!="-1")
			xfa.host.messageBox(nom + " \n" + exc + " \n" + msgNoPrivilegis.value); // SSN el NotAllowed no puede mostrar mas info?
		else
		{
			for(var t in exc) missatgeError += t + " - " + exc[t] + "\n";
			xfa.host.messageBox(nom + " \n" + exc + " \n" + missatgeError);
		}
	}
	else	
	{
		var oMsg = xfa.resolveNode(ACTAINSPECCIO.acusament_rebuda.ACUSAMENT_REBUDA.txtRevisio);
		if (!scoGSITVal.existeixObjecte(oMsg)) return -1;	

		var missatgeError = "";
		if(exc["name"].indexOf("NotAllowed")!="-1")
			oMsg.rawValue += "\n ***" + " \n" + exc + nom + " - " + msgNoPrivilegis.value;
		else
		{
			for(var t in exc) missatgeError += t + " - " + exc[t] + "\n";
			oMsg.rawValue += "\n ***" + " \n" + exc + nom + " - " + missatgeError;
		}
	}

	return -1;	
}

