///////////////////////////////////////////
// MÈTODES
///////////////////////////////////////////

////////////////////////////////////////////////////////////
// Nom: getMuniLlogaret
// Descripció: Mètode que retorna el codi del municipi al que pertany el llogaret
// Paràmetres d'entrada:
//		codiLlogaret - Codi del llogaret
// Paràmetres de sortida:
//		string - Codi del municipi al que pertany el llogaret, "" si el codi és incorrecte
////////////////////////////////////////////////////////////   
function getMuniLlogaret(codiLlogaret)
{
	var rExp = new RegExp("^(08|17|25|43)[0-9]{9}$");
	if (!rExp.test(codiLlogaret))  return "";

	var sCodiMuni = codiLlogaret.substring(0,5);
	if (!scoGSITMunCatInfo.isCodiMunicipi(sCodiMuni)) 
		return "";
	else
		return sCodiMuni;
}

////////////////////////////////////////////////////////////
// Nom: isCodiLlogaret
// Descripció: Mètode que comprova si 'codiLlogaret' és un codi de llogaret vàlid
// Paràmetres d'entrada:
//		codiLlogaret - Codi del llogaret
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si 'codiLlogaret' és un codi d'Unitat Poblacional vàlid
////////////////////////////////////////////////////////////   
function isCodiLlogaret(codiLlogaret)
{
	var sCodiMuni = getMuniLlogaret(codiLlogaret);
	if (sCodiMuni == "") return false;

	var aLlogarets = eval("arr"+sCodiMuni);
	for(var i=0; i<aLlogarets.length; i++)
	{
		if (aLlogarets[i][1] == codiLlogaret) return true;
	}	

	return false;	
}	

////////////////////////////////////////////////////////////
// Nom: obtenirNomLlogaret
// Descripció: Mètode que recupera el nom d'un Llogaret, a partir del seu codi
// Paràmetres d'entrada:
//		codiLlogaret - Codi del llogaret
// Paràmetres de sortida:
//		string - Nom del Llogaret, "" si el codi és incorrecte
////////////////////////////////////////////////////////////   
function obtenirNomLlogaret(codiLlogaret)
{
	var sCodiMuni = getMuniLlogaret(codiLlogaret);
	if (sCodiMuni == "") return "";

	var aLlogarets = eval("arr"+sCodiMuni);
	for(var i=0; i<aLlogarets.length; i++)
	{
		if (aLlogarets[i][1] == codiLlogaret) return aLlogarets[i][0];
	}	

	return "";	
}

////////////////////////////////////////////////////////////
// Nom: obtenirArrayLlogaretsMunicipi
// Descripció: Mètode que recupera una llista dels llogarets d'un municipi
// Paràmetres d'entrada:
//		codiMunicipi - Codi del municipi
// Paràmetres de sortida:
//		array - Llista dels llogarets del municipi, null si el codi és incorrecte
////////////////////////////////////////////////////////////   
function obtenirArrayLlogaretsMunicipi(codiMunicipi)
{
	if (!scoGSITMunCatInfo.isCodiMunicipi(codiMunicipi)) return null;

	return eval("arr"+codiMunicipi);
}

