////////////////////////////////////////////////////////////
// Nom: MissatgeError
// Descripció: Mètode que mostra el missatge d'error "sMissatge" amb títol "sTitol"
// Paràmetres d'entrada:
//		sMissatge - Missatge a mostrar
//		sTitol - Títol del missatge a mostrar
////////////////////////////////////////////////////////////               
function MissatgeError(sMissatge, sTitol)
{
	if (arguments.length == 1) sTitol = "";

     app.alert({  cMsg: sMissatge,
                  cTitle: sTitol,
                  nIcon: 0, nType: 0});
}            

////////////////////////////////////////////////////////////
// Nom: MissatgeAlerta
// Descripció: Mètode que mostra el missatge d'alerta "sMissatge" amb títol "sTitol"
// Paràmetres d'entrada:
//		sMissatge - Missatge a mostrar
//		sTitol - Títol del missatge a mostrar
////////////////////////////////////////////////////////////               
function MissatgeAlerta(sMissatge, sTitol)
{
	if (arguments.length == 1) sTitol = "";

     app.alert({  cMsg: sMissatge,
                  cTitle: sTitol,
                  nIcon: 1, nType: 0});
}

////////////////////////////////////////////////////////////
// Nom: MissatgeInformatiu
// Descripció: Mètode que mostra el missatge informatiu "sMissatge" amb títol "sTitol"
// Paràmetres d'entrada:
//		sMissatge - Missatge a mostrar
//		sTitol - Títol del missatge a mostrar
////////////////////////////////////////////////////////////               
function MissatgeInformatiu(sMissatge, sTitol)
{
	if (arguments.length == 1) sTitol = "";

     app.alert({  cMsg: sMissatge,
                  cTitle: sTitol,
                  nIcon: 3, nType: 0});
}

////////////////////////////////////////////////////////////
// Nom: MissatgePregunta
// Descripció: Mètode que mostra el missatge de pregunta  "sMissatge" amb títol "sTitol"
// Paràmetres d'entrada:
//		sMissatge - Missatge a mostrar
//		sTitol - Títol del missatge a mostrar
// Paràmetres de sortida:
//		Enter - Valor de rotorn del resultat de la pregunta
////////////////////////////////////////////////////////////               
function MissatgePregunta(sMissatge, sTitol)
{
	if (arguments.length == 1) sTitol = "";

    var nResposta = app.alert({  cMsg: sMissatge,
								 cTitle: sTitol,
								 nIcon: 2, nType: 2});

	return (nResposta == 4);
}

