////////////////////////////////////////////////////////////
// Nom: isCodiMunicipi
// Descripció: Mètode que comprova si 'codiMunicipi' és un codi d'un municipi català vàlid
// Paràmetres d'entrada:
//		codiMunicipi - Codi del municipi
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si 'codiMunicipi' és un codi d'un municipi català vàlid
////////////////////////////////////////////////////////////   
function isCodiMunicipi(codiMunicipi)
{
	var rExp = new RegExp("^(08|17|25|43)[0-9]{3}$");
	if (!rExp.test(codiMunicipi))  return false;

	var sProv = codiMunicipi.substring(0,2);
	var sIDMuni = codiMunicipi.substring(2,5);
	var aMunis = eval("arr"+sProv);	

	for(var i=0; i<aMunis.length; i++)
	{
		if (aMunis[i] == sIDMuni) return true;
	}	

	return false;
}	


////////////////////////////////////////////////////////////
// Nom: obtenirNomMunicipi
// Descripció: Mètode que recupera el nom d'un municipi a partir del codi del municipi i el codi de la comarca.
// Paràmetres d'entrada:
//		codiMunicipi - Codi del municipi
//		codiProvincia - Codi de la província que contempla el municipi
// Paràmetres de sortida:
//		string - Nom del municipi
////////////////////////////////////////////////////////////   
function obtenirNomMunicipi(codiMunicipi, codiComarca)
{
	var arrMunComarca = obtenirArrayMunicipisComarca(codiMunicipi, codiComarca);

	if (arrMunComarca != "")
	{
		for(var i=0; i<arrMunComarca.length; i++)
		{
			if (arrMunComarca[i][1] == codiMunicipi) return arrMunComarca[i][0];
		}
	}	

	return "";
}               


////////////////////////////////////////////////////////////
// Nom: obtenirArrayMunicipisComarca
// Descripció: Mètode que recupera una llista de municipis d'una comarca, a partir del codi de municipi i del codi de la comarca.
// Paràmetres d'entrada:
//		codiMunicipi - Codi del municipi
//		codiComarca - Codi de la comarca que contempla el municipi
// Paràmetres de sortida:
//		array - Llista de municipis de la respectiva comarca
////////////////////////////////////////////////////////////   
function obtenirArrayMunicipisComarca(codiMunicipi, codiComarca)
{
	var sArrayComarca = scoGSITComInfo.obtenirIdArrayPoblacionsComarca(codiComarca);
	if (sArrayComarca != "")
	{
		return eval(sArrayComarca);
	}

	return "";
}                 


////////////////////////////////////////////////////////////
// Nom: obtenirIdArrayLlogaretMunicipis
// Descripció: Mètode que recupera una llista de llogarets d'un municipi, a partir del codi del municipi i del codi de la comarca.
// Paràmetres d'entrada:
//		codiMunicipi - Ccodi del municipi
//		codiComarca - Codi de la comarca que contempla el municipi
// Paràmetres de sortida:
//		array - Llista de llogarets del respectiu municipi
////////////////////////////////////////////////////////////   
function obtenirIdArrayLlogaretMunicipis(codiMunicipi, codiComarca)
{
	var arrMunComarca = obtenirArrayMunicipisComarca(codiMunicipi, codiProvincia);

	if (arrMunComarca != "")
	{
		for(var i=0; i<arrMunComarca.length; i++)
		{
			if (arrMunComarca[i][1] == codiMunicipi) return arrMunComarca[i][2];
		}
	}	

	return "";
}

