////////////////////////////////////////////////////////////
// Nom: obtenirNomMunicipi
// Descripció: Mètode que recupera el nom d'un municipi a partir de seu codi de municipi i codi de província
// Paràmetres d'entrada:
//		codiMunicipi - Codi del municipi
//		codiProvincia - Codi de la província
// Paràmetres de sortida:
//		string - Nom del municipi
////////////////////////////////////////////////////////////   
function obtenirNomMunicipi(codiMunicipi, codiProvincia)
{
	var arrMunProvincia= obtenirArrayMunicipisProvincia(codiMunicipi, codiProvincia);

	if (arrMunProvincia != "")
	{
		for(var i=0; i<arrMunProvincia.length; i++)
		{
			if (arrMunProvincia[i][1] == codiMunicipi) return arrMunProvincia[i][0];
		}
	}	

	return "";
}               


////////////////////////////////////////////////////////////
// Nom: obtenirArrayMunicipisProvincia
// Descripció: Mètode que recupera una llista amb els municipis d'una província, a partir del codi del municipi i el codi de la província.
// Paràmetres d'entrada:
//		codiMunicipi - Codi del municipi
//		codiProvincia - Codi de la provincia que contempla el municipi
// Paràmetres de sortida:
//		array - Llista de municipis de la respectiva província
////////////////////////////////////////////////////////////   
function obtenirArrayMunicipisProvincia(codiMunicipi, codiProvincia)
{
	var sArrayProvincia = scoGSITProvInfo.obtenirIdArrayProvinciaEsp(codiProvincia);

	if (sArrayProvincia != "") { return eval(sArrayProvincia);}	

	return "";
}

