// VARIABLES
////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

// var: primerCampNoValid	   
// Descripció: Contindrà el somExpressión del primer camp que no compleixi amb la validació		   
var primerCampNoValid = "";

// var: arrCampsObligatoris
// Descripció: Contrindrà totes les somExpressions de tots els camps amb propietat de camp obligatori
var arrCampsObligatoris = null; 

// var: campOblogatori
// Descripció: Contindrà el somExpressión del primer camp que no compleixi amb la validació
var campOblogatori = "";		

