// MÈTODES
////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

////////////////////////////////////////////////////////////
// Nom: eliminaNodeAdreca
// Descripció:  Mètode que comprova que tipus d'usuari estigui definit
// Paràmetres d'entrada: 
//		oNodeTipusUsuari - Node de tipus d'usuari
//      sPersona - Tipus de persona
// Paràmetres de sortida:
//		booleà - Valor (true/false) en cas que tipus d'usuari estigui definit o no
////////////////////////////////////////////////////////////
function correcteTipusUsuari(oNodeTipusUsuari, sPersona)
{
	if (scoGSITVal.isEmpty(oNodeTipusUsuari.value)) 
	{
		app.alert("ATENCIÓ FACTORIA. El panell associat a " + sPersona + " no està ben definit, no té un valor asignat a Tipus d'usuari.");	
		return false;	
	}

	return true;
}

////////////////////////////////////////////////////////////
// Nom: eliminarOEsborrarNodeSobrant
// Descripció:  Mètode que elimina o esborra els nodes que sobren (Particular/Empresa/Organisme) de la persona indicada depenent de 'bElimina'
// Paràmetres d'entrada: 
//		sPersona - Inspeccionat
//		bElimina - Boleeà que indica si els nodes s'han d'esborrar o eliminar de l'XML
////////////////////////////////////////////////////////////
function eliminarOEsborrarNodeSobrant(sPersona, bElimina)
{
	if (arguments.length < 2) bElimina = false;

	var oNodePersona = xfa.resolveNode("xfa.record.Cos." + sPersona);
	if (!scoGSITVal.existeixObjecte(oNodePersona)) return;	

	// Elimina o esborra els Nodes de les persones no seleccionades (Particular / Empresa / Organisme) de 'sPersona'
	var sPersona = scoGSITVal.personaXML(oNodePersona.tipusUsuari);

	var oNodos = oNodePersona.nodes;

	var arNodesRemove = new Array();
	for (var nNodo = 0; nNodo<oNodos.length; nNodo++)
	{
		var oNodoAct = oNodos.item(nNodo);
		if ((oNodoAct.name != sPersona) && (scoGSITVal.esPersonaXMLCorrecte(oNodoAct.name)))
		{
			if (bElimina)
				arNodesRemove.push(oNodoAct);
			else 
				netejarNode(oNodoAct);		
		}
	}

	if (bElimina) {
		for (var i = 0; i < arNodesRemove.length; i++) {
			oNodePersona.nodes.remove(arNodesRemove[i]);
		}
	}
}

////////////////////////////////////////////////////////////
// Nom: eliminaNodeAdreca
// Descripció:  Mètode que elimina el node 'sNodeAdreca'
// Paràmetres d'entrada: 
//		sNodeAdreca - Panell Adreca a netejar
////////////////////////////////////////////////////////////
function eliminaNodeAdreca(sNodeAdreca)
{
	var oNodeAdrecaEliminar = xfa.resolveNode(sNodeAdreca);
	if (scoGSITVal.existeixObjecte(oNodeAdrecaEliminar))
	{
		if (scoGSITVal.esAdrecaBuida(oNodeAdrecaEliminar))	oNodeAdrecaEliminar.parent.nodes.remove(oNodeAdrecaEliminar);
	}
}

////////////////////////////////////////////////////////////
// Nom: eliminarNodeSobrant
// Descripció:  Mètode que elimina els nodes que sobren de la persona indicada
// Paràmetres d'entrada: 
//		sPersona - Inspeccionat
////////////////////////////////////////////////////////////
function eliminarNodeSobrant(sPersona)
{
	eliminarOEsborrarNodeSobrant(sPersona, true);
}



////////////////////////////////////////////////////////////
// Nom: eliminarNodesXmlSobrants
// Descripció:  Mètode que elimina els nodes que sobren el l'estructura de dades
////////////////////////////////////////////////////////////
function eliminarNodesXmlSobrants()
{
	// Eliminar nodes sobrants del requeridor (inspeccionat)
	eliminarNodeSobrant("Inspeccionat");
}


////////////////////////////////////////////////////////////
// Nom: netejarNode
// Descripció:  Mètode que neteja tots els valors dels fills i atributs el node
// Paràmetres d'entrada: 
//		oNodeNetejar - Panell a netejar
////////////////////////////////////////////////////////////
function netejarNode(oNodeNetejar)
{	
	if ((oNodeNetejar == null) || (oNodeNetejar == undefined)) return;

	var oNodes = oNodeNetejar.nodes;
	if ((oNodes.length)>0)
	{
		for (var i=0; i<oNodes.length; i++)
		{
			netejarNode(oNodes.item(i));
		}
	}
	else
	{
		// revisar si es tipus simple, no complexa
		if (oNodeNetejar.className == "dataValue") oNodeNetejar.value = "";
	}
}

////////////////////////////////////////////////////////////
// Nom: netejarNodeAdreca
// Descripció:  Mètode que neteja tots els valors dels fills i atributs el node 'sNodeAdreca'
// Paràmetres d'entrada: 
//		sNodeAdreca - Panell Adreca a netejar
////////////////////////////////////////////////////////////
function netejarNodeAdreca(sNodeAdreca)
{
	var oNodeAdreca = xfa.resolveNode(sNodeAdreca);
	if (scoGSITVal.existeixObjecte(oNodeAdreca))
	{
		if (scoGSITVal.esAdrecaBuida(oNodeAdreca))  netejarNode(oNodeAdreca);
	}
}


////////////////////////////////////////////////////////////
// Nom: netejarNodeSobrant
// Descripció:  Mètode que elimina els nodes que sobren de la persona indicada
// Paràmetres d'entrada: 
//		sPersona - Valor que indica el tipus de persona "Inspeccionat"
////////////////////////////////////////////////////////////
function netejarNodeSobrant(sPersona)
{
	eliminarOEsborrarNodeSobrant(sPersona, false);
}



////////////////////////////////////////////////////////////
// Nom: netejarNodesXmlSobrants
// Descripció:  Mètode que neteja els nodes que sobren el l'estructura de dades
////////////////////////////////////////////////////////////
function netejarNodesSobrants()
{
