//////////////////////////////////////////////////////////
// Nom: recorreDocumentSomPagina
// Descripció: Mètode que crida la funció 'recorreDocumentSom' per que en faci el respectiu recorregut
////////////////////////////////////////////////////////////
function recorreDocumentSomValidarFormulari()
{
	inicialitzacioVariablesValidacioGlobal();
	recorreDocumentSom(xfa.form.nodes.item(0).somExpression);
}

//////////////////////////////////////////////////////////
// Nom: recorreDocumentSomValidarPlana
// Descripció: Mètode que crida la funció 'recorreDocumentSom' per que en faci el respectiu recorregut
// Paràmetres d'entrada:
//		obj - Node del formulari que representa una pàgina	  
////////////////////////////////////////////////////////////
function recorreDocumentSomValidarPlana(subform)
{
	inicialitzacioVariablesValidacioGlobal();
	recorreDocumentSom(subform.somExpression);
}

//////////////////////////////////////////////////////////
// Nom: recorreDocumentSom
// Descripció: Mètode que recorre tot l'arbre de nodes XML a partir del node passat per paràmetre, aplicant-ne les validacions i remarcant-ne els camps que no siguin vàlids.
// Paràmetres d'entrada:
//		somExpression - Valor de la somExpression del node a partir del qual ha de començar a recórrer l'arbre de nodes del formulari.
// Paràmetres de sortida:
//		enter - Valor "1" si tot ha anat de forma correcte i "-1" si hi ha hagut algún error.
////////////////////////////////////////////////////////////
function recorreDocumentSom(somExpression)
{
	try
	{
		var oNodes = xfa.resolveNodes(somExpression);	
		if (oNodes == null)return;

		for (var i=0; i<oNodes.length; i++)
		{
			var obj = oNodes.item(i);	
			if (obj.name != "PLANA_CFG_TRAMIT" && obj.name != "PLANA_PRESENTADOR_OPCIONAL_PREGUNTA")
			{	
				if (esObjeteTipusSubform(obj))
				{
					for(var j=0;j<obj.nodes.length;j++)
					{
						var obj2 = obj.nodes.item(j);
						if (esObjecteSeleccio(obj2))
						{
							remarcarObjecteSeleccio(obj2);
						}
						else if (esObjeteTipusSubform(obj2))
						{
							recorreDocumentSom(obj2.somExpression);
						}	
						else if(esObjeteTipusCamp(obj2) || esObjeteTipusExclGroup(obj2))
						{
							validarObjecte(obj2);
							remarcarObjecte(obj2);							
						}	
					}
				}	
				else if(esObjeteTipusCamp(obj) || esObjeteTipusExclGroup(obj))
				{
					validarObjecte(obj);
					remarcarObjecte(obj);	
				}
			}	
		}	
	}catch(exc) {
		return scoGSITGen.retornarExcepcio("recorreDocumentSom() : \n", exc);
	}
}


//////////////////////////////////////////////////////////
// Nom: validarObjecte
// Descripció: Mètode que executa si cal, el contingut de l'event validate.
// Paràmetres d'entrada:
//		obj - Objecte del formulari que hauria de ser de tipus camps.
////////////////////////////////////////////////////////////
function validarObjecte(obj)
{
	if (obj == null) return;

	if(obj.presence == "visible")
		if(scoGSITCamps.comprovaVisibleParent(obj) == 1)
			if(obj.validate.scriptTest != "disabled")
				obj.execValidate();
}

//////////////////////////////////////////////////////////
// Nom: remarcarObjecteSeleccio
// Descripció: Mètode que marca com no vàlid un objecte de tipus SELECCIO/MULTISELECCIO, i remarca si cal.
// Paràmetres d'entrada:
//		obj - Objecte del formulari que hauria de ser de tipus camps.
////////////////////////////////////////////////////////////
function remarcarObjecteSeleccio(obj)
{
	if ( (obj.resolveNodes("CHECK[*]").length) <= 0)		return;

	if (obj.validate.nullTest != "error") 			return;

	if (capCheckMarcat(obj.resolveNodes("CHECK[*]")))
	{
		scoGSITCamps.remarcarCampNoValid(obj);	
	}
}


/////////////////////////////////////////////////////////////////////////////
// Nom: remarcarObjecte
// Descripció: Mètode que verifica si el camps s'ha de remarcar com a camp Vàlid o com a camp No Vàlid
// Paràmetres d'entrada:
//		obj - Objecte del formulari que hauria de ser de tipus camp
/////////////////////////////////////////////////////////////////////////////
function remarcarObjecte(obj)
{	
	if (obj == null) return;

	if(obj.validate.nullTest == "error")
	{
		if(scoGSITCamps.comprovaVisibleParent(obj) == 1)
		{
			if(scoGSITVal.isEmpty(obj)|| esNumericAmbValorZeroNoValid(obj)) {
				scoGSITCamps.remarcarCampNoValid(obj);
			}
		}
	}
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esNumericAmbValorZeroNoValid
// Descripció: Mètode que verifica si es tracta d'un camp numèric que no permet el zero
// Paràmetres d'entrada:
//		obj - Objecte del formulari que hauria de ser de tipus camp
// Paràmetres de sortida:
//		booleà - Valor (true/false) en cas de ser un numèric sense el patró de 'Allow Zero'
/////////////////////////////////////////////////////////////////////////////
function esNumericAmbValorZeroNoValid(obj)
{

	if(scoGSITVal.existeixPropietat(obj, "ui.numericEdit"))
		if(obj.rawValue == "0" && !existPatternZero(obj)) return true;		

	return false;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: existPatternZero
// Descripció: Mètode que verifica si es tracta d'un camp numèric que té el patró 'Allow Zero'
// Paràmetres d'entrada:
//		obj - Objecte del formulari que hauria de ser de tipus camp
// Paràmetres de sortida:
//		booleà - Valor (true/false) en cas de ser un numèric amb el patró de 'Allow Zero'
/////////////////////////////////////////////////////////////////////////////
function existPatternZero(obj)
{
	if(scoGSITVal.existeixPropietat(obj, "ui.numericEdit"))	
	{
		if(scoGSITVal.existeixPropietat(obj, "ui.picture"))
			if(String(obj.ui.picture.value).indexOf("zero") != -1) return true;

		if(scoGSITVal.existeixPropietat(obj,"format.picture"))
			if(String(obj.format.picture.value).indexOf("zero") != -1) return true;

		if(scoGSITVal.existeixPropietat(obj, "bind.picture"))
			if(String(obj.bind.picture.value).indexOf("zero") != -1) return true;


		if(scoGSITVal.existeixPropietat(obj, "validate.picture"))
			if(String(obj.validate.picture.value).indexOf("zero") != -1) return true;
	}

	return false;
}              

////////////////////////////////////////////////////////////
// Nom: esObjeteTipusCamp
// Descripció: Mètode que verifica que un objecte sigui de tipus camp
// Paràmetres d'entrada:
//		obj - Objecte del formulari
// Paràmetres de sortida:
//		booleà - Valor (true/false) segons si l'objecte és de tipus camp
////////////////////////////////////////////////////////////
function esObjeteTipusCamp(obj)
{             
	if (obj == null) return false;  

	if (obj.className != "field") return false;

	if (!scoGSITVal.existeixPropietat(obj, "ui.oneOfChild")) return false;

	var objClassName = obj.ui.oneOfChild.className;

	if (objClassName == "textEdit") return true;
	if (objClassName == "numericEdit") return true;
	if (objClassName == "choiceList") return true;
	if (objClassName == "signature") return true;
	if (objClassName == "dateTimeEdit") return true;
	if (objClassName == "checkButton") return true;	
	if (objClassName == "barcode") return true;	

	return false;											
}


////////////////////////////////////////////////////////////
// Nom: esObjeteTipusExclGroup
// Descripció: Mètode que verifica que un objecte sigui de tipus exclGroup
// Paràmetres d'entrada:
//		obj = Objecte del formulari
// Paràmetres de sortida:
//		booleà - Valor (true/false) segons si l'objecte és de tipus exclGroup
////////////////////////////////////////////////////////////
function esObjeteTipusExclGroup(obj)
{
	if (obj == null) return false;

	return (obj.className == "exclGroup");
}

////////////////////////////////////////////////////////////
// Nom: esObjecteSeleccio
// Descripció: Mètode que verifica que un objecte sigui de tipus subform 
// Paràmetres d'entrada:
//		obj - Objecte del formulari
// Paràmetres de sortida:
//		booleà - Valor (true/false) segons si l'objecte és de tipus subform
////////////////////////////////////////////////////////////
function esObjecteSeleccio(obj)
{
	if (obj == null) return false;

	return (esObjeteTipusSubform(obj) && (obj.name == "SELECCIO" || obj.name == "MULTISELECCIO"));
}

////////////////////////////////////////////////////////////
// Nom: esObjeteTipusSubform
// Descripció: Mètode que verifica que un objecte sigui de tipus subform
// Paràmetres d'entrada:
//		obj - Objecte del formulari
// Paràmetres de sortida:
//		booleà - Valor (true/false) segons si l'objecte és de tipus subform
////////////////////////////////////////////////////////////
function esObjeteTipusSubform(obj)
{
	if (obj == null) return false;

	var objClassName = obj.className;
	if (objClassName == "form") return true;
	if (objClassName == "subform") return true;
	if (objClassName == "subformSet") return true;
	if (objClassName == "area") return true;

	return false;
}


/////////////////////////////////////////////////////////
// Nom: carregarArrayCampsObligatoris
// Descripció: Mètode que recorre l'estructura del formulari per recuperar els camps obligatoris.
////////////////////////////////////////////////////////////
function carregarArrayCampsObligatoris()
{
	arrCampsObligatoris = new Array();
	recuperaCampsObligatoris(xfa.form.nodes.item(0).somExpression);
}


//////////////////////////////////////////////////////////
// Nom: recuperaCampsObligatoris
// Descripció: Mètode que recorre tot l'arbre de nodes XML a partir del node passat per paràmetre, aplicant-ne les validacions i remarcant-ne els camps que no són vàlids.
// Paràmetres d'entrada:
//		somExpression - Valor de la somExpression a partir de la qual s'han de començar a recuperar els camps obligatoris
////////////////////////////////////////////////////////////
function recuperaCampsObligatoris(somExpression)
{
	try
	{
		var oNodes = xfa.resolveNodes(somExpression);	
		if (oNodes == null)return;

		for (var i=0; i<oNodes.length; i++)
		{
			var obj = oNodes.item(i);	
			if (obj.name != "PLANA_CFG_TRAMIT")
			{	
				if (esObjeteTipusSubform(obj))
				{
					for(var j=0;j<obj.nodes.length;j++)
					{
						var obj2 = obj.nodes.item(j);
						if (esObjeteTipusSubform(obj2))
						{
							recuperaCampsObligatoris(obj2.somExpression);
						}	
						else if(esObjeteTipusCamp(obj2) || esObjeteTipusExclGroup(obj2))
						{
							recuperaCampsObligatoris(obj2.somExpression);
							/* modificat!!
							if (scoGSITCamps.esObligatori(obj2))
							{
								arrCampsObligatoris[arrCampsObligatoris.length] = obj2.somExpression;
								scoGSITCamps.assignarCampObligatori(obj2, false);
							}
							*/

						}	
					}
				}	
				else if(esObjeteTipusCamp(obj) || esObjeteTipusExclGroup(obj))
				{
					if (scoGSITCamps.esObligatori(obj))
					{ 
						arrCampsObligatoris[arrCampsObligatoris.length] = obj.somExpression;
						scoGSITCamps.assignarCampObligatori(obj, false);
					}	
				}
			}	
		}	
	}catch(exc) {
		return scoGSITGen.retornarExcepcio("recuperaCampsObligatoris() : \n", exc);
	}
}


//////////////////////////////////////////////////////////
// Nom: capCheckMarcat
// Descripció: Mètode que comprova si al conjunt de checks estan tots sense marcar
// Paràmetres d'entrada:
//		oSubChecks - Objectes checks (de TIPUS SELECCIO/MULTISELECCIO)
// Paràmetres de sortida:
//		Retorna true si estan tots desmarcats i false en cas contrari
////////////////////////////////////////////////////////////
function capCheckMarcat(oSubChecks)
{
	if (!scoGSITVal.existeixObjecte(oSubChecks))			return;

	var bMarcat = false;
	var i = 0;
	while (!bMarcat && i < oSubChecks.length)
	{
		var oCheck = oSubChecks.item(i);
		if (scoGSITVal.existeixObjecte(oCheck))
		{
			bMarcat = (oCheck.TXT_CAMP.rawValue == "1");
		}
		i++;
	}
	return !bMarcat;
}

