///////////////////////////////////////////////////////////////////////////// 
// Nom: defTag
// Descripció: Mètode que maqueta el 'sText' en un tag 'sTag' 
// Paràmetres d'entrada: 
//		sTag - Tag que es maquestarà
//		sText - Text que es definirà al tag
//		sEstils - Estils que es definiran per al tag 'P'
///////////////////////////////////////////////////////////////////////////// 
function defTag(sTag, sText)
{
	if (arguments.length == 1) return ("<" + sTag + "/>");

	return "<" + sTag + "\>" + sText + "</" + sTag + ">";
}

///////////////////////////////////////////////////////////////////////////// 
// Nom: generaXML
// Descripció: Mètode que genera l'XML que s'ha d'enviar al servei de negoci
// Paràmetres d'entrada:
//		adreca - Registre amb les dades de l'adreça
// Paràmetres de sortida: 
//		objecte - XML per enviar al servei de negoci
///////////////////////////////////////////////////////////////////////////// 
function generaXML(adreca)
{
	var oDadesTramit = scoGSITPar.oDadesCFGTramit.DADES_TRAMIT;
	if (!scoGSITVal.compPanell(oDadesTramit, "Dades de configuració del tràmit: Dades Tràmit")) return;	

	var locale = oDadesTramit.Locale.rawValue;	
	var versio = "2017";  // TODO  scoGSITPar.versioFormulari;
	var codiTramit = "000000";		// TODO  scoGSITVal.getCodiTramitTramit();
	var codiModalitat = "SOLC";		// TODO  scoGSITVal.getModalitatTramit();

	var xmlCapcalera = "";
	var xmlCos = "";

	xmlCapcalera = defTag("NomServei", "normalitzarAdreca") + defTag("IdPeticio", "GSITGF-"+codiTramit+"-"+codiModalitat+"-"+versio) + 
	               defTag("CodiTramit", codiTramit) + defTag("CodiModalitat", codiModalitat) + 
				   defTag("VersioFormulari", versio) + defTag("Idioma", locale);
	xmlCapcalera = defTag("Capcalera", xmlCapcalera);

	if (!scoGSITVal.isEmpty(adreca.codiPais))      xmlCos += defTag("Pais", defTag("CodiINE", adreca.codiPais)+defTag("Nom", adreca.nomPais));
	if (!scoGSITVal.isEmpty(adreca.codiProvincia)) xmlCos += defTag("Provincia", defTag("CodiINE", adreca.codiProvincia)+defTag("Nom", adreca.nomProvincia));
	if (!scoGSITVal.isEmpty(adreca.codiComarca))   xmlCos += defTag("Comarca", defTag("CodiINE", adreca.codiComarca)+defTag("Nom", adreca.nomComarca));
	if (!scoGSITVal.isEmpty(adreca.codiMunicipi))  xmlCos += defTag("Municipi", defTag("CodiINE", adreca.codiMunicipi)+defTag("Nom", adreca.nomMunicipi));
	if (!scoGSITVal.isEmpty(adreca.codiLlogaret))  xmlCos += defTag("Llogaret", defTag("CodiINE", adreca.codiLlogaret)+defTag("Nom", adreca.nomLlogaret));
	if (!scoGSITVal.isEmpty(adreca.codiPostal))    xmlCos += defTag("CodiPostal", adreca.codiPostal);
	if (!scoGSITVal.isEmpty(adreca.codiTipusVia))  xmlCos += defTag("TipusVia", defTag("CodiArvato", adreca.codiTipusVia)+defTag("Nom", adreca.nomTipusVia));
	if (!scoGSITVal.isEmpty(adreca.nomVia)) xmlCos += defTag("NomVia", adreca.nomVia);
	if (!scoGSITVal.isEmpty(adreca.numero)) xmlCos += defTag("Numero", adreca.numero);
	if (!scoGSITVal.isEmpty(adreca.bloc))   xmlCos += defTag("Bloc", adreca.bloc);
	if (!scoGSITVal.isEmpty(adreca.escala)) xmlCos += defTag("Escala", adreca.escala);
	if (!scoGSITVal.isEmpty(adreca.pis))    xmlCos += defTag("Pis", adreca.pis);
	if (!scoGSITVal.isEmpty(adreca.porta)) 	xmlCos += defTag("Porta", adreca.porta);
	xmlCos = defTag("Cos", defTag("Adreca", xmlCos));

	return defTag("ServeiNegociPeticio", xmlCapcalera + xmlCos);

}

/////////////////////////////////////////////////////////////////////////////
// Nom: generaAdrecaNorm
// Descripció: Mètode que genera el registre amb les dades de l'adreça normalitzada
// Paràmetres d'entrada:
//		result - Objecte amb estructura d'adreça
// Paràmetres de sortida:
//		objecte - Objecte amb estructura d'adreça
///////////////////////////////////////////////////////////////////////////// 
function generaAdrecaNorm(result){

	var adreca = {
		codiPais : result.Adreca.Pais.CodiINE.value,
		nomPais : result.Adreca.Pais.Nom.value,
		codiProvincia : result.Adreca.Provincia.CodiINE.value,
		nomProvincia : result.Adreca.Provincia.Nom.value,
		codiComarca :result.Adreca.Comarca.CodiINE.value,
		nomComarca : result.Adreca.Comarca.Nom.value,
		codiMunicipi : result.Adreca.Municipi.CodiINE.value,
		nomMunicipi : result.Adreca.Municipi.Nom.value,
		codiLlogaret : null,
		nomLlogaret : null,
		codiPostal : result.Adreca.CodiPostal.value,
		codiTipusVia : result.Adreca.TipusVia.CodiArvato.value,
		nomTipusVia : result.Adreca.TipusVia.Nom.value,
		nomVia : result.Adreca.NomVia.value,
		numero : result.Adreca.Numero.value,
		bloc : result.Adreca.Bloc.value,
		escala : result.Adreca.Escala.value,
		pis : result.Adreca.Pis.value,
		porta : result.Adreca.Porta.value,
		coordenadaX : result.Adreca.CoordenadaX.value,
		coordenadaY : result.Adreca.CoordenadaY.value
	};

	if (result.Adreca.Llogaret != null){	
		adreca.codiLlogaret = result.Adreca.Llogaret.CodiINE.value;
		adreca.nomLlogaret = result.Adreca.Llogaret.Nom.value;
	}

	return adreca;
}

////////////////////////////////////////////////////////////
// Nom: adrecaNormToString
// Descripció: Mètode que retorna un String 'sAdreca' amb totes les dades d'una adreça normalitzada
// Paràmetres d'entrada:
//		adreca - Objecte que conté totes les dades d'una adreça normalitzada
// Paràmetres de sortida: 	
//		string - Valor de l'adreça normalitzda
////////////////////////////////////////////////////////////  
function adrecaNormToString(adreca)
{
	var sAdreca = "";
	sAdreca += adreca.codiPais + "|";
	sAdreca += adreca.nomPais + "|";
	sAdreca += adreca.codiProvincia + "|";
	sAdreca += adreca.nomProvincia + "|";
	sAdreca += adreca.codiComarca + "|";
	sAdreca += adreca.nomComarca + "|";
	sAdreca += adreca.codiMunicipi + "|";
	sAdreca += adreca.nomMunicipi + "|";
	sAdreca += adreca.codiLlogaret + "|";
	sAdreca += adreca.nomLlogaret + "|";
	sAdreca += adreca.codiPostal + "|";
	sAdreca += adreca.codiTipusVia + "|";
	sAdreca += adreca.nomTipusVia + "|";
	sAdreca += adreca.nomVia + "|";
	sAdreca += adreca.numero + "|";
	sAdreca += adreca.bloc + "|";
	sAdreca += adreca.escala + "|";
	sAdreca += adreca.pis + "|";
	sAdreca += adreca.porta + "|";
	sAdreca += adreca.coordenadaX + "|";
	sAdreca += adreca.coordenadaY + "|";

	return sAdreca;
}

////////////////////////////////////////////////////////////
// Nom: adrecaNormFromString
// Descripció: Mètode que retorna totes les dades d'una adreça normalitzada en un objecte 'adreca' definit a partir de 'sAdreca'
// Paràmetres d'entrada:
//		sAdreca - String que conté totes les dades d'una adreça normalitzada
// Paràmetres de sortida:
//		Objecte - Objecte amb estructura de tipus adreça 	
////////////////////////////////////////////////////////////  
function adrecaNormFromString(sAdreca)
{
	var aAdreca = sAdreca.split("|");

	if (aAdreca.length != 22) return null;

	var adreca = {
		codiPais : getValueBuit(aAdreca[0]),
		nomPais : getValueBuit(aAdreca[1]),
		codiProvincia : getValueBuit(aAdreca[2]),
		nomProvincia : getValueBuit(aAdreca[3]),
		codiComarca : getValueBuit(aAdreca[4]),
		nomComarca : getValueBuit(aAdreca[5]),
		codiMunicipi : getValueBuit(aAdreca[6]),
		nomMunicipi : getValueBuit(aAdreca[7]),
		codiLlogaret : getValueBuit(aAdreca[8]),
		nomLlogaret : getValueBuit(aAdreca[9]),
		codiPostal : getValueBuit(aAdreca[10]),
		codiTipusVia : getValueBuit(aAdreca[11]),
		nomTipusVia : getValueBuit(aAdreca[12]),
		nomVia : getValueBuit(aAdreca[13]),
		numero : getValueBuit(aAdreca[14]),
		bloc : getValueBuit(aAdreca[15]),
		escala : getValueBuit(aAdreca[16]),
		pis : getValueBuit(aAdreca[17]),
		porta : getValueBuit(aAdreca[18]),
		coordenadaX : getValueBuit(aAdreca[19]),
		coordenadaY : getValueBuit(aAdreca[20])
	};

	return adreca;
}


/////////////////////////////////////////////////////////////////////////////
// Nom: adrecaFromPanell
// Descripció: Mètode que s'encarrega de generar un objecte 'adreca' amb els valors del panell 'oPanellAdreca'
// Paràmetres d'entrada:
//		oPanellAdreca - Panell d'adreça
// Paràmetres de sortida:
//		Objecte - Objecte amb estructura de tipus adreça 
///////////////////////////////////////////////////////////////////////////// 
function adrecaFromPanell(oPanellAdreca)
{
	var bUnitatPob = scoGSITPanells.esPanellAdrecaCatUnitatPob(oPanellAdreca);

	var oCodiLlogaret = (!bUnitatPob) ? getValue(scoGSITPanells.obtenirObjecteFill(oPanellAdreca, "LLISTA_LLOGARETS")) : null; 
	var oNomLlogaret = (!bUnitatPob) ? getValue(scoGSITPanells.obtenirObjecteFill(oPanellAdreca, "LLISTA_LLOGARETS_NOM")) : null;

	var adreca = {
		codiPais : getValue(oPanellAdreca.TXT_PAIS),
		nomPais : getValue(oPanellAdreca.TXT_PAIS_NOM),
		codiProvincia : getValue(oPanellAdreca.LLISTA_PROVINCIES),
		nomProvincia : getValue(oPanellAdreca.LLISTA_PROVINCIES_NOM),
		codiComarca : getValue(oPanellAdreca.LLISTA_COMARQUES),
		nomComarca : getValue(oPanellAdreca.LLISTA_COMARQUES_NOM),
		codiMunicipi : getValue(oPanellAdreca.LLISTA_MUNICIPIS),
		nomMunicipi : getValue(oPanellAdreca.LLISTA_MUNICIPIS_NOM),
		codiLlogaret : getValue(oCodiLlogaret), 
		nomLlogaret : getValue(oNomLlogaret),
		codiPostal : getValue(oPanellAdreca.TXT_CODI_POSTAL),
		codiTipusVia : getValue(oPanellAdreca.TXT_TIPUS_VIA),
		nomTipusVia : getValue(oPanellAdreca.TXT_TIPUS_VIA_NOM),
		nomVia : getValue(oPanellAdreca.TXT_NOM_VIA),
		numero : getValue(oPanellAdreca.TXT_NUM_VIA),
		bloc : getValue(oPanellAdreca.TXT_BLOC),
		escala : getValue(oPanellAdreca.TXT_ESCALA),
		pis : getValue(oPanellAdreca.TXT_PIS),
		porta : getValue(oPanellAdreca.TXT_PORTA),
		coordenadaX : null,
		coordenadaY : null
	};

	return adreca;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: normalitzaAdreca
// Descripció: Mètode que s'encarrega de normalitzar l'adreça del formulari
// Paràmetres d'entrada:
//		adreca - Objecte amb estructura de tipus adreça
// Paràmetres de sortida: 
//		string - Valor de l'adreça normalitzada
///////////////////////////////////////////////////////////////////////////// 
function normalitzaAdreca(adreca)
{						
	var xmlDades = generaXML(adreca);
	var result = scoGSITExt.invocarServeiNegoci(xmlDades);

	if (result != null)
	{ 
		var codiResposta = result.Resposta.CodiResposta;	
		if (codiResposta == "OK")
		{
			var cos = result.Cos;
			var domObj = XMLData.parse(cos, false);	
			if (domObj.Adreca.Normalitzada.value.toUpperCase() == "TRUE")
			{
				var adrecaNorm = generaAdrecaNorm(domObj);
				return adrecaNorm;
			}
			else
			{
				xfa.host.messageBox(msgAdreçaNoNormalitzada.value);
				return null;
			}
		} 
		else 
		{
			xfa.host.messageBox(result.Resposta.Error.MissatgeError);
			return null;
		}
	} 
	else 
	{
		return null;
	}	
}

/////////////////////////////////////////////////////////////////////////////
// Nom: adrecaToString
// Descripció: Mètode que s'encarrega de generar un String amb les dades de l'adreça
// Paràmetres d'entrada:
//		adreca - Objecte amb estructura de tipus adreça
// Paràmetres de sortida:
//		string - Valor amb les dades de l'adreça
///////////////////////////////////////////////////////////////////////////// 
function adrecaToString(adreca)
{				
	var adrecaStr = "";

	if (!scoGSITVal.isEmpty(adreca.nomTipusVia))  adrecaStr += adreca.nomTipusVia;
	if (!scoGSITVal.isEmpty(adreca.nomVia))       adrecaStr += " " + adreca.nomVia;
	if (!scoGSITVal.isEmpty(adreca.numero))       adrecaStr += ", " + adreca.numero;
	if (!scoGSITVal.isEmpty(adreca.bloc))         adrecaStr += ", bloc:" + adreca.bloc;
	if (!scoGSITVal.isEmpty(adreca.escala))       adrecaStr += ", escala:" + adreca.escala;
	if (!scoGSITVal.isEmpty(adreca.pis))          adrecaStr += ", pis:" + adreca.pis;
	if (!scoGSITVal.isEmpty(adreca.porta))        adrecaStr += ", porta:" + adreca.porta;
	if (!scoGSITVal.isEmpty(adreca.codiPostal))   adrecaStr += ". " + adreca.codiPostal;
	if (!scoGSITVal.isEmpty(adreca.nomMunicipi))  adrecaStr += " " + adreca.nomMunicipi;
	if (!scoGSITVal.isEmpty(adreca.nomProvincia)) adrecaStr += " (" + adreca.nomProvincia + ")";

	return adrecaStr;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: actualitzaAdreca
// Descripció: Mètode que s'encarrega de netejar les dades de l'adreça normalitzada
// Paràmetres d'entrada:
//		oPanellAdreca - Panell d'adreça a actualitzar
///////////////////////////////////////////////////////////////////////////// 
function actualitzaAdreca(oPanellAdreca)
{
	var oPanellNormalitzador = scoGSITCamps.obtenirPanellRelacionat(oPanellAdreca, "oPanellNormalitzador");
	if (oPanellNormalitzador == null) return;
	if (!scoGSITVal.existeixObjecte(oPanellNormalitzador.TXT_NORMALITZADA)) return;

	var adreca = adrecaNormFromString(oPanellNormalitzador.TXT_NORMALITZADA.rawValue);
	if (adreca == null) return;

	scoGSITVal.defValor(oPanellAdreca, "TXT_ES_NORMALITZADA", "true");

	scoGSITVal.defValorSiDefinit(oPanellAdreca, "TXT_TIPUS_VIA", adreca.codiTipusVia);
	scoGSITVal.defValorSiDefinit(oPanellAdreca, "TXT_TIPUS_VIA_NOM", adreca.nomTipusVia);
	scoGSITVal.defValorSiDefinit(oPanellAdreca, "TXT_NOM_VIA", adreca.nomVia);
	scoGSITVal.defValorSiDefinit(oPanellAdreca, "TXT_NUM_VIA", adreca.numero);
	scoGSITVal.defValorSiDefinit(oPanellAdreca, "TXT_BLOC", adreca.bloc);
	scoGSITVal.defValorSiDefinit(oPanellAdreca, "TXT_ESCALA", adreca.escala);
	scoGSITVal.defValorSiDefinit(oPanellAdreca, "TXT_PIS", adreca.pis);
	scoGSITVal.defValorSiDefinit(oPanellAdreca, "TXT_PORTA", adreca.porta);
	scoGSITVal.defValorSiDefinit(oPanellAdreca, "TXT_COORDENADA_X", adreca.coordenadaX);
	scoGSITVal.defValorSiDefinit(oPanellAdreca, "TXT_COORDENADA_Y", adreca.coordenadaY);
	scoGSITVal.defValorSiDefinit(oPanellAdreca, "TXT_CODI_POSTAL", adreca.codiPostal);

	scoGSITVal.defValorSiDefinit(oPanellAdreca, "LLISTA_PROVINCIES", adreca.codiProvincia);
	scoGSITAdreca.canviProvinciaCat(oPanellAdreca, false);

	scoGSITVal.defValorSiDefinit(oPanellAdreca, "LLISTA_COMARQUES", adreca.codiComarca);
	scoGSITAdreca.canviComarcaCat(oPanellAdreca, false);

	scoGSITVal.defValorSiDefinit(oPanellAdreca, "LLISTA_MUNICIPIS", adreca.codiMunicipi);
	var bUnitatPob = scoGSITPanells.esPanellAdrecaCatUnitatPob(oPanellAdreca);
	scoGSITAdreca.canviMunicipiCatLlogUnitPob(oPanellAdreca, bUnitatPob, false);

	if (!bUnitatPob) 
	{
		scoGSITVal.defValorSiDefinit(oPanellAdreca, "LLISTA_LLOGARETS", adreca.codiLlogaret);
		scoGSITAdreca.canviLlogaretCat(oPanellAdreca, false);
	}
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esInformat
// Descripció: Mètode que s'encarrega de verifica si els camps estan informats.
// Paràmetres d'entrada:
//		oPanellAdreca - Panell on es troba l'adreça al formulari
// Paràmetres de sortida:
//		booleà - Valor (true/false) segons si els camps estan informats
///////////////////////////////////////////////////////////////////////////// 
function esInformat(oPanellAdreca)
{
 	// Comprova valors correctes				
	if(scoGSITVal.isEmpty(oPanellAdreca.TXT_TIPUS_VIA) || scoGSITVal.isEmpty(oPanellAdreca.TXT_NOM_VIA) || 
	   scoGSITVal.isEmpty(oPanellAdreca.TXT_NUM_VIA) || scoGSITVal.isEmpty(oPanellAdreca.LLISTA_PROVINCIES) ||
	   scoGSITVal.isEmpty(oPanellAdreca.LLISTA_MUNICIPIS))
 			return false;

	if (!scoGSITVal.isEmpty(oPanellAdreca.TXT_CODI_POSTAL))
	{
		if (!scoGSITVal.validarCPostal(oPanellAdreca.TXT_CODI_POSTAL.rawValue, null)) return false;
 	}

 	return true;

}

/////////////////////////////////////////////////////////////////////////////
// Nom: preomplertAdrecaToString
// Descripció: Mètode que s'encarrega de generar un String amb les dades de l'adreça.
// Paràmetres d'entrada:
//		oPanellAdreca - Panell d'adreça
//		oPanellNorm - Panell normalitzador
///////////////////////////////////////////////////////////////////////////// 
function preomplertAdrecaToString(oPanellAdreca,oPanellNorm)
{
	var adreca = {
		codiPais : null,
		nomPais : null,
		codiProvincia : oPanellAdreca.LLISTA_PROVINCIES.rawValue,
		nomProvincia : oPanellAdreca.LLISTA_PROVINCIES_NOM.rawValue,
		codiComarca : null,
		nomComarca : null,
		codiMunicipi : oPanellAdreca.LLISTA_MUNICIPIS.rawValue,
		nomMunicipi : oPanellAdreca.LLISTA_MUNICIPIS_NOM.rawValue,
		codiLlogaret : null,
		nomLlogaret : null,
		codiPostal : oPanellAdreca.TXT_CODI_POSTAL.rawValue,
		codiTipusVia : oPanellAdreca.TXT_TIPUS_VIA.rawValue,
		nomTipusVia :oPanellAdreca.TXT_TIPUS_VIA_NOM.rawValue,
		nomVia : oPanellAdreca.TXT_NOM_VIA.rawValue,
		numero : oPanellAdreca.TXT_NUM_VIA.rawValue,
		bloc : oPanellAdreca.TXT_BLOC.rawValue,
		escala :oPanellAdreca.TXT_ESCALA.rawValue,
		pis : oPanellAdreca.TXT_PIS.rawValue,
		porta : oPanellAdreca.TXT_PORTA.rawValue,
	};

	oPanellNorm.TXT_RESULTAT.rawValue = adrecaToString(adreca);
}      


////////////////////////////////////////////////////////////
// Nom: getValue
// Descripció: Mètode que retorna el valor del camp en cas que existeixi, i si no existeix se'n retorna el valor "".
// Paràmetres d'entrada:
//		oCamp - Objecte de tipus camp
// Paràmetres de sortida:
//		String - Valor del camp o "", en cas que aquest no existeixi
////////////////////////////////////////////////////////////    
function getValue(oCamp)
{
	return ((oCamp != null) ? oCamp.rawValue : "");
}

////////////////////////////////////////////////////////////
// Nom: getValueBuit
// Descripció: Mètode que retorna el valor del paràmetre d'entrada i en cas que aquest no existeixi, se'n retorna el valor "".
// Paràmetres d'entrada:
//		sValor - Valor a verificar
// Paràmetres de sortida:
//		string - Valor verificat
////////////////////////////////////////////////////////////    
function getValueBuit(sValor)
{
	return ((String(sValor) != "null") ? sValor : "");
}

////////////////////////////////////////////////////////////
// Nom: accioVerificaAdreca
// Descripció: Mètode que verifica l'adreça definida al panell 'oAdreca' i si es correcta la mostra al panell Normalitzador
// Paràmetres d'entrada:
//		oPanellNormalizador - Panell Normalizador
// Paràmetres de sortida
//		booleà - true si hi ha les dades mínimes per fer la normalització, i false en cas contrari
////////////////////////////////////////////////////////////    
function accioVerificaAdreca(oPanellNormalitzador)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		var oPanellAdreca = scoGSITCamps.obtenirPanellRelacionat(oPanellNormalitzador, "oPanellAdreca");
		if (oPanellAdreca == null) return;

		if (esInformat(oPanellAdreca))
		{	
			oPanellAdreca.TXT_ES_NORMALITZADA.rawValue = "false";
			oPanellNormalitzador.TXT_NORMALITZADA.rawValue = "";
			oPanellNormalitzador.TXT_RESULTAT.rawValue = "";					

			var adreca = adrecaFromPanell(oPanellAdreca);
			var adrecaNorm = normalitzaAdreca(adreca);
			if (adrecaNorm != null)
			{
				oPanellNormalitzador.TXT_NORMALITZADA.rawValue = adrecaNormToString(adrecaNorm);
				oPanellNormalitzador.TXT_RESULTAT.rawValue = adrecaToString(adrecaNorm);

				scoGSITBot.canviEstatAcceptar(1, "0,0,0", oPanellNormalitzador.BTN_ACCEPTAR);
				scoGSITBot.canviEstatAcceptar(0, null, oPanellNormalitzador.BTN_BUSCAR);
			}
			return true;
		} 
		else {
			xfa.host.messageBox(msgErrorAdrecaCampsNoInformats.value);
			return false;
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITNormalitzador::accioVerificaAdreca", exc);
	}	
}	

////////////////////////////////////////////////////////////
// Nom: accioAcceptarAdreca
// Descripció: Mètode que copia l'adreça normalitzada al panell d'adreça.
// Paràmetres d'entrada:
//		oPanellNormalitzador - Panell Normalizador
////////////////////////////////////////////////////////////    
function accioAcceptarAdreca(oPanellNormalitzador)
{
	try
	{	   
		if (scoGSITVal.isFormulariValidat()) return;

		var oPanellAdreca = scoGSITCamps.obtenirPanellRelacionat(oPanellNormalitzador, "oPanellAdreca");
		if (oPanellAdreca == null) return;

		var esNormalitzada = (scoGSITVal.isEmpty(oPanellAdreca.TXT_ES_NORMALITZADA)) ? "" : oPanellAdreca.TXT_ES_NORMALITZADA.rawValue.toUpperCase();
		if (esNormalitzada == "FALSE")  actualitzaAdreca(oPanellAdreca);

		scoGSITBot.canviEstatAcceptar(0, null, oPanellNormalitzador.BTN_ACCEPTAR);
		xfa.host.setFocus(oPanellNormalitzador.BTN_ACCEPTAR);			   
    }
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITNormalitzador::accioAcceptarAdreca", exc);
	}	
}	


////////////////////////////////////////////////////////////
// Nom: prepararAdreca
// Descripció: Mètode que s'encarrega de mostrar la ajuda contextual i al mateix temps amagar-la.
// Paràmetres d'entrada:
//		arrCarrerer - És un array de dos posicions
//					  Dins del primer array, hi ha d'haver una llista de les somExpression dels objectes que es vulen posar a invisibles quan apareix l'ajuda
//					  Dins del segon array, hi ha d'haver una llista de les somExpression dels objectes que es vulguin posar com a visibles, és a dir que tindran l'ajuda. Normalment aquest segon array només contindrà un element que serà el SUB_CARRERER corresponent a l'ajuda específica d'aquell apartat.
//		mostrarCarrerer - Valor (true/false) que indica si es vol que els elements siguin visibles o invisibles.
////////////////////////////////////////////////////////////
function prepararAdreca(arrCarrerer,mostrarCarrerer)
{
	try{	
		var i = 0;
		if(mostrarCarrerer)
		{	
			for(i=0;i<arrCarrerer[0].length;i++)
			{	
				resolveNode(arrCarrerer[0][i]).presence = "invisible";
			}
			for(i=0;i<arrCarrerer[1].length;i++)
			{
				resolveNode(arrCarrerer[1][i]).presence = "visible";
			}
		}
		else
		{
			for(i=0;i<arrCarrerer[0].length;i++)
			{	
				resolveNode(arrCarrerer[0][i]).presence = "visible";
			}
			for(i=0;i<arrCarrerer[1].length;i++)
			{

				resolveNode(arrCarrerer[1][i]).presence = "invisible";
			}
		}
	}catch(exc){
		return scoGSITGen.retornarExcepcio("scoGSITNormalitzador::prepararAdreca() : \n", exc);
	}
}         

////////////////////////////////////////////////////////////
// Nom: canviEstatAcceptar
// Descripció: Mètode que canvia el botó Accepta del normalitzador a disabled o enabled i li canvia el color de la font.
// Paràmetres d'entrada:
//		estat - "1" Obert, "0" protegit
//		color - Color de la font del botó.
//		objBoto - Objecte de tipus butó al que se li modifica l'aspecte visual.
////////////////////////////////////////////////////////////
function canviEstatAcceptar(estat,color,objBoto)
{
	try
	{
		if(estat)
			objBoto.access = "open";
		else
			objBoto.access = "protected";

		if(color!= "" && color!= null && color!= "undefined")
			objBoto.caption.font.fill.color.value = color;
		else
			objBoto.caption.font.fill.color.value = "125,125,125";
	}catch(exc){
		return scoGSITGen.retornarExcepcio("scoGSITNormalitzador::canviEstatAcceptar() : \n", exc);
	}	
}

