////////////////////////////////////////////////////////////
// Nom: getLlistaPaisosINE
// Descripció: Mètode que retorna la llista de països amb codi INE
// Paràmetres d'entrada:
// Paràmetres de sortida:
//		array - Array arrPaisosINE segons idioma definit al formulari
//////////////////////////////////////////////////////////// 
function getLlistaPaisosINE() 
{
	var sIdioma = scoGSITVal.getIdiomaTramit();	
	return mapaLlistesINE[sIdioma];
}

////////////////////////////////////////////////////////////
// Nom: getLlistaPaisosISO
// Descripció: Mètode que retorna la llista de països amb codi ISO
// Paràmetres d'entrada:
// Paràmetres de sortida:
//		array - Array arrPaisosISO segons idioma definit al formulari
//////////////////////////////////////////////////////////// 
function getLlistaPaisosISO() 
{
	var sIdioma = scoGSITVal.getIdiomaTramit();	
	return mapaLlistesISO[sIdioma];
}

////////////////////////////////////////////////////////////
// Nom: getLlistaPaisosExtINE
// Descripció: Mètode que retorna la llista de països extrangers [tots menys Espanya] amb codi INE
// Paràmetres d'entrada:
// Paràmetres de sortida:
//		array - Array arrPaisosINE eliminant Espanya segons idioma definit al formulari
//////////////////////////////////////////////////////////// 
function getLlistaPaisosExtINE() 
{
	var aPaisos = getLlistaPaisosINE();
	aPaisos = aPaisos.slice(0);  				// Fem una còpia de l'array

	var sTextEsp = obtenirNomPaisINE("108");
	aPaisos.splice(obtenirPosicioPaisINE(sTextEsp), 1);			// Eliminem Espanya de la llista de paisos

	return aPaisos;
}


////////////////////////////////////////////////////////////
// Nom: esPaisINE
// Descripció: Mètode que indica si el 'codiINE' és d'un pais INE
// Paràmetres d'entrada:
//		codiINE - codi del país a verificar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el 'codiINE' és d'un pais INE
////////////////////////////////////////////////////////////               
function esPaisINE(codiINE)
{
	var arrPaisosINE = getLlistaPaisosINE();
	for(var i=0; i<arrPaisosINE.length; i++)
	{
		if (arrPaisosINE[i][1] == codiINE) return true;
	}

	return false;
} 

////////////////////////////////////////////////////////////
// Nom: esPaisISO
// Descripció: Mètode que indica si el 'codiISO' és d'un pais ISO
// Paràmetres d'entrada:
//		codiISO - codi del país a verificar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el 'codiINE' és d'un pais ISO
////////////////////////////////////////////////////////////               
function esPaisISO(codiISO)
{
	var arrPaisosISO = getLlistaPaisosISO();
	for(var i=0; i<arrPaisosISO.length; i++)
	{
		if (arrPaisosISO[i][1] == codiISO) return true;
	}

	return false;
} 


////////////////////////////////////////////////////////////
// Nom: obtenirNomPaisINE
// Descripció: Mètode que recupera el nom d'un país, a partir del seu codi INE
// Paràmetres d'entrada:
//		codiINE - codi del país a obtenir
// Paràmetres de sortida:
//		string - Nom del país
////////////////////////////////////////////////////////////               
function obtenirNomPaisINE(codiINE)
{
	var arrPaisosINE = getLlistaPaisosINE();
	for(var i=0; i<arrPaisosINE.length; i++)
	{
		if (arrPaisosINE[i][1] == codiINE) return arrPaisosINE[i][0];
	}

	return "";
}               

////////////////////////////////////////////////////////////
// Nom: obtenirCodiINEPais
// Descripció: Mètode que recupera el codi d'un país, a partir del seu nom.
// Paràmetres d'entrada:
//		nomPaisINE - Nom del país
// Paràmetres de sortida:
//		string - Codi del país
////////////////////////////////////////////////////////////               
function obtenirCodiINEPais(nomPaisINE)
{
	var arrPaisosINE = getLlistaPaisosINE();
	nomPaisINE = (scoGSITVal.isEmpty(nomPaisINE)) ? "" : nomPaisINE.toUpperCase();
	for(var i=0; i<arrPaisosINE.length; i++)
	{
		if (arrPaisosINE[i][0].toUpperCase() == nomPaisINE) return arrPaisosINE[i][1];
	}

	return "";
}

////////////////////////////////////////////////////////////
// Nom: obtenirPosicioPaisINE
// Descripció: Mètode que recupera la posició d'un país, a partir del seu nom.
// Paràmetres d'entrada:
//		nomPaisINE - Nom del país
// Paràmetres de sortida:
//		string - Posició del país a l'array
////////////////////////////////////////////////////////////               
function obtenirPosicioPaisINE(nomPaisINE)
{
	var arrPaisosINE = getLlistaPaisosINE();
	nomPaisINE = (scoGSITVal.isEmpty(nomPaisINE)) ? "" : nomPaisINE.toUpperCase();
	for(var i=0; i<arrPaisosINE.length; i++)
	{
		if (arrPaisosINE[i][0].toUpperCase() == nomPaisINE) return i;
	}

	return "";
}

////////////////////////////////////////////////////////////
// Nom: obtenirNomPaisISO
// Descripció: Mètode que recupera el nom d'un país, a partir del seu codi ISO.
// Paràmetres d'entrada:
//		codiISO - Codi del país
// Paràmetres de sortida:
//		string - Nom del país
////////////////////////////////////////////////////////////               
function obtenirNomPaisISO(codiISO)
{
	var arrPaisosISO = getLlistaPaisosISO();
	for(var i=0; i<arrPaisosISO.length; i++)
	{
		if (arrPaisosISO[i][1] == codiISO) return arrPaisosISO[i][0];
	}

	return "";
}

