////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

////////////////////////////////////////////////////////////
// Nom: initLogoFormulari
// Descripció:  Mètode que comprova si s'ha definit el logo per precarrega i si no és així ho inicialitza amb el de gencat
// Paràmetres d'entrada:
//		oMarcaAigua - Objecte de logo
////////////////////////////////////////////////////////////
function initLogoFormulari(imgLogo)
{
	if (scoGSITVal.isFormulariValidat()) return; 

    var oLogo = scoGSITPar.oDadesCFGTramit.parent.VALIDACIO.TXT_LOGO;
	if (!scoGSITVal.existeixObjecte(oLogo)) return;

	oLogo.rawValue = "";

	var oLogoInfo = scoGSITPar.oDadesCFGTramit.parent.VALIDACIO.TXT_LOGO_INFO;
	if (scoGSITVal.existeixObjecte(oLogoInfo))
	{
		if (!scoGSITVal.isEmpty(oLogoInfo))
			oLogo.rawValue = oLogoInfo.rawValue;	
	}

	if (oLogo.rawValue == "")
	{
		if (scoGSITPar.sLogo)
			oLogo.rawValue = scoGSITPar.sLogo;		
		else
			oLogo.rawValue = "";
	}

	imgLogo.rawValue = oLogo.rawValue;
}

////////////////////////////////////////////////////////////
// Nom: defMarcaAigua
// Descripció:  Mètode que inicialitza la marca d'aigua 'oMarcaAigua'
// Paràmetres d'entrada:
//      oMarcaAigua - Objecte marca d'aigua
//		sTextMarca - Text per la marca d'aigua
////////////////////////////////////////////////////////////
function defMarcaAigua(oMarcaAigua, sTextMarca)
{
	if (!scoGSITVal.existeixObjecte(oMarcaAigua)) return;

    if (scoGSITPar.bMostrarMarcaAigues)
    {       
        oMarcaAigua.presence = "visible";
        oMarcaAigua.rawValue = sTextMarca;
    }
    else
    {
        oMarcaAigua.presence = "hidden";
        oMarcaAigua.rawValue = "";
    } 
}

////////////////////////////////////////////////////////////
// Nom: initMarcaAiguaFulls
// Descripció:  Mètode que inicialitza la marca d'aigua de tots els fulls
// Paràmetres d'entrada:
//      oMarcaAigua - Objecte marca d'aigua
////////////////////////////////////////////////////////////
function initMarcaAiguaFulls(oMarcaAigua)
{
	if (scoGSITVal.isFormulariAcusament()) return;

    if (scoGSITVal.isFormulariValidat())
	{
	/*
		var bEsSignat = (scoGSITPar.oPanellValidacio.BTN_DESBLOQUEJAR.access == "protected");
		if (bEsSignat) return;
*/
		if (scoGSITVal.isFormulariAcusament())		assignaMarcaAiguaFulls("");	
		else		assignaMarcaAiguaFulls(msgValidatPendentTancar.value);	

		return;
	}

	 defMarcaAigua(oMarcaAigua, msgEsborrany.value);
}

////////////////////////////////////////////////////////////
// Nom: assignaMarcaAiguaFulls
// Descripció:  Mètode que assigna valor a la marca d'aigua de tots els fulls
// Paràmetres d'entrada:
//      marcaAigues - valor que s'ha de mostrar a la marca d'aigua
////////////////////////////////////////////////////////////
function assignaMarcaAiguaFulls(marcaAigues)
{
	//if (scoGSITVal.isFormulariAcusament()) return;

    try
    {   
        if (scoGSITPar.arrayMarquesAigua != null)
        {
            for(var i=0;i<scoGSITPar.arrayMarquesAigua.length;i++)
            {       
                var oMarques = xfa.resolveNodes(scoGSITPar.arrayMarquesAigua[i]);
                if (oMarques != null)
                {
                    for(var j=0; j<oMarques.length;j++)
                    {
						defMarcaAigua(oMarques.item(j), marcaAigues);
                    }           
                }                   
            }
        }
    }   
    catch(exc)
    {
        scoGSITGen.retornarExcepcio("scoGSITPanells::assignaMarcaAiguaFulls", exc);
    }
}


