////////////////////////////////////////////////////////////
// Nom: errorCampPanell
// Descripció:  Mètode que indica que un panell no té un camp determinat
// Paràmetres d'entrada:
//		oPanell - Panell
//		sCamp - Nom del camp que no té el panell	
////////////////////////////////////////////////////////////
function errorCampPanell(oPanell, sCamp)
{
	app.alert("ATENCIÓ factoria, no està ben definit el panell  '" + oPanell.name + "' ja que no té el camp '" + sCamp + "' que és necessari.");
}

////////////////////////////////////////////////////////////
// Nom: errorSubformPanell
// Descripció:  Mètode que indica que un panell no té un subform determinat
// Paràmetres d'entrada:
//		oPanell - Panell
//		sSubform - Nom del subform que no té el panell	
////////////////////////////////////////////////////////////
function errorSubformPanell(oPanell, sSubform)
{
	app.alert("ATENCIÓ factoria, no està ben definit el panell  '" + oPanell.name + "' ja que no té el subformulari '" + sSubform + "' que és necessari.");
}

////////////////////////////////////////////////////////////
// Nom: comprovarCampPanell
// Descripció:  Mètode que comprova si el panell 'oPanell' té definit el camp 'sCamp' si no el té dóna un avís
// Paràmetres d'entrada:
//		oPanell - Panell a validar
//		sCamp - Nom del camp a buscar al panell 	
// Paràmetres de sortida:
//		booleà - Valor (true/false) resultant de la verificació
////////////////////////////////////////////////////////////
function comprovarCampPanell(oPanell, sCamp)
{
	if (!scoGSITVal.existeixObjecteFill(oPanell, sCamp))
	{
		errorCampPanell(oPanell, sCamp);
		return false;
	}

	return true;
}

////////////////////////////////////////////////////////////
// Nom: comprovarCampFillPanell
// Descripció:  Mètode que comprova si el panell 'oPanell' té definit el camp 'sCamp' com a fill si no el té dóna un avís
// Paràmetres d'entrada:
//		oPanell - Panell a validar
//		sCamp - Nom del camp a buscar al panell 	
// Paràmetres de sortida:
//		oCamp - el camp del panell 
////////////////////////////////////////////////////////////
function comprovarCampFillPanell(oPanell, sCamp)
{
	var oCamp = obtenirObjecteFill(oPanell, sCamp);
	if (!scoGSITVal.existeixObjecte(oCamp))
	{
		errorCampPanell(oPanell, sCamp);
		return null;
	}

	return oCamp;
}

////////////////////////////////////////////////////////////
// Nom: obtenirPanellValidacio
// Descripció:  Mètode que obté el panell de validació a partir de la definició del mòdul scoGSITPar "scoGSITPar.oPanellValidacio".
// Paràmetres de sortida:
//		objecte - Panell de validació 	
////////////////////////////////////////////////////////////
function obtenirPanellValidacio()
{
	return scoGSITPar.oPanellValidacio;	
}

////////////////////////////////////////////////////////////
// Nom: esPanellRequeridor
// Descripció:  Mètode que comprova si 'oPanell' o els seus pares estan vinculats al node requeridor de l'esquema
// Paràmetres d'entrada:
//		oPanell - Panell a comprovar
// Paràmetres de sortida: 	
//		booleà - Valor (true/false) resultant de la verificació de si el panell és el de la persona requeridora
////////////////////////////////////////////////////////////
function esPanellRequeridor(oPanell)
{
	var oNode = oPanell;
	var regExp = new RegExp("Inspeccionat");
	var bTrobat = false;
	while (oNode.name != scoGSITPar.nomFormulari)
	{
		if (regExp.test(String(oNode.bind.ref))) return true;
		oNode = oNode.parent;
	}

	return false;
}


////////////////////////////////////////////////////////////
// Nom: esPanell
// Descripció:  Mètode que verifica si l'objecte que es passa per paràmetre és de tipus panell 'subform'
// Paràmetres d'entrada:
//		oPanell - Panell a comprovar
//		sNomPanell - Nom del panell
// Paràmetres de sortida:
//		booleà -  Valor (true/false) que indica si l'objecte 'oPanell' té el nom del contingut del paràmetre 'sNomPanell'
////////////////////////////////////////////////////////////
function esPanell(oPanell, sNomPanell)
{
	try
	{
		if (!scoGSITVal.existeixObjecte(oPanell)) return false;	 
		return (oPanell.name == sNomPanell);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio(("esPanell " + sNomPanell), exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: esPanellMultiple 
// Descripció:  Mètode que verifica si el panell passat per paràmetre és de tipus múltiple de dades d'identificació
// Paràmetres d'entrada: 
//		oPanell - Panell de selecció múltiple (Física/Jurídica, Física/Jurídica/Organisme)
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el contingut del paràmetre 'oPanell' és un panell de selecció múltiple
////////////////////////////////////////////////////////////
function esPanellMultiple(oPanell)
{
	// Si te un check de selector de persona és un panell múltiple
	var oPersona = obtenirObjecteFill(oPanell, "BTN_PERSONA");
	return ((scoGSITVal.existeixObjecte(oPersona)) && (oPersona.className == "exclGroup"));
}

////////////////////////////////////////////////////////////
// Nom: esMultiple
// Descripció:  Mètode que verifica si el panell passat per paràmetre és de tipus múltiple de dades d'identificació o contacte
// Paràmetres d'entrada: 
//		oPanell - Panell a comprovar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el contingut del paràmetre 'oPanell' és un panell multiple de dades d'identificació o contacte
////////////////////////////////////////////////////////////
function esMultiple(oPanell)
{
	return (new RegExp("PERSONA_").test(oPanell.somExpression));
}

////////////////////////////////////////////////////////////
// Nom: esPanellFisicaJuridica
// Descripció:  Mètode que verifica si el panell passat per paràmetre és de tipus Física/Jurídica
// Paràmetres d'entrada: 
//		oPanell - Panell a comprovar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el contingut del paràmetre 'oPanell' és un panell Física/Jurídica
////////////////////////////////////////////////////////////
function esPanellFisicaJuridica(oPanell)
{
	return esPanell(oPanell, "PERSONA_FISICA_O_JURIDICA");
}

////////////////////////////////////////////////////////////
// Nom: esFisicaJuridica
// Descripció:  Mètode que verifica si el panell passat per paràmetre és de tipus Física/Jurídica
// Paràmetres d'entrada: 
//		oPanell - Panell a comprovar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el contingut del paràmetre 'oPanell' és un panell Física/Jurídica
////////////////////////////////////////////////////////////
function esFisicaJuridica(oPanell)
{
	return (esPanell(oPanell, "PERSONA_FISICA_O_JURIDICA") || esPanell(oPanell, "CONTACTE_PERSONA_FISICA_O_JURIDICA"));
}

////////////////////////////////////////////////////////////
// Nom: esPanellDadesIDParticular
// Descripció:  Mètode que verifica si el panell passat per paràmetre és de tipus DADES_IDENTIFICACIO_PARTICULAR
// Paràmetres d'entrada: 
//		oPanell - Panell a comprovar
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica el contingut del paràmetre 'oPanell' és un panell DADES_IDENTIFICACIO_PARTICULAR
////////////////////////////////////////////////////////////
function esPanellDadesIDParticular(oPanell)
{
	return esPanell(oPanell, "DADES_IDENTIFICACIO_PARTICULAR");
}

////////////////////////////////////////////////////////////
// Nom: esPanellDadesIDParticularNac
// Descripció:  Mètode que verifica si el panell passat per paràmetre és de tipus DADES_IDENTIFICACIO_PARTICULAR_NAC
// Paràmetres d'entrada: 
//		oPanell - Panell a comprovar
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica el contingut del paràmetre 'oPanell' és un panell DADES_IDENTIFICACIO_PARTICULAR_NAC
////////////////////////////////////////////////////////////
function esPanellDadesIDParticularNac(oPanell)
{
	return esPanell(oPanell, "DADES_IDENTIFICACIO_PARTICULAR_NAC");
}


////////////////////////////////////////////////////////////
// Nom: esPanellDadesIdentificacioEmpresa
// Descripció:  Mètode que verifica si el panell passat per paràmetre és de tipus DADES_IDENTIFICACIO_EMPRESA
// Paràmetres d'entrada: 
//		oPanell - Panell a comprovar
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica el contingut del paràmetre 'oPanell' és un panell DADES_IDENTIFICACIO_EMPRESA
////////////////////////////////////////////////////////////
function esPanellDadesIdentificacioEmpresa(oPanell)
