////////////////////////////////////////////////////////////
// Nom: esPanellAdrecaCatUnitatPob
// Descripció:  Mètode que verifica si el panell passat per paràmetre és de tipus ADRECA_CAT_UNITATPOB
// Paràmetres d'entrada: 
//		oPanell - Panell a comprovar
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica el contingut del paràmetre 'oPanell' és un panell ADRECA_CAT_UNITATPOB
////////////////////////////////////////////////////////////
function esPanellAdrecaCatUnitatPob(oPanell)
{
	return esPanell(oPanell, "ADRECA_CAT_UNITATPOB");	
}

////////////////////////////////////////////////////////////
// Nom: tipusPersonaPanellMultiple
// Descripció:  Mètode que recupera d'un panell múltiple el nom del panell corresponent al valor de 'TIPUS_USUARI' del panell 'oPanell'
// Paràmetres d'entrada: 
//		oPanell - Panell de selecció múltiple (Física/Jurídica, Física/Jurídica/Organisme)
// Paràmetres de sortida: 
//		string - Nom del panell relacionat: 'PERSONA_JURIDICA' o 'PERSONA_FISICA' o 'PERSONA_ORGANISME' o '' si no existeix
////////////////////////////////////////////////////////////
function tipusPersonaPanellMultiple(oPanell)
{
	var sTipusUsuari = scoGSITVal.tipusUsuariPanell(oPanell);
	if (sTipusUsuari == "particular")           return "PERSONA_FISICA";
	else if (sTipusUsuari == "entitat_privada") return "PERSONA_JURIDICA";
	else if (sTipusUsuari == "organisme")       return "PERSONA_ORGANISME";
	else return "";
}

////////////////////////////////////////////////////////////
// Nom: obtenirPersonaPanellMultiple
// Descripció:  Mètode que recupera d'un panell múltiple el panell corresponent a 'sTipusPersona' o al valor de 'TIPUS_USUARI' del panell 'oPanell'
// Paràmetres d'entrada: 
//		oPanell - Panell de selecció múltiple (Física/Jurídica, Física/Jurídica/Organisme)
//		sTipusPersona - Tipus de persona del panell actiu, ha de ser 'PERSONA_JURIDICA', 'PERSONA_FISICA', 'PERSONA_ORGANISME'
// Paràmetres de sortida: 
//		objecte - Panell corresponent del panell múltiple o null si no existeix el panell relacionat amb el tipus d'usuari
////////////////////////////////////////////////////////////
function obtenirPersonaPanellMultiple(oPanell, sTipusPersona)
{
	if (!scoGSITVal.existeixObjecte(oPanell)) return null; 

	if (arguments.length<2)
	{
		sTipusPersona = tipusPersonaPanellMultiple(oPanell);
		if (sTipusPersona == "") return null;
	}
	return obtenirObjecteFill(oPanell, sTipusPersona);
}

////////////////////////////////////////////////////////////
// Nom: obtenirPanellFisicaJuridicaActiu
// Descripció:  Mètode que recupera el panell actiu del Física/Jurídica: 'PERSONA_JURIDICA' o 'PERSONA_FISICA'
// Paràmetres d'entrada: 
//		oPanell - Panell de Física/Jurídica
//		sTipusPersona - Tipus de persona del panell actiu, ha de ser 'PERSONA_JURIDICA' o 'PERSONA_FISICA'
// Paràmetres de sortida: 
//		objecte - Panell actiu de la persona Física/Jurídica o null en cas que el contingut del paràmetre 'oPanell', no sigui un panell Física/Jurídica.
////////////////////////////////////////////////////////////
function obtenirPanellFisicaJuridicaActiu(oPanell, sTipusPersona)
{
	return ((arguments.length<2) ? obtenirPersonaPanellMultiple(oPanell) : obtenirPersonaPanellMultiple(oPanell, sTipusPersona));
}

////////////////////////////////////////////////////////////
// Nom: obtenirContactePanellMultiple
// Descripció:  Mètode que recupera el panell de CONTACTE corresponent a 'sTipusPersona' del panell múltiple 'oPanell'
// Paràmetres d'entrada: 
//		oPanell - Panell de selecció múltiple (Física/Jurídica, Física/Jurídica/Organisme)
//		sTipusPersona - Tipus de persona del panell actiu, ha de ser 'PERSONA_JURIDICA', 'PERSONA_FISICA', 'PERSONA_ORGANISME'
// Paràmetres de sortida: 
//		objecte - Panell CONTACTE o null si no existeix el panell relacionat amb el tipus de persona
////////////////////////////////////////////////////////////
function obtenirContactePanellMultiple(oPanell, sTipusPersona)
{
	try
	{
		var oPanellPersona = (arguments.length<2) ? obtenirPersonaPanellMultiple(oPanell) : obtenirPersonaPanellMultiple(oPanell, sTipusPersona);
		return obtenirObjecteFill(oPanellPersona, "CONTACTE");
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITPanells::obtenirContactePanellMultiple", exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: obtenirPanellFisicaJuridicaDades
// Descripció:  Mètode que recupera el panell amb les DADES_IDENTIFICATIVES de Física o Jurídica depenent de la selecció feta del panell Física/Jurídica
// Paràmetres d'entrada: 
//		oPanell - Panell de Física/Jurídica
//		sTipusPersona - Tipus de persona del panell actiu
// Paràmetres de sortida: 
//		objecte - Panell amb les DADES_IDENTIFICATIVES o null si el contingut del paràmetre 'oPanell' no és un panell de Física/Jurídica
////////////////////////////////////////////////////////////
function obtenirPanellFisicaJuridicaDades(oPanell, sTipusPersona)
{
	return ((arguments.length < 2) ? obtenirContactePanellMultiple(oPanell) : obtenirContactePanellMultiple(oPanell, sTipusPersona));
}

