////////////////////////////////////////////////////////////
// Nom: obtenirPanellRequeridor
// Descripció:  Mètode que obté el panell de Requeridor a partir de 'oPanell'
// Paràmetres d'entrada: 
//		oPanell - Panell que conté el panell requeridor
// Paràmetres de sortida: 
//		objecte - Panell de Requeridor que es recuperi o null s'hi aquest no es pot recuperar
////////////////////////////////////////////////////////////
function obtenirPanellRequeridor(oPanell)
{
	try
	{
		if (!scoGSITVal.existeixObjecte(oPanell)) return null;			
		if (esPanellMultiple(oPanell)) return obtenirContactePanellMultiple(oPanell); // Retornem el panell actiu del multiple
		else                           return oPanell;
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio(sNom, exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: esObjecteValid
// Descripció:  Mètode que verifica si l'objecte es del tipus acceptat (field, subform o exclGroup)
// Paràmetres d'entrada: 
//		obj - Objecte del formulari a verificar
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si l'objecte es del tipus acceptat
////////////////////////////////////////////////////////////
function esObjecteValid(obj)
{
	if (obj == null) return false;

	if (obj.className == "field") return true;
	if (obj.className == "subform") return true;
	if (obj.className == "exclGroup") return true;
	if (obj.className == "draw") return true;

	return false;
}

////////////////////////////////////////////////////////////
// Nom: obtenirBindObjecte
// Descripció:  Mètode que recupera la relació a l'esquema de dades de l'objecte cercat a partir de l'objecte referència
// Paràmetres d'entrada: 
//		oReferencia - Objecte referència el qual conté relació amb l'objecte a cercar
//		sBind - Bind de l'objecte
//		bIndex - Opcional que indica si en el cas que sigui un element d'una llista ha d'agafar el nº, sinò deixarà *
// Paràmetres de sortida: 	
//		string - Valor de la relació de l'objecte que es passa per paràmetre amb l'esquema de dades.
////////////////////////////////////////////////////////////
function obtenirBindObjecte(oReferencia, oBind, bIndex)
{
	try
	{
		if (oReferencia.name != "xfa" && oReferencia.name != "form")
		{
			if (arguments.length < 2) oBind = "";
			if (arguments.length < 3) bIndex = false;

			var sBind_total = "";
			var sBind_unitari = oReferencia.bind.ref;

			if (sBind_unitari.indexOf("$.")<0) sBind_unitari = "";

			// Canvia el * per l'index	
			if (bIndex && sBind_unitari.indexOf("*") >= 0) sBind_unitari = sBind_unitari.replace(/\*/gi, oReferencia.index);

			if (sBind_unitari != "" && oBind != "") sBind_total = sBind_unitari + "." + oBind;
			else sBind_total = sBind_unitari + oBind;

			var oParent = oReferencia.parent;
			if (oParent == null) return sBind_total;
			else                 return obtenirBindObjecte(oParent, sBind_total, bIndex);
		}
		oBind = oBind.replace(/\$.record/gi,"");
		oBind = oBind.replace(/\$./gi,"");

		return oBind;
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITPanells::obtenirBindObjecte", exc);
	}			
}

////////////////////////////////////////////////////////////
// Nom: obtenirObjectePare
// Descripció:  Mètode que recupera l'objecte pare a partir de l'objecte referència.
// Paràmetres d'entrada:
//		oReferencia - Objecte referència el qual conté relació amb l'objecte a cercar
//		sNomObjecte - Nom de l'objecte a cercar
// Paràmetres de sortida: 	
//		objecte - Objecte pare que es recupera
////////////////////////////////////////////////////////////
function obtenirObjectePare(oReferencia, sNomObjecte)
{
	return obtenirObjectePare_recursiu(oReferencia, sNomObjecte);
}

////////////////////////////////////////////////////////////
// Nom: obtenirObjectePare_recursiu
// Descripció:  Mètode que recupera l'objecte pare a partir de l'objecte referència.
// Paràmetres d'entrada:
//		oReferencia - Objecte referència el qual conté relació amb l'objecte a cercar
//		sNomObjecte - Nom de l'objecte a cercar
// Paràmetres de sortida: 	
//		Objecte - Objecte pare que es recupera
////////////////////////////////////////////////////////////
function obtenirObjectePare_recursiu(oReferencia, sNomObjecte)
{
	if (oReferencia.name == sNomObjecte) return oReferencia;

	var oParent = oReferencia.parent;
	if (oParent == null) return null;
	if (oParent.name == sNomObjecte) return oParent;
	var o = null;
	var oNodes = oParent.nodes;
	for (var i=0; i<oNodes.length; i++)
	{
		o = oNodes.item(i);
		if ((esObjecteValid(o)) && (o.name == sNomObjecte)) return o;
	}			

	return obtenirObjectePare_recursiu(oParent, sNomObjecte);	
}

////////////////////////////////////////////////////////////
// Nom: obtenirObjecteFill
// Descripció:  Mètode que recupera l'objecta fill a partir de l'objecte referència.
// Paràmetres d'entrada:
//		oReferencia - Objecte referència el qual conté relació amb l'objecte a cercar
//		sNomObjecte - Nom de l'objecte a cercar
// Paràmetres de sortida:
//		Objecte - Objecte pare que es recupera
////////////////////////////////////////////////////////////
function obtenirObjecteFill(oReferencia, sNomObjecte)
{
	return obtenirObjecteFill_recursiu(oReferencia, sNomObjecte);
}

////////////////////////////////////////////////////////////
// Nom: obtenirObjecteFill_recursiu
// Descripció:  Mètode que recupera l'objecte fill a partir de l'objecte referència
// Paràmetres d'entrada:
//		oReferencia - Objecte referència el qual conté relació amb l'objecte a cercar
//		sNomObjecte - Nom de l'objecte a cercar
// Paràmetres de sortida:
//		Objecte - Objecte fill que es recupera
////////////////////////////////////////////////////////////
function obtenirObjecteFill_recursiu(oReferencia, sNomObjecte)
{
	if (oReferencia == null) return null;
	if (oReferencia.name == sNomObjecte) return oReferencia;

	var aNodos = [];
	var oNodes = oReferencia.nodes;
	for (var i=0; i<oNodes.length; i++)
	{
		var o = oNodes.item(i);
		if (esObjecteValid(o))
		{
			if (o.name == sNomObjecte) return o;
			aNodos.push(o);
		}			
	}

	for (var i=0; i<aNodos.length; i++)
	{
		var o = obtenirObjecteFill_recursiu(aNodos[i], sNomObjecte);
		if ((esObjecteValid(o)) && (o.name == sNomObjecte)) return o;
	}

	return null;
}

////////////////////////////////////////////////////////////
// Nom: bloquejaIdentificadorPersona
// Descripció:  Mètode que bloqueja els camps de l'identificador de persona de 'oPanell' 
////////////////////////////////////////////////////////////
function bloquejaIdentificadorPersona(oPanell)
