	scoGSITVal.controlPassaport(obtenirObjecteFill(oPanell, "TXT_TIPUS_IDENTIFICADOR"));
	defCampBloquejats(oPanell, ["TXT_TIPUS_IDENTIFICADOR", "TXT_NUM_IDENTIFICADOR", "TXT_PAIS_DOCUMENT"]);
}

