////////////////////////////////////////////////////////////
// Nom: initPanellFisicaJuridica
// Descripció: Mètode que inicialitza el panell de Física/Jurídica
// Paràmetres d'entrada: 
//		oPanellFJ - Panell de Física/Jurídica
//		bModifAvisos - Valor (true/false) que indica si s'ha de modificar el panell d'avisos
////////////////////////////////////////////////////////////
function initPanellFisicaJuridica(oPanellFJ, bModifAvisos)
{
	var sNom = oPanellFJ.name + "::initialize";
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (scoGSITVal.esFormulariGuardat()) return;		

		scoGSITVal.compModuls(sNom, ["scoGSITPaisInfo", "scoGSITCombo"]);

		if (arguments.length < 2) bModifAvisos = esPanellRequeridor(oPanellFJ); // Per defecte el requeridor relacionat amb avisos
		initFisicaJuridica(oPanellFJ, bModifAvisos);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio(sNom, exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: initPanellDadesIdentificacioParticular
// Descripció: Mètode que inicialitza el panell de Dades Identificació Particular
// Paràmetres d'entrada: 
//		oPanell - Panell de Dades Identificacio Particular
////////////////////////////////////////////////////////////
function initPanellDadesIdentificacioParticular(oPanell)
{
	var sNom = oPanell.name + "::initialize";
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (scoGSITVal.esFormulariGuardat()) return;

		scoGSITVal.compModuls(sNom, ["scoGSITPaisInfo", "scoGSITCombo"]);
		defTipusUsuariPanell(oPanell, "particular");
		scoGSITVal.controlPassaport(obtenirObjecteFill(oPanell, "TXT_TIPUS_IDENTIFICADOR"));	
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio(sNom, exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: initPanellDadesIdentificacioParticularNac
// Descripció: Mètode que inicialitza el panell de Dades Identificació Particular amb lloc de Naixement
// Paràmetres d'entrada: 
// 		oPanell - Panell de Dades Identificació Particular amb lloc de Naixement
////////////////////////////////////////////////////////////
function initPanellDadesIdentificacioParticularNac(oPanell)
{
	var sNom = oPanell.name + "::initialize";
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (scoGSITVal.esFormulariGuardat()) return;

		scoGSITVal.compModuls(sNom, ["scoGSITCombo", "scoGSITAdreca", "scoGSITPaisInfo", "scoGSITProvInfo","scoGSITMunEspInfo"]);
		defTipusUsuariPanell(oPanell, "particular");

		var oNaixement = obtenirObjecteFill(oPanell, "NAIXEMENT");
		var oPais = obtenirObjecteFill(oNaixement, "TXT_PAIS");	
		var oPaisNom = obtenirObjecteFill(oNaixement, "TXT_PAIS_NOM");	
		var oIdentificador = obtenirObjecteFill(oPanell, "TXT_TIPUS_IDENTIFICADOR");

		var sCodiINEPais = scoGSITAdreca.obtenirCodiINEPais(oPais.parent);
		if (sCodiINEPais == "")
		{
			sCodiINEPais = "108";
			oPais.rawValue = "108";
            if (oPaisNom != null) oPaisNom.rawValue = scoGSITPaisInfo.obtenirNomPaisINE("108");
		}

		if (scoGSITVal.isFormulariAcusament())
		{
			if (sCodiINEPais != "108")	
			{
				var oChk = obtenirObjecteFill(oPanell, "CHK_ES_ESPANYOL");
				if (oChk != null) oChk.rawValue = "1";
				scoGSITCamps.defVisibilitat(oPais, "visible");

				var oMunicipiExt = obtenirObjecteFill(oNaixement, "TXT_MUNICIPI_EXT");
				scoGSITCamps.defVisibilitat(oMunicipiExt, "visible");

				var oMunicipis = obtenirObjecteFill(oNaixement, "LLISTA_MUNICIPIS");
				scoGSITCamps.defVisibilitat(oMunicipis, "hidden");

				var oProvincies = obtenirObjecteFill(oNaixement, "LLISTA_PROVINCIES");
				scoGSITCamps.defVisibilitat(oProvincies, "hidden");
			}

			if (oIdentificador != null) scoGSITVal.controlPassaport(oIdentificador);

			return;
		}

		defNacionalitat(oPanell, oIdentificador); 
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio(sNom, exc);
	}
}

