////////////////////////////////////////////////////////////
// Nom: obtenirArrAdreca
// Descripció: Mètode que inicialitza la variable array "arrAdrecaCat" relacionat amb el panell d'adreça
// Paràmetres d'entrada: 
//		oPanell - Panell adreça
////////////////////////////////////////////////////////////
function obtenirArrAdreca(oPanell)
{
	var arrAdrecaCat = new Array();
	var o = obtenirObjecteFill(oPanell, "TXT_ARR_ADRECA");
	if (o != null)
	{
		if (!scoGSITVal.isEmpty(o))
		{
			var arr = String(o.rawValue).split(",");
			for(var i=0;i<arr.length;i++)
		 		arrAdrecaCat[i] = arr[i];
		}
	}else{
		if (!scoGSITPar.bUsEnforceStrict) arrAdrecaCat = oPanell.arrAdrecaCat;
	}

	return arrAdrecaCat;
}

