////////////////////////////////////////////////////////////
// Nom: initPanellAdrecaCatLlogaretUnitatPob
// Descripció: Mètode que inicialitza el panell d'Adreca Catalana amb Llogaret o amb Unitats poblacionals
// Paràmetres d'entrada: 
//		oPanell - Panell d'Adreca catalana amb llogaret
//		bUnitatPob - Booleà que indica si és una Unitat poblacional (true) o un LLogaret (false)
////////////////////////////////////////////////////////////
function initPanellAdrecaCatLlogaretUnitatPob(oPanell, bUnitatPob)
{
	var sNom = oPanell.name + "::initialize";
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (scoGSITVal.isFormulariAcusament()) return;
		if (scoGSITVal.esFormulariGuardat()) return;

		scoGSITVal.compModuls(sNom, ["scoGSITAdreca", "scoGSITCombo", "scoGSITViaInfo", "scoGSITProvInfo", "scoGSITComInfo", "scoGSITMunCatInfo"]);

		if (bUnitatPob)  scoGSITVal.compModuls(sNom, ["scoGSITUnitatPobInfo"]);
		else             scoGSITVal.compModuls(sNom, ["scoGSITLlogInfo"]);

		var arrAdrecaCat = obtenirArrAdreca(oPanell);

		var oProvincies = oPanell.LLISTA_PROVINCIES;
		if (scoGSITAdreca.esProvinciaCatalana(oProvincies))
		{
			scoGSITAdreca.initProvinciaCat(oPanell, arrAdrecaCat, true);
			scoGSITAdreca.initComarcaCat(oPanell, arrAdrecaCat, true);

			if (bUnitatPob)  
				scoGSITAdreca.initMunicipisCatLlogUnitPob(oPanell, arrAdrecaCat, bUnitatPob);
			else
				scoGSITAdreca.initMunicipisCat(oPanell, arrAdrecaCat);			
		}
		else
		{
			scoGSITGen.netejarForm(oPanell, false);
			scoGSITAdreca.initProvinciaCat(oPanell, arrAdrecaCat, true);
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio(sNom, exc);
	}
}

