////////////////////////////////////////////////////////////
// Nom: initPanellContacteFJ
// Descripció: Mètode que inicialitza el panell de contacte Física/Jurídica a partir del tipus de panell que tingui el presentador (si té) o el requeridor, aquests no han de ser de tipus física/jurídica. Aquesta funció ja no es fa servir, s'ha de definir el panell relacionat del contacte a cada panell CONTACTE del panell d'avisos amb la crida 'scoGSITPanells.assignarPanellRelacionatContacte(this, oPanellRel);'
// Paràmetres d'entrada: 
//		oPanell - Panell de contacte particular adreça
////////////////////////////////////////////////////////////
function initPanellContacteFJ(oPanell) 
{
	var sNom = oPanell.name + "::initialize";
	try
	{	
		var oAvisosF = obtenirPanellFisicaJuridicaDades(oPanell, "PERSONA_FISICA");
		var oAvisosJ = obtenirPanellFisicaJuridicaDades(oPanell, "PERSONA_JURIDICA");

		var oTipusUsuari = scoGSITVal.existeixPresentador() ? xfa.resolveNode("xfa.record.Cos.Presentador.tipusUsuari") : xfa.resolveNode("xfa.record.Cos.Requeridor.tipusUsuari") ;		
		if ((oTipusUsuari.value == "particular"))  
			scoGSITVal.mostraOcultaPF_PJ(oAvisosF, oAvisosJ, "PERSONA_FISICA", "PERSONA_JURIDICA");			
		else
			scoGSITVal.mostraOcultaPF_PJ(oAvisosJ, oAvisosF, "PERSONA_JURIDICA", "PERSONA_FISICA");			
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio(sNom, exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: defPanellRelacionatContacte
// Descripció: Mètode que defineix el panell relacionat del contacte entre panells del mateix tipus (física-física, jurídica-jurídica, FJ-FJ)
////////////////////////////////////////////////////////////
function defPanellRelacionatContacte() 
{
	var oPanellBase = (scoGSITVal.existeixPresentador()) ? scoGSITPar.oPanellPresentador : scoGSITPar.oPanellRequeridor;

	if (!esPanellFisicaJuridica(oPanellBase))
	{
		var oPanellRel = obtenirObjecteFill(oPanellBase, "CONTACTE");
		var oPanellContacte = obtenirObjecteFill(scoGSITPar.oPanellAvisos, "CONTACTE");

		if (oPanellRel == null)      return errorSubformPanell(oPanellBase, "CONTACTE");
		if (oPanellContacte == null) return errorSubformPanell(scoGSITPar.oPanellAvisos, "CONTACTE");

		assignarPanellRelacionatContacte(oPanellContacte, oPanellRel);
	}
	else
	{
		var oPanellRelF = obtenirObjecteFill(obtenirObjecteFill(oPanellBase, "PERSONA_FISICA"), "CONTACTE");
		var oPanellRelJ = obtenirObjecteFill(obtenirObjecteFill(oPanellBase, "PERSONA_JURIDICA"), "CONTACTE");
		var oPanellContacteF = obtenirObjecteFill(obtenirObjecteFill(scoGSITPar.oPanellAvisos, "PERSONA_FISICA"), "CONTACTE");
		var oPanellContacteJ = obtenirObjecteFill(obtenirObjecteFill(scoGSITPar.oPanellAvisos, "PERSONA_JURIDICA"), "CONTACTE");

		if (oPanellRelF == null)      return errorSubformPanell(oPanellBase, "PERSONA_FISICA.CONTACTE");
		if (oPanellRelJ == null)      return errorSubformPanell(oPanellBase, "PERSONA_JURIDICA.CONTACTE");
		if (oPanellContacteF == null) return errorSubformPanell(scoGSITPar.oPanellAvisos, "PERSONA_FISICA.CONTACTE");
		if (oPanellContacteJ == null) return errorSubformPanell(scoGSITPar.oPanellAvisos, "PERSONA_JURIDICA.CONTACTE");

		assignarPanellRelacionatContacte(oPanellContacteF, oPanellRelF);
		assignarPanellRelacionatContacte(oPanellContacteJ, oPanellRelJ);
	}
}

////////////////////////////////////////////////////////////
// Nom: defPanellRelacionatContacteSimpleOFJ
// Descripció: Mètode que defineix el panell relacionat del contacte entre panells de tipus simple (física o jurídica) a un de tipus FJ-FJ
////////////////////////////////////////////////////////////
function defPanellRelacionatContacteSimpleOFJ()
{
	var oPanellBase = (scoGSITVal.existeixPresentador()) ? scoGSITPar.oPanellPresentador : scoGSITPar.oPanellRequeridor;

	// Panell base
	var oPanellRelF = null;
	var oPanellRelJ = null;	
	if (!esFisicaJuridica(oPanellBase))
	{	
		var oPanellRel = obtenirObjecteFill(oPanellBase, "CONTACTE");
		if (oPanellRel == null)      return errorSubformPanell(oPanellBase, "CONTACTE");

		if (esPanellDadesIdentificacioEmpresa(oPanellBase))  
			oPanellRelJ = oPanellRel;
		else
			oPanellRelF = oPanellRel;
	}
	else
	{
		var oPanellRelF = obtenirObjecteFill(obtenirObjecteFill(oPanellBase, "PERSONA_FISICA"), "CONTACTE");
		var oPanellRelJ = obtenirObjecteFill(obtenirObjecteFill(oPanellBase, "PERSONA_JURIDICA"), "CONTACTE");

		if (oPanellRelF == null)      return errorSubformPanell(oPanellBase, "PERSONA_FISICA.CONTACTE");
		if (oPanellRelJ == null)      return errorSubformPanell(oPanellBase, "PERSONA_JURIDICA.CONTACTE");
	}

	// Panell de contacte
	var oPanellContacteF = null;
	var oPanellContacteJ = null;
	if (!esFisicaJuridica(scoGSITPar.oPanellAvisos))
	{	
		var oPanellContacte = obtenirObjecteFill(scoGSITPar.oPanellAvisos, "CONTACTE");
		if (oPanellContacte == null) return errorSubformPanell(scoGSITPar.oPanellAvisos, "CONTACTE");

		if (esPanellDadesIdentificacioEmpresa(scoGSITPar.oPanellAvisos))  
			oPanellContacteJ = oPanellRel;
		else
			oPanellContacteF = oPanellRel;
	}
	else
	{
		var oPanellContacteF = obtenirObjecteFill(obtenirObjecteFill(scoGSITPar.oPanellAvisos, "PERSONA_FISICA"), "CONTACTE");
		var oPanellContacteJ = obtenirObjecteFill(obtenirObjecteFill(scoGSITPar.oPanellAvisos, "PERSONA_JURIDICA"), "CONTACTE");

		if (oPanellContacteF == null) return errorSubformPanell(scoGSITPar.oPanellAvisos, "PERSONA_FISICA.CONTACTE");
		if (oPanellContacteJ == null) return errorSubformPanell(scoGSITPar.oPanellAvisos, "PERSONA_JURIDICA.CONTACTE");
	}

	// Assignació
	if (oPanellRelF == null) oPanellRelF = oPanellRelJ;
	if (oPanellRelJ == null) oPanellRelJ = oPanellRelF;

	if (oPanellContacteF != null) assignarPanellRelacionatContacte(oPanellContacteF, oPanellRelF);
	if (oPanellContacteJ != null) assignarPanellRelacionatContacte(oPanellContacteJ, oPanellRelJ);
}



////////////////////////////////////////////////////////////
// Nom: initPanellMultiple
// Descripció: Mètode de definició inicial d'un panell de física/jurídica/organisme
// Paràmetres d'entrada:  
//		oPanell - Panell o somExpression de física/jurídica/organisme (objecte o string)
//		bModifAvisos - Valor (true/false) que indica si s'ha de modificar el panell d'avisos
//		sTipusUsuariDef - Tipus d'usuari que es definirà per defecte
////////////////////////////////////////////////////////////
function initPanellMultiple(oPanell, bModifAvisos, sTipusUsuariDef)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (scoGSITVal.esFormulariGuardat()) return;		

		var sNom = oPanell.name + "::initialize";
		scoGSITVal.compModuls(sNom, ["scoGSITPaisInfo", "scoGSITCombo"]);		

		if (typeof(oPanell) == "string") oPanell = xfa.resolveNode(oPanell);
		if (!scoGSITVal.existeixObjecte(oPanell)) return;

        if (arguments.length < 2) bModifAvisos = esPanellRequeridor(oPanell); // Per defecte el requeridor relacionat amb avisos
		if (arguments.length < 3) sTipusUsuariDef = "particular"; 			 // Per defecte particular

		if (scoGSITVal.isEmpty(oPanell.TIPUS_USUARI)) oPanell.TIPUS_USUARI.rawValue = sTipusUsuariDef;

		sUsuari =  oPanell.TIPUS_USUARI.rawValue;

		if (sUsuari == "particular")
		{
			oPanell.BTN_PERSONA.FISICA.rawValue = "1";
			scoGSITVal.canviFisica(oPanell, false, bModifAvisos);	
		}
		else if (sUsuari == "entitat_privada")
		{			
			oPanell.BTN_PERSONA.JURIDICA.rawValue = "2";
			scoGSITVal.canviJuridica(oPanell, false, bModifAvisos);
		}
		else if (sUsuari == "organisme")
		{
			oPanell.BTN_PERSONA.ORGANISME.rawValue = "3";
			scoGSITVal.canviOrganisme(oPanell, false, bModifAvisos);
		}	
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITPanells::initPanellMultiple", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: initFisicaJuridica
// Descripció: Mètode de definició inicial d'un panell de física/jurídica
// Paràmetres d'entrada:  
//		oPanell - Panell o somExpression de física/jurídica (objecte o string)
//		bModifAvisos - Valor (true/false) que indica si s'ha de modificar el panell d'avisos
////////////////////////////////////////////////////////////
function initFisicaJuridica(oPanell, bModifAvisos) 
{
	if (arguments.length == 2) 
		initPanellMultiple(oPanell, bModifAvisos);
	else
		initPanellMultiple(oPanell);	
}  


