////////////////////////////////////////////////////////////
// Nom: defTipusUsuariPanell
// Descripció: Mètode de defineix el tipus d'usuari del panell amb el valor 'sTipusUsuari' si el camp està buit i no es l'acusament de rebuda
// Paràmetres d'entrada:  
//		oPanell - Panell o somExpression del panell del que es vol definir el tipusUsuari
////////////////////////////////////////////////////////////
function defTipusUsuariPanell(oPanell, sTipusUsuari)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;	
		if (typeof(oPanell) == "string") oPanell = xfa.resolveNode(oPanell);
		if (!scoGSITVal.existeixObjecte(oPanell)) return;

		var oTipusUsuari = obtenirObjecteFill(oPanell, "TIPUS_USUARI");
		if (scoGSITVal.isEmpty(oTipusUsuari) && !scoGSITVal.isFormulariAcusament())  oTipusUsuari.rawValue = sTipusUsuari;
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITPanells::defTipusUsuariPanell", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: defNacionalitat
// Descripció: Mètode de defineix la nacionalitat a partir del tipus d'identificador
// Paràmetres d'entrada:  
//		oPanell - Panell o somExpression del panell del que es vol definir el tipusUsuari
//		oIdentificador - Camp de l'identificador
////////////////////////////////////////////////////////////
function defNacionalitat(oPanell, oIdentificador)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;	
		if (typeof(oPanell) == "string") oPanell = xfa.resolveNode(oPanell);
		if (!scoGSITVal.existeixObjecte(oPanell)) return;

		if (arguments.length < 2) oIdentificador = obtenirObjecteFill(oPanell, "TXT_TIPUS_IDENTIFICADOR");
		if (!scoGSITVal.existeixObjecte(oIdentificador)) return;

		var oNacionalitat = obtenirObjecteFill(oPanell, "TXT_NACIONALITAT");	
		if (!scoGSITVal.isEmpty(oIdentificador))
		{
			scoGSITVal.controlPassaport(oIdentificador);
			if (oIdentificador.rawValue.toUpperCase() == "NIF")
				defCampPropietats(oNacionalitat, "protected", "", "visible", msgNacionalitatEspanyola.value);	
			else 
				defCampPropietats(oNacionalitat, "open", "error", "visible", "");	
		}

		var oNaixement = obtenirObjecteFill(oPanell, "NAIXEMENT");
		scoGSITAdreca.initPaisIDParticularNac(obtenirObjecteFill(oNaixement, "TXT_PAIS"));
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITPanells::defTipusUsuariPanell", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: defAdrecaEsp
// Descripció: Mètode de definició inicial d'un panell d'adreça espanyola
// Paràmetres d'entrada:  
//		oAdreca - Panell o somExpression d'adreça espanyola (objecte o string)
////////////////////////////////////////////////////////////
function defAdrecaEsp(oAdreca)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;	
		if (typeof(oAdreca) == "string") oAdreca = xfa.resolveNode(oAdreca);
		if (!scoGSITVal.existeixObjecte(oAdreca)) return;

		scoGSITAdreca.defPaisEsp(oAdreca);
		oAdreca.TXT_ES_NORMALITZADA.rawValue = "false";

		var oProvincies = scoGSITPanells.obtenirObjecteFill(oAdreca, "LLISTA_PROVINCIES");
		if (scoGSITVal.existeixObjecte(oProvincies)) oProvincies.execEvent("exit");
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITPanells::defAdrecaEsp", exc);
	}		
}          


////////////////////////////////////////////////////////////
// Nom: defAdrecaEst
// Descripció: Mètode de definició inicial d'un panell d'adreça estrangera
// Paràmetres d'entrada:  
//		oAdreca - Panell o somExpression d'adreça estrangera (objecte o string)
////////////////////////////////////////////////////////////
function defAdrecaEst(oAdreca)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;	
		if (typeof(oAdreca) == "string") oAdreca = xfa.resolveNode(oAdreca);
		if (!scoGSITVal.existeixObjecte(oAdreca)) return;

		initPanellAdrecaEst(oAdreca);	
