		scoGSITAdreca.canviPanellAdrecaEstr(oChkResidencia);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITPanells::defAdrecaEst", exc);
	}		
}   

////////////////////////////////////////////////////////////
// Nom: defDadesIdent
// Descripció: Mètode de definició inicial d'un panell de dades identificatives d'usuari.
// Paràmetres d'entrada:  
//		oDadesIdent - Panell de dades identificatives d'usuari
//		sRol - TipusRolAcreditacio "1":PersonaFísica, "2":Persona Jurídica, "3":Persona Vinculada, "4":Persona Professional
//		sTipusUsuari - TipusOpcionsUsuari: "particular", "entitat_privada", "entitat_publica_gencat" , "entitat_publica_altres", "organisme"
//		bBorrar - Valor (true/false) que indica si s'han d'esborrar les dades del panell que s'oculta
////////////////////////////////////////////////////////////
function defDadesIdent(oDadesIdent, sTipusUsuari, sRol, bBorrar)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;	

		if (typeof(oDadesIdent) == "string") oDadesIdent = xfa.resolveNode(oDadesIdent);
		if ((oDadesIdent == null) || (oDadesIdent == undefined)) return;

		if (arguments.length < 2) sTipusUsuari = "particular";
		if (arguments.length < 3) sRol = "1";
		if (arguments.length < 4) bBorrar = true;

		var oRolAcreditacio = obtenirObjecteFill(oDadesIdent, "TXT_ROL_ACREDITACIO");
		if (oRolAcreditacio != null)
		{
			if (bBorrar || scoGSITVal.isEmpty(oRolAcreditacio)) oRolAcreditacio.rawValue = sRol;			
		}

		var oTipusUsuari = obtenirObjectePare(oDadesIdent, "TIPUS_USUARI");
		if (oTipusUsuari != null)
		{
			if (bBorrar || scoGSITVal.isEmpty(oTipusUsuari)) oTipusUsuari.rawValue = sTipusUsuari;			
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("defDadesIdent", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: defPanell
// Descripció: Mètode de defineix el panell 'fDefPanell[1]' fill de 'oPanell' amb la funció definida a 'fDefPanell[0]', es poden definir opcionalment més paràmetres per la crida a 'fDefPanell[2]'
// Paràmetres d'entrada: 
//		oPanell - Panell pare 
//		fDefPanell - Array de definició del panell: ["Funció definició", "Nom panell", "Altres paràmetres x la crida (OPCIONALS)"]
//		bBorrar - Valor (true/false) que indica si s'han d'esborrar les dades del panell a definir 'fDefPanell[1]'
////////////////////////////////////////////////////////////
function defPanell(oPanell, fDefPanell, bBorrar)
{
	try
	{
		if (!scoGSITVal.existeixObjecte(oPanell)) return;
		if (!scoGSITVal.existeixObjecte(fDefPanell)) return;
		if (fDefPanell.length < 2) return;
		if ((fDefPanell[0] == "") || (fDefPanell[1] == "")) return;

		if (bBorrar) 
		{	
			var oPanellFill = scoGSITPanells.obtenirObjecteFill(oPanell, fDefPanell[1]);
			scoGSITGen.netejarForm(oPanellFill, esPanellPreOmplert(oPanell));
		}
		var sAdreca = "scoGSITPanells.obtenirObjecteFill(oPanell, \"" + fDefPanell[1] + "\")";
		sAdreca = (fDefPanell[2]) ? (sAdreca + "," + fDefPanell[2]) : sAdreca;
		eval(fDefPanell[0] + "(" + sAdreca + ");");
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("defPanell", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: defAdrecaPanell
// Descripció: Mètode de defineix l'adreça de de 'oPanell': 'fDefPanell[1]' amb la funció definida a 'fDefPanell[0]', es poden definir opcionalment més paràmetres per la crida a 'fDefPanell[2]'
// Paràmetres d'entrada: 
//		oPanell - Panell pare
//		fDefAdreca - Array de definició de l'adreça del tipus: ["Funció definició adreça", "Nom panell adreca", "Altres paràmetres x la crida (OPCIONALS)"]
//		bBorrar - Valor (true/false) que indica si s'han d'esborrar les dades del panell d'adreça
////////////////////////////////////////////////////////////
function defAdrecaPanell(oPanell, fDefAdreca, bBorrar)
{
	defPanell(oPanell, fDefAdreca, bBorrar);
}

////////////////////////////////////////////////////////////
// Nom: esborraAdrecaPanell
// Descripció: Mètode que esborra l'adreca del panell 'oPanell' amb la funció definica a 'fDefAdreca'
// Paràmetres d'entrada: 
//		oPanell - Panell del que es vol definir l'adreça 
//		fEsbAdreca - Array amb la info x esborrar l'adreça : ["Funció x esborrar adreça", "Nom panell adreca", "Altres paràmetres x la crida (OPCIONALS)"]
////////////////////////////////////////////////////////////
function esborraAdrecaPanell(oPanell, fEsbAdreca)
{
	defPanell(oPanell, fEsbAdreca, true);
}

////////////////////////////////////////////////////////////
// Nom: defPaisPassaport
// Descripció: Mètode de definició inicial d'un camp de Pais
// Paràmetres d'entrada:  
//		oPais - Camp de País
////////////////////////////////////////////////////////////
function defPaisPassaport(oPais)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		if (scoGSITVal.existeixObjecte(oPais))
		{
			if (oPais.length == 0)
			{
				var sIDPais = oPais.editValue;
				scoGSITCombo.inicialitzaLlista(oPais, scoGSITPaisInfo.getLlistaPaisosISO());
				oPais.editValue = sIDPais;
				scoGSITVal.canviPaisPassaport(oPais.parent);		
			}
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("defPaisPassaport", exc);
	}				
}

////////////////////////////////////////////////////////////
// Nom: defCampPropietats
// Descripció: Mètode de definició de les propietats d'un camp
// Paràmetres d'entrada:  
//		oCamp - Camp a definir
//		sAcces - Valor a assignar a la propietat 'access'
//		sValidacio - Valor a assignar a la propietat 'validate.nullTest'
//		sPresencia - Valor a assignar a la propietat 'presence'
//		sValor - Valor al valor del camp
////////////////////////////////////////////////////////////
function defCampPropietats(oCamp, sAcces, sValidacio, sPresencia, sValor)
{
	try
	{			
		if (!scoGSITVal.existeixObjecte(oCamp)) return;

		oCamp.access = sAcces;
		oCamp.validate.nullTest = sValidacio;
		oCamp.rawValue = sValor;
		oCamp.presence = sPresencia;

		if (scoGSITVal.esCombo(oCamp) && scoGSITVal.isEmpty(sValor)) oCamp.editValue = sValor;
		if (scoGSITVal.isFormulariAcusament()) oCamp.validate.nullTest = "";
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("defCampPropietats", exc);
	}				
} 

////////////////////////////////////////////////////////////
// Nom: defCampPareBloquejat
// Descripció: Mètode de definició de les propietats d'un camp
// Paràmetres d'entrada:  
//		oPanell - panell on està definit el camp
//		sCamp - nom del camp a bloquejar
////////////////////////////////////////////////////////////
function defCampPareBloquejat(oPanell, sCamp)
{
	var oCamp = obtenirObjectePare(oPanell, sCamp);
	if (!scoGSITVal.existeixObjecte(oCamp)) return;

	defCampPropietats(oCamp, "protected", "", oCamp.presence, scoGSITVal.getValor(oCamp));
} 

////////////////////////////////////////////////////////////
// Nom: defCampBloquejat
// Descripció: Mètode de definició de les propietats d'un camp
// Paràmetres d'entrada:  
//		oPanell - panell on està definit el camp
//		sCamp - nom del camp a bloquejar
////////////////////////////////////////////////////////////
function defCampBloquejat(oPanell, sCamp)
{
	var oCamp = obtenirObjecteFill(oPanell, sCamp);
	if (!scoGSITVal.existeixObjecte(oCamp)) return;

	defCampPropietats(oCamp, "protected", "", oCamp.presence, scoGSITVal.getValor(oCamp));
} 

////////////////////////////////////////////////////////////
// Nom: defCampBloquejats
// Descripció: Mètode de definició de les propietats d'un camp
// Paràmetres d'entrada:  
//		oPanell - panell on està definit el camp
//		aNomCamps - array amb els noms dels camps a bloquejar
////////////////////////////////////////////////////////////
function defCampBloquejats(oPanell, aNomCamps)
{
	for (var n=0; n<aNomCamps.length; n++) defCampBloquejat(oPanell, aNomCamps[n]);
} 

////////////////////////////////////////////////////////////
// Nom: defCampsPropietats
// Descripció: Mètode de definició de les propietats dels camps de l'array
// Paràmetres d'entrada:  
//		aCamps - Llista de camps a definir
//		sAcces - Valor a assignar a la propietat 'access'
//		sValidacio - Valor a assignar a la propietat 'validate.nullTest'
//		sPresencia - Valor a assignar a la propietat 'presence'
//		sValor - Valor al valor del camp
////////////////////////////////////////////////////////////
function defCampsPropietats(aCamps, sAcces, sValidacio, sPresencia, sValor)
{
	try
	{
		for (var n=0; n<aCamps.length; n++)
		{
			if (arguments.length < 5) sValor = scoGSITVal.getValor(aCamps[n]);			
			defCampPropietats(aCamps[n], sAcces, sValidacio, sPresencia, sValor);
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("defCampsPropietats", exc);
	}				
} 

////////////////////////////////////////////////////////////
// Nom: defCampsPropietatsValors
// Descripció: Mètode de definició de les propietats dels camps de l'array
// Paràmetres d'entrada:  
//		aCamps - Llista de camps a definir
//		sAcces - Valor a assignar a la la propietat 'access'
//		sValidacio - Valor a assignar a la propietat  'validate.nullTest'
//		sPresencia - Valor a assignar a la la propietat 'presence'
//		sValor - Valor al valor del camp
////////////////////////////////////////////////////////////
function defCampsPropietatsValors(aCamps, sAcces, sValidacio, sPresencia, aValor)
{
	try
	{
		for (var n=0; n<aCamps.length; n++) 
			defCampPropietats(aCamps[n], sAcces, sValidacio, sPresencia, aValor[n]);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("defCampsPropietatsValors", exc);
	}				
} 

