////////////////////////////////////////////////////////////
// Nom: copiaValorPropietatsCampsEntrePanells
// Descripció: Mètode que còpia els valors i les propietats dels camps d'un panell a un altre.
// Paràmetres d'entrada:  
//		oPanellOrigen - Panell origen del que s'han de recollir els valors de les propietats
//		oPanellDesti  - Panell destí al qual s'han de copiar els valors de les propietats
//		sNomPanellPareOrigen - Nom del panell pare origen
//		sNomPanellPareDesti - Nom del panell pare destí
//		arrLlistesPerActualitzar - Array amb els noms de totes les llistes que es volen copiar
////////////////////////////////////////////////////////////
function copiaValorPropietatsCampsEntrePanells(oPanellOrigen, oPanellDesti,sNomPanellPareOrigen, sNomPanellPareDesti, arrLlistesPerActualitzar)
{
		for(var i = 0; i<oPanellOrigen.nodes.length; i++) {		
			var oNode = oPanellOrigen.nodes.item(i);
			if (oNode.className == "field"){
				var oNodeDesti = recuperaNodeDesti(oNode, oPanellDesti, sNomPanellPareOrigen, sNomPanellPareDesti);		
				if (oNodeDesti != null){
				    // ES_SIGNATARI
					if (oNode.name.toUpperCase() == "ES_SIGNATARI")
					{
						oNodeDesti.rawValue = (!scoGSITVal.isEmpty(oNode)) ? "false" : oNode.rawValue;
					}
					else if (oNode.ui.oneOfChild.className == "choiceList")
					{
						if (esLlistaPerActualitar(oNode.name, arrLlistesPerActualitzar ))
						{
							carregaValorsEntreLlistes(oNode, oNodeDesti);
						}
						oNodeDesti.rawValue = oNode.rawValue;
					}else{
						oNodeDesti.rawValue = oNode.rawValue;
					}

					// Propietats
					if (oNode.ui.oneOfChild.className == "button")
						scoGSITBot.copiarEstatBoto(oNode, oNodeDesti);
					else
					{
						oNodeDesti.access = oNode.access;
						oNodeDesti.presence = oNode.presence;
						oNodeDesti.validate.nullTest = oNode.validate.nullTest;
						oNodeDesti.border.edge.presence = oNode.border.edge.presence;
						oNodeDesti.borderColor = oNode.borderColor;
					}	
				}							
			}else if (oNode.className == "subform"){
				copiaValorPropietatsCampsEntrePanells(oNode, oPanellDesti, sNomPanellPareOrigen, sNomPanellPareDesti, arrLlistesPerActualitzar);
			}else if (oNode.className == "exclGroup"){
				copiaValorPropietatsCampsEntrePanells(oNode, oPanellDesti, sNomPanellPareOrigen, sNomPanellPareDesti, arrLlistesPerActualitzar);
			}
		}
}

////////////////////////////////////////////////////////////
// Nom: copiaDadesEntrePanells
// Descripció: Mètode que còpia de les dades d'un panell a un altre
// Paràmetres d'entrada:  
//		oPanellOrigen - Panell origen del que s'han de recollir les dades
//		oPanelldesti - Panell destí al qual s'han de copiar les dades
//		arrLlistesPerActualitzar - Array amb els noms de totes les llistes que es volen copiar
////////////////////////////////////////////////////////////
function copiaDadesEntrePanells(oPanellOrigen, oPanellDesti, arrLlistesPerActualitzar)
{
	copiaValorCampsEntrePanells(oPanellOrigen, oPanellDesti, oPanellOrigen.name, oPanellDesti.name, arrLlistesPerActualitzar);
}

////////////////////////////////////////////////////////////
// Nom: copiaValorCampsEntrePanells
// Descripció: Mètode que còpia els valors dels camp d'un panell a un altre
// Paràmetres d'entrada:  
//		oPanellOrigen - Panell origen del que s'han de recollir els valors dels camps
//		oPanellDesti - Panell destí al qual s'han de copiar els valors dels camps
//		sNomPanellPareOrigen - Nom del panell pare origen
//		sNomPanellPareDesti - Nom del panell pare destí
//		arrLlistesPerActualitzar - Array amb els noms de totes les llistes que es volen copiar
////////////////////////////////////////////////////////////
function copiaValorCampsEntrePanells(oPanellOrigen, oPanellDesti,sNomPanellPareOrigen, sNomPanellPareDesti, arrLlistesPerActualitzar)
{
		for(var i = 0; i<oPanellOrigen.nodes.length; i++) {		
			var oNode = oPanellOrigen.nodes.item(i);
			if (oNode.className == "field"){			
				var oNodeDesti = recuperaNodeDesti(oNode, oPanellDesti, sNomPanellPareOrigen, sNomPanellPareDesti);		
				if (oNodeDesti != null){
				    // ES_SIGNATARI
					if (oNode.name.toUpperCase() == "ES_SIGNATARI")
					{
						oNodeDesti.rawValue = (!scoGSITVal.isEmpty(oNode)) ? "false" : oNode.rawValue;
					}
					else if (oNode.ui.oneOfChild.className == "choiceList")
					{
						if (esLlistaPerActualitar(oNode.name, arrLlistesPerActualitzar ))
						{
							carregaValorsEntreLlistes(oNode, oNodeDesti);
						}
						oNodeDesti.rawValue = oNode.rawValue;
					}else{
						oNodeDesti.rawValue = oNode.rawValue;
					}
				}							
			}else if (oNode.className == "subform"){
				copiaValorCampsEntrePanells(oNode, oPanellDesti, sNomPanellPareOrigen, sNomPanellPareDesti, arrLlistesPerActualitzar);
			}else if (oNode.className == "exclGroup"){
				copiaValorCampsEntrePanells(oNode, oPanellDesti, sNomPanellPareOrigen, sNomPanellPareDesti, arrLlistesPerActualitzar);
			}
		}
}

////////////////////////////////////////////////////////////
// Nom: copiaCampsPanells
// Descripció: Mètode que copia el valor dels camps de 'aCamps' del panell d'origen 'oPanellOri' al mateix camp del panell destí 'oPenellDest'
// Paràmetres d'entrada:
//		oPanellOri - Panell d'origen
//		oPenellDest - Panell de destí
//		aCamps - Array amb el nom dels camps a copiar
//      bPropietats - Valor (true/false) que indica si s'han de copiar també les propietats dels camps (per defecte las copia)
//      bVisible - Valor (true/false) que indica si s'han de copiar també les propietats de visibilitat
//		bObligat - Valor (true/false) que indica si s'han de copiar també les propietats d'obligatorietat
////////////////////////////////////////////////////////////
function copiaCampsPanells(oPanellOri, oPenellDest, aCamps, bPropietats, bVisible, bObligat) 
{
	if (arguments.length < 4) bPropietats = true;
	if (arguments.length < 5) bPropietats = false;
	if (arguments.length < 6) bPropietats = false;

	var nCamps = aCamps.length;
	for (var n=0; n<nCamps; n++)
	{
		var sCamp = aCamps[n];
		var oCampOri = obtenirObjecteFill(oPanellOri, sCamp);
		var oCampDes = obtenirObjecteFill(oPenellDest, sCamp);
		if (oCampOri != null && oCampDes != null)
		{
			oCampDes.rawValue = oCampOri.rawValue;

			if (bPropietats)
			{
				oCampDes.border.edge.presence = oCampOri.border.edge.presence;
				oCampDes.borderColor = oCampOri.borderColor;
			}				

			if (bVisible) oCampDes.presence = oCampOri.presence;
			if (bObligat) oCampDes.validate.nullTest = oCampOri.validate.nullTest; 
		}
	}		
}

////////////////////////////////////////////////////////////
// Nom: clonaCampsPanells
// Descripció: Mètode que clona els camps de 'aCamps' del panell d'origen 'oPanellOri' al panell destí 'oPenellDest'
// Paràmetres d'entrada:
//		oPanellOri - Panell d'origen
//		oPanellDest - Panell de destí
//		aCamps - Array amb el nom dels camps a clonar
//		bClonaAccess - (opcional, xdefecte = false) Indica si volem clonar també la propietat 'access'
////////////////////////////////////////////////////////////
function clonaCampsPanells(oPanellOri, oPanellDest, aCamps, bClonaAccess, bClonaPosicions) 
{
	if (arguments.length < 4) bClonaAccess = false;
	if (arguments.length < 5) bClonaPosicions = true;

	var nCamps = aCamps.length;
	for (var n=0; n<nCamps; n++)
	{
		var sCamp = aCamps[n];
		var oCampOri = obtenirObjecteFill(oPanellOri, sCamp);
		var oCampDes = obtenirObjecteFill(oPanellDest, sCamp);
		if (oCampOri != null && oCampDes != null)
		{	
			scoGSITCamps.clonaCamp(oCampDes, oCampOri, bClonaAccess, bClonaPosicions);

			if (oCampOri.ui.oneOfChild.className == "choiceList") carregaValorsEntreLlistes(oCampOri, oCampDes);
			oCampDes.rawValue = oCampOri.rawValue;			
		}
	}		
}

////////////////////////////////////////////////////////////
// Nom: copiaValorsEntreLlistes
// Descripció: Mètode que copia els valors de les llistes de 'aCamps' de 'oPanellOri' a 'oPenellDest'
// Paràmetres d'entrada:
//		oPanellOri - Panell d'origen
//		oPenellDest - Panell de destí
//		aCamps - Array amb el nom dels camps a copiar
////////////////////////////////////////////////////////////
function copiaValorsEntreLlistes(oPanellOri, oPenellDest, aCamps) 
{
	if (arguments.length < 4) bPropietats = true;

	var nCamps = aCamps.length;
	for (var n=0; n<nCamps; n++)
	{
		var sCamp = aCamps[n];
		var oCampOri = obtenirObjecteFill(oPanellOri, sCamp);
		var oCampDes = obtenirObjecteFill(oPenellDest, sCamp);
		if (oCampOri != null && oCampDes != null)
		{
			carregaValorsEntreLlistes(oCampOri, oCampDes);			
		}
	}		
}

////////////////////////////////////////////////////////////
// Nom: copiaDadesPersona
// Descripció: Mètode que copia els camps d'informació d'una persona del panell d'origen al panell de destí (sempre: nom/cognoms i identificador i opcionalment: data naixement, gènere, telèfons, mail)
// Paràmetres d'entrada:
//		oPanellOri - Panell d'adreça origen
//		oPanellDes - Panell d'adreça destí
//		bInfoExtra - Indica si es vol copiar la informació extra de la persona: data naixement, gènere
//		bInfoContacte - Indica si es vol copiar la informacióde contacte de la persona: telèfons, mail
////////////////////////////////////////////////////////////
function copiaDadesPersona(oPanellOri, oPanellDes, bInfoExtra, bInfoContacte)
{
	if (!scoGSITVal.isFormulariValidat())
	{
		if (arguments.length < 3) bInfoExtra = false;
		if (arguments.length < 4) bInfoContacte = true;	

		var oContateOri = (esPanellMultiple(oPanellOri)) ? obtenirPersonaPanellMultiple(oPanellOri) : obtenirObjecteFill(oPanellOri, "CONTACTE");
		var oContateDes = (esPanellMultiple(oPanellDes)) ? obtenirPersonaPanellMultiple(oPanellDes) : obtenirObjecteFill(oPanellDes, "CONTACTE");

		if (!scoGSITVal.existeixObjecte(oContateOri)) return;
		if (!scoGSITVal.existeixObjecte(oContateDes)) return;

		// Si és Empresa o Organisme la persona és el Representant
		var sTipusUsuariOri = scoGSITVal.tipusUsuariPanell(oPanellOri);
		var sTipusUsuariDest = scoGSITVal.tipusUsuariPanell(oPanellDes);

		if (scoGSITVal.esPanellAmbRepresentant(sTipusUsuariOri))   oContateOri = obtenirObjecteFill(oContateOri, "REPRESENTANT");
		if (scoGSITVal.esPanellAmbRepresentant(sTipusUsuariDest))  oContateDes = obtenirObjecteFill(oContateDes, "REPRESENTANT");

		copiaCampsPanells(oContateOri, oContateDes, ["TXT_TIPUS_IDENTIFICADOR"]);
		scoGSITVal.controlPassaport(obtenirObjecteFill(oContateDes, "TXT_TIPUS_IDENTIFICADOR")); 

		var aCamps = ["TXT_NOM", "TXT_COGNOM1", "TXT_COGNOM2", "TXT_NUM_IDENTIFICADOR", "TXT_PAIS_DOCUMENT", "TXT_PAIS_DOCUMENT_NOM"];
		copiaCampsPanells(oContateOri, oContateDes, aCamps);	

		if (bInfoExtra)
			copiaCampsPanells(oContateOri, oContateDes, ["TXT_GENERE", "TXT_DATA_NAIXEMENT"]);			

		if (bInfoContacte)
			copiaCampsPanells(oContateOri, oContateDes, ["TXT_TELEFON_FIX", "TXT_TELEFON_MOBIL", "TXT_ADRECA_ELECTRONICA"]);			
	}
}

////////////////////////////////////////////////////////////
// Nom: copiaDadesContacte
// Descripció: Mètode que copia els camps de nom/cognoms i identificador del presentador si hi és i sino del requeridor al panell de Dades de Contacte
// Paràmetres d'entrada:
//		bPregunta - Indica si s'ha de preguntar si es vol realitzar la copia
//		bInfoExtra - Indica si es vol copiar la informació extra de la persona: data naixement, gènere
//		bInfoContacte - Indica si es vol copiar la informacióde contacte de la persona: telèfons, mail
//		sAdreca - Nom del panell d'adreça a copiar, si no es vol copiar l'adreça s'ha de definir string buit ''
////////////////////////////////////////////////////////////
function copiaDadesContacte(bPregunta, bInfoExtra, bInfoContacte, sAdreca)
{
	if (!scoGSITVal.isFormulariValidat())
	{
		if (arguments.length < 1) bPregunta = true;	
		if (arguments.length < 2) bInfoExtra = false;
		if (arguments.length < 3) bInfoContacte = true;	
		if (arguments.length < 4) sAdreca = "";	

		var oPanellOri = (scoGSITVal.existeixPresentador()) ? scoGSITPar.oPanellPresentador : scoGSITPar.oPanellRequeridor;
		var sMsg = (scoGSITVal.existeixPresentador()) ?  sMsg = msgPreguntaCopiarDadesPresentador.value : msgPreguntaCopiarDadesRequeridor.value;

		var bCopia = (bPregunta) ? (scoGSITMissatges.MissatgePregunta(sMsg,"")) : true;
		if (bCopia)
		{
			copiaDadesPersona(oPanellOri, scoGSITPar.oPanellAvisos, bInfoExtra, bInfoContacte);
			if (!scoGSITVal.isEmpty(sAdreca)) scoGSITAdreca.copiaAdrecesPanellsGenerica(oPanellOri, scoGSITPar.oPanellAvisos, sAdreca);
		}
	}
}

////////////////////////////////////////////////////////////
// Nom: copiaDadesContacteAdreca
// Descripció: Mètode que copia els camps de persona i adreça del presentador si hi és i sino del requeridor al panell de Dades de Contacte
// Paràmetres d'entrada:
//		bPregunta - Indica si s'ha de preguntar si es vol realitzar la copia
//		sAdreca - Nom del panell d'adreça a copiar
//		bInfoExtra - Indica si es vol copiar la informació extra de la persona: data naixement, gènere
//		bInfoContacte - Indica si es vol copiar la informacióde contacte de la persona: telèfons, mail
////////////////////////////////////////////////////////////
function copiaDadesContacteAdreca(bPregunta, sAdreca, bInfoExtra, bInfoContacte)  
{
	if (!scoGSITVal.isFormulariValidat())
	{
		if (arguments.length < 3) bInfoExtra = false;
		if (arguments.length < 4) bInfoContacte = true;	
		copiaDadesContacte(bPregunta, bInfoExtra, bInfoContacte, sAdreca);
	}
}


////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
// MÈTODES: RECUPERACIÓ DE NODES I PANELLS
////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

////////////////////////////////////////////////////////////
// Nom: recuperaNodeDesti
// Descripció: Mètode que recupera el node destí a partir del nom del node origen i de les somExpressions
// Paràmetres d'entrada:
//		oNode - Camp de tipus llista del qual s'han de recuperar els valors a copiar
//		oPanellDesti - Panell destí el qual conté el camp de tipus llista en el que s'han de copiar les dades
//		sNomPanellPareOrigen - Nom del panell origen
//		sNomPanellPareDesti - Nom del panell destí
// Paràmetres de sortida:
//		objecte - Camp de tipus llista que se li hauràn de copiar els valors
////////////////////////////////////////////////////////////
function recuperaNodeDesti(oNode, oPanellDesti, sNomPanellPareOrigen, sNomPanellPareDesti)
{
	var somExprOrigen = new String(oNode.somExpression);
	var somExprDesti = new String (oPanellDesti.somExpression);			
	var posMigPost = somExprOrigen.indexOf(sNomPanellPareOrigen + "[");
	var posFinalPost = somExprOrigen.length;
	var posMigPre = somExprDesti.indexOf(sNomPanellPareDesti + "[");
	var preSomExpr = somExprDesti.substr(0,posMigPre);
	var postSomExpr = somExprOrigen.substr(posMigPost,posFinalPost);
	return xfa.resolveNode(preSomExpr + postSomExpr);
}

////////////////////////////////////////////////////////////
// Nom: carregaValorsEntreLlistes
// Descripció: Mètode que còpia les dades del camp de llista origen cap al camp de llista destí
// Paràmetres d'entrada:  
//		oLlistaOrigen - Camp origen de tipus llista del que s'han de recollir les dades
//		oLlistaDesti - Camp destí de tipus llista al qual s'han de copiar les dades
////////////////////////////////////////////////////////////
function carregaValorsEntreLlistes(oLlistaOrigen, oLlistaDesti)
{
	oLlistaDesti.clearItems();
	for(i=0;i<oLlistaOrigen.length;i++) 
	{
		oLlistaDesti.addItem(oLlistaOrigen.getDisplayItem(i),oLlistaOrigen.getSaveItem(i));			
	}
}

////////////////////////////////////////////////////////////
// Nom: esLlistaPerActualitar
// Descripció: Mètode que verifica si un objecte camp de tipus llista s'ha d'actualitzar.
// Paràmetres d'entrada:  
//		nomLlista - Nom del camp de llista actual
//		arrLlistesPerActualitzar - Array amb totes les llistes que s'han d'actualitzar
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si el nom del camp està en la llista per actualitzar
////////////////////////////////////////////////////////////
function esLlistaPerActualitar(sNomLLista, arrLlistesPerActualitzar)
{
	for(var i=0;i<arrLlistesPerActualitzar.length;i++)
	{
		if (sNomLLista.toUpperCase() == arrLlistesPerActualitzar[i].toUpperCase()) return true;
	}

	return false;
}


 ////////////////////////////////////////////////////////////
// Nom: esPanellPreOmplert
// Descripció: Mètode que verifica si el panell és pleomplert, en funció de si hi ha presentador o no i si hi han dades preomplertes
// Paràmetres d'entrada: 
//           oPanell - Panell del qual se'n verifica si hi han dades amb pleomplert
// Paràmetres de sortida: 
//           booleà - Valor (true/false) que indica si hi han dades amb pleomplert
////////////////////////////////////////////////////////////
function esPanellPreOmplert(oPanell)
{
	var oBtnPersona = obtenirObjecteFill(oPanell, "BTN_PERSONA");
	if (!scoGSITVal.existeixObjecte(oBtnPersona))			return false;

	return (oBtnPersona.access == "protected");
}


////////////////////////////////////////////////////////////
// Nom: esPanellEsSignatari
// Descripció: Mètode que verifica si el panell és signatari, en funció de si hi ha presentador o no i si el formulari té signatura
// Paràmetres d'entrada: 
//		oPanell - Panell del qual se'n verifica si esSigantari
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si el panell esSigantari
////////////////////////////////////////////////////////////
function esPanellEsSignatari(oPanell)
{
	// Controla si hi ha signatura, segons tipus panell si te presentador o no
	return (scoGSITPar.bFormulariTeFirma && esPanellRequeridor(oPanell));
}


/////////////////////////////////////////////////////////////////////////////
// Nom: obtenirDadesCampPanellRelacionat
// Descripció: Mètode que recupera el camp fill del paràmetre 'oField' del panell del paràmetre 'oPanell'.
// Paràmetres d'entrada:  
//		oPanell - Panell pare que conté el camp a recuperar-ne la informació
//		oField - Camp que conté la informació
// Paràmetres de sortida: 
//		string - Valor del camp 'oField' recuperat del panell 'oPanell' 
/////////////////////////////////////////////////////////////////////////////               
function obtenirDadesCampPanellRelacionat(oPanell, oField)
{
    var o = obtenirObjecteFill(oPanell, oField.name);
    if (o != null) return o.rawValue;               

    return "";
}

////////////////////////////////////////////////////////////
// Nom: obtenirNomPanellAdreca
// Descripció: Mètode que retorna el nom del panell d'adreça de l'array 'fDefAdreca' corresponent al panell actiu de 'oPanell'
// Paràmetres d'entrada: 
//		oPanell - Panell de selecció múltiple (Física/Jurídica, Física/Jurídica/Organisme)
//		fDefAdreca - Array de definició de l'adreça del tipus: ["Funció definició adreça", "Nom panell adreca"]
// Paràmetres de sortida: 
//		sNomPanell - Nom del panell d'adreça del panell actiu del Física/Jurídica de Presentador
////////////////////////////////////////////////////////////
function obtenirNomPanellAdrecaPanellMultiple(oPanell, fDefAdreca)
{
	try
	{
		if (fDefAdreca == null)
		{
			app.alert("ATENCIÓ factoria, cal definir correctament les variables 'defAdrecaPresentador', 'defAdrecaRequeridor' i 'defAdrecaAvisos' que calguin del mòdul 'scoGSITPar'");
			return;
		}

		var nPanell = scoGSITVal.numeroPanell(oPanell);
		return fDefAdreca[nPanell][1];		
	} 
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITPanells.obtenirNomPanellAdreca", exc);
	}		
}

////////////////////////////////////////////////////////////
// Nom: obtenirNomPanellAdrecaFJ
// Descripció: Mètode que retorna el nom del panell d'adreça del panell actiu del Física/Jurídica 
// Paràmetres de sortida: 
//		oPanellFJ -  Panell de selecció múltiple (Física/Jurídica)
//		fDefAdreca - Array de definició de l'adreça del tipus: ["Funció definició adreça", "Nom panell adreca"]
////////////////////////////////////////////////////////////
function obtenirNomPanellAdrecaFJ(oPanellFJ, aAdreces)
{
	return obtenirNomPanellAdrecaPanellMultiple(oPanellFJ, aAdreces);
}

////////////////////////////////////////////////////////////
// Nom: obtenirPanellAdrecaPanellMultiple
// Descripció: Mètode que retorna el panell d'adreça del panell actiu d'un panell múltiple
// Paràmetres d'entrada: 
//		oPanell - Panell de selecció múltiple (Física/Jurídica, Física/Jurídica/Organisme)
//		sAdreca - Nom del panell d'adreça a cercar
// Paràmetres de sortida: 
//		oPanell - Panell d'adreça del panell actiu del Física/Jurídica o null si no existeix algún dels panells
////////////////////////////////////////////////////////////
function obtenirPanellAdrecaPanellMultiple(oPanell, sAdreca)
{
	if (!scoGSITVal.existeixObjecte(oPanell)) return null;

	var oPanellAct = obtenirPersonaPanellMultiple(oPanell);
	if (oPanellAct != null) return obtenirObjecteFill(oPanellAct, sAdreca);	

	return null;
}

////////////////////////////////////////////////////////////
// Nom: obtenirPanellAdrecaFJ
// Descripció: Mètode que retorna el panell d'adreça del panell actiu del Física/Jurídica
// Paràmetres d'entrada: 
//		oPanellFJ - Panell de Física/Jurídica del que se'n vol l'adreça activa
//		sAdreca - Nom del panell d'adreça a cercar
// Paràmetres de sortida: 
//		oPanell - Panell d'adreça del panell actiu del Física/Jurídica o null si no existeix algún dels panells
////////////////////////////////////////////////////////////
function obtenirPanellAdrecaFJ(oPanellFJ, sAdreca)
{
	return obtenirPanellAdrecaPanellMultiple(oPanellFJ, sAdreca);
}

////////////////////////////////////////////////////////////
// Nom: obtenirPanellNormalitzadorPanellMultiple
// Descripció: Mètode que retorna el panell Normalitzador del panell actiu d'un panell múltiple
// Paràmetres d'entrada: 
//		oPanellFJ - Panell de Física/Jurídica del que se'n vol l'adreça activa
// Paràmetres de sortida: 
//		oPanell - Panell Normalitzador del panell actiu del Física/Jurídica o null si no existeix algún dels panells
////////////////////////////////////////////////////////////
function obtenirPanellNormalitzadorPanellMultiple(oPanell)
{
	if (!scoGSITVal.existeixObjecte(oPanell)) return null;

	var oPanellAct = obtenirPersonaPanellMultiple(oPanell);
	if (oPanellAct != null) return obtenirObjecteFill(oPanellAct, "NORMALITZADOR");	

	return null;
}

////////////////////////////////////////////////////////////
// Nom: obtenirPanellNormalitzadorFJ
// Descripció: Mètode que retorna el panell Normalitzador del panell actiu del Física/Jurídica
// Paràmetres d'entrada: 
//		oPanellFJ - Panell de Física/Jurídica del que se'n vol l'adreça activa
// Paràmetres de sortida: 
//		oPanell - Panell Normalitzador del panell actiu del Física/Jurídica o null si no existeix algún dels panells
////////////////////////////////////////////////////////////
function obtenirPanellNormalitzadorFJ(oPanellFJ)
{
	return obtenirPanellNormalitzadorPanellMultiple(oPanellFJ);
}

////////////////////////////////////////////////////////////
// Nom: getPanellRel
// Descripció: Mètode que retorna el panell relacionat amb nom 'sNomPanellRel' de 'oPanell'
// Paràmetres d'entrada: 
//		oPanell - Panell
//		sNomPanellRel - Nom del Panell relacionat
////////////////////////////////////////////////////////////
function getPanellRel(oPanell, sNomPanellRel)
{
	var oPanellRel = scoGSITCamps.obtenirValorVariable(oPanell, sNomPanellRel);
	if (oPanellRel != null)
	{
		if (typeof(oPanellRel ) == "string") oPanellRel = xfa.resolveNode(oPanellRel);
	}

	return oPanellRel;
}

////////////////////////////////////////////////////////////
// Nom: assignarPanellRelacionatContacte
// Descripció: Mètode que relaciona el panell de contacte de les dades de contacte, amb el panell de les dades origen (Presentador / Requeridor / Altres interessats)
// Paràmetres d'entrada: 
//		oPanellContacte - Panell de contacte
//		oPanellRel - Panell relacionat
////////////////////////////////////////////////////////////
function assignarPanellRelacionatContacte(oPanellContacte, oPanellRel)
{
	if (typeof(oPanellRel) != "string") oPanellRel = oPanellRel.somExpression;
	scoGSITCamps.assignarValorVariable(oPanellContacte, "oPanellRel", oPanellRel, "string");
}

////////////////////////////////////////////////////////////
// Nom: assignarPanellRelacionatNormalitzador
// Descripció: Mètode que relaciona el panell d'adreça amb el panell de normalització
// Paràmetres d'entrada: 
//		oPanellAdreca - Panell d'adreça
//		oPanellNormalitzadorRel - Panell normalitzador relacionat
////////////////////////////////////////////////////////////
function assignarPanellRelacionatNormalitzador(oPanellAdreca, oPanellNormalitzadorRel)
{
	if (typeof(oPanellNormalitzadorRel) != "string") oPanellNormalitzadorRel = oPanellNormalitzadorRel.somExpression;
	scoGSITCamps.assignarValorVariable(oPanellAdreca, "oPanellNormalitzador", oPanellNormalitzadorRel, "string");
}

////////////////////////////////////////////////////////////
// Nom: assignarPanellRelacionatAdreca
// Descripció: Mètode que relaciona el panell d'adreça amb el panell de normalització
// Paràmetres d'entrada: 
//		oPanellNormalitzador - Panell de normalització
//		oPanellAdrecaRel - Panell adreça relacionat
////////////////////////////////////////////////////////////
function assignarPanellRelacionatAdreca(oPanellNormalitzador, oPanellAdrecaRel)
{
	if (typeof(oPanellAdrecaRel) != "string") oPanellAdrecaRel = oPanellAdrecaRel.somExpression;
	scoGSITCamps.assignarValorVariable(oPanellNormalitzador, "oPanellAdreca", oPanellAdrecaRel, "string");

}

////////////////////////////////////////////////////////////
// Nom: defRebreAvisos
// Descripció: Mètode que defineix el camp RebreAvisos amb la llista d'avisos que vol rebre
// Paràmetres d'entrada: 
//		oPanellAvisos - Panell d'avisos
////////////////////////////////////////////////////////////
function defRebreAvisos(oPanellAvisos) 
{
	try{
		if (scoGSITVal.isFormulariValidat()) return;
		if (scoGSITVal.isFormulariAcusament()) return;	

		if (!comprovarCampPanell(oPanellAvisos, "TXT_REBRE_AVISOS")) return;
		if (!comprovarCampPanell(oPanellAvisos, "CHK_MAIL")) return;
		if (!comprovarCampPanell(oPanellAvisos, "CHK_MOBIL")) return;


		oPanellAvisos.TXT_REBRE_AVISOS.rawValue = scoGSITVal.trim(scoGSITVal.getValor(oPanellAvisos.CHK_MAIL) + " " + scoGSITVal.getValor(oPanellAvisos.CHK_MOBIL));

		scoGSITVal.controlAvisMult(oPanellAvisos, "TXT_ADRECA_ELECTRONICA", "CHK_MAIL");
		scoGSITVal.controlAvisMult(oPanellAvisos, "TXT_TELEFON_MOBIL", "CHK_MOBIL");	
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITPanells::defRebreAvisos", exc);
	}		
}

////////////////////////////////////////////////////////////
// Nom: defRebreAvisosInicial
// Descripció: Mètode que defineix els checks d'avisos a partir del camp RebreAvisos
// Paràmetres d'entrada: 
//		oPanellAvisos - Panell d'avisos
////////////////////////////////////////////////////////////
function defRebreAvisosInicial(oPanellAvisos)
{
	if (!comprovarCampPanell(oPanellAvisos, "TXT_REBRE_AVISOS")) return;
	if (!comprovarCampPanell(oPanellAvisos, "CHK_MAIL")) return;
	if (!comprovarCampPanell(oPanellAvisos, "CHK_MOBIL")) return;

	var sLlistaAvisos = scoGSITVal.getValor(oPanellAvisos.TXT_REBRE_AVISOS);
	var aAvisos = sLlistaAvisos.split(" ");

	var nAvisos = aAvisos.length;
	for (n=0; n<nAvisos; n++)
	{
		if (aAvisos[n] == "adrecaElectronica") oPanellAvisos.CHK_MAIL.rawValue = "adrecaElectronica";
		if (aAvisos[n] == "sms") oPanellAvisos.CHK_MOBIL.rawValue = "sms";
	}
}        


/////////////////////////////////////////////////////////////////////////////
// Nom : teAlgunCampPlePanell
// Descripció: Mètode que controla si el panell té algun camp definit amb valor
// Paràmetres d'entrada: 
//		oPanell - Panell a revisar
// Paràmetres de sortida:
//		booleà - Valor (true/false) resultant de la verificació
/////////////////////////////////////////////////////////////////////////////
function teAlgunCampPlePanell(oPanell)
{
	try
	{
		if (!scoGSITVal.existeixObjecte(oPanell)) return false;

		var oNodesPanell = oPanell.nodes; 
		var nElements = oNodesPanell.length;
		for (var n=0; n< nElements; n++)
		{
			var oCamp = oNodesPanell.item(n);
			if (scoGSITNod.esObjeteTipusCamp(oCamp) && scoGSITCamps.esVisible(oCamp))	
			{ 
				if (!scoGSITVal.isEmpty(oCamp)) return true;
			}
			else if (oCamp.className == "subform") 
			{
				if (teAlgunCampPlePanell(oCamp)) return true;
			}
		}

		return false;
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoGSITPanells.teAlgunCampPlePanell",exc); 
	}			
} 

 ////////////////////////////////////////////////////////////
// Nom: initPanellAdjunts
// Descripció:  Mètode que inicialitza el panell d'adjunts
// Paràmetres d'entrada: 
//		oPAdjunts - Panell d'adjunts
////////////////////////////////////////////////////////////
function initPanellAdjunts(oPAdjunts)
{
	var sNom = oPAdjunts.name + "::initialize";
	try
	{
		if (scoGSITVal.esFormulariGuardat()) return;
		if (scoGSITVal.isFormulariValidat()) return;

		var oMissatge = obtenirObjecteFill(oPAdjunts, "cMissatge");
		if (scoGSITVal.existeixObjecte(oMissatge)) oMissatge.rawValue = scoGSITVal.getMsgMidaMaxAdjuntsPDF();		
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio(sNom, exc);
	}	
}

