////////////////////////////////////////////////////////////               
// Nom: obtenirNomProvincia
// Descripció: Mètode que recupera el nom de la província del codi especificat
// Paràmetres d'entrada:
//		codiProvincia - Valor del codi de la província a obtenir
// Paràmetres de sortida:
//		string - Nom del país
////////////////////////////////////////////////////////////               
function obtenirNomProvincia(codiProvincia)
{
	// Catalanes
	for(var i=0; i<arrProvinciesCat.length; i++)
	{
		if (arrProvinciesCat[i][1] == codiProvincia) return arrProvinciesCat[i][0];
	}

	// Espanyoles
	for(var i=0; i<arrProvinciesEsp.length; i++)
	{
		if (arrProvinciesEsp[i][1] == codiProvincia) return arrProvinciesEsp[i][0];
	}

	return "";
}

////////////////////////////////////////////////////////////
// Nom: obtenirCodiINEProvincia
// Descripció: Mètode que recupera el codi INE d'una província a partir del seu nom
// Paràmetres d'entrada:
//		nomProvincia - Nom de la província
// Paràmetres de sortida:
//		string - Codi de la província
////////////////////////////////////////////////////////////               
function obtenirCodiINEProvincia(nomProvincia)
{
	nomProvincia = (scoGSITVal.isEmpty(nomProvincia)) ? "" : nomProvincia.toUpperCase();
	for(var i=0; i<arrProvinciesEsp.length; i++)
	{
		if (arrProvinciesEsp[i][0].toUpperCase() == nomProvincia) return arrProvinciesEsp[i][1];
	}

	return "";
}               

////////////////////////////////////////////////////////////
// Nom: obtenirIdArrayProvinciaEsp
// Descripció: Mètode que recupera el nom de la província espanyola del codi de província especificat
// Paràmetres d'entrada:
//		codiProvincia - Valor del codi de la província a obtenir
// Paràmetres de sortida:
//		string - Nom del país
////////////////////////////////////////////////////////////               
function obtenirIdArrayProvinciaEsp(codiProvincia)
{
	// Espanyoles	
	for(var i=0; i<arrProvinciesEsp.length; i++)
	{
		if (arrProvinciesEsp[i][1] == codiProvincia) return arrProvinciesEsp[i][2];
	}

	return "";
}   

////////////////////////////////////////////////////////////
// Nom: obtenirIdArrayProvinciaCat
// Descripció: Mètode que recupera el nom de l'array de la província catalana de codi 'codiProvincia'
// Paràmetres d'entrada:
//		codiProvincia - Valor del codi de la província catalana a obtenir
// Paràmetres de sortida:
//		string - Nom del país
////////////////////////////////////////////////////////////               
function obtenirIdArrayProvinciaCat(codiProvincia)
{
	// Espanyoles
	for(var i=0; i<arrProvinciesCat.length; i++)
	{
		if (arrProvinciesCat[i][1] == codiProvincia) return arrProvinciesCat[i][2];
	}

	return "";
}

/***************************************************************
 Nom: scoGSITVal
 Descripció: Creat a partir de l'sco del FW 2.4.8 - Conté els mètodes de validació del formulari
**************************************************************************/		

///////////////////////////////////////////
// VARIABLES
///////////////////////////////////////////

// var: missatgeValidacio	   
// Descripció: Variable global de emmagatzema missatges de validació
var missatgeValidacio = "";   
var CT_MIDA_MAX = "20";		// Si es canvia --> canviar també els literals d'adjunts i imatges

///////////////////////////////////////////
// MÈTODES
///////////////////////////////////////////

/////////////////////////////////////////////////////////////////////////////
// Nom: inicialitzarFormulari
// Descripció: Mètode que es crida al inicialitzar-se el formulari
/////////////////////////////////////////////////////////////////////////////
function inicialitzarFormulari()
{
	try
	{	
		if (!isFormulariAcusament())
		{
			if (!scoGSITPar.bPDFDesenvolupament && scoGSITPar.tipusForm == "GSIT")
			{		
				if (!checkVisorReader()) return;  
//				if (!checkVisorReaderNoBrowser()) return;
				if (!checkReaderVersion()) return;
			}

			if (isFormulariValidat())
			{
			  if (xfa.host.name == "Acrobat") app.runtimeHighlight = false;
			  return;
			}
			else
			{
				scoGSITCamps.canviColorFonsCampsOblig();
				if (xfa.host.name == "Acrobat")  app.runtimeHighlight = scoGSITPar.bResaltarCampsFormulari; // Resalta els camps obligatoris 
			}

			if (esFormulariCarregat())
			{
				if (scoGSITPar.bUsEnforceStrict) actualitzarFormulari();
				return;
			}

			if (scoGSITPar.bUsEnforceStrict)
			{
				if (xfa.host.name == "Acrobat") app.runtimeHighlight = false;
				scoGSITNod.carregarArrayCampsObligatoris();
			}	
		}

		compModuls(scoGSITPar.nomFormulari + "::initialize", ["scoGSITPar", "scoGSITCamps", "scoGSITPanells", "scoGSITVal", "scoGSITBot", "scoGSITGen", "scoGSITNod", "scoGSITMissatges", "scoGSITEsborrar", "scoGSITExData"]);

		if (!isFormulariAcusament() && !esFormulariGuardat()) 
		{
			// PROVA		comprovaEsborraDadesPrecarregades();

			var sVersioAdobe = getReaderVersion();
			scoGSITPar.oDadesCFGTramit.DADES_TRAMIT.VersioReader.rawValue = sVersioAdobe;

			defValorNodeXML(xfa.record.DadesForm, "versioAdobe", "dataValue", "xfa.record.DadesForm", String(sVersioAdobe));
		}

		// Estableix el formulari amb estat Carregat/Obert
 		assignarFormulariCarregat("true");
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("inicialitzarFormulari", exc);
	}			
} 


////////////////////////////////////////////////////////////
// Nom: errorModuls
// Descripció: Mètode que mostra el missatge d'errors dels mòduls no referenciats
// Paràmetres d'entrada:
//		nomFunc - Mètode (Funció) que comprova mòduls
//		msgError - Missatge base d'error
//		sError - Noms dels mòduls amb errors	
////////////////////////////////////////////////////////////
function errorModuls(nomFunc, msgError, sError)
{
	xfa.host.messageBox(nomFunc + " \n" + msgError + " " + sError);
}

////////////////////////////////////////////////////////////
// Nom: compModuls
// Descripció: Mètode que comprova que els mòduls indicats en l'array, estiguin contemplats al formulari.
// Paràmetres d'entrada:
//		nomFunc - Nom del mètode (funció) que crida la validació
//		aModuls - Array ambs els mòduls a validar	
////////////////////////////////////////////////////////////
function compModuls(nomFunc, aModuls)
{
	if (scoGSITVal.isFormulariAcusament()) return;

	var sError = "";
	var nIncorrectes = 0;	
	var numModuls = aModuls.length;                   
	for (var n=0; n<numModuls; n++)
	{
		var oModul = xfa.resolveNode("xfa.form.nodes.item(0).#variables[0]." + aModuls[n]);
		if ((oModul == null) || (oModul == undefined))
		{
			nIncorrectes += 1;
			sError += (sError != "") ? (", " + aModuls[n]): aModuls[n];
		}
	}

    if (nIncorrectes > 1)     errorModuls(nomFunc, msgScoErrors.value, sError);
    else if (nIncorrectes == 1)  errorModuls(nomFunc, msgScoError.value, sError);

	return (nIncorrectes == 0);
}  

////////////////////////////////////////////////////////////
// Nom: compPanell
// Descripció: Mètode que comprova que el 'oPanell' indicat estigui definit al formulari i retorna true/false per indicar-lo.
// Paràmetres d'entrada:
//		oPanell - Panell que es vol comprovar
//		sPanell - Nom del panell
////////////////////////////////////////////////////////////
function compPanell(oPanell, sPanell)
{
	try
	{
		if (!existeixObjecte(oPanell)) return;
		if ((oPanell.className == "subform")) return true;

		app.alert("ATENCIÓ FACTORIA. El panell " + sPanell + " no està ben definit");
		return false;
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITVal::compPanell", exc);
	}	
}

/////////////////////////////////////////////////////////////////////////////
// Nom: defFormulariValidat
// Descripció: Mètode que defineix el formulari com a validat
///////////////////////////////////////////////////////////////////////////// 
function defFormulariValidat()
{
	var oPanellValidacio = scoGSITPanells.obtenirPanellValidacio();
	if (oPanellValidacio == null) return;
	oPanellValidacio.TXT_ES_BLOQUEJAT.rawValue = "true";

	scoGSITPanells.assignaMarcaAiguaFulls(msgValidatPendentTancar.value);
}


/////////////////////////////////////////////////////////////////////////////
// Nom: isFormulariValidat
// Descripció: Mètode que comprova si el formulari esta validat
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el formulari està validat
///////////////////////////////////////////////////////////////////////////// 
function isFormulariValidat()
{
	if (scoGSITPar.oDadesCFGTramit == null) return false;
	var oBloquejat = scoGSITPar.oDadesCFGTramit.DADES_TRAMIT.EsBloquejat;
	if (!isEmpty(oBloquejat))
	{
	  if (isFormulariAcusament()) return false;

	  return (oBloquejat.rawValue == "true");	
	}
	else
		return false;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: isFormulariAcusament
// Descripció: Mètode que comprova si el formulari és de tipus acusament de rebuda
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el formulari és d'acusament de rebuda
///////////////////////////////////////////////////////////////////////////// 
function isFormulariAcusament()
{
	if (scoGSITPar.oDadesCFGTramit == null) return false;
	var oACK = scoGSITPar.oDadesCFGTramit.DADES_TRAMIT.EsOutput;
	if (!isEmpty(oACK))
	{
	  return (oACK.rawValue == "true");	
	}
	return false;
}

/////////////////////////////////////////////////////////////////////////////
// Nom : getModalitatTramit
// Descripció : retorna la modalitat del tramit
// Paràmetres de sortida:
//		string - Valor de la modalitat del tràmit
/////////////////////////////////////////////////////////////////////////////
function getModalitatTramit()
{	
	var oCapcelera = scoGSITPar.oDadesCFGTramit.CAPCALERA;
	if (!compPanell(oCapcelera, "Dades de configuració del tràmit")) return;
	return oCapcelera.Objecte_Modalitat_idModalitat.rawValue;	
}   

/////////////////////////////////////////////////////////////////////////////
// Nom : getIdiomaTramit
// Descripció : retorna l'idioma del tramit
// Paràmetres de sortida:
//		string - Valor de l'idioma del tramit ('ca_ES' per català, 'es_ES' per castellà, 'en_GB' per anglès i 'an_ES' per occitan aranés)
/////////////////////////////////////////////////////////////////////////////
function getIdiomaTramit() 
{	
	var sIdioma = xfa.record.Capcalera.Idioma.value; 
	return (isEmpty(sIdioma) ? "ca_ES" : sIdioma);
}  


/////////////////////////////////////////////////////////////////////////////
// Nom: existeixObjecte
// Descripció: Mètode que comprova si l'objecte existeix
// Paràmetres d'entrada:
//		obj - Objecte a validar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si l'objecte existeix
///////////////////////////////////////////////////////////////////////////// 
function existeixObjecte(obj)
{
	try
	{
		return (obj != null && obj != undefined);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITVal::existeixObjecte", exc);
	}
	return false;     
}

/////////////////////////////////////////////////////////////////////////////
// Nom: existeixObjecteFill
// Descripció: Mètode que comprova si el fill de l'Objecte existeix.
// Paràmetres d'entrada:
//		obj - Objecte pare a validar
//		sRutaFill - Ruta del fill a comprovar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si existeix el fill en l'objecte
///////////////////////////////////////////////////////////////////////////// 
function existeixObjecteFill(obj, sRutaFill)
{
	try
	{
		return (obj.resolveNode(sRutaFill) != null);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITVal::existeixObjecteFill", exc);
	}
	return false;     
}

/////////////////////////////////////////////////////////////////////////////
// Nom: existeixPropietat
// Descripció: Mètode que comprova si la propietat de l'objecte existeix.
// Paràmetres d'entrada:
//		obj - Objecte a validar
//		sPropietat - Propietat a comprovar que pot ser una ruta de varis nivells
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si existeix la propietat en l'objecte
///////////////////////////////////////////////////////////////////////////// 
function existeixPropietat(obj, sPropietat)
{
	try
	{
		return (obj.resolveNode(sPropietat) != null);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITVal::existeixPropietat", exc);
	}
	return false;     
}

////////////////////////////////////////////////////////////
// Nom: existeixPropietat1Nivell
// Descripció: Mètode que comprova que existeixi la propietat sPropietat en oNod
// Paràmetres d'entrada:
//		oNod - Objecte del qual volem comprovar si existeix la propietat
//		sPropietat - Nom de la propietat
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si existeix la propietat en l'objecte
////////////////////////////////////////////////////////////
function existeixPropietat1Nivell(oNod, sPropietat)
{
	var oNodes = oNod.nodes;
	var nodesLength = oNodes.length; 
	for (var i = 0; i<nodesLength; i++) 
	{
		if(oNodes.item(i).className == sPropietat || oNodes.item(i).name == sPropietat)
		{
			 return true;
		}
	}
	return false;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: obtenirPropietat
// Descripció: Mètode que comprova si la propietat de l'Objecte existeix
// Paràmetres d'entrada:
//		obj - Objecte a validar
//		sPropietat - Propietat a comprovar
// Paràmetres de sortida:
//		objecte - Propietat de l'objecte en cas que existeixi, o "null" en cas que no existeixi
///////////////////////////////////////////////////////////////////////////// 
function obtenirPropietat(obj, sPropietat)
{
	try
	{
		return obj.resolveNode(sPropietat);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITVal::obtenirPropietat", exc);
	}
	return null;     
}

////////////////////////////////////////////////////////////
// Nom: getValor
// Descripció: Mètode que retorna el valor del camp en cas que existeixi i estigui definit, i si no existeix se'n retorna el valor "".
// Paràmetres d'entrada:
//		oCamp - Objecte del que es vol el valor
// Paràmetres de sortida:
//		String - Valor del camp o "", en cas que aquest no existeixi o sigui null
////////////////////////////////////////////////////////////    
function getValor(oCamp)
{
	if (!existeixObjecte(oCamp)) return ""; 
	return (oCamp.rawValue != null && oCamp.rawValue != undefined) ? oCamp.rawValue : "";
}

////////////////////////////////////////////////////////////
// Nom: getValorNum
// Descripció: Mètode que retorna el valor numeric del camp en cas que existeixi i estigui definit, i si no existeix se'n retorna el valor 0.
// Paràmetres d'entrada:
//		oCamp - Objecte del que es vol el valor
// Paràmetres de sortida:
//		Integer - Valor numeric del camp o 0, en cas que aquest no existeixi o sigui null
////////////////////////////////////////////////////////////    
function getValorNum(oCamp)
{
	if (!existeixObjecte(oCamp)) return 0; 
	var sValor = getValor(oCamp);
	return ((sValor == "") ? 0 : parseInt(sValor, 10));
}

////////////////////////////////////////////////////////////
// Nom: getValorFloat
// Descripció: Mètode que retorna el valor numeric decimal del camp en cas que existeixi i estigui definit, i si no existeix se'n retorna el valor 0.
// Paràmetres d'entrada:
//		oCamp - Objecte del que es vol el valor
// Paràmetres de sortida:
//		Integer - Valor numeric del camp o 0, en cas que aquest no existeixi o sigui null
////////////////////////////////////////////////////////////    
function getValorFloat(oCamp)
{
	if (!existeixObjecte(oCamp)) return 0; 
	var sValor = getValor(oCamp);
	return ((sValor == "") ? 0 : parseFloat(sValor, 10));
}

////////////////////////////////////////////////////////////
// Nom: defValor
// Descripció: Mètode que asigna el valor 'sValor' al camp 'sCamp' de 'oPanell'
// Paràmetres d'entrada:
//		oPanell - Panell en el que es buscarà el camp
//		sCamp - nom de l'bjecte al que es vol definir el valor
//		sValor - Valor que es vol definir
////////////////////////////////////////////////////////////    
function defValor(oPanell, sCamp, sValor)
{
	var oCamp = scoGSITPanells.obtenirObjecteFill(oPanell, sCamp);
	if (existeixObjecte(oCamp)) oCamp.rawValue = (!isEmpty(sValor)) ? sValor : "";
}

////////////////////////////////////////////////////////////
// Nom: defValorSiDefinit
// Descripció: Mètode que asigna el valor 'sValor' al camp 'sCamp' de 'oPanell' si no és buit
// Paràmetres d'entrada:
//		oPanell - Panell en el que es buscarà el camp
//		sCamp - nom de l'objecte al que es vol definir el valor
//		sValor - Valor que es vol definir
////////////////////////////////////////////////////////////    
function defValorSiDefinit(oPanell, sCamp, sValor)
{
	var oCamp = scoGSITPanells.obtenirObjecteFill(oPanell, sCamp);
	if (existeixObjecte(oCamp) && !isEmpty(sValor)) oCamp.rawValue = sValor;
}

////////////////////////////////////////////////////////////
// Nom: defValorSiBuit
// Descripció: Mètode que asigna el valor 'sValor' al camp 'sCamp' de 'oPanell' si és buit
// Paràmetres d'entrada:
//		oPanell - Panell en el que es buscarà el camp
//		sCamp - nom de l'bjecte al que es vol definir el valor
//		sValor - Valor que es vol definir
////////////////////////////////////////////////////////////    
function defValorSiBuit(oPanell, sCamp, sValor)
{
	var oCamp = scoGSITPanells.obtenirObjecteFill(oPanell, sCamp);
	if (existeixObjecte(oCamp) && isEmpty(sValor)) oCamp.rawValue = sValor;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: getValorVariable
// Descripció: Mètode que obté el valor de la variable del formulari 'sNom', si no existeix ""
// Paràmetres d'entrada:
//		sNom - No de la variable 
// Paràmetres de sortida:
//		string - Text amb el valor de la variable o "" si no existeix
///////////////////////////////////////////////////////////////////////////// 
function getValorVariable(sNom)
{
	var oVariable = xfa.resolveNode("xfa.form.nodes.item(0).#variables[0]." + sNom);
	return (scoGSITVal.existeixObjecte(oVariable) ? eval(sNom + ".value") : "");
}

/////////////////////////////////////////////////////////////////////////////
// Nom: isCheckButton
// Descripció: Mètode que comprova si 'oCamp' es un camp de tipus isCheckButton.
// Paràmetres d'entrada:
//		oCamp - Objete a verificar
/////////////////////////////////////////////////////////////////////////////
function isCheckButton(oCamp)
{
	if(oCamp == null) return false;
	if(!existeixPropietat(oCamp, "ui.checkButton")) return false;
	return (oCamp.ui.checkButton.className == "checkButton");
}

////////////////////////////////////////////////////////////
// Nom: defValorsPerDefecteCheck
// Descripció: Mètode que asigna els valors per defecte (per marcat i desmarcat) a un camp de Check
// Paràmetres d'entrada:
//		oCheck - oCheck a definir
//		sValorOn - Valor per quan està marcat
//		sValorOff - Valor per quan està desmarcat
////////////////////////////////////////////////////////////    
function defValorsPerDefecteCheck(oCheck, sValorOn, sValorOff)
{
	if (!isCheckButton(oCheck)) return;

	var oNode = oCheck.resolveNode("#items[0]");
	if (oNode != null)
	{	
		if (oNode.nodes.item(0) != null) oNode.nodes.item(0).value = String(sValorOn);
		if (oNode.nodes.item(1) != null) oNode.nodes.item(1).value = String(sValorOff);
	}
}

////////////////////////////////////////////////////////////
// Nom: getValorPerDefecteCheck
// Descripció: Mètode que retorna el valor per defecte (per marcat o desmarcat) definit a un camp de Check
// Paràmetres d'entrada:
//		oCheck - oCheck a definir
//		bValorOn - Indica si es vol el Valor per quan està marcat (true) o el de desmarcat (false)
//		sValorOff - Valor per quan està desmarcat
////////////////////////////////////////////////////////////    
function getValorPerDefecteCheck(oCheck, bValorOn)
{
	if (!isCheckButton(oCheck)) return;

	var oNode = oCheck.resolveNode("#items[0]");
	if (oNode != null)
	{	
		var nValor = (bValorOn) ? 0 : 1; 
		return oNode.nodes.item(nValor).value;
	}
}

/////////////////////////////////////////////////////////////////////////////
// Nom: isEmpty
// Descripció: Mètode que comprova si la cadena o el valor de l'objecte està buit
// Paràmetres d'entrada:
//		valor - Cadena o objecte a validar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada és buit
///////////////////////////////////////////////////////////////////////////// 
function isEmpty(valor)
{
	try
	{
		if (valor == null || valor == undefined)     return true;
		if (valor == "null" || valor == "undefined") return true;

		if (typeof(valor) == "object")
		{
			if (valor.className == "field")
			{
				if (existeixPropietat(valor, "ui.oneOfChild"))
					if ( (valor.ui.oneOfChild.className == "checkButton") && (String(valor.rawValue) == getValorPerDefecteCheck(valor, false))) return true;

				valor = valor.rawValue;
			}
			else if(valor.className == "exclGroup")
			{
				valor = valor.rawValue;
			}
			else return false; // Obj q no es un field i no es null o undefined
		}

		valor = trim(String(valor)).toLowerCase();
		return ((valor == "") || (valor == "null") || (valor == "undefined"));
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITVal::isEmpty", exc);
	}	
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esCombo
// Descripció: Mètode que comprova si el camp és un objecte de tipus llista (combo).
// Paràmetres d'entrada:
//		oCamp - Camp a comprovar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada és un camp de tipus llista
///////////////////////////////////////////////////////////////////////////// 
function esCombo(oCamp)
{
	if (!existeixPropietat(oCamp, "ui.oneOfChild")) return false;

	return (oCamp.ui.oneOfChild.className == "choiceList");
}

/////////////////////////////////////////////////////////////////////////////
// Nom: contruirBindingNom
// Descripció: Mètode que concatena els valors dels paràmetres d'entrada
// Paràmetres d'entrada:
//		nom - Nom
//		cognom1 - Primer cognom
//		cognom2 - Segon cognom
// Paràmetres de sortida:
//		string - Valor concatenat resultant dels paràmetres d'entrada
/////////////////////////////////////////////////////////////////////////////
function contruirBindingNom(nom,cognom1,cognom2){
	var nomString = "";	
	if (isEmpty(cognom2)){
		nomString = nom+" "+cognom1;
	} else {
		nomString = nom+" "+cognom1+" "+cognom2;
	}
	return nomString;
}

////////////////////////////////////////////////////////////
// Nom: esBindingCorrecte
// Descripció: Mètode que comprova si el binding de l'objecte 'oCamp' conté com a final els elements de 'aBindingFi'
// Paràmetres d'entrada: 
//		oCamp - Camp del formulari a comprobar
//		aBindingFi - Ruta final que ha de tenir el binding de l'objecte 'oCamp', per exemple si ha d'acabar amb "Pais.CodiINE" seria ["Pais", "CodiINE"]
// Paràmetres de sortida: 	
//		booleà - Valor (true/false) que indica si el binding de l'objecte 'oCamp' conté com a final els elements de 'aBindingFi'
//////////////////////////////////////////////////////////// 
function esBindingCorrecte(oCamp, aBindingFi)
{
	if (arguments.length < 2) return false;

	if (!existeixObjecte(oCamp)) return false;

	var bind = scoGSITPanells.obtenirBindObjecte(oCamp);
	var aBind = bind.split(".");
	var nBindings = aBind.length;

	var nBindingsFi = aBindingFi.length;
	if (nBindingsFi >= nBindings) return false;

	for (var n=0; n<nBindingsFi; n++)
	{
		if (aBind[nBindings-1-n] != aBindingFi[nBindingsFi-1-n]) return false;
	}

	return true;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: isNifCorrecte
// Descripció: Mètode que comprova si un NIF conté l' estructura corresponent
// Paràmetres d'entrada:
//		sValor - Paràmatre que conté el NIF a comprovar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada té un valor/format de NIF acceptat
/////////////////////////////////////////////////////////////////////////////
function isNifCorrecte(sValor)
{
	var CadMay = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
	var CadMin = "abcdefghijklmnopqrstuvwxyz";
	var CadFormat = "TRWAGMYFPDXBNJZSQVHLCKET";

	//Faig això perque treure els blancs al davant i darrere
	var sValorFormat = 	sValor.replace(/^\s*|\s*$/g,"");

	if (sValorFormat.length==0)
		return true;

	//Validem que no tingui més de 9 dígits. 
	if (sValorFormat.length != 9) {
		return false;
	}

	if (!isNumeric(sValorFormat.substring(0,8))) { //Valido que els 8 primers siguin un valor numèric
		return false;
	}
	var sLletra;
	sLletra = sValorFormat.substring(8,9);
	if (CadMay.indexOf(sLletra)==-1&&CadMin.indexOf(sLletra)==-1) { //Valido que l' últim caràcter sigui una lletra
		return false;
	}

	//Valido que la lletra sigui la corresponent
	var pos = sValorFormat.substring(0,8) % 23;
	var letra = CadFormat.substring(pos,pos+1);
	if(sValorFormat.substring(8,9).toUpperCase()!=letra) {
		return false;
	}

	return true;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: isNieCorrecte
// Descripció: Mètode que comprova si un NIE conté l' estructura corresponent
// Paràmetres d'entrada:
//		sValor - Paràmatre que conté el NIE a comprovar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada té un valor/format de NIE acceptat
/////////////////////////////////////////////////////////////////////////////
function isNieCorrecte(sValor)
{
	//Faig això perque treure els blancs al davant i darrere
	var sValorFormat = 	sValor.replace(/^\s*|\s*$/g,"");
	var	sNIE = sValorFormat.toUpperCase(); // pasar a majuscules

	if (sNIE.length==0)
		return true;

    if (sNIE.length != 9)
		return false;

	var sLetra = sNIE.substring(0,1);
	if (sLetra!='X' && sLetra!='Y' && sLetra!='Z') //Primer dígit ha de ser una X o una Y o una Z
		return false;

	if (sLetra == 'X')
		sNIE = "0" + sNIE.substring(1);
	else if (sLetra == 'Y')
		sNIE = "1" + sNIE.substring(1);
	else if (sLetra == 'Z')
		sNIE = "2" + sNIE.substring(1);

	return isNifCorrecte(sNIE);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: validarMail
// Descripció: Mètode que valida que el camp tingui un format de correu electrònic acceptat
// Paràmetres d'entrada:
//		mail - Cadena a validar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada té un valor/format de mail acceptat
///////////////////////////////////////////////////////////////////////////// 
function validarMail(mail){
	var resultatFinal = false;

	var r = new RegExp();
	r.compile("^\\b(^[_A-Za-z0-9-]+(\\.[_A-Za-z0-9-]+)*@([A-Za-z0-9-])+(((\\.[A-Za-z0-9-]+)*\\.[A-Za-z0-9]{2,}))$)\\b","i");	

    if(!r.test(mail)){
	   	resultatFinal = false;
    } else {
    	resultatFinal = true;
    }
	return resultatFinal;
}


////////////////////////////////////////////////////////////
// Nom: validarURL
// Descripció: Mètode que valida que la URL tingui un format acceptat
// Paràmetres d'entrada:
//		sURL - URL a validar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el paràmtre d'entrada té un valor/format de URL acceptat
////////////////////////////////////////////////////////////
function validarURL(sURL)
{
	var re = new RegExp();
	re.compile("((https?|ftp|gopher|telnet|file|notes|ms-help):((//)|(\\\\))+[\w\d:#@%/;$()~_?\+-=\\\.&]*)", "i");
	return (re.test(sURL));
}

/////////////////////////////////////////////////////////////////////////////
// Nom: isCifCorrecte
// Descripció: Mètode que comprova si un CIF conté l' estructura corresponent
// Paràmetres d'entrada:
//		sValor - Paràmatre que conté el CIF a comprovar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada té un valor/format de CIF acceptat
/////////////////////////////////////////////////////////////////////////////
function isCifCorrecte(sValor)
{
	// Treiem els blancs al davant i darrere i pasem a majuscules
	var sValorFormat = trim(sValor);
	var	sValorFormat = sValorFormat.toUpperCase();

	if (sValorFormat.length==0)  return true;

	// Format
	if (!/^(([A|B|C|D|E|F|G|H|J|N|P|Q|R|S|U|V|W][0-9]{7}([A-J]|[0-9])))$/.test(sValorFormat)) return false;	

	//validació del dígit de control
	var num = sValorFormat.substring(1,8);
	var pars = 0;
	var impars = 0;

	for(i=1; i<6; i+=2)
	{
		pars += parseInt(num.charAt(i));
	}

	for(i=0; i<7; i+=2)
	{
		var aux = parseInt(num.charAt(i))*2;
		impars += (aux%10 + parseInt(aux/10));
	}

	var dc = ((10 - (pars + impars)%10)%10);
	var dcUsuari = sValorFormat.charAt(8);
	var lletresDC = {1 : 'A', 2 : 'B', 3 : 'C', 4 : 'D', 5 : 'E', 6 : 'F', 7 : 'G', 8 : 'H', 9 : 'I', 0 : 'J'};

	if (isNumeric(dcUsuari)) 
		return (dcUsuari == String(dc));
	else 
		return (dcUsuari == lletresDC[dc]);

	return true;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: validarHora
// Descripció: Mètode que comprova que el camp tingui el format HH:MM
// Paràmetres d'entrada:
//		hora - Cadena a validar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada té un valor/format d'hora acceptat
///////////////////////////////////////////////////////////////////////////// 
function validarHora(hora)
{
	var exp = new RegExp("^([0-1][0-9]|[2][0-3])$");
	if(exp.test(hora))  hora += ":00";

	var rExp = new RegExp("^([0-1][0-9]|[2][0-3]):([0-5][0-9])$"); 
	return (rExp.test(hora));
}

/////////////////////////////////////////////////////////////////////////////
// Nom: validarCadenaCaracter
// Descripció: Mètode que comprova si la cadena conté caràcters
// Paràmetres d'entrada:
//		camp - Cdena a validar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada té un valor/format acceptat
///////////////////////////////////////////////////////////////////////////// 
function validarCadenaCaracter(camp)
{
    var r = new RegExp("^[\\.a-zA-Z àáèéíòóúÀÁÈÉÍÒÓÚäëïöüÄËÏÖÜñÑªºçÇ·'_\\-&âêîôûÂÊÎÔÛ]+$"); 
    return r.test(camp);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: validarTelefon
// Descripció: Mètode que valida que el camp sigui de 9 caràcters i tots numèrics. 
// Paràmetres d'entrada:
//		telf - Telèfon a validar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada té un valor/format acceptat
/////////////////////////////////////////////////////////////////////////////
function validarTelefon(telf)
{	
    var r = new RegExp("^[0-9]{9}$"); 
	var r2 = new RegExp("^[0]{9}$");
	return (r.test(telf) && !r2.test(telf));
}

/////////////////////////////////////////////////////////////////////////////
// Nom: validarTelefonEstranger
// Descripció: Mètode que valida que el valor sigui un telèfon que pot ser nacional o estranger 
// Paràmetres d'entrada:
//		telf - Telèfon a validar
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada té un valor/format acceptat
/////////////////////////////////////////////////////////////////////////////
function validarTelefonEstranger(telf)
{	
    var r = new RegExp("^([\+]|[0-9])?[0-9]{0,14}$"); 
	var r2 = new RegExp("^([\+]|[0])?[0]{14}$");
	return (r.test(telf) && !r2.test(telf));
}


/////////////////////////////////////////////////////////////////////////////
// Nom: normalitzaString
// Descripció: Mètode que elimina els espais i accents d'un string
// Paràmetres d'entrada:
//		str - Cadena a normalitzar
// Paràmetres de sortida:
//		string - Valor del paràmetre d'entrada normalitzat
/////////////////////////////////////////////////////////////////////////////
function normalitzaString(str){
	str = str.replace(/[\s]/gi,"");
	str = str.replace(/[À]/gi,"A");
	str = str.replace(/[Á]/gi,"A");
	str = str.replace(/[É]/gi,"E");
	str = str.replace(/[È]/gi,"E");
	str = str.replace(/[Í]/gi,"I");
	str = str.replace(/[Ò]/gi,"O");
	str = str.replace(/[Ó]/gi,"O");
	str = str.replace(/[Ú]/gi,"U");
	return str;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: validarFormulariSencer
// Descripció: Mètode que valida el contingut de tot el formulari
/////////////////////////////////////////////////////////////////////////////
function validarFormulariSencer()
{
	//Agafem el form
	var oForm = xfa.form.nodes.item(0);

	//Realitzem la validació general (camps obligatoris buits, executar validació dels camps)
	validacioGeneral(oForm);

	//Realitzem la validació especifica definida en scoGSITPar.mapaFuncionsValidacio
	var validacioEspecificaResultat = validacioEspecificaFormulari();

	accionsDeValidacio(validacioEspecificaResultat);

	//retornar resultat
	return(recollirResultatValidacio(validacioEspecificaResultat,true));	

}

/////////////////////////////////////////////////////////////////////////////
// Nom: validacioEspecificaFormulari
// Descripció: Mètode que realitza les validacions definides al mapa de funcions del scoGSITPar
/////////////////////////////////////////////////////////////////////////////
function validacioEspecificaFormulari()
{
	var validacioEspecificaTotal = inicialitzarVariableValidacioEspecificaCorrecte();
	var sSaltLinia = "";
	for (sPagina in scoGSITPar.mapaFuncionsValidacio)
	{
		var validacioPlanaActual = validacioEspecifica(sPagina);
		if(!validacioPlanaActual.validacioCorrecte)
		{
			validacioEspecificaTotal.validacioCorrecte = false;
			validacioEspecificaTotal.missatgeError = validacioEspecificaTotal.missatgeError + sSaltLinia + validacioPlanaActual.missatgeError;
			if(validacioPlanaActual.campsIncorrectes != null)
			{
				if(validacioEspecificaTotal.campsIncorrectes == null) 
					validacioEspecificaTotal.campsIncorrectes = validacioPlanaActual.campsIncorrectes;
				else
				{
					for(var t=0; t<validacioPlanaActual.campsIncorrectes.length; t++)
						validacioEspecificaTotal.campsIncorrectes.push(validacioPlanaActual.campsIncorrectes[t]);

				}
			}
			sSaltLinia = "\n";
		}	
	}

	return(validacioEspecificaTotal);
}


/////////////////////////////////////////////////////////////////////////////
// Nom: validarPlana
// Descripció: Mètode que realitza la validació d'una plana. 
// Paràmetres d'entrada:
//		sPlana - Nom de la plana que s'ha de validar
/////////////////////////////////////////////////////////////////////////////
function validarPlana(sPlana)
{
	missatgeValidacio = "";
	if (arguments.length == 0) return validarFormulariSencer();

	var oPlana = xfa.form.nodes.item(0).resolveNode(sPlana);

	//Realitzem la validació general (camps obligatoris buits, executar validació dels camps)
	validacioGeneral(oPlana);

	//Realitzem la validació especifica definida en scoGSITPar.mapaFuncionsValidacio
	var validacioEspecificaResultat = validacioEspecifica(sPlana);	

	accionsDeValidacio(validacioEspecificaResultat);

	//retornar resultat
	return(recollirResultatValidacio(validacioEspecificaResultat,false));

} 

/////////////////////////////////////////////////////////////////////////////
// Nom: accionsDeValidacio
// Descripció: Mètode que realitza les respectives accions posteriors a la validació
// Paràmetres d'entrada:
//		validacioEspecificaResultat - Conté el resultat de la validació
/////////////////////////////////////////////////////////////////////////////
function accionsDeValidacio(validacioEspecificaResultat)
{
	//Activar el highlight dels camps
	activacioHighlightCamps();

	//Posicionar el focus
	posicionarFocusValidacio(validacioEspecificaResultat);

	//Requadrar els camps invalids de la validacio Especifica
	requadrarCampsIncorrectesValidacioEspecifica(validacioEspecificaResultat);

}

/////////////////////////////////////////////////////////////////////////////
// Nom: requadrarCampsIncorrectesValidacioEspecifica
// Descripció: Mètode que requadre els camps incorrectes de la validació específica
// Paràmetres d'entrada:
//		validacioEspecificaResultat - Conté el resultat de la validació
/////////////////////////////////////////////////////////////////////////////
function requadrarCampsIncorrectesValidacioEspecifica(validacioEspecificaResultat)
{
	if(validacioEspecificaResultat.campsIncorrectes == null) return;

	for(var x=0; x<validacioEspecificaResultat.campsIncorrectes.length; x++)
		scoGSITCamps.remarcarCampNoValid(validacioEspecificaResultat.campsIncorrectes[x]);

}

/////////////////////////////////////////////////////////////////////////////
// Nom: posicionarFocusValidacio
// Descripció: Mètode que posiciona el focus al primer camp incorrecte.
// Paràmetres d'entrada:
//		validacioEspecificaResultat - Conté el resultat de la validació
/////////////////////////////////////////////////////////////////////////////
function posicionarFocusValidacio(validacioEspecificaResultat)
{
	if(!validacioGeneralOk())
	{
		if (scoGSITNod.primerCampNoValid.name == "SELECCIO" || scoGSITNod.primerCampNoValid.name == "MULTISELECCIO") {
			var oPrimerCheck = scoGSITPanells.obtenirObjecteFill(scoGSITNod.primerCampNoValid, "TXT_CAMP");
			xfa.host.setFocus(scoGSITNodoPrimerCheck.somExpression);
		}
		else
			xfa.host.setFocus(scoGSITNod.primerCampNoValid);
		return;
	}

	if(validacioEspecificaResultat.campsIncorrectes != null)
	{
		if (existeixObjecte(validacioEspecificaResultat.campsIncorrectes[0]))
		{
			xfa.host.setFocus(validacioEspecificaResultat.campsIncorrectes[0].somExpression);
			return;	
		}
	}		
}

/////////////////////////////////////////////////////////////////////////////
// Nom: validacioGeneralOk
// Descripció: Mètode que verifica si la validació general del formulari és correcte
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si existeix un camp no vàlid
/////////////////////////////////////////////////////////////////////////////
function validacioGeneralOk()
{
	return(scoGSITNod.primerCampNoValid == "");
}

/////////////////////////////////////////////////////////////////////////////
// Nom: activacioHighlightCamps
// Descripció: Mètode que activa el resaltat dels camps, depenent de la validació i de la configuració del scoGSITPar
/////////////////////////////////////////////////////////////////////////////
function activacioHighlightCamps()
{
	if ((isFormulariAcusament() || xfa.host.name == "XFAPresentationAgent"))  return;

	if(!validacioGeneralOk() && scoGSITPar.bResaltarCampsFormulari != "false")
		app.runtimeHighlight = scoGSITPar.bResaltarCampsFormulari;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: recollirResultatValidacio
// Descripció: Mètode que recull el resultat de la validació.
// Paràmetres d'entrada:
//		validacioEspecificaResultat - Conté el resultat de la validació específica
//		bEsValidacioGlobal - Valor (true = Formulari /false = pàgina)
/////////////////////////////////////////////////////////////////////////////
function recollirResultatValidacio(validacioEspecificaResultat, bEsValidacioGlobal)
{
	var result = {
		returnStatus : 1,
		missatge : ""
	};

	if (arguments.length<3) bEsValidacioGlobal = false;

	if(validacioGeneralOk() && validacioEspecificaResultat.validacioCorrecte) return result;

	result.returnStatus = 0;
	var msgErrorValidacioEspecifica = validacioEspecificaResultat.missatgeError;
	msgErrorValidacioEspecifica = isEmpty(msgErrorValidacioEspecifica) ? "" : msgErrorValidacioEspecifica + "\n";

	result.missatge = msgErrorsEnFormulari.value + "\n\n" + msgErrorValidacioEspecifica + msgValidarGlobalNoOk.value;

	return(result);
} 

/////////////////////////////////////////////////////////////////////////////
// Nom: validacioGeneral
// Descripció: Mètode que realitza la validació general d'una plana
// Paràmetres d'entrada:
//		oPlana - Plana a validar
/////////////////////////////////////////////////////////////////////////////
function validacioGeneral(oPlana)
{
	scoGSITNod.recorreDocumentSomValidarPlana(oPlana);

}

/////////////////////////////////////////////////////////////////////////////
// Nom: validacioEspecifica
// Descripció: Mètode que realitza la validació de les funcions definides en scoGSITPar.mapaFuncionsValidacio
// Paràmetres d'entrada:
//		sPlana - Plana de la que hem de comprovar la seva funció especifica de validació
////////////////////////////////////////////////////////////////////////////
function validacioEspecifica(sPlana)
{
	var result = inicialitzarVariableValidacioEspecificaCorrecte();

	// No validem planes ocultes
	var oPlana = xfa.form.nodes.item(0).resolveNode(sPlana);

	if (oPlana.presence == "hidden") return result;

	//Es mira quina funció de validació te definida
	var funcio = scoGSITPar.mapaFuncionsValidacio[sPlana];	

	//No hi ha funcio de validació	
	if (isEmpty(funcio)) return result;

	//Es comprova si la validació es correcte o incorrecte
	var resultatFuncioValidacio = eval(funcio);    

	return(esValidacioEspecificaFuncioOK(resultatFuncioValidacio));

}

/////////////////////////////////////////////////////////////////////////////
// Nom: inicialitzarVariableValidacioEspecificaCorrecte
// Descripció: Mètode que inicialitza les variables específiques de validació
////////////////////////////////////////////////////////////////////////////
function inicialitzarVariableValidacioEspecificaCorrecte()
{
	var result = {
		validacioCorrecte : true,
		campsIncorrectes : null,
		missatgeError : ""
	};

	return result;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esValidacioEspecificaFuncioOK
// Descripció: Mètode que comprova la validació de les funcions definides en scoGSITPar.mapaFuncionsValidacio
// Paràmetres d'entrada:
//		sPlana - Plana de la que hem de comprovar la seva funció especifica de validació
////////////////////////////////////////////////////////////////////////////
function esValidacioEspecificaFuncioOK(resultatFuncioValidacio)
{
    var result = inicialitzarVariableValidacioEspecificaCorrecte();

    //Paràmetres validació correcte
    if (typeof(resultatFuncioValidacio) != "object")
    {
    	if (String(resultatFuncioValidacio) ==  "1") result.validacioCorrecte = true;
    	if (String(resultatFuncioValidacio) ==  "true") result.validacioCorrecte = true;
    }	
    else 
	{
		if (resultatFuncioValidacio.validacioCorrecte != "undefined")
        	if(String(resultatFuncioValidacio.validacioCorrecte) == "true" || String(resultatFuncioValidacio.validacioCorrecte) == "1")
            	result.validacioCorrecte = true;

	}        	

    //Paràmetres validació incorrecte
    if (typeof(resultatFuncioValidacio) != "object")
    {
    	if (String(resultatFuncioValidacio) ==  "-1") result.validacioCorrecte = false;
    	if (String(resultatFuncioValidacio) ==  "0") result.validacioCorrecte = false;
    	if (String(resultatFuncioValidacio) ==  "false") result.validacioCorrecte = false;
    }	
    else 
		if (resultatFuncioValidacio.validacioCorrecte != "undefined")        
        	if(String(resultatFuncioValidacio.validacioCorrecte) == "false" || String(resultatFuncioValidacio.validacioCorrecte) == "-1"
        	|| String(resultatFuncioValidacio.validacioCorrecte) == "0")
            	result.validacioCorrecte = false;


	//No esta ben definit el resultat de la funcio de validació
	if(result.validacioCorrecte != true && result.validacioCorrecte != false)
	{
		xfa.host.messageBox(msgErrorValidacioParam.value);
		return result;	
	}

	if(!result.validacioCorrecte)
	{	
	    if (typeof(resultatFuncioValidacio) != "object")
	    {
	    	result.campsIncorrectes = null;
	    	if(missatgeValidacio != "") 
				result.missatgeError = missatgeValidacio + "\n";
	    }	
    	else
    	{
    		 if (resultatFuncioValidacio.campsIncorrectes != "undefined") result.campsIncorrectes = resultatFuncioValidacio.campsIncorrectes;   		 

    		 if (resultatFuncioValidacio.missatgeError != "undefined")
    		 	if(resultatFuncioValidacio.missatgeError != "") 
					result.missatgeError = resultatFuncioValidacio.missatgeError + "\n";
    	}	 
	}

	return result;

}

/////////////////////////////////////////////////////////////////////////////
// Nom: mostraErrors
// Descripció: Mètode que mostra un missatge a l'usuari amb tots els errors 
// Paràmetres d'entrada:
//		errArray - Llista (array) amb el contingut de tots els missatges d'error
//		msgValidacioGlobal - Missatge resultat de la validació global
/////////////////////////////////////////////////////////////////////////////
function mostraErrors(errArray, msgValidacioGlobal)
{
	var msg = "";	
	var errors = errArray.length;
	if(errors == 0) return;

	for(var nError=0; nError<errors; nError++)
	{
		msg += errArray[nError] + "\n\n";
	}

	if (isEmpty(msgValidacioGlobal))  msg += msgErrorsEnFormulari.value + "\n\n" + msgValidarGlobalNoOk.value;

	xfa.host.messageBox(msg);	
}   

/////////////////////////////////////////////////////////////////////////////
// Nom: campsObligatorisInfoContacte
// Descripció: Mètode que defineix els camps obligatoris del panell de 'CONTACTE': 'Telèfon', 'Mòbil' o 'Mail'
// Paràmetres d'entrada:
//		oPanell - Panell 'CONTACTE' a definir
/////////////////////////////////////////////////////////////////////////////
function campsObligatorisInfoContacte(oPanell) 
{	
	if (isFormulariValidat()) return; 
	if (isFormulariAcusament()) return;
	if ((oPanell == null) || (oPanell == undefined)) return;

	var oFix = scoGSITPanells.comprovarCampFillPanell(oPanell, "TXT_TELEFON_FIX");
	var oMobil = scoGSITPanells.comprovarCampFillPanell(oPanell, "TXT_TELEFON_MOBIL");
	var oMail = scoGSITPanells.comprovarCampFillPanell(oPanell, "TXT_ADRECA_ELECTRONICA");

	if ((oFix == null) || (oMobil == null) || (oMail == null)) return;

	var sEstat = (isEmpty(oFix) && isEmpty(oMobil) && isEmpty(oMail)) ? "error" : "";

	scoGSITCamps.defCampObligatori(oFix, sEstat);
	scoGSITCamps.defCampObligatori(oMobil, sEstat);
	scoGSITCamps.defCampObligatori(oMail, sEstat);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: campsObligatorisInfoContacteFJ
// Descripció: Mètode que defineix els camps obligatoris del panell de 'CONTACTE': 'Telèfon', 'Mòbil' o 'Mail' d'un panell de física/jurídica
// Paràmetres d'entrada:
//		oPanellFJ - Panell 'física/jurídica' a definir
/////////////////////////////////////////////////////////////////////////////
function campsObligatorisInfoContacteFJ(oPanellFJ) 
{	
	if (isFormulariValidat()) return; 
	if (isFormulariAcusament()) return;

	var oPanellRelF = scoGSITPanells.obtenirObjecteFill(scoGSITPanells.obtenirObjecteFill(oPanellFJ, "PERSONA_FISICA"), "CONTACTE");
	var oPanellRelJ = scoGSITPanells.obtenirObjecteFill(scoGSITPanells.obtenirObjecteFill(oPanellFJ, "PERSONA_JURIDICA"), "CONTACTE");

	if (oPanellRelF == null)      return scoGSITPanells.errorSubformPanell(oPanellBase, "PERSONA_FISICA.CONTACTE");
	if (oPanellRelJ == null)      return scoGSITPanells.errorSubformPanell(oPanellBase, "PERSONA_JURIDICA.CONTACTE");	

	campsObligatorisInfoContacte(oPanellRelF); 
	campsObligatorisInfoContacte(oPanellRelJ);  
}


/////////////////////////////////////////////////////////////////////////////
// Nom: validarInfoContacte
// Descripció: Mètode que verifica que un dels següents camps del panell de 'CONTACTE' estigui definit: 'Telèfon', 'Mòbil' o 'Mail'
// Paràmetres d'entrada:
//		oPanell - Panell 'CONTACTE' a comprovar
//		sMsg - Missatge amb la persona a la que pertany el panell de 'CONTACTE'
// Paràmetres de sortida:
//		resultat - Conté el resultat de la validació específica
/////////////////////////////////////////////////////////////////////////////
function validarInfoContacte(oPanell, sMsg)
{	
	if (isFormulariValidat()) return; 
	if ((oPanell == null) || (oPanell == undefined)) return;	

	var oFix = scoGSITPanells.comprovarCampFillPanell(oPanell, "TXT_TELEFON_FIX");
	var oMobil = scoGSITPanells.comprovarCampFillPanell(oPanell, "TXT_TELEFON_MOBIL");
	var oMail = scoGSITPanells.comprovarCampFillPanell(oPanell, "TXT_ADRECA_ELECTRONICA");

	if ((oFix == null) || (oMobil == null) || (oMail == null)) return;

	var result = inicialitzarVariableValidacioEspecificaCorrecte();

	if (isEmpty(oFix) && isEmpty(oMobil) && isEmpty(oMail))
	{	
		result.validacioCorrecte = -1;
		result.missatgeError = msgErrorAvisos.value + " " + sMsg;
		xfa.host.setFocus(oMail.somExpression);
	}	
	return result;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: validarInfoContactePanellMultiple
// Descripció: Mètode que verifica que un dels següents camps del panell actiu de 'oPanell' estigui definit: 'Telèfon', 'Mòbil' o 'Mail' per un panell de Física/Jurídica
// Paràmetres d'entrada:
//		oPanell - Panell a comprovar
//		sMsg - Missatge amb la persona a la que pertany el panell de 'CONTACTE' (requeridor, contacte)
// Paràmetres de sortida:
//		resultat - Conté el resultat de la validació específica
/////////////////////////////////////////////////////////////////////////////
function validarInfoContactePanellMultiple(oPanell, sMsg) 
{	
	var oPanell = scoGSITPanells.obtenirObjecteFill(scoGSITPanells.obtenirPersonaPanellMultiple(oPanell), "CONTACTE");
	return validarInfoContacte(oPanell, sMsg);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: validarInfoContacteFJ
// Descripció: Mètode que verifica que un dels següents camps del panell actiu de 'oPanell' estigui definit: 'Telèfon', 'Mòbil' o 'Mail' per un panell de Física/Jurídica
// Paràmetres d'entrada:
//		oPanellFJ - Panell 'Física/Jurídica' a comprovar
//		sMsg - Missatge amb la persona a la que pertany el panell de 'CONTACTE' (requeridor, contacte)
// Paràmetres de sortida:
//		resultat - Conté el resultat de la validació específica
/////////////////////////////////////////////////////////////////////////////
function validarInfoContacteFJ(oPanellFJ, sMsg) 
{	
	var oPanell = scoGSITPanells.obtenirObjecteFill(scoGSITPanells.obtenirPanellFisicaJuridicaActiu(oPanellFJ), "CONTACTE");
	return validarInfoContacte(oPanell, sMsg);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: validarPlanaAvisosNotificacions
// Descripció: Mètode que realitza la validació de les notificacions i avisos. Controla que o bé el correu electrònic o bé el telèfon estigui informat
// Paràmetres d'entrada:
//		oPanellAvisos - Panell d'avisos, si no rep el parametre agafara el definit a  scoGSITPar.oPanellAvisos
// Paràmetres de sortida:
//		enter - Valor (1/-1) que indica si és correcta, o s'han trobat els dos camps buits
/////////////////////////////////////////////////////////////////////////////
function validarPlanaAvisosNotificacions(oPanellAvisos)
{	
	if (arguments.length < 1) oPanellAvisos = scoGSITPar.oPanellAvisos;

	var oContacte = scoGSITPar.oPanellAvisosContacte;
	var mobil = oContacte.TXT_TELEFON_MOBIL;
	var mail = oContacte.TXT_ADRECA_ELECTRONICA;
	var telf = oContacte.TXT_TELEFON_FIX;

	var returnStatus = 1;	
	missatgeValidacio = "";	

	var chk1 = String(oPanellAvisos.AVISOS_NOTIFICACIONS.Avisos.CHECK_AE_REBUT.rawValue);
	var chk2 = String(oPanellAvisos.AVISOS_NOTIFICACIONS.Avisos.CHECK_SMS_REBUT.rawValue);

	if(chk1 == "1" && chk2 == "1")
	{
		if(isEmpty(mail) && isEmpty(mobil))
		{
			returnStatus = defMissatgeError(returnStatus, msgErrorMailMobilAvisos.value);
			scoGSITCamps.marcaErrorCamp(mobil);
		}
	}
	else if(chk1 == "1")
	{
		if(isEmpty(mail))
		{
			returnStatus = defMissatgeError(returnStatus, msgErrorMailAvisos.value);
			scoGSITCamps.marcaErrorCamp(mail);			
		}
	}
	else if(chk2 == "1")
	{
		if(isEmpty(mobil))
		{
			returnStatus = defMissatgeError(returnStatus, msgErrorMobilAvisos.value);
			scoGSITCamps.marcaErrorCamp(mobil);			
		}
	}
	else if (isEmpty(telf) && isEmpty(mobil) && isEmpty(mail))
	{	
		returnStatus = defMissatgeError(returnStatus, msgErrorAvisos.value);
		xfa.host.setFocus(mail);
	}

	return returnStatus;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: validarPlanaAvisosNotificacionsFJ
// Descripció: Mètode que realitza la validació de les notificacions i avisos del panell de Física/Jurídica. Controla que o bé el correu electrònic o bé el telèfon estigui informat
// Paràmetres de sortida:
//		enter - Valor (1/-1) que indica si és correcta, o s'han trobat els dos camps buits/////////////////////////////////////////////////////////////////////////////
function validarPlanaAvisosNotificacionsFJ()
{
	var persFisica = scoGSITPar.oPanellRequeridor.BTN_PERSONA.rawValue;
	var oPanellAvisos = (persFisica == "1") ? scoGSITPar.oPanellAvisosF : scoGSITPar.oPanellAvisosJ;
	return validarPlanaAvisosNotificacions(oPanellAvisos);
}

////////////////////////////////////////////////////////////
// Nom: defMissatgeError
// Descripció:  Mètode que inicialitza el missatge d'error o l'afegeix a l'existent depenent de returnStatus
// Paràmetres d'entrada:
//		returnStatus - Valor del return status
//		sMsgError - Missatge d'error a afegir
// Paràmetres de sortida: 	
//		enter - Valor (-1) prefixat 
////////////////////////////////////////////////////////////
function defMissatgeError(returnStatus, sMsgError)
{
	if (returnStatus == -1)
		missatgeValidacio += "\n" + sMsgError;
	else 
		missatgeValidacio =  sMsgError;

	return -1;
}

////////////////////////////////////////////////////////////
// Nom: getValueTagXML
// Descripció: Mètode que retorna el valor del tag en cas que existeixi, i si no existeix se'n retorna el valor "".
// Paràmetres d'entrada:
//		oTag - Objecte de tipus camp
// Paràmetres de sortida:
//		String - Valor del camp o "", en cas que aquest no existeixi
////////////////////////////////////////////////////////////    
function getValueTagXML(oTag)
{
	if (!existeixObjecte(oTag)) return "";
	return ((isEmpty(oTag.value)) ? "" : oTag.value);
}

////////////////////////////////////////////////////////////
// Nom: getValorNodeXML
// Descripció: Mètode que retorna el valor del Node en cas que existeixi, i si no existeix se'n retorna el valor "".
// Paràmetres d'entrada:
//		sTag - Ruta del tag XML del que es vol el valor
//		oPare - Objecte pare, opcional
// Paràmetres de sortida:
//		String - Valor del camp o "", en cas que aquest no existeixi
////////////////////////////////////////////////////////////    
function getValorNodeXML(sTag, oPare)
{
	if (!existeixObjecte(oPare)) return "";

	var oTagXML = (arguments.length < 2) ? xfa.resolveNode(sTag) : oPare.resolveNode(sTag); 
	return getValueTagXML(oTagXML);
}

////////////////////////////////////////////////////////////
// Nom: getValueTagXMLMajuscules
// Descripció: Mètode que retorna el valor del tag en cas que existeixi en majúscules, i si no existeix se'n retorna el valor "".
// Paràmetres d'entrada:
//		oTag - Objecte de tipus camp
// Paràmetres de sortida:
//		String - Valor del camp en majuscules o "", en cas que aquest no existeixi
////////////////////////////////////////////////////////////    
function getValueTagXMLMajuscules(oTag)
{
	return (getValueTagXML(oTag).toUpperCase());
}

/////////////////////////////////////////////////////////////////////////////
// Nom: campsXMLIguals
// Descripció: Mètode que comprova si el camp 'sTag' del node de l'XML 'oNode1' és igual al del node 'oNode2'
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si els camps són iguals
/////////////////////////////////////////////////////////////////////////////
function campsXMLIguals(oNode1, oNode2, sTag)
{
	if (!existeixObjecte(oNode1) || !existeixObjecte(oNode2)) return false;

	var oCamp1 = oNode1.resolveNode(sTag); 
	var oCamp2 = oNode2.resolveNode(sTag); 

	var sVal1 = getValueTagXMLMajuscules(oCamp1);
	var sVal2 = getValueTagXMLMajuscules(oCamp2);

	return (sVal1 == sVal2);	
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esMateixDocument
// Descripció: Mètode que comprova si 'oDoc1' i 'oDoc2' són el mateix document, comprova identificador i Pais
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si els documents són iguals, comprovant identificador i Pais
/////////////////////////////////////////////////////////////////////////////
function esMateixDocument(oDoc1, oDoc2)
{
	// Tipus de document
	if (!campsXMLIguals(oDoc1, oDoc2, "tipusDocument")) return false;

	// Identificador
	if (!campsXMLIguals(oDoc1, oDoc2, "Identificador")) return false;

	// Pais
	if (!campsXMLIguals(oDoc1, oDoc2, "PaisDocument.CodiINE")) return false;
	if (!campsXMLIguals(oDoc1, oDoc2, "PaisDocument.Nom")) return false;

	return true;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: sonDocsPersonesIguals
// Descripció: Mètode que comprova si els documents de 'aDocs' de 'oPersona1' i 'oPersona2' són iguals
// Paràmetres d'entrada: 
//		oPersona1 - Objecte de la 1º persona de la que es vol comparar el document
//		oPersona2 - Objecte de la 2º persona de la que es vol comparar el document
//		aDocs - Rutes dels documents que es volen comparar
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si els documents són els mateixos
/////////////////////////////////////////////////////////////////////////////
function sonDocsPersonesIguals(oPersona1, oPersona2, aDocs)
{	
	var nDocs = aDocs.length;
	for (var n=0; n<nDocs; n++)
	{
		if (!esMateixDocument(oPersona1.resolveNode(aDocs[n]), oPersona2.resolveNode(aDocs[n]))) return false;	
	}

	return true;	
}


/////////////////////////////////////////////////////////////////////////////
// Nom: esPersonaXMLCorrecte
// Descripció: Mètode que comprova si 'sTipusPersona' és un dels tipus de persona correctes del XML
// Paràmetres d'entrada:
// 		sTipusUsuari - Persona que pot tenir, valors 'Particular', 'Empresa', 'Organisme'
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si 'sTipusPersona' està definit correctament
/////////////////////////////////////////////////////////////////////////////
function esPersonaXMLCorrecte(sTipusPersona)
{
	if (isEmpty(sTipusPersona)) return false;
	return ((sTipusPersona == "Particular") || (sTipusPersona == "Empresa") || (sTipusPersona == "Organisme"));
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esValorTipusUsuariCorrecte
// Descripció: Mètode que comprova si 'tipusUsuari' està definit correctament
// Paràmetres d'entrada:
// 		sTipusUsuari - Tipus de persona que pot tenir, valors 'particular', 'entitat_privada', 'organisme'
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si 'tipusUsuari' està definit correctament
/////////////////////////////////////////////////////////////////////////////
function esValorTipusUsuariCorrecte(sTipusUsuari)
{
	if (isEmpty(sTipusUsuari)) return false;
	return ((sTipusUsuari == "particular") || (sTipusUsuari == "entitat_privada") || (sTipusUsuari == "organisme"));
}


/////////////////////////////////////////////////////////////////////////////
// Nom: esPanellAmbRepresentant
// Descripció: Mètode que comprova si 'tipusUsuari' indica un panell amb Representant: 'entitat_privada', 'organisme' 
// Paràmetres d'entrada:
// 		sTipusUsuari - Tipus de persona que pot tenir, valors 'particular', 'entitat_privada', 'organisme'
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si 'tipusUsuari' és 'entitat_privada', 'organisme'
/////////////////////////////////////////////////////////////////////////////
function esPanellAmbRepresentant(sTipusUsuari)
{
	if (isEmpty(sTipusUsuari)) return false;
	return ((sTipusUsuari == "entitat_privada") || (sTipusUsuari == "organisme"));
}


/////////////////////////////////////////////////////////////////////////////
// Nom: esTipusUsuariCorrectePerTipusPersona
// Descripció: Mètode que comprova si les dades precarregades del Requeridor són correctes d'acord amb els tipus d'usuaris acceptats
// Paràmetres d'entrada:
//		oNode - Node del que es vol comprobar 'tipusUsuari' 
// 		sTipusPersona - Tipus de persona que pot tenir, valors 'PF', 'PJ', 'OR', 'PF-PJ', 'PF-OR', 'PJ-OR', 'PF-PJ-OR'
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si 'tipusUsuari' de 'oNode' es correcte per l'especificació de 'sTipusPersona'
/////////////////////////////////////////////////////////////////////////////
function esTipusUsuariCorrectePerTipusPersona(oNode, sTipusPersona)
{
	if (existeixObjecte(oNode))
	{
		var sTipus = (!isEmpty(sTipusPersona) ? sTipusPersona : "PF-PJ-OR"); // Si no ho indica és qualsevol dels tipus

		if (oNode.value == "particular")      return (new RegExp("PF").test(sTipus));
		if (oNode.value == "entitat_privada") return (new RegExp("PJ").test(sTipus));
		if (oNode.value == "organisme")       return (new RegExp("OR").test(sTipus));
	}

	return true;	
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esTipusUsuariCorrecte
// Descripció: Mètode que comprova si les dades precarregades del Requeridor són correctes d'acord amb els tipus d'usuaris acceptats
// Paràmetres d'entrada:
//		sNode - "Requeridor"
// 		sTipusPersona - Tipus de persona que pot tenir, valors 'PF', 'PJ', 'OR', 'PF-PJ', 'PF-OR', 'PJ-OR', 'PF-PJ-OR'
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si 'tipusUsuari' de 'sNode' es correcte per l'especificació de 'sTipusPersona'
/////////////////////////////////////////////////////////////////////////////
function esTipusUsuariCorrecte(sNode, sTipusPersona)
{
	var oNode = xfa.resolveNode("xfa.record.Cos." + sNode + ".tipusUsuari");
	return esTipusUsuariCorrectePerTipusPersona(oNode, sTipusPersona);	
}

/////////////////////////////////////////////////////////////////////////////
// Nom: getTipusUsuariCorrecte
// Descripció: Mètode que retorna el tipus d'usuari correcte per 'sTipusPersona'
// Paràmetres d'entrada:
// 		sTipusPersona - Tipus de persona que pot tenir, valors 'PF', 'PJ', 'OR', 'PF-PJ', 'PF-OR', 'PJ-OR', 'PF-PJ-OR'
// Paràmetres de sortida: 
//		string - Tipus d'usuari "particular", "entitat_privada" o "organisme"
/////////////////////////////////////////////////////////////////////////////
function getTipusUsuariCorrecte(sTipusPersona)
{
	if (new RegExp("PF").test(sTipusPersona))      return "particular";
	else if (new RegExp("PJ").test(sTipusPersona)) return "entitat_privada";
	else if (new RegExp("OR").test(sTipusPersona)) return "organisme";
	else                                           return "";
}



/////////////////////////////////////////////////////////////////////////////
// Nom: eliminaNodePrecarregaAdreca
// Descripció: Mètode que elimina el node d'adreca 'oNode'
// Paràmetres d'entrada:
//		oNode - Node de l'adreca a esborrar a l'XML
/////////////////////////////////////////////////////////////////////////////
function eliminaNodePrecarregaAdreca(oNode)
{
	if (existeixObjecte(oNode))  oNode.parent.nodes.remove(oNode);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esborraPrecarregaAdreca
// Descripció: Mètode que esborra el node d'adreca 'oNode'
// Paràmetres d'entrada:
//		oNode - Node de l'adreca a esborrar a l'XML
/////////////////////////////////////////////////////////////////////////////
function esborraPrecarregaAdreca(oNode)
{
	if (existeixObjecte(oNode))  scoGSITNod.netejarNode(oNode);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esTipusAdrecaCorrecta
// Descripció: Mètode que indica si l'adreça és correcta comparant les dades de 'oNode' amb el tipus definit a 'sTipusAdreca'
// Paràmetres d'entrada:
//		oNode - Node de l'adreca a esborrar a l'XML
// 		sTipusAdreca -  "": No té adreca, "CAT": Adreca catalana, "ESP": Adreca espanyola, "EXT": Adreca extrangera 
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si el tipus d'adreça és acceptada, prèviament definida en el mòdul scoGSITPar
/////////////////////////////////////////////////////////////////////////////
function esTipusAdrecaCorrecta(oNode, sTipusAdreca)
{
	if (!existeixObjecte(oNode))  return;
	if ((sTipusAdreca!="")  &&  (sTipusAdreca!="CAT")  && (sTipusAdreca!="ESP")  &&(sTipusAdreca!="EXT"))
	{
		app.alert("ATENCIÓ factoria, no està ben definit el tipus d'adreça per al node: \n" + oNode.somExpression + "\n\n té com valor '" + sTipusAdreca + "' i ha de tenir valor '', 'CAT', 'ESP' o 'EXT' corregiu el mòdul scoGSITPar.");
		return;
	}

	if (sTipusAdreca == "") return false;
	if ((sTipusAdreca == "ESP") && !scoGSITAdreca.esAdrecaEspanyolaXML(oNode)) return false;
	if ((sTipusAdreca == "CAT") && !scoGSITAdreca.esAdrecaCatalanaXML(oNode))  return false;

	return true;
}



/////////////////////////////////////////////////////////////////////////////
// Nom: esborraNodePersona
// Descripció: Mètode que esborra el node 'oNode' i l'assigna el tipus d'usuari 'sTipusUsuari'
// Paràmetres d'entrada:
//		osNode - Node de les dades de contacte
// 		sTipusUsuari - "particular" / "entitat_privada" / "organisme"
//		bBorrarNomConcatenat - Indica si s'ha d'esborrar el node 'NomConcatenat'
/////////////////////////////////////////////////////////////////////////////
function esborraNodePersona(oNode, sTipusUsuari, bBorrarNomConcatenat)
{
	if (existeixObjecte(oNode))
	{
		scoGSITNod.netejarNode(oNode.parent);
		oNode.value = sTipusUsuari;

		if (bBorrarNomConcatenat) scoGSITPar.oDadesCFGTramit.DADES_TRAMIT.Autenticacio_NomConcatenat.rawValue = ""; 
	}
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esborraPrecarregaPresentadorRequeridor
// Descripció: Mètode que comprova si s'han d'esborrar les dades precarregades del Requeridor, per ser d'un tipus d'usuari no acceptat
// Paràmetres d'entrada:
//		osNode - Requeridor
// 		sTipusUsuari - "particular" / "entitat_privada" / "organisme"
/////////////////////////////////////////////////////////////////////////////
function esborraPrecarregaPresentadorRequeridor(oNode, sTipusUsuari)
{
	if (!existeixObjecte(oNode)) return;

	esborraNodePersona(oNode, sTipusUsuari, true);
}




