/////////////////////////////////////////////////////////////////////////////
// Nom: esborraNodeTipusPersona
// Descripció: Mètode que esborra tots els nodes de persona de l'xml que no són el definit per 'sTipusPersona'
// Paràmetres d'entrada:
//		oNodeXML - Node de l'xml del que esborrarem els nodes de persona corresponents
//		sTipusPersona - "particular" / "entitat_privada" / "organisme"
/////////////////////////////////////////////////////////////////////////////
function esborraNodeTipusPersona(oNodeXML, sTipusPersona)
{
	try
	{
		if (oNodeXML) 
		{
			oNodeXML.tipusUsuari.value = sTipusPersona;	
			if (sTipusPersona != "particular")      oNodeXML.nodes.remove(oNodeXML.Particular);
			if (sTipusPersona != "entitat_privada") oNodeXML.nodes.remove(oNodeXML.Empresa);
			if (sTipusPersona != "organisme")       oNodeXML.nodes.remove(oNodeXML.Organisme);
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("esborraNodeTipusPersona", exc);
	}		
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esborraTipusPersonaPrecarregat
// Descripció: Mètode que esborra els nodes de persona de l'XML precarregats i defineix el definit per 'sTipusPersona'
// Paràmetres d'entrada:
//		sTipusPersona - "particular" / "entitat_privada" / "organisme"
//		sMsgError - Missatge d'error que es mostrarà
/////////////////////////////////////////////////////////////////////////////
function esborraTipusPersonaPrecarregat(sTipusPersona, sMsgError)
{
	try
	{
		var oDadesTramit = scoGSITPar.oDadesCFGTramit.DADES_TRAMIT;
		if (!compPanell(oDadesTramit, "Dades de configuració del tràmit: Dades Tràmit")) return;	

		scoGSITMissatges.MissatgeAlerta(sMsgError);

		esborraNodeTipusPersona(xfa.record.Cos.Requeridor, sTipusPersona);
		esborraNodeTipusPersona(getNodeDadesContacte(), sTipusPersona);
		oDadesTramit.Autenticacio_NomConcatenat.rawValue = "";

		var sXML = xfa.data.saveXML();
		xfa.data.loadXML(sXML,1,1);
		xfa.form.remerge();	

		scoGSITPar.oPanellRequeridor.parent.execEvent("initialize");	
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("esborraTipusPersonaPrecarregat", exc);
	}		
}

