/////////////////////////////////////////////////////////////////////////////
// Nom: validarAdrecaNormalitzada
// Descripció: Mètode que valida que 'oPanell' sigui una adreça normalitza, si no ho es afegeix l'error a 'errArray'
// Paràmetres d'entrada:
//		oPanell - Panell de l'adreça a comprovar
//		errArray - Array de missatges d'error
/////////////////////////////////////////////////////////////////////////////
function validarAdrecaNormalitzada(oPanell, errArray)
{
	if (arguments.length < 2) errArray = new Array();

	if (scoGSITAdreca.esNormalitzada(oPanell) == "FALSE")
		errArray[0] = msgErrorAdreçaNormalitzada.value; 

	return errArray;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: validarAdrecesNormalitzades
// Descripció: Mètode que valida que les adreces de 'aAdreces' estiguin normalitzades, si no ho estan afegeix l'error a 'errArray'
// Paràmetres d'entrada:
//		aAdreces - Array de panells d'adreces a comprovar
//		errArray - Array de missatges d'error
/////////////////////////////////////////////////////////////////////////////
function validarAdrecesNormalitzades(aAdreces, errArray)
{
	try
	{
		if (arguments.length < 2) errArray = new Array();

		var nAdreces = aAdreces.length;
		for (var n=0; n<nAdreces; n++)
		{
			if (scoGSITAdreca.esNormalitzada(aAdreces[n]) == "FALSE")
			{
				errArray[errArray.length] = msgErrorAdreçaNormalitzada.value; 
				return errArray;
			}
		}
		return errArray;
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("validarAdrecesNormalitzades", exc);
	}		
}

/////////////////////////////////////////////////////////////////////////////
// Nom: validarAdrecesNormalitzadesMsg
// Descripció: Mètode que valida que les adreces de 'aAdreces' estiguin normalitzades, si no ho estan afegeix l'error a 'errArray'
// Paràmetres d'entrada:
//		aAdreces - Array de duples de panells a revisar i error corresponent: [[panell_adreça, missatge_error],...[panell_adreça, missatge_error]]
//		errArray - Array de missatges d'error
/////////////////////////////////////////////////////////////////////////////
function validarAdrecesNormalitzadesMsg(aAdreces, errArray)
{
	try
	{
		if (arguments.length < 2) errArray = new Array();

		var nAdreces = aAdreces.length;
		for (var n=0; n<nAdreces; n++)
		{
			if (scoGSITAdreca.esNormalitzada(aAdreces[n][0]) == "FALSE")
			{
				errArray[errArray.length] = aAdreces[n][1]; 
				return errArray;
			}
		}
		return errArray;
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("validarAdrecesNormalitzadesMsg", exc);
	}		
}

/////////////////////////////////////////////////////////////////////////////
// Nom: validarClausulaLOPD
// Descripció: Mètode que comprova que el check de la clàusula LOPD estigui marcat per poder validar
/////////////////////////////////////////////////////////////////////////////
function validarClausulaLOPD()
{
	// Accepta condicions LOPD
	var oChkLOPD = scoGSITPanells.obtenirObjecteFill(scoGSITPar.oPanellValidacio, "CHK_LOPD");
	if (scoGSITVal.existeixObjecte(oChkLOPD)) 
	{
		if (scoGSITCamps.esObligatori(oChkLOPD) && String(oChkLOPD.rawValue) == "0") 
		{
			xfa.host.setFocus(oChkLOPD.somExpression);
			xfa.host.messageBox(msgErrorClausulaLOPD.value);
			return false;		
		}
	}

	return true;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: getMidaMaxPDF
// Descripció: Mètode que obté la mida màxima del PDF 
// Paràmetres de sortida:
//		enter - Valor que indica la mida màxima que pot tenir el PDF
/////////////////////////////////////////////////////////////////////////////
function getMidaMaxPDF()
{
	var oMida = xfa.resolveNode("xfa.record.DadesForm.MidaMaxima");
	var nMida = (oMida != null) ? oMida.value : (CT_MIDA_MAX * 1024); // Per defecte són 5MB

	return nMida;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: getMidaPDF
// Descripció: Mètode que obté la mida del PDF sense adjunts
// Paràmetres de sortida:
//		enter - Valor que indica la mida del PDF sense adjunts
/////////////////////////////////////////////////////////////////////////////
function getMidaPDF()
{
	var bPDFModif = event.target.dirty; // Hem de definir el PDF com no modificat pq sino excuta el preSave
	event.target.dirty = false;
	event.target.embedDocAsDataObject("thisDoc", event.target);
	event.target.dirty = bPDFModif; // Restaurem l'estat del PDF

	var oFile = event.target.getDataObject("thisDoc");
	var nMida = (oFile.size/1024);
	event.target.removeDataObject("thisDoc");	

	return nMida;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: getMidaPDFGuardat
// Descripció: Mètode que retorna la mida del PDF sense adjunts
// Paràmetres de sortida:
//		enter - Valor que indica la mida del PDF sense adjunts
/////////////////////////////////////////////////////////////////////////////
function getMidaPDFGuardat()
{
	return parseInt(scoGSITPar.oDadesCFGTramit.parent.VALIDACIO.TXT_MIDA_PDF.rawValue, 10);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: defMidaPDF
// Descripció: Mètode que guarda el valor de la mida del formulari sense adjunts 
/////////////////////////////////////////////////////////////////////////////
function defMidaPDF()
{	
	if (!isFormulariValidat())
	{
		if (!esFormulariGuardat()) 
			scoGSITPar.oDadesCFGTramit.parent.VALIDACIO.TXT_MIDA_PDF.rawValue = getMidaPDF();
	}
}	

/////////////////////////////////////////////////////////////////////////////
// Nom: validarMidaPDF
// Descripció: Mètode que valida la mida del PDF 
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si la mida del PDF és correcta
/////////////////////////////////////////////////////////////////////////////
function validarMidaPDF()
{	
	// Es verifiquen els adjunts existents
	scoGSITAdj.sincronitzarAdjunts(scoGSITPar.oPanellAdjunts);

	var nMida = (!esFormulariGuardat()) ? getMidaPDF() : getMidaPDFGuardat();
	nMida += scoGSITAdj.midaAdjunts();
	return (nMida < getMidaMaxPDF());
}


/////////////////////////////////////////////////////////////////////////////
// Nom: getMsgErrorMidaMaxPDF
// Descripció: Mètode que retorna el missatge de la mida màxima del PDF 'Mida MB.' o 'Mida KB.'
// Paràmetres de sortida:
//		string - Missatge de la mida màxima del PDF 
/////////////////////////////////////////////////////////////////////////////
function getMsgMidaMaxPDF()
{
	var nMidaMax = parseInt(getMidaMaxPDF(), 10);
	return ((nMidaMax < 1024) ? (nMidaMax + "KB.") : ((nMidaMax/1024) + "MB."));
}

/////////////////////////////////////////////////////////////////////////////
// Nom: getMsgErrorMidaMaxPDF
// Descripció: Mètode que retorna el missatge d'error si es supera la mida màxima del PDF 
// Paràmetres de sortida:
//		string - Missatge d'error si es supera la mida màxima del PDF 
/////////////////////////////////////////////////////////////////////////////
function getMsgErrorMidaMaxPDF()
{
	var sMsg = msgErrorPDFMidaMax.value + " " + msgAdjuntMidaMax.value + " " + getMsgMidaMaxPDF();
	return sMsg;
}	

/////////////////////////////////////////////////////////////////////////////
// Nom: getMsgErrorMidaMaxAdjuntsPDF
// Descripció: Mètode que retorna el missatge d'error si es supera la mida màxima del PDF a l'afegir un adjunt 
// Paràmetres de sortida:
//		string - Missatge d'error si es supera la mida màxima del PDF a l'afegir un adjunt 
/////////////////////////////////////////////////////////////////////////////
function getMsgErrorMidaMaxAdjuntsPDF()
{
	var sMsg = msgErrorAdjuntMidaMaxPDF.value + " " + msgAdjuntMidaMax.value + " " + getMsgMidaMaxPDF();
	return sMsg;
}	

