/////////////////////////////////////////////////////////////////////////////
// Nom: validarFormulari
// Descripció: Mètode que comprova el contingut del formulari i en cas de ser tot correcte, es passa a estat Validat
// Paràmetres d'entrada:
//		errArray - Array que conté els erros de les validacions especifiques
/////////////////////////////////////////////////////////////////////////////
function validarFormulari(errArray)
{
	try
	{		
		// Es verifica si els adjunts son correctes i la seva mida
		// 202012	Verifiquem sempre la mida! ADJUNTS + IMATGES !! 		if (scoGSITAdj.teAdjunts(scoGSITPar.oPanellAdjunts))
		//{
			if (!validarMidaPDF())  errArray[errArray.length] = getMsgErrorMidaMaxPDF();
		//}

		// Validacions globals
		var result = validarFormulariSencer();
		if (result.returnStatus == 0)  errArray[errArray.length] = result.missatge;

		if (errArray.length != 0)
		{
			mostraErrors(errArray, result.missatge);
			return;
		} 

		// Neteja els nodes que sobren en l'estructura de dades
		scoGSITNod.eliminarNodesXmlSobrants(); 

		// Neteja els nodes que sobren en l'estructura de qüestions
		scoINSPQuestions.eliminarNodesXmlSobrants();

		// Es verifica i assigna el valor correcte als nodes PaisDocument
		assignarPaisDocumentPersones();  

		// Es verifica els valors dels direfents nodes d'adreça i se'n completa el contingut si fa falta
		assignarValorsAdreces();

		// Cercar el botó depenent del mode en que ens trobem
		var modeVisualitzacio = scoINSPVisualitzacio.getModeVisualitzacio();		// TODO MILLORAR		-		creem funcions per retornar els botons en funció del mode??
		var oBtnDesbloquejar = scoGSITPar.oPanellValidacio.resolveNode("S_BTNS[" + modeVisualitzacio + "].BTN_DESBLOQUEJAR");
		var oBtnTancar = scoGSITPar.oPanellValidacio.resolveNode("S_BTNS[" + modeVisualitzacio + "].BTN_TANCAR");
		var oBtnDesar = scoGSITPar.oPanellDesar.resolveNode("BTN_DESAR[" + modeVisualitzacio + "]");

		// Array amb les somExpressions dels camps que no volem bloquejar al validar (BTN_DESBLOQUEJAR i BTN_DESAR) 
		var arrExceptionSOMs = new Array(
			oBtnDesbloquejar.somExpression,
			oBtnTancar.somExpression,
			oBtnDesar.somExpression
		);	

		scoGSITGen.carregaDades(); // Carrega les dades necessàries del tràmit a la part de Capçalera
		scoGSITPar.oDadesCFGTramit.parent.VALIDACIO.TXT_DADES.rawValue = getLockableObjects(arrExceptionSOMs);

		scoGSITCamps.protectAllFields(scoGSITPar.oDadesCFGTramit.parent.VALIDACIO.TXT_DADES.rawValue);
		scoGSITBot.canviEstatAcceptar(1, "0,0,0", oBtnDesbloquejar);
		scoGSITBot.canviEstatAcceptar(1, "0,0,0", oBtnTancar);

		defFormulariValidat();					

		// TODO No mostramos nada por ahora   scoGSITBot.definicioTextTramitValidat(false);

		if (xfa.host.name == "Acrobat") app.runtimeHighlight = false;							
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("validarFormulari", exc);
	}			
} 

/////////////////////////////////////////////////////////////////////////////
// Nom: desbloquejarFormulari
// Descripció: Mètode que deixa el formulari en estat Desbloquejat
/////////////////////////////////////////////////////////////////////////////
function desbloquejarFormulari()
{
	// TODO 		- Deslligar del framework! Crear funcions per retornar botons
	var oBtnDesbloquejar0 = scoGSITPar.oPanellValidacio.resolveNode("S_BTNS[0].BTN_DESBLOQUEJAR");
	var oBtnDesbloquejar1 = scoGSITPar.oPanellValidacio.resolveNode("S_BTNS[1].BTN_DESBLOQUEJAR");
	var oBtnTancar0 = scoGSITPar.oPanellValidacio.resolveNode("S_BTNS[0].BTN_TANCAR");
	var oBtnTancar1 = scoGSITPar.oPanellValidacio.resolveNode("S_BTNS[1].BTN_TANCAR");		

    scoGSITCamps.unProtectAllFields(scoGSITPar.oDadesCFGTramit.parent.VALIDACIO.TXT_DADES.rawValue);
    scoGSITBot.canviEstatAcceptar(0, null, oBtnDesbloquejar0);
    scoGSITBot.canviEstatAcceptar(0, null, oBtnTancar0);
    scoGSITBot.canviEstatAcceptar(0, null, oBtnDesbloquejar1);
    scoGSITBot.canviEstatAcceptar(0, null, oBtnTancar1);

    scoGSITPar.oPanellValidacio.TXT_ES_BLOQUEJAT.rawValue = "false";

	// TODO Per ara no posem res!!!!     scoGSITBot.definicioTextTramitValidat(false);

  	if (xfa.host.name == "Acrobat") app.runtimeHighlight = scoGSITPar.bResaltarCampsFormulari; // Per resaltar els camps obligatoris   

	if (scoGSITPar.bMostrarMarcaAigues) scoGSITPanells.assignaMarcaAiguaFulls(msgEsborrany.value);
}


