//////////////////////////////////////////////////////////// 
// Nom: mostraPaginaInfo() 
// Descripció: Mètode que mostra la pàgina de info i oculta la resta
// Paràmetres d'entrada: 
//		oPagina - Pàgina a mostrar
// Paràmetres de sortida: 
//		booleà - Valor false per indicar que s'està mostrant una pàgina d'error
//////////////////////////////////////////////////////////// 
function mostraPaginaInfo(oPagina)
{ 
	if ((oPagina == null) || (oPagina == undefined)) return false;

	 scoGSITCamps.defVisibilitat(oPagina, "visible");
	 ocultarTotesLesPagines();

	 scoGSITCamps.defVisibilitat(oPagina.parent, "visible");

	 if (oPagina.name.substring(oPagina.name.length-7,oPagina.name.length) == "_READER") 
	 	scoGSITCamps.defVisibilitat(scoGSITPar.oDadesCFGTramit.parent.btnGetReaderUpdate, "visible");

	 return false; 
}


//////////////////////////////////////////////////////////// 
// Nom: getReaderVersion() 
// Descripció: Mètode que recupera la versió del client que executa el formulari
// Paràmetres de sortida: 
//		string - Valor de la versió del client que està executant el formulari (Acrobat/Reader)
//////////////////////////////////////////////////////////// 
function getReaderVersion()
{ 
	if ((isFormulariAcusament() || xfa.host.name == "XFAPresentationAgent"))  return scoGSITPar.requiredReaderVersion;

	try
	{
		var sReaderVersion = ""; 
		var nPlugIns = app.plugIns.length;
		for (var n = 0; n<nPlugIns; n++) 
		{
			if (app.plugIns[n].name == "Forms") sReaderVersion = app.plugIns[n].version; 
		} 

		return String(sReaderVersion); 
	}
	catch(exc)
	{
		return scoGSITPar.requiredReaderVersion;
	}
}  

//////////////////////////////////////////////////////////// 
// Nom: checkReaderVersion() 
// Descripció: Mètode que comprova que la versió del client que executa el formulari, sigi l'acceptada.
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si la versión del client que està executant el formulari (Acrobat/Reader), és acceptada
//////////////////////////////////////////////////////////// 
function checkReaderVersion() 
{ 
	if ((isFormulariAcusament() || xfa.host.name == "XFAPresentationAgent"))  return true;

	// Hem de comprovar la versió i subversions
	var aVersionAct = String(getReaderVersion()).split(".");
	var aVersionNec = String(scoGSITPar.requiredReaderVersion).split(".");

	// Comprovem la versió i subversions
	var nVersiones = Math.min(aVersionAct.length, aVersionNec.length);
	for (var nV=0; nV<nVersiones; nV++)
	{
		if (parseInt(aVersionAct[nV], 10) > parseInt(aVersionNec[nV], 10)) return true;  // Si la versió q té és POSTERIOR és correcta
		if (parseInt(aVersionAct[nV], 10) < parseInt(aVersionNec[nV], 10)) 
			return mostraPaginaInfo(scoGSITPar.oDadesCFGTramit.parent.VERSIO_READER); // Si la versió q té és ANTERIOR és incorrecta
	}	

	// Si la Versió Necessària té + subversiones i NO són 0 no és correcta
	if (nVersiones < aVersionNec.length)
	{
		for (var nV=nVersiones; nV<aVersionNec.length; nV++)
		{
			if (parseInt(aVersionNec[nV], 10) != 0) return mostraPaginaInfo(scoGSITPar.oDadesCFGTramit.parent.VERSIO_READER);
		}			
	}

	return true;
}              

//////////////////////////////////////////////////////////// 
// Nom: checkVisorReader() 
// Descripció: Mètode que comprova que el visor que ha obert el PDF sigui l'Adobe
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si el visor que ha obert el PDF sigui l'Adobe
//////////////////////////////////////////////////////////// 
function checkVisorReader() 
{ 
	try
	{
		if ((isFormulariAcusament() || xfa.host.name == "XFAPresentationAgent"))  return true;

		var sVisor = xfa.host.appType; 
		var sVisorNombre = xfa.host.name;
		if (((sVisorNombre != "Acrobat")) || (sVisor != "Reader" && sVisor != "Exchange" && sVisor != "Exchange-Pro"))
		{     
			return mostraPaginaInfo(scoGSITPar.oDadesCFGTramit.parent.VISOR_READER);			 
		} 	
	}
	catch(exc)
	{
		return mostraPaginaInfo(scoGSITPar.oDadesCFGTramit.parent.VISOR_READER);
	}	

	return true;
}  

//////////////////////////////////////////////////////////// 
// Nom: checkVisorReaderNoBrowser() 
// Descripció: Mètode que comprova que el visor que ha obert el PDF no sigui de browser
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si el visor que ha obert el PDF no sigui de browser
//////////////////////////////////////////////////////////// 
function checkVisorReaderNoBrowser() 
{ 
	try
	{
		if ((isFormulariAcusament() || xfa.host.name == "XFAPresentationAgent"))  return true;

		var sPath = event.target.path.toString();
		var sRuta = sPath.substring(0, 5);
		if (sRuta == "file:")
		{
			 return mostraPaginaInfo(scoGSITPar.oDadesCFGTramit.parent.NOBROWSER_READER);
		} 	
	}
	catch(exc)
	{
		return mostraPaginaInfo(scoGSITPar.oDadesCFGTramit.parent.NOBROWSER_READER);
	}		

    return true; 
}

