/////////////////////////////////////////////////////////////////////////////
// Nom: getLockableObjects
// Descripció: Mètode que recupera tots el objectes que s'han de bloquejar en la validació del formulari
// Paràmetres d'entrada: 
//		arrExceptionSOMs - Array amb les somExpressions dels objectes que no hem de bloquejar
// Paràmetres de sortida: 
//		string - Valor que conté les somExpressions de tots els camps que s'han de bloquejar en la validació del formulari
/////////////////////////////////////////////////////////////////////////////
function getLockableObjects(arrExceptionSOMs) {

	var sLockableCSV = "";

	// Conversió de l'array de strings a un array d'objectes
	var arrExceptionObjs = new Array();

	for (var i = 0; i < arrExceptionSOMs.length; i++) {
		arrExceptionObjs[i] = xfa.resolveNode(arrExceptionSOMs[i]);
	}

	// Loop through each page
	for (var i = 0; i < xfa.layout.pageCount(); i++) {
		// Get all fields in the page
		var oFields = xfa.layout.pageContent(i, "field");
		var nodesLength = oFields.length;
		for (var j = 0; j < nodesLength; j++) {
			var oItem = oFields.item(j);	
			// Retain the SOM expression of opened non-signature fields.
			if (oItem.access == "open") {
				if (oItem.isPropertySpecified("ui")) {
					var sClass = oItem.ui.oneOfChild.className;
					if (sClass != "signature") {
						var bAdd = true;
						if (arrExceptionObjs.length != "0") {
							for (var k = 0; k < arrExceptionObjs.length; k++) {
								if (oItem.somExpression	== arrExceptionObjs[k].somExpression) {					
									bAdd = false;
										break;
								}
							}
						}
						if (bAdd == true) {
							sLockableCSV = sLockableCSV + ",\"" + oItem.somExpression.replace(/xfa\[0\]\.form\[0\]\.ACTAINSPECCIO\[0\]\./gi, "") + "\"";
						}
					}
				}
			}
		}
	}
	return sLockableCSV;       
}           


