			var bValidat = true;   
			if(!isEmpty(oCamp))
			{
				oCamp.rawValue = trim(oCamp.rawValue);
				bValidat = validarCadenaCaracter(oCamp.rawValue);
			}

	        scoGSITCamps.campLocalValidat(oCamp,bValidat);
		}	    

		return true;
    }catch(exc) {
        scoGSITGen.retornarExcepcio(oCamp.name + "::validarCampText",exc);
    }
}

