// Nom: validarCampIdentificadorPersona
// Descripció: Mètode que valida un camp d'Identificador de persona.
// Paràmetres d'entrada:
//		oCamp - Camp que conté el valor del identificador de la persona
//		tipusIdentificador - Valor identificador de tipus de persona
// Paràmetres de sortida: 	
//		booleà - Valor (true/false) que indica si el contingut del paràmetre d'entrada té un valor/format acceptat
////////////////////////////////////////////////////////////
function validarCampIdentificadorPersona(oCamp, tipusIdentificador)
{
    try
	{
		if (isFormulariValidat()) return true;

		var bValidat = true;
		if (!isEmpty(oCamp))
		{
			oCamp.rawValue = trim(oCamp.rawValue.toUpperCase());
			if (tipusIdentificador == "nif")      bValidat = isNifCorrecte(oCamp.rawValue);
			else if (tipusIdentificador == "nie") bValidat = isNieCorrecte(oCamp.rawValue);
		}

		scoGSITCamps.campLocalValidat(oCamp, bValidat);
		return true;
    }
	catch(exc)
	{
        scoGSITGen.retornarExcepcio("scoGSITVal::validarCampIdentificadorPersona::" + oCamp.somExpression, exc);
    }
}

