////////////////////////////////////////////////////////////
// Nom: validarCampData
// Descripció: Mètode que valida un camp de data
// Paràmetres d'entrada:
//		oCamp - Camp de data
//		pDataValor - Es guardarà en aquest camp la data 'pData' en format YYYY-MM-DD (s'ha de definir per dates anteriors a 1900)
// Paràmetres de sortida: 	
//		booleà - Valor (tre/false) que indica si el contingut del paràmetre d'entrada té un valor/format acceptat
////////////////////////////////////////////////////////////           
function validarCampData(oCamp, pDataValor)
{
    try{	
		if (!isFormulariValidat())
		{     
			if (arguments.length < 2) pDataValor = null;

			var bValidat = true;
	        if(!isEmpty(oCamp))
			{
				oCamp.rawValue = trim(oCamp.rawValue);
				bValidat = validarData(oCamp, pDataValor);
			}
			else
			{
				if (pDataValor != null) pDataValor.rawValue = "";			
			}

        	scoGSITCamps.campLocalValidat(oCamp,bValidat);
		}

		return true;

    }catch(exc){
        scoGSITGen.retornarExcepcio(oCamp.name + "::validarCampData",exc);
    }
}

