/////////////////////////////////////////////////////////////////////////////
function validaCampDataNaixement(oCamp)
{
    try
	{	
		if (!isFormulariValidat())
		{     
			var bValidat = true;
	        if(!isEmpty(oCamp))
			{
				oCamp.rawValue = trim(oCamp.rawValue);
				bValidat = validarData(oCamp);
				if (bValidat) bValidat = validaDataNaixement(oCamp);
			}

        	scoGSITCamps.campLocalValidat(oCamp,bValidat);
		}

		return true;

    }
	catch(exc)
	{
        scoGSITGen.retornarExcepcio(oCamp.name + "::validaCampDataNaixement",exc);
    }
}


