/////////////////////////////////////////////////////////////////////////////
// Nom : validaCampDataPosteriorAltreData 
// Descripció: Mètode que valida un camp de data, comprobant que sigui posterior a 'oCampAnterior'
// Paràmetres d'entrada:
//		oCampAnterior - Camp de data anterior
//		oCampPosterior - Camp de data posterior
// Paràmetres de sortida: 	
//		booleà - Valor (tre/false) que indica si el contingut del paràmetre d'entrada té un valor/format acceptat
/////////////////////////////////////////////////////////////////////////////
function validaCampDataPosteriorAltreData(oCampAnterior, oCampPosterior)
{
    try
	{	
		if (!isFormulariValidat())
		{     
			var bValidat = true;
	        if(!isEmpty(oCampPosterior))
			{
				oCampPosterior.rawValue = trim(oCampPosterior.rawValue);
				bValidat = validarData(oCampPosterior);
				if (bValidat) bValidat = validaDataPosteriorAltreData(oCampAnterior, oCampPosterior);
			}

        	scoGSITCamps.campLocalValidat(oCampPosterior, bValidat);
		}

		return true;

    }
	catch(exc)
