////////////////////////////////////////////////////////////
// Nom: mostraOcultaPanellMultiple
// Descripció: Mètode que fa visible el panell a activar del panell múltiple i oculta la resta de panells
// Paràmetres d'entrada:
//		oPanell - Panell de selecció múltiple (Física/Jurídica, Física/Jurídica/Organisme)
//		oPanellAct - Panell a activar: 'PERSONA_JURIDICA' o 'PERSONA_FISICA' o 'PERSONA_ORGANISME'
////////////////////////////////////////////////////////////
function mostraOcultaPanellMultiple(oPanell, oPanellAct)
{
	scoGSITCamps.defVisibilitat(oPanellAct, "visible");

	var oNodes = oPanell.nodes;
	var nNodes = oNodes.length;
	for (var n=0; n<nNodes; n++)
	{
		var oPanellFill = oNodes.item(n);
		if ((oPanellFill.name != oPanellAct.name) && (oPanellFill.name.substring(0,8) == "PERSONA_"))
		{
			scoGSITCamps.defVisibilitat(oPanellFill, "hidden");
		}
	}
}

////////////////////////////////////////////////////////////
// Nom: mostraOcultaPF_PJ
// Descripció: Mètode que posa visible el panell a activar i oculta el desactivar
// Paràmetres d'entrada:
//		oPanellAct - Panell del Fisica/Juridica a activar
//		oPanellDes - Panell del Fisica/Juridica a desactivar
//		sTipusPesonaAct - "PERSONA_FISICA" / "PERSONA_JURIDICA"
//		sTipusPesonaDes - "PERSONA_FISICA" / "PERSONA_JURIDICA"
////////////////////////////////////////////////////////////
function mostraOcultaPF_PJ(oPanellAct, oPanellDes, sTipusPesonaAct, sTipusPesonaDes)
{
	var oPanellActPare = scoGSITPanells.obtenirObjectePare(oPanellAct, sTipusPesonaAct);
	mostraOcultaPanellMultiple(oPanellActPare.parent, oPanellActPare);
}

////////////////////////////////////////////////////////////
// Nom: nomPanellPersonaPanellMultiple
// Descripció: Mètode que recupera el nom del panell actiu d'un panell múltiple: "PERSONA_JURIDICA" o "PERSONA_FISICA" o "PERSONA_ORGANISME"
// Paràmetres d'entrada:
//		oPanell - Panell de selecció múltiple (Física/Jurídica, Física/Jurídica/Organisme)
// Paràmetres de sortida:
//		string - "PERSONA_JURIDICA" o "PERSONA_FISICA" o "PERSONA_ORGANISME"
////////////////////////////////////////////////////////////
function nomPanellPersonaPanellMultiple(oPanell) 
{
	if (new RegExp("PERSONA_FISICA").test(oPanell.somExpression))    return "PERSONA_FISICA";
	if (new RegExp("PERSONA_JURIDICA").test(oPanell.somExpression))  return "PERSONA_JURIDICA";
	if (new RegExp("PERSONA_ORGANISME").test(oPanell.somExpression)) return "PERSONA_ORGANISME";	

	return "";
}

////////////////////////////////////////////////////////////
// Nom: tipusUsuariPanell
// Descripció: Mètode que recupera el tipus d'usuari del panell 'oPanell' si no troba el camp TIPUS_USUARI retorna un string buit
// Paràmetres d'entrada:
//		oPanell - Panell
// Paràmetres de sortida:
//		string - "particular" o "entitat_privada" o "entitat_publica_gencat" o "entitat_publica_altres" o "organisme" o string buit si no l'ha trobat
////////////////////////////////////////////////////////////
function tipusUsuariPanell(oPanell)
{
	var oTipusUsuari = scoGSITPanells.obtenirObjecteFill(oPanell, "TIPUS_USUARI");
	return getValor(oTipusUsuari);
}

////////////////////////////////////////////////////////////
// Nom: tipusUsuariPanellPare
// Descripció: Mètode que recupera el tipus d'usuari del panell 'oPanell' si no troba el camp TIPUS_USUARI retorna un string buit
// Paràmetres d'entrada:
//		oPanell - Panell
// Paràmetres de sortida:
//		string - "particular" o "entitat_privada" o "entitat_publica_gencat" o "entitat_publica_altres" o "organisme" o string buit si no l'ha trobat
////////////////////////////////////////////////////////////
function tipusUsuariPanellPare(oPanell)
{
	var oTipusUsuari = scoGSITPanells.obtenirObjectePare(oPanell, "TIPUS_USUARI");
	return getValor(oTipusUsuari);
}

////////////////////////////////////////////////////////////
// Nom: esTipusUsuariEntitat
// Descripció: Mètode que comprova si el tipus d'usuari del panell 'oPanell' és 'entitat'
// Paràmetres d'entrada:
//		oPanell - Panell
//		bParent - Indica si 'TIPUS_USUARI' s'ha de buscar com a Pare de 'oPanell' o no
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el tipus d'usuari del panell 'oPanell' és 'entitat'
////////////////////////////////////////////////////////////
function esTipusUsuariEntitat(oPanell, bParent)
{
	var sTipus = (bParent) ? tipusUsuariPanellPare(oPanell) : tipusUsuariPanell(oPanell);
	return (new RegExp("entitat").test(sTipus));
}

////////////////////////////////////////////////////////////
// Nom: campIdentificadorPanell
// Descripció: Mètode que recupera el camp d'identificador depenent del tipus de panell "PERSONA_FISICA" o "PERSONA_JURIDICA" o "PERSONA_ORGANISME"
// Paràmetres d'entrada:
//		oPanell - Panell: "PERSONA_FISICA", "PERSONA_JURIDICA", "PERSONA_ORGANISME"
// Paràmetres de sortida:
//		Objecte - Camp d'identificador del panell o null si no es troba
////////////////////////////////////////////////////////////
function campIdentificadorPanell(oPanell)
{
	if (!existeixObjecte(oPanell)) return null;

	var sIdentificador = (oPanell.name == "PERSONA_FISICA") ? "TXT_TIPUS_IDENTIFICADOR" : "TXT_TIPUS_IDENTIFICADOR_EMPRESA";
	return scoGSITPanells.obtenirObjecteFill(oPanell, sIdentificador);
}

////////////////////////////////////////////////////////////
// Nom: campIdentificadorRepPanell
// Descripció: Mètode que recupera el camp d'identificador del representant del panell 
// Paràmetres d'entrada:
//		oPanell - Panell 
// Paràmetres de sortida:
//		Objecte - Camp d'identificador del representant del panell o null si no es troba
////////////////////////////////////////////////////////////
function campIdentificadorRepPanell(oPanell)
{
	var oRep = scoGSITPanells.obtenirObjecteFill(oPanell, "REPRESENTANT");
	if (existeixObjecte(oRep)) controlPassaport(scoGSITPanells.obtenirObjecteFill(oRep, "TXT_TIPUS_IDENTIFICADOR"));  
}

////////////////////////////////////////////////////////////
// Nom: numeroPanell
// Descripció: Mètode que recupera el número del tipus de panell "PERSONA_FISICA" o "PERSONA_JURIDICA" o "PERSONA_ORGANISME"
// Paràmetres d'entrada:
//		oPanell - Panell: "PERSONA_FISICA", "PERSONA_JURIDICA", "PERSONA_ORGANISME"
// Paràmetres de sortida:
//		Integer - Número del panell o 0 si no es troba
////////////////////////////////////////////////////////////
function numeroPanell(oPanell)
{
	if (!existeixObjecte(oPanell)) return 0;

	var oPersona = scoGSITPanells.obtenirObjecteFill(oPanell, "BTN_PERSONA");
	if (existeixObjecte(oPersona) && (!isEmpty(oPersona))) 
		return (oPersona.rawValue - 1);
	else
		return 0;
}

////////////////////////////////////////////////////////////
// Nom: numeroTipoPersona
// Descripció: Mètode que recupera el número de la persona de 'sTipusUsuari'
// Paràmetres d'entrada:
//		sTipusUsuari - Tipus de persona: 'particular', 'entitat_privada', 'organisme'
// Paràmetres de sortida:
//		Integer - Número de la persona o -1 si no es troba
////////////////////////////////////////////////////////////
function numeroTipoPersona(sTipusUsuari)
{
	try
	{
		if (sTipusUsuari == "particular")      	    return 0;
		else if (sTipusUsuari == "entitat_privada") return 1;
		else if (sTipusUsuari == "organisme")		return 2;	

		return -1;
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITVal::numeroTipoPersona", exc);
	}		
}

////////////////////////////////////////////////////////////
// Nom: numeroPersona
// Descripció: Mètode que recupera el número de la persona de 'oNode'
// Paràmetres d'entrada:
//		oNode - Node de l'XML, tipusUsuari del Requeridor...
// Paràmetres de sortida:
//		Integer - Número de la persona o -1 si no es troba
////////////////////////////////////////////////////////////
function numeroPersona(oNode)
{
	try
	{
		if (!existeixObjecte(oNode)) return -1;

		return numeroTipoPersona(oNode.value);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITVal::numeroPersona", exc);
	}		
}

////////////////////////////////////////////////////////////
// Nom: personaXML
// Descripció: Mètode que recupera el nom del node XML relatiu al node 'oNode'
// Paràmetres d'entrada:
//		oNode - Node de l'XML, tipusUsuari del Requeridor...
// Paràmetres de sortida:
//		String - Nom del node XML de la persona "" si no el troba
////////////////////////////////////////////////////////////
function personaXML(oNode)
{
	try
	{
		if (!existeixObjecte(oNode)) return "";

		// Obtenim persona seleccionada
		var sTipusUsuari = oNode.value;	
		if (sTipusUsuari == "particular")      	    return "Particular";
		else if (sTipusUsuari == "entitat_privada") return "Empresa";
		else if (sTipusUsuari == "organisme")		return "Organisme";	

		return "";
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITVal::personaXML", exc);
	}		
}

////////////////////////////////////////////////////////////
// Nom: tipusUsuariPanellActiuPF_PJ
// Descripció: Mètode que recupera el tipus d'usuari del panell actiu de "PERSONA_JURIDICA" o "PERSONA_FISICA" per indicar el tipus que es 'oPanellFJ'
// Paràmetres d'entrada:
//		oPanellFJ - Panell del Fisica/Juridica
// Paràmetres de sortida:
//		string - "PERSONA_JURIDICA" o "PERSONA_FISICA"
////////////////////////////////////////////////////////////
function tipusUsuariPanellActiuPF_PJ(oPanellFJ)
{
	return nomPanellPersonaPanellMultiple(oPanellFJ);
}

////////////////////////////////////////////////////////////
// Nom: defPanellMultiple
// Descripció: Mètode que defineix el panell actual d'un panell de tipus Física/Jurídica/Organisme
// Paràmetres d'entrada:
//		oPanell - Panell de selecció múltiple (Física/Jurídica, Física/Jurídica/Organisme)
//		oPanellAct - panell del Física/Jurídica/Organisme a activar
//		sTipusUsuari - TipusOpcionsUsuari: "particular", "entitat_privada", "entitat_publica_gencat" o "entitat_publica_altres" o "organisme"
//		sRol - TipusRolAcreditacio "1":PersonaFísica, "2":Persona Jurídica, "3":Persona Vinculada, "4":Persona Professional
//		bBorrar - Valor (true/false) que indica si s'han d'esborrar les dades del panell que s'oculta
//		nPanell -  Número del tipus de panell "PERSONA_FISICA" o "PERSONA_JURIDICA" o "PERSONA_ORGANISME"
//		fDefAdreca - Array de definició de l'adreça del tipus: ["Funció definició adreça", "Nom panell adreca"]
////////////////////////////////////////////////////////////
function defPanellMultiple(oPanell, oPanellAct, sTipusUsuari, sRol, bBorrar, nPanell, fDefAdreca)
{
	// Obtenim el panell actiu fins al moment per desactivar-lo i esborrar-lo
	var oPanellDes = scoGSITPanells.obtenirPersonaPanellMultiple(oPanell);
	if (tipusUsuariPanell(oPanell) != sTipusUsuari) scoGSITGen.netejarForm(oPanellDes);	

	mostraOcultaPanellMultiple(oPanell, oPanellAct);        

	if (!isFormulariAcusament())
	{     
		scoGSITPanells.defDadesIdent(oPanellAct, sTipusUsuari, sRol, bBorrar); 
		if (scoGSITVal.existeixObjecte(fDefAdreca))
		{
			if (fDefAdreca.length >= nPanell) scoGSITPanells.defAdrecaPanell(oPanellAct, fDefAdreca[nPanell], false);		
		}
	}

	controlPassaport(campIdentificadorPanell(oPanellAct));
	controlPassaport(campIdentificadorRepPanell(oPanellAct));
}

////////////////////////////////////////////////////////////
// Nom: canviPersonaPanellMultiple
// Descripció: Mètode que modifica els camps i valors al canviar a  Física o Jurídica
// Paràmetres d'entrada:
//		oPanell - Panell de selecció múltiple (Física/Jurídica, Física/Jurídica/Organisme)
//		sTipusPanell - String que indica el panell actiu: "PERSONA_FISICA", "PERSONA_JURIDICA", "PERSONA_ORGANISME"
//		sTipusUsuari - TipusOpcionsUsuari: "particular", "entitat_privada", "entitat_publica_gencat" o "entitat_publica_altres" o "organisme"
//		sRol - TipusRolAcreditacio "1":PersonaFísica, "2":Persona Jurídica, "3":Persona Vinculada, "4":Persona Professional
//		bBorrar - Valor (true/false) que indica si s'han d'esborrar les dades del panell que s'oculta
//		bModifAvisos - Valor (true/false) que indica si s'ha de modificar el panell d'avisos
////////////////////////////////////////////////////////////
function canviPersonaPanellMultiple(oPanell, sTipusPanell, sTipusUsuari, sRol, bBorrar, bModifAvisos)  
{
    if (isFormulariValidat()) return;

    try
	{
		if (!existeixObjecte(oPanell)) return;

		// Panells a activar
		var oPanellAct = scoGSITPanells.obtenirObjecteFill(oPanell, sTipusPanell);
		var oAvisosAct = existeixObjecte(scoGSITPar.oPanellAvisos) ? scoGSITPanells.obtenirObjecteFill(scoGSITPar.oPanellAvisos, sTipusPanell) : null;

		// Obtenim la info necessaria: Es Requeridor, numero de panell que estem activant
		var bEsRequeridor = scoGSITPanells.esPanellRequeridor(oPanellAct);
		var nPanell = numeroPanell(oPanell);		

		if (arguments.length < 5) bBorrar = true; // Per defecte esborrem
		if (arguments.length < 6) bModifAvisos = bEsRequeridor; // Per defecte el requeridor relacionat amb avisos

		// Definim el panell a activar
		var fDefAdreca = (bEsRequeridor) ? scoGSITPar.defAdrecaRequeridor : null;
		defPanellMultiple(oPanell, oPanellAct, sTipusUsuari, sRol, bBorrar, nPanell, fDefAdreca);

		// Definim el panell d'avisos a activar	si cal
		if (!bModifAvisos || !existeixObjecte(oAvisosAct)) return;
		defPanellMultiple(scoGSITPar.oPanellAvisos, oAvisosAct, sTipusUsuari, sRol, bBorrar, nPanell, scoGSITPar.defAdrecaAvisos);
    }
    catch(exc) 
    {
        scoGSITGen.retornarExcepcio(oPanellAct.name + "::canviFisicaJuridica",exc);
    }       

}

////////////////////////////////////////////////////////////
// Nom: canviFisicaJuridicaAcusament
// Descripció: Mètode que modifica els camps i valors al canviar a Física o Jurídica per l'acusament de rebuda
// Paràmetres d'entrada:
//		oPanellAct - Panell del Física/Jurídica a activar
//		oPanellDes - Panell del Física/Jurídica a desactivar
//		oAvisosAct - Panell d'avisos relacionat amb el de Física/Jurídica a activar
//		oAvisosDes - Panell d'avisos relacionat amb el de Física/Jurídica a activar
//		bEsRequeridor - Valor (true/false) que indica si el panell de Física/Jurídica esta vinculat al Requeridor 
//		bModifAvisos - Valor (true/false) que indica si s'ha de modificar el panell d'avisos
function canviFisicaJuridicaAcusament(oPanellAct, oPanellDes, oAvisosAct, oAvisosDes, bEsRequeridor, bModifAvisos)
{
	if (arguments.length < 6) bModifAvisos = bEsRequeridor; // Per defecte el requeridor relacionat amb avisos

	var sTipusPesonaAct = tipusUsuariPanellActiuPF_PJ(oPanellAct);
	var sTipusPesonaDes = tipusUsuariPanellActiuPF_PJ(oPanellDes);
	mostraOcultaPF_PJ(oPanellAct, oPanellDes, sTipusPesonaAct, sTipusPesonaDes);

	var oIdentificador = (sTipusPesonaAct == "PERSONA_FISICA") ? "TXT_TIPUS_IDENTIFICADOR" : "TXT_TIPUS_IDENTIFICADOR_EMPRESA";
	controlPassaport(scoGSITPanells.obtenirObjecteFill(oPanellAct, oIdentificador));	

      // Nomes el requeridor te avisos associats
      if (bModifAvisos)
      {
            if (!existeixObjecte(oAvisosAct)) return;
            if (!existeixObjecte(oAvisosDes)) return;
            mostraOcultaPF_PJ(oAvisosAct, oAvisosDes, sTipusPesonaAct, sTipusPesonaDes); 
			var oIdentificador = (sTipusPesonaAct == "PERSONA_FISICA") ? "TXT_TIPUS_IDENTIFICADOR" : "TXT_TIPUS_IDENTIFICADOR_EMPRESA";
			controlPassaport(scoGSITPanells.obtenirObjecteFill(oAvisosAct, oIdentificador));
      }
}  

////////////////////////////////////////////////////////////
// Nom: canviFisicaJuridica
// Descripció: Mètode que modifica els camps i valors al canviar a  Física o Jurídica
// Paràmetres d'entrada:
//		oPanellAct - panell del Física/Jurídica a activar
//		oPanellDes - panell del Física/Jurídica a desactivar
//		sTipusUsuari - TipusOpcionsUsuari: "particular", "entitat_privada", "entitat_publica_gencat" o "entitat_publica_altres" o "organisme"
//		sRol - TipusRolAcreditacio "1":PersonaFísica, "2":Persona Jurídica, "3":Persona Vinculada, "4":Persona Professional
//		oAvisosAct - panell d'avisos relacionat amb el de Física/Jurídica a activar
//		oAvisosDes - panell d'avisos relacionat amb el de Física/Jurídica a activar
//		bBorrar - Valor (true/false) que indica si s'han d'esborrar les dades del panell que s'oculta
//		bModifAvisos - Valor (true/false) que indica si s'ha de modificar el panell d'avisos
////////////////////////////////////////////////////////////
function canviFisicaJuridica(oPanellAct, oPanellDes, sTipusUsuari, sRol, oAvisosAct, oAvisosDes, bBorrar, bModifAvisos)
{
	canviPersonaPanellMultiple(oPanellAct.parent, oPanellAct.name, sTipusUsuari, sRol, bBorrar, bModifAvisos);
}

////////////////////////////////////////////////////////////
// Nom: canviFisica
// Descripció: Mètode que modifica els camps i valors al canviar a física
// Paràmetres d'entrada:
//		oPanell - Panell de Física/Jurídica/Organisme   
//		bBorrar - Valor (true/false) que indica si s'han d'esborrar les dades del panell que s'oculta
//		bModifAvisos - Valor (true/false) que indica si s'ha de modificar el panell d'avisos
////////////////////////////////////////////////////////////
function canviFisica(oPanell, bBorrar, bModifAvisos)
{
	if (isFormulariValidat()) return;
	if (arguments.length < 2) bBorrar = true;
	if (arguments.length < 3) bModifAvisos = scoGSITPanells.esPanellRequeridor(oPanell);
	if (oPanell.BTN_PERSONA.FISICA.rawValue == "1") canviPersonaPanellMultiple(oPanell, "PERSONA_FISICA", "particular", "1", bBorrar, bModifAvisos);
}

