////////////////////////////////////////////////////////////
// Nom: actualitzarAvisos
// Descripció: Mètode que modifica els camps i valors dels avisos
// Paràmetres d'entrada:
//		oPanell - Panell Avisos
////////////////////////////////////////////////////////////
function actualitzarAvisos(oPanell)
{
    try
    {
        if (isFormulariValidat()) return;

        // Adreça electrònica
        var oAE = scoGSITPanells.obtenirObjecteFill(oPanell, "CHECK_AE_REBUT");
        var bAE = (oAE != null) ? String(oAE.rawValue) : "0";      

        var oAvisosAE_CE = xfa.resolveNode("xfa.record.DadesForm.Avisos.CanviEstat.AdrecaElectronica");
        if (oAvisosAE_CE != null) oAvisosAE_CE.value = bAE;
		var oAvisosAE_RE = xfa.resolveNode("xfa.record.DadesForm.Avisos.Resolt.AdrecaElectronica");
		if (oAvisosAE_RE != null) oAvisosAE_RE.value = bAE;

		// SMS
        var oSMS = scoGSITPanells.obtenirObjecteFill(oPanell, "CHECK_SMS_REBUT");
        var bSMS = (oSMS != null) ? String(oSMS.rawValue) : "0"; 

        var oAvisosSMS_CE = xfa.resolveNode("xfa.record.DadesForm.Avisos.CanviEstat.SMS");
        if (oAvisosSMS_CE != null) oAvisosSMS_CE.value = bSMS;
        var oAvisosSMS_RE = xfa.resolveNode("xfa.record.DadesForm.Avisos.Resolt.SMS");
        if (oAvisosSMS_RE != null) oAvisosSMS_RE.value = bSMS;		

		// Avis
        var oVolRebreAvis = xfa.resolveNode("xfa.record.Cos.InfoServei.volRebreAvis");
        if (oVolRebreAvis != null) oVolRebreAvis.value = ((bAE == "1" || bSMS == "1") ? "1" : "0");
    }
    catch(exc)
    {
        scoGSITGen.retornarExcepcio(oPanell.name + "::actualitzarAvisos", exc);
    }       
}

////////////////////////////////////////////////////////////
// Nom: controlAvisMail
// Descripció: Mètode que controla la obligatorietat del camp de mail a partir dels avisos
// Paràmetres d'entrada:
//		oMail - Camp de Mail
////////////////////////////////////////////////////////////               
function controlAvisMail(oMail)
{
	try
	{
		if (isFormulariValidat() || isFormulariAcusament()) return;
		if (scoGSITPar.oPanellAvisosNotificions == null) return;

		if ((oMail.presence == "visible") && (scoGSITCamps.comprovaVisibleParent(oMail) == 1))
		{
			var bAE_Rebut =  scoGSITPar.oPanellAvisosNotificions.Avisos.CHECK_AE_REBUT.rawValue;
			oMail.validate.nullTest = (bAE_Rebut == 1) ? "error" : "";
			if (isEmpty(oMail) && (bAE_Rebut == 0)) amagarRequadre(oMail);
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio(oMail.name + "::controlAvisMail", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: controlAvisMovil
// Descripció: Mètode que controla la obligatorietat del camp de telf movil a partir dels avisos
// Paràmetres d'entrada:
//		oMovil - Camp de Telèfon mòbil
////////////////////////////////////////////////////////////               
function controlAvisMovil(oMovil)
{
	try
	{
		if (isFormulariValidat() || isFormulariAcusament()) return;
		if (scoGSITPar.oPanellAvisosNotificions == null) return;

		if ((oMovil.presence == "visible") && (scoGSITCamps.comprovaVisibleParent(oMovil) == 1))
