////////////////////////////////////////////////////////////
// Nom: controlAvisMult
// Descripció: Mètode que controla la obligatorietat del camp 'sCamp' a partir de 'sCheck', per avisos multiples
// Paràmetres d'entrada: 
//		oPanellAvisos - Panell d'avisos
////////////////////////////////////////////////////////////               
function controlAvisMult(oPanellAvisos, sCamp, sCheck)
{
	try
	{
		if (isFormulariValidat() || isFormulariAcusament()) return;

		var oCamp = scoGSITPanells.obtenirObjecteFill(oPanellAvisos.parent, sCamp);
		if ((oCamp.presence == "visible") && (scoGSITCamps.comprovaVisibleParent(oCamp) == 1))
		{
			var oCheck = scoGSITPanells.obtenirObjecteFill(oPanellAvisos, sCheck);
			oCamp.validate.nullTest = (isEmpty(oCheck)) ? "" : "error";
			if (isEmpty(oCamp) && isEmpty(oCheck)) amagarRequadre(oCamp);
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio(oPanellAvisos.name + "::controlAvisMailMult", exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: esDocumentAmbPais
// Descripció: Mètode que indica si pel tipus de document 'sTipusDoc' s'ha de mostrar el camp de pais
// Paràmetres d'entrada:
//		 sTipusDoc - String que indica el tipus de document
////////////////////////////////////////////////////////////               
function esDocumentAmbPais(sTipusDoc)
{
	if (isEmpty(sTipusDoc)) return false; 

	sTipusDoc = sTipusDoc.toUpperCase();
	return ((sTipusDoc == "PASSAPORT") || (sTipusDoc == "DOCUMENTIDENTITATESTRANGER") || (sTipusDoc == "DOCUMENTEMPRESAESTRANGERA"));
}

////////////////////////////////////////////////////////////
// Nom: controlPassaport
// Descripció: Mètode que controla la visibilitat/obligatorietat del camp de passaport a partir dels camp d'identificador.
// Paràmetres d'entrada:
//		 oIdentificador - Camp Identificador
////////////////////////////////////////////////////////////               
function controlPassaport(oIdentificador)
{
	try
	{
		if (isFormulariValidat()) return;
		if ((oIdentificador == null) || (oIdentificador == undefined)) return;		

		var oPanell = oIdentificador.parent;  // CONTACTE
		var sID = isEmpty(oIdentificador) ? "" : oIdentificador.rawValue.toUpperCase();			

		if (isFormulariAcusament() && esDocumentAmbPais(sID))
		{
			scoGSITCamps.defVisibilitat(oPanell.TXT_PAIS_DOCUMENT, "visible");
			return;			
		}

		if ((oIdentificador.presence == "visible") && (scoGSITCamps.comprovaVisibleParent(oIdentificador)) == 1)
		{		
			scoGSITPanells.defPaisPassaport(oPanell.TXT_PAIS_DOCUMENT);
			var sID = isEmpty(oIdentificador) ? "" : oIdentificador.rawValue.toUpperCase();					
			if (esDocumentAmbPais(sID))
			{
				var sIDPais = getValor(oPanell.TXT_PAIS_DOCUMENT);
				var sAcces = (sIDPais != "") ? oIdentificador.access : "open";

				var sValidacio = (sAcces == "open") ? "error" : "";
				scoGSITPanells.defCampPropietats(oPanell.TXT_PAIS_DOCUMENT, sAcces, sValidacio, "visible", sIDPais);
				oPanell.TXT_PAIS_DOCUMENT_NOM.rawValue = oPanell.TXT_PAIS_DOCUMENT.editValue;
			}
			else
			{
				scoGSITPanells.defCampPropietats(oPanell.TXT_PAIS_DOCUMENT, "protected", "", "hidden", "");
				oPanell.TXT_PAIS_DOCUMENT_NOM.rawValue = "";			
			}
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio(oIdentificador.name + "::controlPassaport", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: defCampPaisPassaport
// Descripció: Mètode que modifica el camps del pais del passaport per mostrar/ocultar i definir els seus paissos
// Paràmetres d'entrada:
//		oIdentificador - Camp Identificador
////////////////////////////////////////////////////////////
function defCampPaisPassaport(oIdentificador)
{
	try
	{
		if (isFormulariValidat()) return;
		if (oIdentificador.access == "protected") return;

		var oPanell = oIdentificador.parent; // CONTACTE
		if ((oIdentificador.presence == "visible") && (scoGSITCamps.comprovaVisibleParent(oIdentificador)) == 1)
		{
			var oPais = scoGSITPanells.obtenirObjecteFill(oPanell, "TXT_PAIS_DOCUMENT");
			var sID = isEmpty(oIdentificador) ? "" : oIdentificador.rawValue.toUpperCase();
			if (esDocumentAmbPais(sID))
			{
				if (oPais.presence != "visible")
				{
					scoGSITPanells.defPaisPassaport(oPais);
					scoGSITPanells.defCampPropietats(oPais, "open", "error", "visible", "");
					var oPaisNom = scoGSITPanells.obtenirObjecteFill(oPanell, "TXT_PAIS_DOCUMENT_NOM");
                   	if (oPaisNom != null) oPaisNom.rawValue = "";               
				}
			}
			else{
				scoGSITPanells.defCampPropietats(oPais, "protected", "", "hidden", "");

				var oPaisNom = scoGSITPanells.obtenirObjecteFill(oPanell, "TXT_PAIS_DOCUMENT_NOM");
				if (oPaisNom != null) oPaisNom.rawValue = "";
			}				
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio(oIdentificador.name + "::defCampPaisPassaport", exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: defCampPaisNacionalitat
// Descripció: Mètode que modifica el camps relacionats amb la nacionalitat a partir del tipus d'identificador
// Paràmetres d'entrada:
//		oIdentificador - Camp Identificador
////////////////////////////////////////////////////////////
function defCampPaisNacionalitat(oIdentificador)
{
	try
	{
		if (isFormulariValidat()) return;
		if (oIdentificador.access == "protected") return;

		var oPanell = oIdentificador.parent; // CONTACTE
		if ((oIdentificador.presence == "visible") && (scoGSITCamps.comprovaVisibleParent(oIdentificador)) == 1)
		{
			var sID = isEmpty(oIdentificador) ? "" : oIdentificador.rawValue.toUpperCase();		
			var oNacionalitat = scoGSITPanells.obtenirObjecteFill(oPanell, "TXT_NACIONALITAT");
			if (oNacionalitat != null)
			{
				if (sID == "NIF")
					scoGSITPanells.defCampPropietats(oNacionalitat, "protected", "", "visible", msgNacionalitatEspanyola.value);	
				else if (sID == "")
					scoGSITPanells.defCampPropietats(oNacionalitat, "protected", "", "visible", "");
				else
					scoGSITPanells.defCampPropietats(oNacionalitat, "open", "error", "visible", "");
			}

			var oChkEspanyol = scoGSITPanells.obtenirObjecteFill(oPanell, "CHK_ES_ESPANYOL"); 
			if (oChkEspanyol != null)
			{
				oChkEspanyol.rawValue = (sID == "NIF" || sID == "") ? "0" : "1"; 
				scoGSITAdreca.canviNacionalitatIDParticularNac(oChkEspanyol);
			}	
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio(oIdentificador.name + "::defCampPaisNacionalitat", exc);
	}
}


////////////////////////////////////////////////////////////
// Nom: canviIdentificador
// Descripció: Mètode que modifica els camps i valors al canviar el tipus d'Identificador
// Paràmetres d'entrada:
//		oIdentificador - Camp Identificador
////////////////////////////////////////////////////////////
function canviIdentificador(oIdentificador)
{
	try
	{
		if (isFormulariValidat()) return;
		if (oIdentificador.access == "protected") return;

		defCampPaisPassaport(oIdentificador);
		defCampPaisNacionalitat(oIdentificador);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio(oIdentificador.name + "::canviIdentificador", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: canviIdentificadorEmpresa
// Descripció: Mètode que modifica els camps i valors al canviar el tipus d'Identificador d'empresa
// Paràmetres d'entrada:
//		oIdentificador - Camp Identificador
////////////////////////////////////////////////////////////
function canviIdentificadorEmpresa(oIdentificador)
{
	try
	{
		if (isFormulariValidat()) return;
		if (oIdentificador.access == "protected") return;

		defCampPaisPassaport(oIdentificador);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio(oIdentificador.name + "::canviIdentificadorEmpresa", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: canviPaisPassaport
// Descripció: Mètode que defineix inicialment un camp de Pais.
// Paràmetres d'entrada:
//		oPanellAdreca - Panell adreca, amb els camps TXT_PAIS_DOCUMENT i TXT_PAIS_DOCUMENT_NOM
////////////////////////////////////////////////////////////
function canviPaisPassaport(oPanellAdreca)
{
	try
	{
		if (isFormulariValidat()) return;
		var sPais = oPanellAdreca.TXT_PAIS_DOCUMENT.editValue;
		oPanellAdreca.TXT_PAIS_DOCUMENT_NOM.rawValue = (!isEmpty(sPais)) ? sPais : ""; 
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio(oPanellAdreca.name + "::canviPaisPassaport", exc);
	}	
}


////////////////////////////////////////////////////////////
// Nom: controlAdrecaNormalizada
// Descripció: Mètode que s'encarrega de generar un String amb les dades de l'adreça i copiarla al normalizador
// Paràmetres d'entrada:
//		oAdreca - Panell adreca, aquest panell ha de tenir definit el panell de Normalizacio relacionat com 'oNormalizador' al seu event init 
////////////////////////////////////////////////////////////               
function controlAdrecaNormalizada(oAdreca)
{
	try
	{		
		var oNormalitzador = scoGSITCamps.obtenirValorVariable(oAdreca, "oPanellNormalitzador");
		if (oNormalitzador != null)
		{
			if (typeof(oNormalitzador) == "string") oNormalitzador = xfa.resolveNode(oNormalitzador);
		}

		if (!existeixObjecte(oNormalitzador)) return;

		var sAdreca = isEmpty(oAdreca.TXT_ES_NORMALITZADA) ? "" : oAdreca.TXT_ES_NORMALITZADA.rawValue;
		if (sAdreca.toUpperCase() == "TRUE")
			scoGSITNormalitzador.preomplertAdrecaToString(oAdreca, oNormalitzador);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITVal::controlAdrecaNormalizada", exc);
	}			
}

