////////////////////////////////////////////////////////////
// Nom: esAdrecaBuida
// Descripció: Mètode que comprova si el panell d'adreça és buida
// Paràmetres d'entrada: 
//		oAdreca - Panell d'adreça
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si el panell d'adreça es considera buida
////////////////////////////////////////////////////////////
function esAdrecaBuida(oAdreca)
{
	if (existeixObjecteFill(oAdreca, "NomVia"))
		return isEmpty(oAdreca.NomVia.value);

	return true;
}

////////////////////////////////////////////////////////////
// Nom: assignarPaisDocumentPersona
// Descripció: Mètode que verifica tots els panells i posa el valor del node 'Pais' dels documents amb el valor correcte
// Paràmetres d'entrada:
//		sPersona - Tipus de persona 
////////////////////////////////////////////////////////////
function assignarPaisDocumentPersona(sPersona)               
{
	var oNode = xfa.resolveNode("xfa.record.Cos." + sPersona);
	if (!existeixObjecte(oNode))return;

	if (!existeixObjecteFill(oNode, "tipusUsuari"))
	{
		app.alert("ATENCIÓ factoria, no està ben definit l'enllaç del camp 'TIPUS_USUARI' al node de l'estructura de dades '" + sPersona + ".tipusUsuari'.");
		return;
	}

	if (oNode.tipusUsuari.value == "particular")
	{
		// Particular
		if (existeixObjecteFill(oNode, "Particular.Document"))
			assignarValorsDocumentPaisBuit(oNode.Particular.Document, "nif");
	}
	else if (oNode.tipusUsuari.value == "entitat_privada")
	{
		// Empresa
		if (existeixObjecteFill(oNode, "Empresa.Document"))	
			assignarValorsDocumentPaisBuit(oNode.Empresa.Document, "cif");

		// Empresa -> Representant
		if (existeixObjecteFill(oNode, "Empresa.Representant.Document"))	
			assignarValorsDocumentPaisBuit(oNode.Empresa.Representant.Document, "nif");
	}
	else if (oNode.tipusUsuari.value == "organisme")
	{
		// Organisme
		if (existeixObjecteFill(oNode, "Organisme.Document"))	
			assignarValorsDocumentPaisBuit(oNode.Organisme.Document, "cif");

		// Organisme -> Representant
		if (existeixObjecteFill(oNode, "Organisme.Representant.Document"))	
			assignarValorsDocumentPaisBuit(oNode.Organisme.Representant.Document, "nif");
	}	
	else
		app.alert("ATENCIÓ factoria, no està ben definit el valor del camp 'TIPUS_USUARI' relacionat al node de l'estructura de dades '" + sPersona + ".tipusUsuari'.");			
}               


////////////////////////////////////////////////////////////
// Nom: assignarPaisDocumentPersones
// Descripció: Mètode que comprova tots els panells i posa el valor del node PaisDocument amb el valor correcte
////////////////////////////////////////////////////////////
function assignarPaisDocumentPersones()               
{
	// Revisa node requeridor (inspeccionat)
	assignarPaisDocumentPersona("Inspeccionat");

}               		

////////////////////////////////////////////////////////////
// Nom: assignarValorsDocumentPaisBuit
// Descripció: Mètode que assigna els valors de Pais Espanya si el pais del document no està definit i el tipus és 'sIdentificador', si és passaport i el nom es buit el defineix apartir del seu codi INE
// Paràmetres d'entrada: 
//		oNodeDocument - Node
//		sIdentificador - Identificador de persona
////////////////////////////////////////////////////////////
function assignarValorsDocumentPaisBuit(oNodeDocument, sIdentificador)
{
	if (!existeixObjecte(oNodeDocument)) return;
	if (!existeixObjecteFill(oNodeDocument, "tipusDocument") || !existeixObjecteFill(oNodeDocument, "Identificador")) return;

	if ((isEmpty(oNodeDocument.tipusDocument.value)) && (!isEmpty(oNodeDocument.Identificador.value))) 
		oNodeDocument.tipusDocument.value = sIdentificador;

	if (sIdentificador != "cif")
	{
		if  (existeixObjecteFill(oNodeDocument, "PaisDocument.CodiINE") && existeixObjecteFill(oNodeDocument, "PaisDocument.Nom"))
		{
			if (oNodeDocument.tipusDocument.value == sIdentificador)
			{
				if (isEmpty(oNodeDocument.PaisDocument.CodiINE.value)) oNodeDocument.PaisDocument.CodiINE.value = "ES";		
				if (isEmpty(oNodeDocument.PaisDocument.Nom.value))     oNodeDocument.PaisDocument.Nom.value = scoGSITPaisInfo.obtenirNomPaisISO("ES");
			}

			if (esDocumentAmbPais(oNodeDocument.tipusDocument.value))
			{
				var sINEPais = oNodeDocument.PaisDocument.CodiINE.value;
				if (isEmpty(oNodeDocument.PaisDocument.Nom.value)) oNodeDocument.PaisDocument.Nom.value = scoGSITPaisInfo.obtenirNomPaisISO(sINEPais);
			}
		}
	} 				
}			

////////////////////////////////////////////////////////////
// Nom: assignarValorsAdreca
// Descripció: Mètode que assigna els valors de Pais Espanya si la adreá no en té
// Paràmetres d'entrada: 
//		oNodeAdreca - Node d'adreça
////////////////////////////////////////////////////////////
function assignarValorsAdreca(oNodeAdreca)
{

	if (!existeixObjecte(oNodeAdreca)) return;

	if (!esAdrecaBuida(oNodeAdreca))
	{	
		// Normalizada
		assignarValorNormalitzada(oNodeAdreca);

		// Pais
		assignarValorsAdrecaPais(oNodeAdreca);

		// Provincia / Comarca / Municipi / Llogaret
		assignarValorsAdrecaProvComMunLlog(oNodeAdreca, "Provincia");
		assignarValorsAdrecaProvComMunLlog(oNodeAdreca, "Comarca");
		assignarValorsAdrecaProvComMunLlog(oNodeAdreca, "Municipi");
		assignarValorsAdrecaProvComMunLlog(oNodeAdreca, "Llogaret");

		// TipusVia
		assignarValorsAdrecaTipusVia(oNodeAdreca);
	}
}				

////////////////////////////////////////////////////////////
// Nom: assignarValorNormalitzada
// Descripció: Mètode que comprova/assigna el valor d'adreça normalizada
// Paràmetres d'entrada: 
//		oNodeAdreca - Panell d'adreça
////////////////////////////////////////////////////////////
function assignarValorNormalitzada(oNodeAdreca)
{
	if (!existeixObjecteFill(oNodeAdreca, "normalitzada"))
	{
		app.alert("ATENCIÓ factoria, el camp 'normalitzada' de l'adreça '" + oAdreca.somExpression + "' no està definit correctament");
		return;
	}

	if (isEmpty(oNodeAdreca.normalitzada.value)) oNodeAdreca.normalitzada.value = "false";
}


////////////////////////////////////////////////////////////
// Nom: assignarValorsAdrecaPais
// Descripció: Mètode que comprova/assigna valors als camp de Pais
// Paràmetres d'entrada: 
//		oNodeAdreca - Panell d'adreça
////////////////////////////////////////////////////////////
function assignarValorsAdrecaPais(oNodeAdreca)
{
	if (!existeixObjecteFill(oNodeAdreca, "Pais.CodiINE") || !existeixObjecteFill(oNodeAdreca, "Pais.Nom"))
	{
		app.alert("ATENCIÓ factoria, el camp 'Pais.CodiINE' o 'Pais.Nom' del panell '" + oNodeAdreca.somExpression + "' no estan definits correctament");
	}
	else
	{
		if (isEmpty(oNodeAdreca.Pais.CodiINE.value))
		{
			oNodeAdreca.Pais.CodiINE.value = "108";
			oNodeAdreca.Pais.Nom.value = scoGSITPaisInfo.obtenirNomPaisINE("108");	
		}
		else
		{
			if (isEmpty(oNodeAdreca.Pais.Nom.value))
				oNodeAdreca.Pais.Nom.value = scoGSITPaisInfo.obtenirNomPaisINE(oNodeAdreca.Pais.CodiINE.value);
		}
	}
}

////////////////////////////////////////////////////////////
// Nom: assignarValorsAdrecaProvComMunLlog
// Descripció: Mètode que comprova/assigna valors als camp de Província, Comarca, Municipi i Llogaret
// Paràmetres d'entrada: 
//		oNodeAdreca - Panell d'adreça
//		sTipus	- "Provincia" / "Comarca" / "Municipi" / "Llogaret"	
////////////////////////////////////////////////////////////
function assignarValorsAdrecaProvComMunLlog(oNodeAdreca, sTipus)
{
	if (existeixObjecteFill(oNodeAdreca, sTipus))
	{
		if (!existeixObjecteFill(oNodeAdreca, sTipus + ".Nom") || !existeixObjecteFill(oNodeAdreca, sTipus + ".CodiINE"))
			return;

		var nom = oNodeAdreca.resolveNode(sTipus + ".Nom");
		var codiINE = oNodeAdreca.resolveNode(sTipus + ".CodiINE");

//		if (isEmpty(nom.value) && !isEmpty(codiINE.value))
		if (!isEmpty(codiINE.value))
		{
			if (sTipus == "Provincia") nom.value = scoGSITProvInfo.obtenirNomProvincia(codiINE.value);
			else if (sTipus == "Comarca") nom.value = scoGSITComInfo.obtenirNomComarca(codiINE.value);
			else if (sTipus == "Municipi") nom.value = scoGSITMunEspInfo.obtenirNomMunicipi(codiINE.value, oNodeAdreca.Provincia.CodiINE.value);
			else if (sTipus == "Llogaret") 
			{
				var sINE = codiINE.value;
				if (isCodiUnitatPoblacional(sINE))
					nom.value = scoGSITUnitatPobInfo.obtenirNomUnitatPoblacional(sINE);
				else
					nom.value = scoGSITLlogInfo.obtenirNomLlogaret(sINE);
			}
		}
	}
}

////////////////////////////////////////////////////////////
// Nom: assignarValorsAdrecaTipusVia
// Descripció: Mètode que comprova/assigna valors al camps de tipus via
// Paràmetres d'entrada: 
//		oNodeAdreca - Panell d'adreça
////////////////////////////////////////////////////////////
function assignarValorsAdrecaTipusVia(oNodeAdreca)
{
	if (!existeixObjecteFill(oNodeAdreca, "TipusVia.Descripcio") || !existeixObjecteFill(oNodeAdreca, "TipusVia.CodiArvato")) return;

	if (isEmpty(oNodeAdreca.TipusVia.Descripcio.value) && !isEmpty(oNodeAdreca.TipusVia.CodiArvato.value))
		oNodeAdreca.TipusVia.Descripcio.value = scoGSITViaInfo.obtenirNomTipusVia(oNodeAdreca.TipusVia.CodiArvato.value);	
}

////////////////////////////////////////////////////////////
// Nom: assignarValorsAdrecaPersona
// Descripció: Mètode que comprova tots els panells d'adreça i posa els valors correctes
// Paràmetres d'entrada: 
//		sPersona - Tipus de persona "particular / entitat_privada"
////////////////////////////////////////////////////////////
function assignarValorsAdrecaPersona(sPersona)
{
	var oNode = xfa.resolveNode("xfa.record.Cos." + sPersona);
	if (!existeixObjecte(oNode)) return;

	if (!existeixObjecteFill(oNode, "tipusUsuari"))
	{
		app.alert("ATENCIÓ factoria, no està ben definit l'enllaç del camp 'TIPUS_USUARI' al node de l'estructura de dades '" + sPersona + ".tipusUsuari'.");
		return;
	}	

	if (oNode.tipusUsuari.value == "particular")
	{
		if (existeixObjecteFill(oNode, "Particular.Adreca")) assignarValorsAdreca(oNode.Particular.Adreca);
	}
	else if (oNode.tipusUsuari.value == "entitat_privada")
	{
		if (existeixObjecteFill(oNode, "Empresa.Adreca")) assignarValorsAdreca(oNode.Empresa.Adreca);	
		if (existeixObjecteFill(oNode, "Empresa.Representant.Adreca")) assignarValorsAdreca(oNode.Empresa.Representant.Adreca);	
	}
	else if (oNode.tipusUsuari.value == "organisme")
	{
		if (existeixObjecteFill(oNode, "Organisme.Adreca")) assignarValorsAdreca(oNode.Organisme.Adreca);	
		if (existeixObjecteFill(oNode, "Organisme.Representant.Adreca")) assignarValorsAdreca(oNode.Organisme.Representant.Adreca);	
	}	
	else
		app.alert("ATENCIÓ factoria, no està ben definit el valor del camp 'TIPUS_USUARI' relacionat al node de l'estructura de dades '" + oNode.somExpression + ".tipusUsuari'.");
}               

