// Nom: assignarValorsAdreces
// Descripció: Mètode que recorre els diferents nodes d'adreça i li assigna valors a les adreces si fa falta...
////////////////////////////////////////////////////////////
function assignarValorsAdreces()               
{
	// Revisa node requeridor (Inspeccionat)
	assignarValorsAdrecaPersona("Inspeccionat");
}

////////////////////////////////////////////////////////////
// Nom: comprovaCreaNodeXML
// Descripció: Mètode que comprova que existeixi el node 'sNodeXML' i sino el crea
// Paràmetres d'entrada: 
//		oNodePare - Node del pare del node a comprovar
//		sNodeXML - Nom del node XML a comprovar i crear
//		sTipus - Tipus del node XML 'dataValue' o 'groupValue'
//		sPathPare - Ruta XMl del pare
// Paràmetres de sortida:
//		Objecte - Objecte fill que es recupera o es crea
////////////////////////////////////////////////////////////
function comprovaCreaNodeXML(oNodePare, sNodeXML, sTipus, sPathPare)
{
	try
	{
		var sRuta = sPathPare + "." + sNodeXML;
		var oNodeXML = xfa.resolveNode(sRuta);
		if (oNodeXML != null) return oNodeXML;

		var oNode = xfa.datasets.createNode(sTipus, sNodeXML);
		oNodePare.nodes.append(oNode);
		return (xfa.resolveNode(sRuta));
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITVal.comprovaCreaNodeXML() : \n", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: defValorNodeXML
// Descripció: Mètode que comprova que assigna 'sValor' al node de l'XML 'sNodeXML', si no existeix el crea 
// Paràmetres d'entrada: 
//		oNodePare - Node del pare del node a comprovar
//		sNodeXML - Nom del node XML a comprovar i crear
//		sTipus - Tipus del node XML 'dataValue' o 'groupValue'
//		sPathPare - Ruta XMl del pare
//		sValor - Valor del node
// Paràmetres de sortida:
//		Objecte - Objecte fill que es recupera o es crea
////////////////////////////////////////////////////////////
function defValorNodeXML(oNodePare, sNodeXML, sTipus, sPathPare, sValor)
{
	try
	{
		var oNode = comprovaCreaNodeXML(oNodePare, sNodeXML, sTipus, sPathPare);
		oNode.value = sValor;
	}	
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITVal.defValorNodeXML() : \n", exc);
	}		
}

////////////////////////////////////////////////////////////
// Nom: defValorXML
// Descripció: Mètode que assigna 'sValor' al node de l'XML 'oNodeXML' si aquest existeix 
// Paràmetres d'entrada: 
//		oNodeXML - Node XML a definir
//		sValor - Valor del node
// Paràmetres de sortida:
//		Objecte - Objecte fill que es recupera o es crea
////////////////////////////////////////////////////////////
function defValorXML(oNodeXML, sValor)
{
	if (existeixObjecte(oNodeXML)) oNodeXML.value = sValor; 
}




////////////////////////////////////////////////////////////
// Nom: validarCampCodiPostalEstr
// Descripció: Mètode que valida un camp de codi postal si el pais no és extranger
// Paràmetres d'entrada:
//		oCamp = Camp de CP
// Paràmetres de sortida: 	
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada té un valor/format acceptat
////////////////////////////////////////////////////////////     
function validarCampCodiPostalEstr(oCamp)               
{
	try
	{
		if (!isFormulariValidat())
	    {
			oCamp.rawValue = trim(oCamp.rawValue);
			var oAdreca = oCamp.parent;
			var oChkResidencia = scoGSITPanells.obtenirObjecteFill(oAdreca, "CHK_RESIDENCIA");

			var bEsCatalana = scoGSITAdreca.esPanellAdrecaCatalana(oAdreca) || scoGSITAdreca.esLlistaProvCatalanes(oAdreca);
			var bEspanyola = scoGSITAdreca.esAdrecaEspanyola(oAdreca) || (getValorNum(oChkResidencia) == 0);
			if (bEsCatalana)                                   return (validarCampCodiPostalCat(oCamp));
			else if (bEspanyola)                               return (validarCampCodiPostal(oCamp));
			else                                               return (amagarRequadre(oCamp));   
	    }
	} 
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITVal.validarCampCodiPostalEstr() : \n", exc);
	}	
}


////////////////////////////////////////////////////////////
// Nom: actualitzarFormulari
// Descripció: Mètode que recupera els camps obligatoris
////////////////////////////////////////////////////////////
function actualitzarFormulari()
{
	if (isFormulariValidat()) return;
	if (isFormulariAcusament()) return; // A un acusament no cal marcar els obligatoris

	if (scoGSITPar.bUsEnforceStrict)
	{		
		scoGSITCamps.assignarPropietatCampsObligatoris(); 
		if (xfa.host.name == "Acrobat") app.runtimeHighlight = scoGSITPar.bResaltarCampsFormulari;
		scoGSITNod.arrCampsObligatoris = new Array();
	}	
}	                       

////////////////////////////////////////////////////////////
// Nom: validarData
// Descripció: Mètode que s'encarrega de validar si el format i el contingut d'una data és correcte. Seguint l'esquema DD/MM/YYYY	
// Paràmetres d'entrada:
//		pData - Data que haurà de validar
//		pDataValor - Es guardarà en aquest camp la data 'pData' en format YYYY-MM-DD (s'ha de definir per dates anteriors a 1900)
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada té un valor/format acceptat
////////////////////////////////////////////////////////////
function validarData(pData, pDataValor)
{
	try{
		if (arguments.length < 2) pDataValor = null;

		if (pData.rawValue != null)
		{
			var dataFormat = pData.formattedValue;			
            if (dataFormat != null)
            {
            	var data = dataFormat.replace(/-/gi, "/");  
				data = data.replace(/\./gi, "/"); 
				var separadors = "/";
                if (data.match("^[0-9]{1,2}["+separadors+"][0-9]{1,2}["+separadors+"]([0-9]{1,4})$") == null)
                {	
 					return false;
				}

				var sZeros = "0000";
                var aDies = new Array(31,28,31,30,31,30,31,31,30,31,30,31);
                var arrData = data.split(separadors);
				var sDia = (arrData[0].length == 1) ? ("0"+arrData[0]) : arrData[0];
				var sMes = (arrData[1].length == 1) ? ("0"+arrData[1]) : arrData[1];

				var sAny = sZeros.substring(0,4-arrData[2].length) + arrData[2];

				data = sDia + separadors + sMes + separadors + sAny;
				pData.formattedValue = data;

                if (data.match("^[0-9]{2}["+separadors+"][0-9]{2}["+separadors+"]([0-9]{4})$") == null)
                {
 					return false;
				}		

                var ultimDia;
				var dia = parseInt(arrData[0], 10);
				var mes = parseInt(arrData[1], 10);
                var any = parseInt(arrData[2], 10);
                if (mes == 2)
                {
					ultimDia = (any % 4 == 0 && any % 100 != 0 || any % 400 ==0) ? 29 : 28;

					if (dia < 1 || dia > ultimDia) return false;
				}
                else
                {
					if (dia < 1 || dia > aDies[(mes-1)] || mes > 12 || mes < 1) return false;
            	}

				if (pDataValor != null) pDataValor.rawValue = sAny + "-" + sMes + "-" + sDia;

            	return true;
			}
		}
		else
		{
			if (pDataValor != null) pDataValor.rawValue = "";
		}

	}
	catch(exc) {
		scoGSITGen.retornarExcepcio("scoGSITVal.validarData() : \n", exc);
	}
}    

////////////////////////////////////////////////////////////
// Nom: validaDataAnteriorAvui
// Descripció: Mètode que s'encarrega de validar una data que sigui correcta, i que sigui major o igual a 1 de gener de 1900 i menor o igual al dia d'avui
// Paràmetres d'entrada:
//		pData - Data que haurà de validar
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada té un valor/format acceptat
////////////////////////////////////////////////////////////
function validaDataAnteriorAvui(pData)
{
	try
	{
		if (pData.rawValue != null)
		{
			var dataFormat = pData.formattedValue;
            if (dataFormat != null)
            {
            	var data = dataFormat.replace(/-/gi, "/");  
				data = data.replace(/\./gi, "/"); 
				var separadors = "/";
                var arrData = data.split(separadors);
				var dia = parseInt(arrData[0], 10);
				var mes = parseInt(arrData[1], 10);
                var any = parseInt(arrData[2], 10);

                if (any < 1900) return false;

				var oFechaHoy = new Date();
				var dia_actual  = oFechaHoy.getDate();
				var mes_actual  = oFechaHoy.getMonth()+1;
				var any_actual  = oFechaHoy.getFullYear();

				if (any > any_actual) return false;
				if ((any == any_actual) && (mes > mes_actual)) return false;
				if ((any == any_actual) && (mes == mes_actual) && (dia > dia_actual)) return false;

            	return true;
			}
		}
	}
	catch(exc) 
	{
		scoGSITGen.retornarExcepcio("scoGSITVal.validaDataAnteriorAvui() : \n", exc);
	}
}    


////////////////////////////////////////////////////////////
// Nom: validaDataAnteriorAvui
// Descripció: Mètode que s'encarrega de validar que una data sigui posterior a una altre data
// Paràmetres d'entrada:
//		oCampAnterior - Data anterior
//		oCampPosterior - Data posterior a validar
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada té un valor/format acceptat
////////////////////////////////////////////////////////////
function validaDataPosteriorAltreData(oCampAnterior, oCampPosterior)
{
	try
	{
		if (!scoGSITVal.existeixObjecte(oCampAnterior)) return;
		if (!scoGSITVal.existeixObjecte(oCampPosterior)) return;
		if (scoGSITVal.isEmpty(oCampAnterior))  return true;
		if (scoGSITVal.isEmpty(oCampPosterior)) return true;

		var dataAntFormat = oCampAnterior.formattedValue;
		var dataPosFormat = oCampPosterior.formattedValue;
		if (dataAntFormat != null && dataPosFormat != null)
		{
			var dataAnt = dataAntFormat.replace(/-/gi, "/");  
			dataAnt = dataAnt.replace(/\./gi, "/"); 
			var separadors = "/";
			var arrDataAnt = dataAnt.split(separadors);
			var diaAnt = parseInt(arrDataAnt[0], 10);
			var mesAnt = parseInt(arrDataAnt[1], 10);
			var anyAnt = parseInt(arrDataAnt[2], 10);

			var dataPos = dataPosFormat.replace(/-/gi, "/");  
			dataPos = dataPos.replace(/\./gi, "/"); 
			var separadors = "/";
			var arrDataPos = dataPos.split(separadors);
			var diaPos = parseInt(arrDataPos[0], 10);
			var mesPos = parseInt(arrDataPos[1], 10);
			var anyPos = parseInt(arrDataPos[2], 10);

			if (anyAnt > anyPos) return false;
			if ((anyAnt == anyPos) && (mesAnt > mesPos)) return false;
			if ((anyAnt == anyPos) && (mesAnt == mesPos) && (diaAnt >= diaPos)) return false;

			return true;
		}

	}
	catch(exc) 
	{
		scoGSITGen.retornarExcepcio("scoGSITVal.validaDataPosteriorAltreData() : \n", exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: validaDataNaixement
// Descripció: Mètode que s'encarrega de validar una data de naixement correcta, ha de ser major o igual a 1 de gener de 1900 i menor o igual al dia d'avui
// Paràmetres d'entrada:
//		pData - Data que haurà de validar
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada té un valor/format acceptat
////////////////////////////////////////////////////////////
function validaDataNaixement(pData)
{
	return validaDataAnteriorAvui(pData);
}	

////////////////////////////////////////////////////////////
// Nom: validarCPostal
// Descripció: Mètode que comprova que el codi postal que se li passa per paràmetre, sigui d'alguna província si és així dóna el valor dels 2 primer dígits a la llista de províncies que se li passa retorna true si tot va bé
// Paràmetres d'entrada:
//		pCP - codi postal 
//		pLllista - Objecte desplegable a que es donarà valor 
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada té un valor/format acceptat
//////////////////////////////////////////////////////////// 
function validarCPostal(pCP, pLlista)
{
	try
	{
		var re = new RegExp("^(0[1-9]|[1-4][0-9]|5[0-2])[0-9]{3}$");
		if (!re.test(pCP))  return false;
		else 
		{
			if (pLlista != null)
			{
				var codProv = pCP.substring(0, 2);
				if (scoGSITVal.isEmpty(pLlista))
				{				
					if (scoGSITCombo.cercaPosicioLlista(pLlista, codProv) != -1)
					{
						pLlista.rawValue = codProv;
						pLlista.execEvent("exit");
					}
				}
				else return (pLlista.rawValue == codProv);
			}

			return true;
		}
	}
	catch(exc) {
		scoGSITGen.retornarExcepcio("scoGSITVal.validarCPostal() : \n", exc);
	}
} 

////////////////////////////////////////////////////////////
// Nom: validarCPostalCat
// Descripció: Mètode que comprova que el codi postal que se li passa per paràmetre, sigui d'alguna província CAT si és així dóna el valor dels 2 primer dígits a la llista de províncies que se li passa retorna true si tot va bé
// Paràmetres d'entrada:
//		pCP - codi postal 
//		pLllista - Objecte desplegable a que es donarà valor 
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si el paràmetre d'entrada té un valor/format acceptat
//////////////////////////////////////////////////////////// 
function validarCPostalCat(pCP, pLlista)
{
	try
	{
		var re = new RegExp("^(08|17|25|43)[0-9]{3}$");
		if (!re.test(pCP))  return false;
		else 
		{
			if (pLlista != null)
			{
				var codProv = pCP.substring(0, 2);
				if (scoGSITVal.isEmpty(pLlista))
				{				
					if (scoGSITCombo.cercaPosicioLlista(pLlista, codProv) != -1)
					{
						pLlista.rawValue = codProv;
						pLlista.execEvent("exit");
					}
				}
				else return (pLlista.rawValue == codProv);
			}

			return true;
		}
	}
	catch(exc) {
		scoGSITGen.retornarExcepcio("scoGSITVal.validarCPostal() : \n", exc);
	}
}               


////////////////////////////////////////////////////////////	
// Nom: isNumeric
// Descripció: Mètode que comprova si un valor determinat es numèric.
// Paràmetres d'entrada:
//		sValor - Valor a comprovar
////////////////////////////////////////////////////////////
function isNumeric(sValor) {
	var i;
	var c;
	var digits = "0123456789";
	//Faig això per treure els blancs al davant i darrere
	var sValorFormat = 	trim(sValor);
	for (i = 0; i < sValorFormat.length ; i++)	{
		c = sValorFormat.charAt(i);
		if (digits.indexOf(c) == -1) return false;
	}
	return true;
}

////////////////////////////////////////////////////////////	
// Nom: trim
// Descripció: Mètode que elimina espais pel davant i pel darrere d'una cadena de dades.
// Paràmetres d'entrada:
//		sVal - Paràmatre que conté la cadena de texte a la que li volem treure els espais.
////////////////////////////////////////////////////////////
function trim(sVal) 
{
	if (sVal == null || sVal == undefined) return "";

	return String(sVal).replace(/^\s*|\s*$/g,"");
}


////////////////////////////////////////////////////////////	
// Nom: preGuardat
// Descripció: Mètode que comprova que si el formulari està validat, i en cas que no es mostra un missatge informatiu.
////////////////////////////////////////////////////////////               
function preGuardat()               
{                          
	if (isFormulariValidat()) {
		scoGSITAdj.sincronitzarAdjunts(scoGSITPar.oPanellAdjunts, false);
	}
	else if (!isFormulariValidat() && !isFormulariAcusament())  app.alert(msgErrorFormNoValidat.value);
}	


////////////////////////////////////////////////////////////
// Nom: obtenirDataArray
// Descripció: Mètode que recupera la data del sistema en un array.
// Paràmetres de sortida:
//		array - Array amb la data del sistema
////////////////////////////////////////////////////////////
function obtenirDataArray (){
	var aDies = new Array ('diumenge','dilluns','dimarts','dimecres','dijous','divendres','disabte');
	var aMesos = new Array ('gener','febrer','març','abril','maig','juny','juliol','agost','setembre','octubre','novembre','desembre');
    var oData = new Date (); 
	var sDia = aDies[oData.getDay()]; 
	var sDiaNum = oData.getDate(); 
	var sMes = aMesos[oData.getMonth()]; 
	var sAny = 1900 + oData.getYear();
	var aData=new Array();
	aData[0]=sDia;	
    aData[1]=sDiaNum;
	aData[2]=sMes;
	aData[3]=sAny;
	return aData;
}


////////////////////////////////////////////////////////////	
// Nom: obtenirDataArrayDades
// Descripció: Mètode que recupera la data en un array, indicant una data inicial.
// Paràmetres d'entrada:
//		dia - Dia inicial
//		mes - Mes inicial
//		any - Any inicial
// Paràmetres de sortida:
//		array - Array amb la data inicial
////////////////////////////////////////////////////////////
function obtenirDataArrayDades (dia,mes,any){
	var aDies = new Array ('diumenge','dilluns','dimarts','dimecres','dijous','divendres','disabte');
	var aMesos = new Array ('gener','febrer','març','abril','maig','juny','juliol','agost','setembre','octubre','novembre','desembre');
    var oData = new Date (); 

	var oData = new Date(any,mes,dia);		
	var sDia = aDies[oData.getDay()]; 
	var sDiaNum = oData.getDate(); 
	var sMes = aMesos[oData.getMonth()]; 
	var sAny = 1900 + oData.getYear();
	var aData=new Array();
	aData[0]=sDia;	
    aData[1]=sDiaNum;
	aData[2]=sMes;
	aData[3]=sAny;
	return aData;
}

////////////////////////////////////////////////////////////	
// Nom: obtenirDies
// Descripció: Mètode que recupera el nombre de dies de un mes donat en un any en concret.
// Paràmetres d'entrada:
//		mes - Mes del que es vol saber el nombre de dies que té
//		any - Any al que pertany el mes
// Paràmetres de sortida:
//		enter - Valor de dies que té un més d'un any concret
////////////////////////////////////////////////////////////
function obtenirDies(mes,any){
	if (mes==4 || mes==6 || mes==9 || mes==11) return 30;

	if (mes==1 || mes==3 || mes==5 || mes==7 || mes==8 || mes==10 || mes==12) return 31;

	if (mes==2){
		return obtenirDiesDeFebrer(any);
	}
}

////////////////////////////////////////////////////////////	
// Nom: obtenirDiesDeFebrer
// Descripció: Mètode que recupera el nombre de dies del mes de Febrer en un any en concret.
// Paràmetres d'entrada:
//		any - Any al que pertany el mes
// Paràmetres de sortida:
//		enter - Valor de dies que té el mes Febrer d'un any concret
////////////////////////////////////////////////////////////
function obtenirDiesDeFebrer(any)
{
    // Febrero tiene 29 dias en cada año divisible por 4 EXCEPTO en los años divisibles por 100 y por 400
    return (((any % 4 == 0) && ( (!(any % 100 == 0)) || (any % 400 == 0))) ? 29 : 28 );
}           

////////////////////////////////////////////////////////////
// Nom: crearAleatori
// Descripció: Mètode que genera un número aleatori
// Paràmetres de sortida:
//		enter - Número aleatori generat
////////////////////////////////////////////////////////////
function crearAleatori()
{
	try
	{
		return Math.floor(Math.random() * (999999 + 1));
	}
	catch(exc)
    {
		return scoGSITGen.retornarExcepcio("scoGSITVal::crearAleatori()", exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: numRoma
// Descripció: Mètode que retorna 'num' en numeros romans
// Paràmetres de sortida:
//		string - Número roma de 'num'
////////////////////////////////////////////////////////////
function numRoma(num)
{
	if (typeof(num) != "string") num = String(num);

	var roman = "";
	var ronumdashes = "";

	var buffer=10-num.length;

	while (buffer>0) 
	{
		num = "0" + num;
		buffer--;
	}

	var units = new Array("","I","II","III","IV","V","VI","VII","VIII","IX");
	var tens = new Array("","X","XX","XXX","XL","L","LX","LXX","LXXX","XC");
	var hundreds = new Array("","C","CC","CCC","CD","D","DC","DCC","DCCC","CM");
	var thousands = new Array("","M","MM","MMM","MV","V","VM","VMM","VMMM","MX");
	var billionsdashes = new Array("","=","==","===","==","=","==","===","====","==");

	romandashes = billionsdashes[num.substring(0,1)];
	var hundredmillionsdashes = new Array("","=","==","===","==","=","==","===","====","==");
	romandashes += hundredmillionsdashes[num.substring(1,2)];

	var tenmillionsdashes = new Array("","=","==","===","==","=","==","===","====","==");
	romandashes += tenmillionsdashes[num.substring(2,3)];

	var millionsdashes = new Array("","_","__","___","_=","=","=_","=__","=___","_=");
	romandashes += millionsdashes[num.substring(3,4)];

	var hundredthousandsdashes = new Array("","_","__","___","__","_","__","___","____","__");
	romandashes += hundredthousandsdashes[num.substring(4,5)];

	var tenthousandsdashes=new Array("","_","__","___","__","_","__","___","____","__");
	romandashes += tenthousandsdashes[num.substring(5,6)];

	var thousandsdashes = new Array("","","",""," _","_","_","_","_"," _");
	romandashes += thousandsdashes[num.substring(6,7)];

	roman = thousands[num.substring(0,1)];
	roman += hundreds[num.substring(1,2)];
	roman += tens[num.substring(2,3)];
	roman += thousands[num.substring(3,4)];
	roman += hundreds[num.substring(4,5)];
	roman += tens[num.substring(5,6)];
	roman += thousands[num.substring(6,7)];
	roman += hundreds[num.substring(7,8)];
	roman += tens[num.substring(8,9)];
	roman += units[num.substring(9,10)];

	return (romandashes + "\n" + roman);
}

////////////////////////////////////////////////////////////
// Nom: getValueParametreDinamic
// Descripció: Mètode que retorna el valor del paràmetre dinàmic 'sNom'
// Paràmetres de sortida:
//		String - valor del paràmetre dinàmic 'sNom'
////////////////////////////////////////////////////////////
function getValueParametreDinamic(sNom)
{
	var oParamDin = xfa.resolveNode("xfa.record.DadesForm.ParametresDinamics"); 
	if (!existeixObjecte(oParamDin)) return "";

	var nParams = oParamDin.nodes.length;
	for (var n=0; n<nParams; n++)
	{
		var oParam = oParamDin.nodes.item(n);
		if (oParam.Nom.value == sNom) return oParam.Valor.value;
	}

	return "";
}

////////////////////////////////////////////////////////////
// Nom: setValueParametreDinamic
// Descripció: Mètode que assigna 'sValor' al paràmetre dinàmic 'sNom'
////////////////////////////////////////////////////////////
function setValueParametreDinamic(sNom, sValor)
{
	var oParamDin = xfa.resolveNode("xfa.record.DadesForm.ParametresDinamics"); 
	if (!existeixObjecte(oParamDin)) return "";

	var nParams = oParamDin.nodes.length;
	for (var n=0; n<nParams; n++)
	{
		var oParam = oParamDin.nodes.item(n);
		if (oParam.Nom.value == sNom) oParam.Valor.value = sValor;
	}

	return "";
}

/////////////////////////////////////////////////////////////////////////////
// Nom: defVisibilitatRel
// Descripció: Mètode que defineix la visibilitat de 'sCamp' segons les visibilitats de 'aVisibilitats'
// Paràmetres d'entrada:
//		sCamp - Nom del camp
//		oPanellPare - Panell pare del camp
//		aVisibilitats - Array amb les visibilitats relacionades
//		sPresenceRel - Visibilitat x defecte relacionada, a la que trova aquesta a 'aVisibilitats' ja se la defineix a 'oCamp'
///////////////////////////////////////////////////////////////////////////// 
function defVisibilitatRel(sCamp, oPanellPare, aVisibilitats, sPresenceRel)
{
	var oCamp = scoGSITPanells.obtenirObjecteFill(oPanellPare, sCamp);	

	var n = 0;
	var sPres = "";
	var nVisibilitats = aVisibilitats.length;
	do
	{
		sPres = aVisibilitats[n++];
	}
	while (n<nVisibilitats && sPres != sPresenceRel);

	scoGSITCamps.defVisibilitat(oCamp, sPres);
}


 /////////////////////////////////////////////////////////////////////////////
// Nom: comprovaEsborraDadesPrecarregades
// Descripció: Mètode que comprova si les dades precarregades a 'Presentador', 'Requeridor' i 'Contacte' són correctes sino les esborra
/////////////////////////////////////////////////////////////////////////////
function comprovaEsborraDadesPrecarregades()
{
  try
  {            

	if (esFormulariGuardat()) return;
	// NO FEM LA COMPROVACIÓ			if (!esFormulariPreOmplert()) return;

	// NO TENIM PRESENTADOR!!!			comprovaEsborraPresentador();   
	// EN PRINCIPI NO TENIM INCONGRUÈNCIES			comprovaEsborraRequeridor(scoGSITPar.bFormulariTePresentador && existeixPresentador());
	comprovaPrecarregaContacte();

  }
  catch(exc)
  {
		scoGSITGen.retornarExcepcio("comprovaEsborraDadesPrecarregades", exc);
  }     
}


/////////////////////////////////////////////////////////////////////////////
// Nom: comprovaPrecarregaContacte
// Descripció: Mètode que comprova si s'han d'esborrar les dades precarregades de les dades de Contacte, per ser d'un tipus d'usuari no acceptat
//				EL FORMULARI ÚNICAMENT ACCEPTA TIPUS USUARI PARTICULAR. 
/////////////////////////////////////////////////////////////////////////////
function comprovaPrecarregaContacte()
{
	try
	{ 
		comprovaPrecarregaPersona(rutaNodePersona('contacte'), scoGSITPar.sTipusContacte, scoGSITPar.aTipusAdrecaContacte, scoGSITPar.aTipusAdrecaContacteRepresentant, false);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("comprovaPrecarregaContacte", exc);
	}			
}

/////////////////////////////////////////////////////////////////////////////
// Nom: comprovaPrecarregaPersona
// Descripció: Mètode que comprova si s'han d'esborrar les dades precarregades de , per ser d'un tipus d'usuari no acceptat
// Paràmetres d'entrada:
//		sNodePersona - Ruta inicial del Node del que es vol comprovar: 'xfa.record.Cos.Presentador', 'xfa.record.Cos.Requeridor', 'xfa.record.Cos.InfoServei.DadesContacte'
// 		sTipusPersona - Tipus de persona que pot tenir, valors 'PF', 'PJ', 'OR', 'PF-PJ', 'PF-OR', 'PJ-OR', 'PF-PJ-OR'
//      aTipusAdreca - ["tipus_adreca_física", "tipus_adreca_jurídica", "tipus_adreca_organisme"] amb valors: '', 'CAT', 'ESP' o 'EXT'
//      aTipusAdrecaRep - ["tipus_adreca_representant_jurídic", "tipus_adreca_representant_organisme"] amb valors: '', 'CAT', 'ESP' o 'EXT'
//		bBorrarNomConcatenat - Indica si en el cas d'esborrar la precarrega s'ha d'esborrar el node 'NomConcatenat'
///////////////////////////////////////////////////////////////////////////// 
function comprovaPrecarregaPersona(sNodePersona, sTipusPersona, aTipusAdreca, aTipusAdrecaRep, bBorrarNomConcatenat)
{
	try
	{
	 	sTipusPersona = (sTipusPersona) ? sTipusPersona : "PF-PJ-OR";
		aTipusAdreca = (aTipusAdreca) ? aTipusAdreca : ["EXT", "EXT", "EXT"];
		aTipusAdrecaRep = (aTipusAdrecaRep) ? aTipusAdrecaRep : ["EXT", "EXT"];
		comprovaPrecarregaNodePersona(sNodePersona, sTipusPersona, aTipusAdreca, aTipusAdrecaRep, bBorrarNomConcatenat);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("comprovaPrecarregaPersona", exc);
	}			
}

/////////////////////////////////////////////////////////////////////////////
// Nom: comprovaPrecarregaNodePersona
// Descripció: Mètode que comprova si s'han d'esborrar les dades precarregades del Presentador o Requeridor, per ser d'un tipus d'usuari no acceptat
// Paràmetres d'entrada:
//		sNode - Ruta inicial del Node del que es vol comprovar l'adreça: 'xfa.record.Cos.Presentador', 'xfa.record.Cos.Requeridor', 'xfa.record.Cos.InfoServei.DadesContacte'
// 		sTipusPersona - scoGSITPar.sTipusPresentador / scoGSITPar.sTipusRequeridor / scoGSITPar.sTipusContacte
//      aTipusAdreca - scoGSITPar.aTipusAdrecaPresentador / scoGSITPar.aTipusAdrecaRequeridor / scoGSITPar.aTipusAdrecaContacte
//      aTipusAdrecaRep - scoGSITPar.aTipusAdrecaPresentadorRepresentant / scoGSITPar.aTipusAdrecaRequeridorRepresentant / scoGSITPar.aTipusAdrecaContacteRepresentant
//		bBorrarNomConcatenat - Indica si en el cas d'esborrar la precarrega s'ha d'esborrar el node 'NomConcatenat'
///////////////////////////////////////////////////////////////////////////// 
function comprovaPrecarregaNodePersona(sNode, sTipusPersona, aTipusAdreca, aTipusAdrecaRep, bBorrarNomConcatenat)
{	
	var oNode = xfa.resolveNode(sNode + ".tipusUsuari");
	if (existeixObjecte(oNode))
	{	
		if (!esTipusUsuariCorrectePerTipusPersona(oNode, sTipusPersona)) 
		{
			esborraNodePersona(oNode, getTipusUsuariCorrecte(sTipusPersona), bBorrarNomConcatenat);
		}
		/* PER ARA NO COMPROVEM L'ADREÇA!!!!  else
		{	
			if (aTipusAdreca != null)    comprovaPrecarregaAdreca(sNode, aTipusAdreca);
			if (aTipusAdrecaRep != null) comprovaPrecarregaAdrecaRepresentant(sNode, aTipusAdrecaRep);
		}	*/
	}
}

/////////////////////////////////////////////////////////////////////////////
// Nom: rutaNodePersona
// Descripció: Mètode que retorna la ruta del node 'sPersona'
// Paràmetres d'entrada:
//		sPersona - Nom del node del que es vol la ruta a l'XML, pot tenir valors 'presentador', 'requeridor', 'contacte', 'altresInteressats'
// Paràmetres de sortida: 
//		Objecte - Ruta del node a l'XML
/////////////////////////////////////////////////////////////////////////////
function rutaNodePersona(sPersona)
{
	if ((sPersona != 'presentador') && (sPersona != 'requeridor') && (sPersona != 'contacte') && (sPersona != 'altresInteressats')) return "";

	var mapaRuta = { presentador: "xfa.record.Cos.Presentador", 
	                 requeridor: "xfa.record.Cos.Requeridor", 
					 contacte: "xfa.record.Cos.InfoServei.DadesContacte",
					 altresInteressats: "xfa.record.Cos.Contingut.AltresInteressats.AltreInteressat[*]"};

	return mapaRuta[sPersona]; 
}

