////////////////////////////////////////////////////////////
// Nom: getLlistaVia
// Descripció: Mètode que retorna l'array de tipus de via depenent de l'idioma del formulari
// Paràmetres d'entrada:
// Paràmetres de sortida
//			array - array de tipus de via segons idioma del formulari
////////////////////////////////////////////////////////////    
function getLlistaVia()
{
	var sIdioma = scoGSITVal.getIdiomaTramit();	
	return mapaLlistes[sIdioma];
}

////////////////////////////////////////////////////////////
// Nom: initTipusVia
// Descripció: Mètode que inicialitza la llista de Tipus de Via depenent de l'idioma del formulari que per defecte és CA.
// Paràmetres d'entrada:
//		oTipusVia - Camp de Tipus de Via
//		sIdioma - Idioma en que es mostra la llista de tipus de via. Aquest paràmetre es manté per versions anteriors.
////////////////////////////////////////////////////////////    
function initTipusVia(oTipusVia)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if ((oTipusVia == null) || (oTipusVia == undefined)) return;

		if (oTipusVia.length == 0)
		{	
			scoGSITCombo.inicialitzaLlista(oTipusVia, getLlistaVia());
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITViaInfo::initTipusVia", exc);
	}	
}

////////////////////////////////////////////////////////////
// Nom: canviTipusVia
// Descripció:  Mètode que s'encarrega de fer les modificacions necessàries quan es canvia el Tipus de Via
// Paràmetres d'entrada:
//		oAdreca - Panell d'adreça
////////////////////////////////////////////////////////////  
function canviTipusVia(oAdreca)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		if ((oAdreca == null) || (oAdreca == undefined)) return;

		var oTipusVia = scoGSITPanells.obtenirObjecteFill(oAdreca, "TXT_TIPUS_VIA");
		var oTipusViaNom = scoGSITPanells.obtenirObjecteFill(oAdreca, "TXT_TIPUS_VIA_NOM");

		oTipusViaNom.rawValue = (!scoGSITVal.isEmpty(oTipusVia.editValue)) ? oTipusVia.editValue : "";
		scoGSITAdreca.modifAdreca(oAdreca);
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoGSITViaInfo::canviTipusVia", exc);
	}	
}


////////////////////////////////////////////////////////////
// Nom: obtenirNomTipusVia
// Descripció: Mètode que recupera el nom del tipus de via de la llista predefinida.
// Paràmetres d'entrada:
//		codiArvato - Codi del tipus de via
// Paràmetres de sortida:
//		string - Nom del tipus de via
////////////////////////////////////////////////////////////               
function obtenirNomTipusVia(codiArvato)
{
	var arrVia = getLlistaVia();
	if (arrVia != null && arrVia != undefined)
	{
		for(var i=0; i<arrVia.length; i++)
		{
			if (arrVia[i][1] == codiArvato) return arrVia[i][0];
		}
	}	

	return "";
}

