// VARIABLES

// FUNCIONS


///////////////////////////////////////
//Nom : validaDatesCorrectes
//Paràmetres d'entrada : 
// sData1 : String amb la primera data.
// sData2 : String amb la segona data
//Retorna: Retorna true si sData1 < sData2 i false en cas contrari
//Descripció : Comprova donades dues dates que una sigui menor que l'altra.
//////////////////////////////////////////////////////////////////////
function validaDatesCorrectes(sData1, sData2, sComparacio)
{
	// Si alguna de las 2 es null no comprovem
    if (scoGSITVal.isEmpty(sData1) || scoGSITVal.isEmpty(sData2)) return true;

	// Obtenim la data a partir de l'string
	var oData1 = util.scand("dd/mm/yyyy",sData1);
	var oData2 = util.scand("dd/mm/yyyy", sData2);

	// Si alguna de las 2 es null no comprovem
	if ((oData1 == null) || (oData2 == null)) return true;

	var sData1 = util.printd("yyyymmdd", oData1);
	var sData2 = util.printd("yyyymmdd", oData2);

	var sEval = "parseInt( " + sData1 + ",10)" + sComparacio + "parseInt( " + sData2 + ",10)";
	if(eval(sEval)) return(true);

	return false;

}


///////////////////////////////////////////////////////////////////////
//Nom : formatStringData
//Paràmetres d'entrada : 
// nMes : mes en valor numéric.
// nAny : any amb format aaaa
// nDia : opcional. Si no s'informa s'agafa valor 1
//Retorna: Retorna la data en format dd/mm/aaaa
//Descripció : Formateja la data a partir del dia, mes i any donat
//////////////////////////////////////////////////////////////////////
function formatStringData(nDia, nMes, nAny)
{
	var sDia = nDia.toString();
	var sMes = nMes.toString();

	return (scoSBSStrings.afegeixCarsRep(sDia, "0", 2) + "/" + scoSBSStrings.afegeixCarsRep(sMes, "0", 2) + "/" + nAny);
}     


///////////////////////////////////////////////////////////////////////
//Nom : dataActual
//Paràmetres d'entrada : 
//Retorna:
//Descripció : retorna la data actual en format string dd/mm/yyyy
//////////////////////////////////////////////////////////////////////              
function dataActual()
{
	var oData = new Date();			
	var dataDia = oData.getDate();
	var dataMes = parseInt(oData.getMonth())+1;
	var data = formatStringData(dataDia,dataMes,oData.getFullYear());

	return(data);
}     


///////////////////////////////////////////////////////////////////////
//Nom : validaDataComparaAvui
//Paràmetres d'entrada : 
// sData1
// sComparacio
//Retorna:
//Descripció : compara sData1 amb la data actual segons sComparacio
////////////////////////////////////////////////////////////////////// 
function validaDataComparaAvui(sData1,sComparacio)
{
	var sAvui = dataActual();

	return(validaDatesCorrectes(sData1,sAvui,sComparacio));

}              

///////////////////////////////////////////////////////////////////////
//Nom : validaDataMesAnyMesActual
//Paràmetres d'entrada : 
// sMes
// sAny
// sComparacio
//Retorna:
//Descripció : compara sMes/sAny amb el mes actual
//////////////////////////////////////////////////////////////////////  
function validaDataMesAnyMesActual(sMes,sAny,sComparacio)
{
	var sAvui = dataActual();			

	// Obtenim la data a partir de l'string
	var oDataAvui = util.scand("dd/mm/yyyy", sAvui );

	// Comprovem els anys
	var sDataActual = util.printd("yyyymm", oDataAvui);
	var sData1  =   sAny + scoSBSStrings.afegeixCarsRep(sMes, "0", 2);

	var sEval =  "parseInt( " + sData1 + ",10)" + sComparacio + "parseInt( " + sDataActual + ",10)";
	if(eval(sEval)) 
		return true; 

	return false;

}  
///////////////////////////////////////////////////////////////////////
//Nom : validaDataAnyActual
//Paràmetres d'entrada : 
// sAny
// sComparacio
//Retorna:
//Descripció : compara sAny amb el any actual
//////////////////////////////////////////////////////////////////////  
function validaDataAnyActual(sAny,sComparacio)
{
	var sAvui = dataActual();

	if(parseInt(sAny)<1000) return false;			

	// Obtenim la data a partir de l'string
	var oDataAvui = util.scand("dd/mm/yyyy", sAvui );

	// Comprovem els anys
	var sDataActual = util.printd("yyyy", oDataAvui);
	var sData1  =   sAny;


	var sEval =  "parseInt( " + sData1 + ",10)" + sComparacio + "parseInt( " + sDataActual + ",10)";
	if(eval(sEval)) 
		return true; 

	return false;

}

