// bDesactiva: true-> bloqueja camps en compte de desactivar
//Retorna: 
//Descripció: mostra/oculta un panell segons el valor de bMostrar
//////////////////////////////////////////////////////////////////////
function mostrarOcultarPanell(oPanell, bMostrar, bInvisible)
{
	if(bMostrar)
		oPanell.presence = "visible";
	else{
		oPanell.presence = (!bInvisible) ? "hidden" : "invisible";
		scoGSITGen.netejarForm(oPanell, true);
	}
}

