Data creació : 01/2010
Autor : 
Empresa : Factoria
Nom : scoSBSStrings
Descripció : Mòdul per treballar amb cadenes de text.
**************************************************************************************************************/

// FUNCIONS

//////////////////////////////////////////////////////////////////////
//Nom : afegeixCarsRepDreta
//Paràmetres d'entrada : 
// sTxt: text al que hem d'afegir caràcters.
// sCaracter: lletra que hem d'afegir.
// nCops: cops que hem d'afegir el caràcter 'sCaracter'.
//Retorna: Text inicial amb el text afegit.
//Descripció : Completa 'sTxt' amb 'sCaracter' a la dreta fins a completar els 'nCops' demanats.
//////////////////////////////////////////////////////////////////////
function afegeixCarsRepDreta(sTxt, sCaracter, nCops)
{
	// Comprovem que el valor d'entrada sigui de tipus text
	sTxt = sTxt.toString();

	// Afegim els caràcters
	var nLong = sTxt.length;
	for (var pos = nLong; pos < nCops; pos++)
		sTxt += sCaracter;

	return sTxt;
}

 //////////////////////////////////////////////////////////////////////
//Nom : afegeixCarsRep
//Paràmetres d'entrada : 
// sTxt: text al que hem d'afegir caràcters.
// sCaracter: lletra que hem d'afegir.
// nCops: cops que hem d'afegir el caràcter 'sCaracter'.
//Retorna: Text inicial amb el text afegit.
//Descripció : Completa 'sTxt' amb 'sCaracter' a l'esquerra fins a completar els 'nCops' demanats.
//////////////////////////////////////////////////////////////////////
function afegeixCarsRep(sTxt, sCaracter, nCops)
{
	var sTxtFinal = "";

	// Comprobamos el valor de entrada
	if (typeof(sTxt) != "string")
		sTxt = sTxt.toString();

	// Añadimos los 0s
	var nLong = sTxt.length;
	for (var pos=nLong; pos<nCops; pos++)
		sTxtFinal += sCaracter;

	return sTxtFinal + sTxt;
}

///////////////////////////////////////////////////////////////////////
//Nom : left
//Paràmetres d'entrada : 
// sTxt: text al que hem d'extreure els caracters
// n: num de caracters.
//Retorna: n caracters per l'esquerra del text str.
//Descripció : Extreu n caracters per l'esquerra del text str
//////////////////////////////////////////////////////////////////////

function left(str, n){
	if (n <= 0)
	    return "";
	else if (n > String(str).length)
	    return str;
	else
	    return String(str).substring(0,n);
}

///////////////////////////////////////////////////////////////////////
//Nom : right
//Paràmetres d'entrada : 
// sTxt: text al que hem d'extreure els caracters
// n: num de caracters.
//Retorna: n caracters per la dreta del text str.
//Descripció : Extreu n caracters per la dreta del text str
//////////////////////////////////////////////////////////////////////
function right(str, n){
    if (n <= 0)
       return "";
    else if (n > String(str).length)
       return str;
    else {
       var iLen = String(str).length;
       return String(str).substring(iLen, iLen - n);
    }
}          

///////////////////////////////////////////////////////////////////////
//Nom : RTrim
//Paràmetres d'entrada : 
// sValue
//Retorna: true/false
//Descripció : fer rtrim sobre el string
//////////////////////////////////////////////////////////////////////
function RTrim(sValue)
{
   var whitespace = new String(" \t\n\r");
   var s = new String(sValue);
   if (whitespace.indexOf(s.charAt(s.length-1)) != -1) 
   {
      var i = s.length - 1;
      while (i >= 0 && whitespace.indexOf(s.charAt(i)) != -1)
         i--;
      s = s.substring(0, i+1);
   }
   return s;
}  

///////////////////////////////////////////////////////////////////////
//Nom : LTrim
//Paràmetres d'entrada : 
// sValue
//Retorna: true/false
//Descripció : fer ltrim sobre el string
//////////////////////////////////////////////////////////////////////
function LTrim(str)
{
  var whitespace = new String(" \t\n\r");
  var s = new String(str);

  if (whitespace.indexOf(s.charAt(0)) != -1)
  {
    var j=0;
    var i = s.length;
    while (j < i && whitespace.indexOf(s.charAt(j)) != -1)
      j++;
    s = s.substring(j, i);
  }

  return s;
}

///////////////////////////////////////////////////////////////////////
//Nom : Trim
//Paràmetres d'entrada : 
// sValue
//Retorna: true/false
//Descripció : fer trim sobre el string
//////////////////////////////////////////////////////////////////////
function Trim(str)
{
  return RTrim(LTrim(str));
}  

///////////////////////////////////////////////////////////////////////
//Nom : getPosition
//Paràmetres d'entrada : 
// arrayName
// arrayItem
//Retorna: -1 si no s'ha trobat arrayItem en arrayName
// pos en array de arrayItem en arrayName
//Descripció : obtindre posicio de arrayItem en arrayName
//////////////////////////////////////////////////////////////////////
function getPosition(arrayName,arrayItem)
{
    for(var i=0;i<arrayName.length;i++){ 
       if(arrayName[i]==arrayItem)
            return i;
    }

	return(-1);
}

///////////////////////////////////////////////////////////////////////
//Nom : primerCaracterMajuscula
//Paràmetres d'entrada : 
// sValue
//Retorna: sValue amb el primer caracter amb majuscula
//Descripció : retorna el string rebut amb el primer caracter amb majuscula
//////////////////////////////////////////////////////////////////////
function primerCaracterMajuscula(sValue)
{
	var sVal = String(sValue)
	return(sVal.substring(0,1).toUpperCase() + sVal.substring(1,sVal.length));
}

///////////////////////////////////////////////////////////////////////
//Nom : primerCaracterMinuscula
//Paràmetres d'entrada : 
// sValue
//Retorna: sValue amb el primer caracter amb majuscula
//Descripció : retorna el string rebut amb el primer caracter amb majuscula
//////////////////////////////////////////////////////////////////////
function primerCaracterMinuscula(sValue)
{
	var sVal = String(sValue)
	return(sVal.substring(0,1).toLowerCase() + sVal.substring(1,sVal.length));
}

