/////////////////////////////////////////////////////////////////////////////
// Nom: iniConsentimentBIO
// Descripció: Mètode que s'encarrega d'inicialitzar el panell de consentiment de signatura biomètrica amb les dades de la precàrrega
// Paràmetres d'entrada:
//		oPanell - Panell de consentiment de signatura biomètrica
///////////////////////////////////////////////////////////////////////////// 
function iniConsentimentBIO(oPanell)
{
	try {
		if (scoGSITVal.isEmpty(getValorXMLTextLegalBIO()))
		{
			oPanell.parent.presence = "hidden";
			return;
		}
		oPanell.parent.presence = "visible";

		var oText = oPanell.CONFIRMACIO_TEXT;
		var oTextACK = oPanell.CONFIRMACIO_TEXT_ACK;

		oText.presence = (scoGSITVal.isFormulariAcusament())?"hidden":"visible";
		oTextACK.presence = (scoGSITVal.isFormulariAcusament())?"visible":"hidden";

		if (!scoGSITVal.isFormulariAcusament())		iniTextConsentimentBIO(oPanell);
	}
	catch(exc) {
		scoGSITGen.retornarExcepcio("scoTextEnriquit::iniConsentimentBIO", exc);
	}
}


/////////////////////////////////////////////////////////////////////////////
// Nom: iniTextConsentimentBIO
// Descripció: Mètode que inicialitza el text legal del panell de consentiment BIO
// Paràmetres d'entrada:
//		oPanell - Panell de consentiment de signatura biomètrica
///////////////////////////////////////////////////////////////////////////// 
function iniTextConsentimentBIO(oPanell)
{
	var oCamp = oPanell.CONFIRMACIO_TEXT;
	defCampRichText(oCamp, getValorXMLTextLegalBIO(), false);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: getValorXMLTextLegalBIO
// Descripció: Mètode que retorna el text legal de BIO del XML
// Paràmetres de sortida: valor node del XML
///////////////////////////////////////////////////////////////////////////// 
function getValorXMLTextLegalBIO()
{
	var oTag = xfa.resolveNode("xfa.record.DadesForm.ConsentimentDadesBio.TextLegal"); 
	return scoGSITVal.getValueTagXML(oTag);	
}


///////////////////////////////////////////////////////////////////////
// Nom : defCampRichText
// Descripció: Mètode que inicialitza el valor del camp de text enriquit amb el text (amb entitats)
// Paràmetres d'entrada:
//		oCamp - Camp de text enriquit
//		sText - Text enriquit (pot contenir entitats)
//		bParagraf - Indica si s'ha de definir el paragram
//////////////////////////////////////////////////////////////////////
function defCampRichText(oCamp, sText, bParagraf)
{
	if (!scoGSITVal.existeixObjecte(oCamp))			return;
	if (scoGSITVal.isEmpty(sText))		return;

	var sValorXML = scoGSITExData.maquetaRichTextCamp(obtenirTextLiteral(sText), "padding:0; margin:0", bParagraf);
	scoGSITExData.defValueCampRichText(oCamp, sValorXML);

}

///////////////////////////////////////////////////////////////////////
// Nom : obtenirTextLiteral
// Descripció: 
//////////////////////////////////////////////////////////////////////
function obtenirTextLiteral(sText)
{
	sText = extreureCDataLiteral(sText);
	sText = replaceEtiquetesNoInterpretables(sText);
	sText = scoDecodeHTML.decode(sText);
	return sText;
}

///////////////////////////////////////////////////////////////////////
// Nom : extreureCDataLiteral
// Descripció: 
//////////////////////////////////////////////////////////////////////
function extreureCDataLiteral(sText)
{
	sText = String(sText).replace("&lt;![CDATA[","");
	sText = String(sText).replace("]]&gt;","");	

	sText = String(sText).replace("<![CDATA[","");
	sText = String(sText).replace("]]>","");	

	return String(sText);
}

///////////////////////////////////////////////////////////////////////
// Nom : replaceEtiquetesNoInterpretables
// Descripció: 
//////////////////////////////////////////////////////////////////////
function replaceEtiquetesNoInterpretables(sText)
{
	var aEtiquetes = [["strong","b"],["em","i"]];

	for(var x=0;x<aEtiquetes.length; x++)
	{
		var regex = new RegExp("&lt;" + aEtiquetes[x][0] + "&gt;", 'g');
        sText = sText.replace(regex, "&lt;" + aEtiquetes[x][1] + "&gt;");

        regex = new RegExp("<" + aEtiquetes[x][0] + ">", 'g');
        sText = sText.replace(regex, "<" + aEtiquetes[x][1] + ">");

        regex = new RegExp("&lt;/" + aEtiquetes[x][0] + "&gt;", 'g');
        sText = sText.replace(regex, "&lt;/" + aEtiquetes[x][1] + "&gt;");

        regex = new RegExp("</" + aEtiquetes[x][0] + ">", 'g');
        sText = sText.replace(regex, "</" + aEtiquetes[x][1] + ">");
	}

	return sText;
}

