////////////////////////////////////////////////////////////
// Nom: adrecaPermesa
// Descripció: Comprova si l'adreça definida és correcta per al tipus que pot tenir segons el PV 
// Paràmetres d'entrada: 
//		oAdreca - Panell d'Adreça 
//		sPV - Nom del PV relacionat
//		sTipusAdre - Tipus d'adreca carregada al XML: 'CAT', 'ESP', 'EST', '' BUIDA
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si l'adreça definida és correcta per al tipus que pot tenir segons el PV 
////////////////////////////////////////////////////////////
function adrecaPermesa(sPV, sTipusAdre)
{
	if (sPV == "CAT")      return (sTipusAdre == "CAT");
	else if (sPV == "ESP") return (sTipusAdre == "CAT" || sTipusAdre == "ESP");
	else if (sPV == "EST") return (sTipusAdre == "CAT" || sTipusAdre == "ESP" || sTipusAdre == "EST");
	else return true;
}

////////////////////////////////////////////////////////////
// Nom: adrecaNoPermesa
// Descripció: Comprova si l'adreça definida és incorrecta per al tipus que pot tenir segons el PV 
// Paràmetres d'entrada: 
//		oAdreca - Panell d'Adreça 
//		sPV - Nom del PV relacionat
//		sTipusAdre - Tipus d'adreca carregada al XML: 'CAT', 'ESP', 'EST', '' BUIDA
// Paràmetres de sortida:
//		booleà - Valor (true/false) que indica si l'adreça definida és incorrecta per al tipus que pot tenir segons el PV 
////////////////////////////////////////////////////////////
function adrecaNoPermesa(sPV, sTipusAdre)
{
	return (!adrecaPermesa(sPV, sTipusAdre));
}

////////////////////////////////////////////////////////////
// Nom: tipusAdrecaDefinida
// Descripció: Mètode que retorna el tipus d'adreca definida al panell   
// Paràmetres d'entrada: 
//		oPanell - Panell d'Adreça estrangera
// Paràmetres de sortida:
//		string - Tipus d'adreca carregada al XML: 'CAT', 'ESP', 'EST', '' BUIDA
////////////////////////////////////////////////////////////
function tipusAdrecaDefinida(oAdreca)
{
	try
	{
		var oNode = xfa.resolveNode("xfa.record." + scoGSITPanells.obtenirBindObjecte(oAdreca));

		if (oNode == null) return "";
		else if (scoGSITAdreca.esAdrecaCatalanaXML(oNode, true)) return "CAT";
		else if (scoGSITAdreca.esAdrecaEspanyolaXML(oNode))       return "ESP";
		else if (scoGSITAdreca.esAdrecaEstrangeraXML(oNode))      return "EST";
		else                                                      return "";
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEAdreca.tipusAdrecaDefinida",exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: mostraOcultaCampsEstrangera
// Descripció: Mètode que mostra / oculta els camps i linies d'empresa estrangera
// Paràmetres d'entrada: 
//		oPanell - Panell d'Adreça 
//		sVisibilitat - defineix la visibilitat a definir: 'visible', 'invisible' o 'hidden'
////////////////////////////////////////////////////////////
function mostraOcultaCampsEstrangera(oPanell, sVisibilitat)
{
	var aCamps =  scoGSITCamps.getCampsPanell(oPanell, ["CHK_RESIDENCIA", "SEPARADOR_CHECK"]);
	scoGSITCamps.defCampsVisibilitat(aCamps, sVisibilitat);
}

