////////////////////////////////////////////////////////////
// Nom: defineixCheckResidencia
// Descripció: Mètode que inicialitza el check de residencia a 0 si està buit
// Paràmetres d'entrada: 
//		oPanell - Panell d'Adreça
////////////////////////////////////////////////////////////
function defineixCheckResidencia(oPanell)
{
	scoGSITVal.defValorSiBuit(oPanell, "CHK_RESIDENCIA", "0");
}

////////////////////////////////////////////////////////////
// Nom: initPanellAdrecaTipus
// Descripció: Mètode que inicialitza el panell d'adreca 'oAdreca' segons 'sPV' i 'sTipusAdre'
// Paràmetres d'entrada: 
//		oAdreca - Panell d'Adreça 
//		sPV - Nom del PV relacionat
//		sTipusAdre - Tipus d'adreca carregada al XML: 'CAT', 'ESP', 'EST', '' BUIDA
////////////////////////////////////////////////////////////
function initPanellAdrecaTipus(oAdreca, sPV, sTipusAdre)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		if (sTipusAdre == "") sTipusAdre = ((sPV == "EST") ? "ESP" : sPV); 

		if (sPV == "EST")       initPanellAdrecaEst(oAdreca);
		else if (sPV == "ESP")  initPanellAdrecaEsp(oAdreca);  
		else if (sPV == "CAT")  initPanellAdrecaCat(oAdreca);

		defineixCheckResidencia(oAdreca);					
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEAdreca.initPanellAdrecaTipus",exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: obteAdrecaRequeridor
// Descripció: retorna el panell d'adreça del requeridor de 'oPanell'
// Paràmetres d'entrada:
//		oPanell - Panell del que es vol l'adreça
////////////////////////////////////////////////////////////
function obteAdrecaRequeridor(oPanell)
{
	if (!scoGSITVal.existeixObjecte(oPanell)) return;

	var oRepre = scoGSITPanells.obtenirObjecteFill(oPanell, "REPRESENTANT");
	if (!scoGSITVal.existeixObjecte(oRepre)) return;

	return scoGSITPanells.obtenirObjecteFill(oRepre, "ADRECA_ESTR");
}

////////////////////////////////////////////////////////////
// Nom: initPanellAdreca
// Descripció: Mètode que inicialitza el panell d'adreca 'oAdreca' segons 'sPV' i si està definit 'sPVRepre' la del representant corresponet
// Paràmetres d'entrada: 
//		oAdreca - Panell d'Adreça 
//		sPV - Nom del PV relacionat
//		sPVRepre - Nom del PV relacionat per al representant x si és PJ o Organisme
////////////////////////////////////////////////////////////
function initPanellAdreca(oAdreca, sPV, sPVRepre)
{
	try
	{	
		if (scoGSITVal.isFormulariValidat()) return;

		var sPVTipusAdreca = scoOGEParam.valorParam(sPV);	
		if (sPVTipusAdreca == null)
		{
			scoOGEInicialitzar.mostraOcultaAdreca(sPV, oAdreca);
			scoGSITAdreca.esborraAdreca(oAdreca);
			scoGSITVal.defValorSiBuit(oAdreca, "CHK_RESIDENCIA", "0");
		}
		else
		{	
			var sTipusAdre = tipusAdrecaDefinida(oAdreca);	
			if (adrecaNoPermesa(sPVTipusAdreca, sTipusAdre))
			{
				scoGSITAdreca.esborraAdreca(oAdreca);
				sTipusAdre = "";
			}				
			initPanellAdrecaTipus(oAdreca, sPVTipusAdreca, sTipusAdre);
		}

		// Es fa la del representant x la incialització definida al scoGSITPar a defAdrecaPresentador i defAdrecaRequeridor
		if (arguments.length > 2)  
		{
			var oAdrecaReq = obteAdrecaRequeridor(oAdreca.parent);
			initPanellAdreca(oAdrecaReq, sPVRepre);
		}
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEAdreca.initPanellAdreca",exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: copiaAdrecesEstrToCat
// Descripció: Copia les dades d'una adreça de tipus EXT a una de tipus CAT
// Paràmetres d'entrada:
//		oAdrecaOri - Panell adreça d'origen
//		oPenellDest - Panell adreça de destí
//		oNormalizadorOri - Panell normalitzador d'origen
//		oNormalizadorDest - Panell normalitzador de destí
//		bUnitatPob - Booleà que indica si és una Unitat poblacional (true) o un LLogaret (false)
////////////////////////////////////////////////////////////
function copiaAdrecesEstrToCat(oAdrecaOri, oAdrecaDest, oNormalizadorOri, oNormalizadorDest, bUnitatPob) 
{
	try
	{
		if (arguments.length < 3) oNormalizadorOri = null;
		if (arguments.length < 4) oNormalizadorDest = null;
		if (arguments.length < 5) bUnitatPob = false;

		var aCamps = ["TXT_TIPUS_VIA", "TXT_TIPUS_VIA_NOM", "TXT_NOM_VIA", "TXT_NUM_VIA", 
		              "TXT_BLOC", "TXT_ESCALA", "TXT_PIS", "TXT_PORTA", "TXT_CODI_POSTAL",
					  "TXT_PAIS", "TXT_PAIS_NOM",
					  "LLISTA_PROVINCIES", "LLISTA_PROVINCIES_NOM", "LLISTA_COMARQUES", "LLISTA_COMARQUES_NOM", 
					  "LLISTA_MUNICIPIS", "LLISTA_MUNICIPIS_NOM", "LLISTA_LLOGARETS", "LLISTA_LLOGARETS_NOM", 
		              "TXT_ES_NORMALITZADA", "TXT_ARR_ADRECA", "TXT_MOSTRAR_COMARCA", "TXT_MOSTRAR_PAIS"];

		scoGSITAdreca.esborraAdreca(oAdrecaDest);
		scoGSITGen.amagarRequadresForm(oAdrecaDest);

		// 202012	Si deixem provincies ens canvia la llista de províncies catalanes!!!!   var aCampsLlistes = ["LLISTA_PROVINCIES", "LLISTA_COMARQUES", "LLISTA_MUNICIPIS", "LLISTA_LLOGARETS"];
		var aCampsLlistes = ["LLISTA_COMARQUES", "LLISTA_MUNICIPIS", "LLISTA_LLOGARETS"];
		scoGSITPanells.copiaValorsEntreLlistes(oAdrecaOri, oAdrecaDest, aCampsLlistes) 

		scoGSITPanells.copiaCampsPanells(oAdrecaOri, oAdrecaDest, aCamps);	
		var aLlistesDesti = scoGSITPanells.obtenirArrAdreca(oAdrecaDest);

		var oMunicipis = scoGSITPanells.obtenirObjecteFill(oAdrecaDest, "LLISTA_MUNICIPIS");
		var oLlogarets = scoGSITPanells.obtenirObjecteFill(oAdrecaDest, "LLISTA_LLOGARETS");
		if (scoGSITVal.existeixObjecte(oLlogarets))
		{
			var aLlistesDesti = scoGSITPanells.obtenirArrAdreca(oAdrecaDest);
			var sModul = (bUnitatPob) ? "scoGSITUnitatPobInfo" : "scoGSITLlogInfo";
			scoGSITCombo.carregaSeguentLlista(oMunicipis, oLlogarets, eval(aLlistesDesti[1]), sModul, true);	
		}		

		scoGSITAdreca.copyNormalizador(oNormalizadorOri, oNormalizadorDest);	
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("scoOGEAdreca::copiaAdrecesEstr", exc);
	}			
}


////////////////////////////////////////////////////////////
// Nom: validaIntentNormalitzarAdreca
// Descripció: Mètode que valida que l'usuari hagi intentat com a mínim normalitzar l'adreça
// 			   (només si s'ha seleccionat una adreca catalana). 
//			   No es necessari que ho hagi fet, sino intentat
// Paràmetres d'entrada: 
//		oAdreca - Panell d'adreça 
//		oNormalitzador - Panell normalitzador de l'adreça 
////////////////////////////////////////////////////////////
function validaIntentNormalitzarAdreca(oAdreca, oNormalitzador, msgError)
{
	var result = scoGSITVal.inicialitzarVariableValidacioEspecificaCorrecte();

	if(!scoGSITVal.existeixObjecte(oNormalitzador)) return result;
	if (!scoGSITCamps.esVisibleParents(oAdreca)) return result;

	var bOmplertAdrecaCatalana = scoGSITAdreca.esPanellAdrecaCatalana(oAdreca, false);	
	if(!bOmplertAdrecaCatalana) return result;

	var oIntent = scoGSITPanells.obtenirObjecteFill(oNormalitzador, "TXT_VERIFICAT");
	if(!scoGSITVal.existeixObjecte(oIntent)) return result;

	if(oIntent.rawValue != "1" && !scoGSITAdreca.esNormalitzada(oAdreca))
	{
		result.validacioCorrecte = false;
		result.missatgeError = msgError;
		var oBoto = scoGSITPanells.obtenirObjecteFill(oNormalitzador, "BTN_BUSCAR");
		result.campsIncorrectes = [oBoto];
	}

	return result;

}

