////////////////////////////////////////////////////////////
// Nom: validaTelefonNoEstranger
// Descripció: Mètode que valida que el telèfon no sigui estranger si té marcat rebre SMS
// Paràmetres d'entrada: 
//		oPanellAvisos - Panell d'avisos
////////////////////////////////////////////////////////////
function validaTelefonNoEstranger(oPanellAvisos) 
{
	if (scoGSITVal.isFormulariValidat()) return;
	if (scoGSITVal.isFormulariAcusament()) return;		

	var oChkMobil = scoGSITPanells.obtenirObjecteFill(oPanellAvisos, "CHK_MOBIL");
	if (!scoGSITVal.existeixObjecte(oChkMobil)) return;

	var bValidat = true;		
	if (scoGSITCamps.esVisibleParents(oPanellAvisos) && oChkMobil.rawValue == "sms")
	{
		var oMobil = scoGSITPanells.obtenirObjecteFill(oPanellAvisos.parent, "TXT_TELEFON_MOBIL");
		if (!scoGSITVal.isEmpty(oMobil)) bValidat = scoGSITVal.validarTelefon(oMobil.rawValue);
	}

	scoGSITCamps.campLocalValidat(oChkMobil, bValidat);
}

