	*/
}


////////////////////////////////////////////////////////////
// Nom: initBtnsPlegar
// Descripció: Mètode que inicialitza els botons plegar/desplegar
//			bPlegar - (booleà) true indica que cal plegar i false que cal desplegar
////////////////////////////////////////////////////////////
function initBtnsPlegar(oPanell, bPlegar) 
{
	canviPlegarPanellContacte(oPanell, bPlegar, false, true);
}


////////////////////////////////////////////////////////////
// Nom: estanDCOcultes
// Descripció: Mètode que retorna true si les dades estan ocultes i false en cas contrari
////////////////////////////////////////////////////////////
function estanDCOcultes(oPanell)
{
	return scoGSITCamps.esVisible(getBtnSumar(oPanell));
}

////////////////////////////////////////////////////////////
// Nom: canviPlegarPanellContacte
// Descripció: Mètode que plega/desplega el panell de dades de contacte, i fa els canvis visuals necessaris
// Paràmetres d'entrada:
//			bPlegar - (booleà) true indica que cal plegar i false que cal desplegar
//			bSetFocus - (booleà) indica si cal posicionar el cursor
//			bOcutaDades - (booleà) opcional x defecte = true. Indica si cal ocultar les dades de contacte.
////////////////////////////////////////////////////////////
function canviPlegarPanellContacte(oPanell, bPlegar, bSetFocus, bOcutaDades) 
{
	if (arguments.length < 4)		bOcutaDades = true;

	if (bOcutaDades)		scoSBSMostra.mostrarOcultarPanell(scoGSITPanells.obtenirObjecteFill(oPanell, "CONTACTE"), !bPlegar);

	scoSBSMostra.mostrarOcultarPanell(getSubformBotonsAccio(oPanell), !bPlegar, true);
	scoSBSMostra.mostrarOcultarPanell(getBtnSumar(oPanell), bPlegar);
	scoSBSMostra.mostrarOcultarPanell(getBtnRestar(oPanell), !bPlegar);

	if (bSetFocus) {
		if (bPlegar)		xfa.host.setFocus(getBtnSumar(oPanell).somExpression);
		else				xfa.host.setFocus(getCampContacte(oPanell, "TXT_NOM").somExpression);
	}
}

////////////////////////////////////////////////////////////
// Nom: changeDC
// Descripció: Mètode que s'executa quan hi ha algun canvi en el panell de DC
// Paràmetres d'entrada:
//		bInitBtns - (boolean) opcional x defecte = true
// Paràmetres de sortida:
//		booleà (true|false) - true si hi ha algun camp ple i false en cas contrari
////////////////////////////////////////////////////////////
function changeDC(oPanell, bInitBtns) 
{
	if (arguments.length < 2)			bInitBtns = true;
	var bObligatori = true;		// 12/2019	SEMPRE OBLIGATORI			scoGSITPanells.teAlgunCampPlePanell(oPanell);
	if (scoGSITVal.isFormulariAcusament())		return bObligatori;

	for (var i = 0; i < aOblig.length; i++) {
		scoGSITCamps.assignarCampObligatori(getCampContacte(oPanell, aOblig[i]), bObligatori);
	}

	for (i = 0; i < aObligAdreca.length; i++) {
		scoGSITCamps.assignarCampObligatori(getCampAdreca(oPanell, aObligAdreca[i]), bObligatori);
	}
	corregirObligatorietatCodiPostal(oPanell);

	// Mostrar/ocultar botons
	//		alguncample -> + OCULT  - OCULT   ELIMINAR VISIBLE
	// 		!alguncampple -> + VISIBLE + VISIBLE ELIMINAR OCULT
	/* 12/2019	CANVI : Sempre obligatori NO pleguem i despleguem 
	if (bInitBtns)
	{
		scoSBSMostra.mostrarOcultarPanell(getSubformBotonsPlegar(oPanell), !bObligatori, false);
		scoSBSMostra.mostrarOcultarPanell(getBtnEliminar(oPanell), bObligatori, true);
	}*/
	return bObligatori;
}


////////////////////////////////////////////////////////////
// Nom: corregirObligatorietatCodiPostal
// Descripció: Mètode que corregeix l'obligatorietat del camp CODI_POSTAL
////////////////////////////////////////////////////////////
function corregirObligatorietatCodiPostal(oPanell) 
{
	if (scoGSITVal.isFormulariValidat())			return;

	var bOblig = scoGSITPanells.teAlgunCampPlePanell(oPanell) && !scoINSPItemSeleccio.isCheckMarcat(getCampAdreca(oPanell, "CHK_RESIDENCIA"));
	scoGSITCamps.assignarCampObligatori(getCampAdreca(oPanell, "TXT_CODI_POSTAL"), bOblig);
}

