// Nom: copiaAdrecaDC
// Descripció: Mètode que copia l'adreça de 'oPanellOri' a DC
// Paràmetres d'entrada:
//		oPanellOri - Panell d'adreça origen
////////////////////////////////////////////////////////////
function copiaAdrecaDC(oPanellOri, oPanellContacte)
{
	try
	{
		//if (scoGSITVal.isFormulariValidat()) return;

		var oAdrecaOri = scoGSITPanells.obtenirPanellAdrecaPanellMultiple(oPanellOri, "ADRECA_ESTR"); // Presentador o Requeridor
		var oNormalOri = scoGSITPanells.obtenirPanellNormalitzadorPanellMultiple(oPanellOri);

		var oAdrecaDes = scoGSITPanells.obtenirObjecteFill(oPanellContacte, "ADRECA_ESTR");
		var oNormalDes = scoGSITPanells.obtenirObjecteFill(oPanellContacte, "NORMALITZADOR");

		scoGSITAdreca.copyAdreces(oAdrecaOri, oAdrecaDes, oNormalOri, oNormalDes, false, false);	
		scoOGEAdreca.initPanellAdrecaEst(oAdrecaDes);

		// 202012	SEMPRE OBLIGATORIS!!		changeDC();
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEDC.copiaAdrecaDC",exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: copiaDadesContacte
// Descripció: Mètode que copia els camps de nom/cognoms i identificador del requeridor al panell de Dades de Contacte
// Paràmetres d'entrada:
//		bPregunta - Indica si s'ha de preguntar si es vol realitzar la copia
////////////////////////////////////////////////////////////
function copiaDadesContacte(oPanellContacte, index, bPregunta)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		if (arguments.length < 2) bPregunta = true;	
		var oPanellOrig = scoINSPInspeccionat.getPanellDadesRequeridor(index);

		var sMsgFi = (scoGSITPanells.tipusPersonaPanellMultiple(oPanellOrig) == "PERSONA_FISICA")?"":" " + msgPreguntaCopiarDadesPJFi.value;
		var sMsgCopia = msgPreguntaCopiarDadesRequeridor.value + sMsgFi;


		var bCopia = (bPregunta) ? (scoGSITMissatges.MissatgePregunta(sMsgCopia,"")) : true;
		if (bCopia) 
		{
			 scoGSITEsborrar.esborraDadesPanellDadesIDParticular(oPanellContacte);
			 scoGSITPanells.copiaDadesPersona(oPanellOrig, oPanellContacte, false, true); 
			 copiaAdrecaDC(oPanellOrig, oPanellContacte);
			 return true;
		}
		return false;
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEDC.copiaDadesContacte",exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: copiaDadesContacteAdreca
// Descripció: Mètode que copia els camps de persona i adreça del requeridor al panell de Dades de Contacte
// Paràmetres d'entrada:
//		bPregunta - Indica si s'ha de preguntar si es vol realitzar la copia
////////////////////////////////////////////////////////////
function copiaDadesContacteAdreca(oPanellContacte, index, bCopiaPresentador, bPregunta)  
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		var bPregunta = (scoOGEGeneral.teAlgunCampPlePanell(oPanellContacte) && bPregunta) ? true : false;  
		return copiaDadesContacte(oPanellContacte, index, bPregunta);
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEDC.copiaDadesContacteAdreca",exc);
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : eliminaDadesContacte
// Descripció: neteja el panell de dades de contacte
//////////////////////////////////////////////////////////////////////
function eliminaDadesContacte(oPanell)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;


		if (scoGSITMissatges.MissatgePregunta(msgEliminaDadesContacte.value,""))
		{
			netejaDC(oPanell);
		}				
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEDC.eliminaDadesContacte",exc);
	}	
}

///////////////////////////////////////////////////////////////////////
// Nom : netejaDC
// Descripció: neteja el panell de dades de contacte
//////////////////////////////////////////////////////////////////////
function netejaDC(oPanell)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;

		if (arguments.length < 2)			bAccio = true;		
		scoGSITGen.netejarForm(oPanell);	
		scoGSITAdreca.defPanellAdrecaEstr(scoGSITPanells.obtenirObjecteFill(oPanell, "ADRECA_ESTR"));

		// 202012	SEMPRE OBLIGATORIS!!		changeDC(true);		// forçar obligatorietat camps segons si hi ha o no algun camp ple
		// 202012	SEMPRE OBLIGATORIS!!		if (!estanDCOcultes(oPanell))			canviPlegarPanellContacte(oPanell, true, false, true); 
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEDC.netejaDC",exc);
	}	
}

/////////////////////////////////////////////////////////////////////////////
// Nom: validarInfoContacteSeccio
// Descripció: Mètode que verifica que si és visible, almenys 1 dels camps de 'CONTACTE' estigui definit: 'Telèfon', 'Mòbil' o 'Mail'
// Paràmetres d'entrada:
//		oPanell - Panell a comprovar
//		sMsg - Missatge amb la persona a la que pertany el panell de 'CONTACTE'
// Paràmetres de sortida:
//		resultat - Conté el resultat de la validació específica
/////////////////////////////////////////////////////////////////////////////
function validarInfoContacteSeccio(oPanell, sMsg) 
{	
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (!scoGSITPanells.teAlgunCampPlePanell(oPanell)) return scoGSITVal.inicialitzarVariableValidacioEspecificaCorrecte();	

		return ((scoGSITPanells.esMultiple(oPanell)) ? scoGSITVal.validarInfoContactePanellMultiple(oPanell, sMsg) : scoGSITVal.validarInfoContacte(oPanell, sMsg));													
	}
	catch(exc) 
	{
		return scoGSITGen.retornarExcepcio("scoOGEVal.validarInfoContacteSeccio",exc);
	}
}

