///////////////////////////////////////////////////////////////////////
// Nom : mostraPanellCoordenades
// Descripció: Mètode per mostrar/ocultar les coordenades de l'adreca de l'establiment
// Paràmetres d'entrada: 
//		oPanell - Panell Coordenades 
//		sPresence - presencia
//////////////////////////////////////////////////////////////////////
function mostraPanellCoordenades(oPanell, sPresence)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (!scoGSITVal.existeixObjecte(oPanell)) return;

		oPanell.presence = sPresence;
		xfa.layout.relayout();
	}
	catch(exc) 
	{
		return scoGSITGen.retornarExcepcio("scoOGEstabliment.mostraPanellCoordenades",exc);
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : mostraCoordenades
// Descripció: Mètode per mostrar/ocultar les coordenades de l'adreca de l'establiment
//////////////////////////////////////////////////////////////////////
function mostraCoordenades(oPanellEstabliment)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		// 122020		descomentem per  poder implementar mode visualització		if (!scoGSITCamps.esVisible(oPanellEstabliment)) return;

		var oAdreca = scoGSITPanells.obtenirObjecteFill(oPanellEstabliment, "ADRECA_CAT_LLOGARET");
		if (!scoGSITVal.existeixObjecte(oAdreca)) return;

		var oCoordenades = scoGSITPanells.obtenirObjecteFill(oAdreca, "coordenades");
		if (!scoGSITVal.existeixObjecte(oCoordenades)) return;

		var sPresencePanell = (scoGSITAdreca.esNormalitzada(oAdreca)) ? "visible" : "hidden";
		if (sPresencePanell != oCoordenades.presence) {
			// POS. Deixava de funcionar el mostrar/ocultar, segurament al cridar tantes vegades!
			scoGSITCamps.defVisibilitat(oCoordenades, sPresencePanell);		
		}
	}
	catch(exc) 
	{
		return scoGSITGen.retornarExcepcio("scoOGEstabliment.mostraCoordenades",exc);
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : netejaCoordenadesSiVisible
// Descripció: 
//////////////////////////////////////////////////////////////////////
function netejaCoordenadesSiVisible(oAdreca)
{
	var oCoordenades = scoGSITPanells.obtenirObjecteFill(oAdreca, "coordenades");
	if (!scoGSITVal.existeixObjecte(oCoordenades)) return;

	if (oCoordenades.presence != "visible")		return;
	scoGSITGen.netejarForm(oCoordenades);

	oCoordenades.presence = "hidden";
}

///////////////////////////////////////////////////////////////////////
// Nom : mostraRetolNumTreb
// Descripció: funcio per definir si es mostra o no Rètol i Nº de treballador de l'establiment depenent dels PVs corresponents
//////////////////////////////////////////////////////////////////////
function mostraRetolNumTreb(oPanellEstabliment)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (!scoGSITCamps.esVisible(oPanellEstabliment)) return;

		var sPresRetol = "visible"; // TODO     scoOGEPVs.defVisibilitatDePV("PARAM_MOSTRAR_ESTAB_RETOL", "TXT_RETOL", scoOGEPar.oPanellEstabliment, "visible"); 
		var sPresNumTreb = "hidden"; // TODO     scoOGEPVs.defVisibilitatDePV("PARAM_MOSTRAR_ESTAB_NTREBALLADORS", "TXT_NUM_TREBALLADOR", scoOGEPar.oPanellEstabliment, "visible"); 

		if (sPresNumTreb == "hidden")
		{
			var oRetol = scoGSITPanells.obtenirObjecteFill(oPanellEstabliment, "TXT_RETOL");
			if (scoGSITVal.existeixObjecte(oRetol)) oRetol.w =  "470pt";
		}

		var aVisibilitats = [sPresRetol, sPresNumTreb];
		scoGSITVal.defVisibilitatRel("sLineaSeparador", oPanellEstabliment, aVisibilitats, "visible");		
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEstabliment.mostraRetolNumTreb",exc);
	}	
}

///////////////////////////////////////////////////////////////////////
//Nom : iniEstabliment
//Descripció: Funcio per inicialitzar el panell de dades de l'establiment
//////////////////////////////////////////////////////////////////////
function iniEstabliment(oPanellEstabliment)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (!scoGSITCamps.esVisible(oPanellEstabliment)) return;

		/* TODO Deixem el que hi ha???
		scoOGEPVs.defTitolSeccioDePV(scoOGEPar.oPanellEstabliment, "PARAM_TITULO_ESTABLIMENT");
		if (!scoGSITVal.isFormulariAcusament()) scoOGEPVs.defBotoCopiaTxtPregunta(scoOGEPar.oPanellEstabliment.sBotons.BTN_COPIAR_DADES, "PARAM_TEXT_BOTO_COPIA_ESTABLIMENT", msgPreguntaCopiarDadesAEstabliment, "PARAM_TEXT_PREGUNTA_COPIA_ESTABLIMENT");
*/
		mostraCoordenades(oPanellEstabliment);
		mostraRetolNumTreb(oPanellEstabliment);
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEstabliment.iniEstabliment",exc);
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : netejaEstabliment
// Descripció: funcio per esborrar el panell de dades de l'establiment
//////////////////////////////////////////////////////////////////////
function netejaEstabliment(oPanellEstabliment)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (!scoGSITCamps.esVisible(oPanellEstabliment)) return;

		var oDades =  scoGSITPanells.obtenirObjecteFill(oPanellEstabliment, "dadesIdentificatives");
		if (scoGSITVal.existeixObjecte(oDades)) scoGSITGen.netejarForm(oDades);
		var oAdreca = scoGSITPanells.obtenirObjecteFill(oPanellEstabliment, "ADRECA_CAT_LLOGARET");
		scoGSITEsborrar.esborraDadesPanellAdrecaEsp(oAdreca);
		mostraCoordenades();																	 																																														

		//Netejem perquè sigui obligatori tornar a intentar verificar l'adreça
		var oNormalitzador = scoGSITPanells.obtenirObjecteFill(oPanellEstabliment, "NORMALITZADOR");
		var oIntent = scoGSITPanells.obtenirObjecteFill(oNormalitzador, "TXT_VERIFICAT");
		if(scoGSITVal.existeixObjecte(oIntent)) oIntent.rawValue = "0";																 																																														
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEstabliment.netejaEstabliment",exc);
	}
}

