// Nom : modifAdreca
// Descripció: 
//////////////////////////////////////////////////////////////////////
function modifAdreca(oAdreca)
{
	try
	{
		scoGSITAdreca.modifAdreca(oAdreca);
		netejaCoordenadesSiVisible(oAdreca);																			 																																														
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEstabliment.modifAdreca",exc);
	}
}

