///////////////////////////////////////////////////////////////////////
// Nom : asignaPaisEstabliment
// Descripció: 
//////////////////////////////////////////////////////////////////////
function asignaPaisEstabliment(oPanellEstabliment)
{
	try
	{
		var oAdreca = scoGSITPanells.obtenirObjecteFill(oPanellEstabliment, "ADRECA_CAT_LLOGARET");
		if (!scoGSITVal.existeixObjecte(oAdreca)) return;

		var oPais = scoGSITPanells.obtenirObjecteFill(oAdreca, "TXT_PAIS");
		var oPaisNom  = scoGSITPanells.obtenirObjecteFill(oAdreca, "TXT_PAIS_NOM");

		if (!scoGSITVal.existeixObjecte(oPais)) return;
		if (!scoGSITVal.existeixObjecte(oPaisNom)) return;

		if (teEstabliment())
		{
			oPais.rawValue = "108";
			oPaisNom.rawValue = scoGSITPaisInfo.obtenirNomPaisINE("108");
		}
		else
		{
			oPais.rawValue = "";
			oPaisNom.rawValue = "";
		}

	}catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEstabliment.asignaPaisEstabliment",exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: copiaDadesRequeridorEstabliment
// Descripció: Mètode que copia els camps de requeridor a Establiment
// Paràmetres d'entrada:
//		bPregunta - Indica si s'ha de preguntar si es vol realitzar la copia
// Paràmetres de sortida:
//		booleà - indicant si s'ha fet o no la còpia
////////////////////////////////////////////////////////////
function copiaDadesRequeridorEstabliment(oPanellEstabliment, oPanellRequeridor, bPregunta)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		// VISUALITZACIÓ --> fem còpia encara que estigui ocult		if (!scoGSITCamps.esVisible(oPanellEstabliment)) return;

		var bPregunta = (scoGSITPanells.teAlgunCampPlePanell(oPanellEstabliment) && bPregunta) ? true : false;

		bCopia = (bPregunta) ? (scoGSITMissatges.MissatgePregunta(msgPreguntaCopiarDadesAEstabliment.value,"")) : true;
		if (bCopia) 
		{		
			var oRequeridor = scoGSITPanells.obtenirPersonaPanellMultiple(oPanellRequeridor);
			var bReqEsEmpresa = scoGSITVal.esPanellAmbRepresentant(scoGSITVal.tipusUsuariPanell(oPanellRequeridor)); // PJ / Organisme

			// Retol
			var oRetolEstab = scoGSITPanells.obtenirObjecteFill(oPanellEstabliment, "TXT_RETOL");
			if (bReqEsEmpresa && scoGSITCamps.esVisible(oRetolEstab))
				oRetolEstab.rawValue = scoGSITVal.getValor(scoGSITPanells.obtenirObjecteFill(oRequeridor, "TXT_NOM_EMPRESA"));

			// Adreca
			var oAdrecaReq = scoGSITPanells.obtenirObjecteFill(oRequeridor, "ADRECA_ESTR");	
			if (scoGSITAdreca.esPanellAdrecaCatalana(oAdrecaReq, false))
			{
				var oAdrecaEst = scoGSITPanells.obtenirObjecteFill(oPanellEstabliment, "ADRECA_CAT_LLOGARET");
				scoOGEAdreca.copiaAdrecesEstrToCat(oAdrecaReq, oAdrecaEst, null, null);
			}
		}
		return bCopia;	
	}
	catch(exc) 
	{
		return scoGSITGen.retornarExcepcio("scoOGEEstabliment.copiaDadesRequeridorEstabliment",exc);
	}
}

