/*** TODO revisar a partir d'aquí ****/
////////////////////////////////////////////////////////////
// Nom: netejaDadesAutenticacio
// Descripció: Neteja les dades de autenticació si aquestes NO estan bloquejades (si la precàrrega autenticada NO és correcta)
////////////////////////////////////////////////////////////
function netejaDadesAutenticacio(oPanell)
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (scoGSITVal.isFormulariAcusament()) return;
		if (!scoGSITVal.esFormulariPreOmplert()) return;

		if (!scoGSITVal.existeixObjecte(oPanell)) return;

		var sTipusPersona = scoGSITPanells.tipusPersonaPanellMultiple(oPanell);
		var oPanellPer = scoGSITPanells.obtenirContactePanellMultiple(oPanell, sTipusPersona);
		if (!scoGSITVal.existeixObjecte(oPanellPer)) return null; // Presentador no té Organisme

		var aCamps = ["TXT_TIPUS_IDENTIFICADOR", "TXT_NUM_IDENTIFICADOR", "TXT_PAIS_DOCUMENT"]; // PF o Representant de PJ i Organisme
		scoOGEGeneral.esborraCampsPanellSiEditables(oPanellPer, aCamps);
		scoOGEGeneral.ocultaCampSiEditable(scoGSITPanells.obtenirObjecteFill(oPanellPer, "TXT_PAIS_DOCUMENT"));  // Si esborrem el pais del doc s'oculta

		// Camps d'empresa / organisme 
		if (sTipusPersona == "PERSONA_FISICA") return;

		var aCamps = ["TXT_IDENTIFICADOR_EMPRESA", "TXT_TIPUS_IDENTIFICADOR_EMPRESA"]; 
		scoOGEGeneral.esborraCampsPanellSiEditables(oPanellPer, aCamps);

		var oRepre = scoGSITPanells.obtenirObjecteFill(oPanellPer, "REPRESENTANT");
		scoOGEGeneral.esborraCampsPanellSiEditables(oRepre, ["TXT_PAIS_DOCUMENT"]);
		scoOGEGeneral.ocultaCampSiEditable(scoGSITPanells.obtenirObjecteFill(oPanellPer, "TXT_PAIS_DOCUMENT"));  // Si esborrem el pais del doc s'oculta		
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEFigures.netejaDadesAutenticacio",exc);
	}
}

