/////////////////////////////////////////////////////////////////////////////
// Nom: esMateixIDParticular
// Descripció: Comprova si els IDs de les dades particulars de 'oPerso1' i 'oPerso2' són iguals, en cas de PJ o Organisme mira el del representant
// Paràmetres d'entrada:
//		oPerso1 - 1º persona a mirar
//		oPerso2 - 2º persona a mirar
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si el presentador i el requeridor són la mateixa persona
/////////////////////////////////////////////////////////////////////////////
function esMateixIDParticular(oPerso1, oPerso2)
{
	try
	{		
		if (!scoGSITVal.existeixObjecte(oPerso1) || !scoGSITVal.existeixObjecte(oPerso2)) return false;

		var mapaDocs = { particular: "Particular.Document", 
						 entitat_privada: "Empresa.Representant.Document", 
						 organisme: "Organisme.Representant.Document"};

		var sTipusPerso1 = oPerso1.tipusUsuari.value;
		var sTipusPerso2 = oPerso2.tipusUsuari.value;

		if (!scoGSITVal.esValorTipusUsuariCorrecte(sTipusPerso1) || !scoGSITVal.esValorTipusUsuariCorrecte(sTipusPerso2)) return false;

		return (scoGSITVal.esMateixDocument(oPerso1.resolveNode(mapaDocs[sTipusPerso1]), oPerso2.resolveNode(mapaDocs[sTipusPerso2])) );
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEFigures.esMateixIDParticular",exc);
	} 	
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esMateixaPersonaIDPresReq
// Descripció: Comprova si els IDs de les dades particulars de presentador i requeridor corresponen a la mateixa persona, en cas de PJ o Organisme mira el representant
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si el presentador i el requeridor són la mateixa persona
/////////////////////////////////////////////////////////////////////////////
function esMateixaPersonaIDPresReq()
{
	return esMateixIDParticular(scoGSITVal.getNodePresentador(), scoGSITVal.getNodeRequeridor());				
}

/////////////////////////////////////////////////////////////////////////////
// Nom: esMateixaPersonaIDReqCont
// Descripció: Comprova si els IDs de les dades particulars de requeridor i contacte corresponen a la mateixa persona, en cas de PJ o Organisme mira el representant
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si el presentador i/o el requeridor són la mateixa persona que el Contacte
/////////////////////////////////////////////////////////////////////////////
function esMateixaPersonaIDReqCont()
{			
	return esMateixIDParticular(scoGSITVal.getNodeRequeridor(), scoGSITVal.getNodeDadesContacte());		
}	

/////////////////////////////////////////////////////////////////////////////
// Nom: esMateixaPersonaIDPresReqCont
// Descripció: Comprova si els IDs de les dades particulars de presentador, requeridor i contacte corresponen a la mateixa persona, en cas de PJ o Organisme mira el representant
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si el presentador i/o el requeridor són la mateixa persona que el Contacte
/////////////////////////////////////////////////////////////////////////////
function esMateixaPersonaIDPresReqCont()
{
	var oContacte = scoGSITVal.getNodeDadesContacte();
	return (esMateixIDParticular(scoGSITVal.getNodePresentador(), oContacte) ||
	        esMateixIDParticular(scoGSITVal.getNodeRequeridor(),  oContacte) );
}

