/////////////////////////////////////////////////////////////////////////////
// Nom: defVisibilitatRelPanellsoCamps
// Descripció: Mètode que defineix la visibilitat de 'oPanelloCamp' segons les visibilitats de 'aPanellsoCamps'
// Paràmetres d'entrada:
//		oPanelloCamp - Panell o Camp a mostrar u ocultar
//		aPanellsoCamps - Array de Panells o Camps amb les visibilitats relacionades
///////////////////////////////////////////////////////////////////////////// 
function defVisibilitatRelPanellsoCamps(oPanelloCamp, aPanellsoCamps)
{
	var n = 0;
	var sPresence = "hidden";
	var numElems = aPanellsoCamps.length;
	do
	{
		sPresence = aPanellsoCamps[n++].presence;
	}
	while (n<numElems && sPresence != "visible");

	scoGSITCamps.defVisibilitat(oPanelloCamp, sPresence);
}	

/////////////////////////////////////////////////////////////////////////////
// Nom: defVisibilitatRelPanellDelsSeusSubforms
// Descripció: Mètode que defineix la visibilitat de 'oPanelloCamp' segons les visibilitats de 'oCamps'
// Paràmetres d'entrada:
//		oPanelloCamp - Panell o Camp a mostrar u ocultar
//		oCamps - camps relacionats
//		sExcepcio - Nom del panell que no aplica
///////////////////////////////////////////////////////////////////////////// 
function defVisibilitatRelPanellDelsSeusSubforms(oPanelloCamp, oCamps, sExcepcio)
{
	if (!scoGSITVal.existeixObjecte(oPanelloCamp)) return;
	if (!scoGSITVal.existeixObjecte(oCamps)) return;

	var n = 0;
	var sPresence = "hidden";
	var numElems = oCamps.length;
	do
	{
		var oCamp = oCamps.item(n++);
		if ((oCamp.className == "subform") && (oCamp.name != sExcepcio))  sPresence = oCamp.presence;	
	}
	while (n<numElems && sPresence != "visible");

	scoGSITCamps.defVisibilitat(oPanelloCamp, sPresence);
}


///////////////////////////////////////////////////////////////////////
// Nom : defBotoWVariesLinies
// Descripció: Funció que defineix l'amplada del botó per tal de que sigui fixe i es mostri en varies línies
// Paràmetres d'entrada:
//		oBtn - Botó a definir
//		nW - Ample que s'ha de definir al botó
//////////////////////////////////////////////////////////////////////
function defBotoWVariesLinies(oBtn, nW)
{
	oBtn.minW = "0 in";
	oBtn.w = nW + " pt";
	return nW;
}

///////////////////////////////////////////////////////////////////////
// Nom : defBotoMargin
// Descripció: Funció que defineix l'amplada del botó en funció de la pàgina i el marge per tal de posar-lo a la dreta de la pàgina
// Paràmetres d'entrada:
//		oSubBotons - subformulari que conté el botó i el subformulari de marge
//		oBtn1 - Botó a definir
//		oMargin - Subformulari de marge a definir per tal de posar el botó a la dreta de la pàgina
//		nMargin - Integer que indica el marge en amplada definit i que s'ha de tenir en compte
//////////////////////////////////////////////////////////////////////
function defBotoMargin(oSubBotons, oBtn1, oMargin, nMargin)
{
	if (scoGSITVal.isFormulariAcusament()) return;  // ACK no té botons
	if (scoGSITVal.isFormulariValidat()) return;
	if (!scoGSITVal.existeixObjecte(oSubBotons) || !scoGSITVal.existeixObjecte(oBtn1) || !scoGSITVal.existeixObjecte(oMargin)) return;

	if (scoGSITCamps.comprovaVisibleParent(oSubBotons) == 0) return; 

	if (arguments.length < 4) nMargin = 0;

	var pageW = parseInt(xfa.layout.w(oSubBotons, "pt"), 10);
	var btn1W = parseInt(xfa.layout.w(oBtn1, "pt"), 10);

	if ((btn1W + nMargin) > (pageW/2))
	{
		var nW = (pageW-nMargin)/2;
		if (btn1W > nW) btn1W = defBotoWVariesLinies(oBtn1, nW);
	}

	var wMargin = (pageW - (btn1W + nMargin + 1));
	oSubBotons.sMargin.w = (wMargin >= 1) ? (wMargin + "pt") : "0 pt";	
}

///////////////////////////////////////////////////////////////////////
// Nom : defBotonsMargin
// Descripció: Funció que defineix l'amplada de 2 botons en funció de la pàgina i el marge per tal de posar-lo a la dreta de la pàgina
// Paràmetres d'entrada:
//		oSubBotons - subformulari que conté el botons i el subformulari de marge
//		oBtn1 - 1º Botó a definir
//		oBtn2 - 2º Botó a definir
//		oMargin - Subformulari de marge a definir per tal de posar el botó a la dreta de la pàgina
//		nMargin - Integer que indica el marge en amplada definit i que s'ha de tenir en compte
//////////////////////////////////////////////////////////////////////
function defBotonsMargin(oSubBotons, oBtn1, oBtn2, oMargin, nMargin)
{
	if (scoGSITVal.isFormulariAcusament()) return;  // ACK no té botons
	if (scoGSITVal.isFormulariValidat()) return;
	if (!scoGSITVal.existeixObjecte(oSubBotons) || !scoGSITVal.existeixObjecte(oBtn1) || !scoGSITVal.existeixObjecte(oBtn1) || 
	    !scoGSITVal.existeixObjecte(oMargin)) return;
	if (scoGSITCamps.comprovaVisibleParent(oSubBotons) == 0) return; 

	if (arguments.length < 5) nMargin = 0;

	if (scoGSITCamps.comprovaVisibleParent(oBtn1) == 0) 
	{
		defBotoMargin(oSubBotons, oBtn2, oMargin, nMargin);
	}
	else
	{
		var pageW = parseInt(xfa.layout.w(oSubBotons, "pt"), 10);
		var btn1W = parseInt(xfa.layout.w(oBtn1, "pt"), 10);
		var btn2W = parseInt(xfa.layout.w(oBtn2, "pt"), 10);

		if ((btn1W + btn2W + nMargin) > pageW)
		{
			var nW = (pageW-nMargin)/2;
			if (btn1W > nW) btn1W = defBotoWVariesLinies(oBtn1, nW);
			if (btn2W > nW) btn2W = defBotoWVariesLinies(oBtn2, nW);		
		}

		var wMargin = (pageW - (btn1W + btn2W + nMargin + 1));
		oSubBotons.sMargin.w = (wMargin >= 1) ? (wMargin + "pt") : "0 pt";	
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : defVisibleXIndex
// Descripció: Funció que defineix la visibilitat de 'oObjecte' en funció de 'nIndex', si és 0 l'oculta sinò el mostra
// Paràmetres d'entrada:
//		oObjecte - Objecte a mostrar/ocultar
//		nIndex - número que indicarà si mostrar o no 'oObjecte'
//////////////////////////////////////////////////////////////////////
function defVisibleXIndex(oObjecte, nIndex)
{
	var sPresencia = ((nIndex == 0) ? "hidden" : "visible");
	scoGSITCamps.defVisibilitat(oObjecte, sPresencia);
}

///////////////////////////////////////////////////////////////////////
// Nom : defBtnBloquejatXIndex
// Descripció: Funció que defineix la visibilitat de 'oObjecte' en funció de 'nIndex', si és 0 l'oculta sinò el mostra
// Paràmetres d'entrada:
//		oBtn - Botó a bloquejar/desbloquejar
//		nIndex - número que indicarà si mostrar o no 'oObjecte'
//		nMax - Número max que pot tenir
//////////////////////////////////////////////////////////////////////
function defBtnBloquejatXIndex(oBtn, nIndex, nMax)
{
	if (nIndex == nMax) 
		scoGSITBot.canviEstatAcceptar(0, null, oBtn);	
	else
		scoGSITBot.canviEstatAcceptar(1, "0,0,0", oBtn);
}

///////////////////////////////////////////////////////////////////////
// Nom : defAlturaBlocDe2Camps
// Descripció: Funció que defineix l'altura d'un bloc en funcio de 2 camps
// Paràmetres d'entrada:
//		oBloc - Bloc a definir
//		oCamp1 - Camp 1
//		oCamp2 - Camp 2
//////////////////////////////////////////////////////////////////////
function defAlturaBlocDe2Camps(oBloc, oCamp1, oCamp2)
{
	if(!scoGSITVal.isFormulariValidat()) 
	{
		var nAltura1 = (parseInt(xfa.layout.h(oCamp1, "pt"), 10));
		var nAltura2 = (parseInt(xfa.layout.h(oCamp2, "pt"), 10));

		var hCamps = (Math.max(nAltura1, nAltura2) + 8) + "pt";
		if (oBloc.h != hCamps)  oBloc.h = hCamps;
		xfa.layout.relayout();	
	} 
}

////////////////////////////////////////////////////////////
// Nom: isArray
// Descripció: retorna true si oParam es un array
// Paràmetres d'entrada:
//		oParam - Paràmetre que s'ha de mirar per veure si és un array
////////////////////////////////////////////////////////////
function isArray(oParam)
{
	try
	{
		if (typeof(oParam) != "object") return false;

		if(!scoGSITVal.existeixPropietat1Nivell(oParam,"length")) return false;
		return(String(oParam.length) != "undefined");
	}
	catch(exc) 
	{
		return scoGSITGen.retornarExcepcio("scoOGEGeneral.isArray",exc);
	}
}

////////////////////////////////////////////////////////////
// Nom: mostra_o_oculta
// Descripció: Si 'bMostra' és true mostra 'oObject' sinò l'oculta 
////////////////////////////////////////////////////////////
function mostra_o_oculta(oObject, bMostra)
{
	if (scoGSITVal.isFormulariValidat()) return;

	scoGSITCamps.defVisibilitat(oObject, ((bMostra) ? "visible" : "hidden"));
}

////////////////////////////////////////////////////////////
// Nom: activa_o_desactiva
// Descripció: Si 'bActiva' és true defineix 'oObject' com open sinò protected
// Paràmetres d'entrada: 
//		oObject - Objecte a definir
//		bActiva - Si true serà open sinò protected
////////////////////////////////////////////////////////////
function activa_o_desactiva(oObject, bActiva)
{
	if (scoGSITVal.isFormulariValidat()) return;
	if (!scoGSITVal.existeixObjecte(oObject)) return;

	oObject.access = (bActiva) ? "open" : "protected";
}

////////////////////////////////////////////////////////////
// Nom: activaDesactivaCamps
// Descripció: Si 'bActiva' és true defineix els objectes de 'aCamps' com open sinò protected
// Paràmetres d'entrada: 
//		aCamps - Array dels camps a definir
//		bActiva - Si true serà open sinò protected
////////////////////////////////////////////////////////////
function activaDesactivaCamps(aCamps, bActiva)
{
	if (scoGSITVal.isFormulariValidat()) return;

	var sEstat = (bActiva) ? "open" : "protected";

	var numCamps = aCamps.length;
	for (var n=0; n<numCamps; n++) aCamps[n].access = sEstat;
}


////////////////////////////////////////////////////////////
// Nom: desbloquejaCamp
// Descripció:  Mètode que desbloqueja 'oCamp' si està buit i és visible
// Paràmetres d'entrada:
//		oCamp - Camp a tractar
////////////////////////////////////////////////////////////
function desbloquejaCamp(oCamp)
{	
	if (!scoGSITVal.existeixObjecte(oCamp)) return;

	if (scoGSITVal.isEmpty(oCamp) && oCamp.presence == "visible")
	{
		oCamp.mandatory = "error";
		oCamp.access = "open";
	}
}

////////////////////////////////////////////////////////////
// Nom: desbloquejaCampsPanell
// Descripció:  Mètode que desbloqueja els camps de 'aCamps' de 'oPanell' si estan buits
// Paràmetres d'entrada:
//		oPanell - Panell a tractar
//		aCamps - Camps de 'oPanell' a tractar
////////////////////////////////////////////////////////////
function desbloquejaCampsPanell(oPanell, aCamps)
{	
	if (!scoGSITVal.existeixObjecte(oPanell)) return;

	var nCamps = aCamps.length;
	for (var n=0; n<nCamps; n++)
	{
		desbloquejaCamp(scoGSITPanells.obtenirObjecteFill(oPanell, aCamps[n]));
	}
}

////////////////////////////////////////////////////////////
// Nom: esborraCampSiEditable
// Descripció: Mètode que oculta 'oCamp' si està editable
// Paràmetres d'entrada:
//		oCamp - Camp a tractar
////////////////////////////////////////////////////////////    
function ocultaCampSiEditable(oCamp)
{
	if (!scoGSITVal.existeixObjecte(oCamp)) return;

	if (oCamp.access == "open") oCamp.presence = "invisible";
}					

////////////////////////////////////////////////////////////
// Nom: ocultaCampsPanellSiEditables
// Descripció:  Mètode que oculta els camps de 'aCamps' de 'oPanell' si estan editable
// Paràmetres d'entrada:
//		oPanell - Panell a tractar
//		aCamps - Camps de 'oPanell' a tractar
////////////////////////////////////////////////////////////
function ocultaCampsPanellSiEditables(oPanell, aCamps)
{	
	if (!scoGSITVal.existeixObjecte(oPanell)) return;

	var nCamps = aCamps.length;
	for (var n=0; n<nCamps; n++)
	{
		ocultaCampSiEditable(scoGSITPanells.obtenirObjecteFill(oPanell, aCamps[n]));
	}
}

////////////////////////////////////////////////////////////
// Nom: esborraCampSiEditable
// Descripció: Mètode que esborra 'oCamp' si està editable
// Paràmetres d'entrada:
//		oCamp - Camp a tractar
////////////////////////////////////////////////////////////    
function esborraCampSiEditable(oCamp)
{
	if (!scoGSITVal.existeixObjecte(oCamp)) return;

	if (oCamp.access == "open")
	{
		oCamp.rawValue = "";
		scoGSITVal.amagarRequadre(oCamp);	
	}
}					

////////////////////////////////////////////////////////////
// Nom: esborraCampsPanellSiEditables
// Descripció:  Mètode que esborra els camps de 'aCamps' de 'oPanell' si estan editable
// Paràmetres d'entrada:
//		oPanell - Panell a tractar
//		aCamps - Camps de 'oPanell' a tractar
////////////////////////////////////////////////////////////
function esborraCampsPanellSiEditables(oPanell, aCamps)
{	
	if (!scoGSITVal.existeixObjecte(oPanell)) return;

	var nCamps = aCamps.length;
	for (var n=0; n<nCamps; n++)
	{
		esborraCampSiEditable(scoGSITPanells.obtenirObjecteFill(oPanell, aCamps[n]));
	}
}

////////////////////////////////////////////////////////////
// Nom: obtenirNomCognom
// Descripció: Retorna el nom i dognoms de 'oPanellPersona'
////////////////////////////////////////////////////////////
function obtenirNomCognom(oPanellPersona)
{
	if (scoGSITVal.isFormulariValidat()) return;

	var oNom = scoGSITPanells.obtenirObjecteFill(oPanellPersona, "TXT_NOM");
	var oCognom1 = scoGSITPanells.obtenirObjecteFill(oPanellPersona, "TXT_COGNOM1");
	var oCognom2 = scoGSITPanells.obtenirObjecteFill(oPanellPersona, "TXT_COGNOM2");

	var nom = scoGSITVal.isEmpty(oNom) ? "" : oNom.rawValue;
	var cognom1 = scoGSITVal.isEmpty(oCognom1) ? "" : oCognom1.rawValue;
	var cognom2 = scoGSITVal.isEmpty(oCognom2) ? "" : oCognom2.rawValue;
	var usuari = nom + " " + cognom1 + " " + cognom2;

	return usuari;
}

/////////////////////////////////////////////////////////////////////////////
// Nom : teAlgunCampPlePanell
// Descripció: Mètode que controla si el panell té algun camp definit amb valor
// Paràmetres d'entrada: 
//		oPanell - Panell a revisar
// Paràmetres de sortida:
//		booleà - Valor (true/false) resultant de la verificació
/////////////////////////////////////////////////////////////////////////////
function teAlgunCampPlePanell(oPanell)
{
	try
	{
		if (!scoGSITVal.existeixObjecte(oPanell)) return false;

		var oNodesPanell = oPanell.nodes; 
		var nElements = oNodesPanell.length;
		for (var n=0; n< nElements; n++)
		{
			var oCamp = oNodesPanell.item(n);
			if (scoGSITNod.esObjeteTipusCamp(oCamp) && scoGSITCamps.esVisible(oCamp))	
			{ 
				if (!scoGSITVal.isEmpty(oCamp)) return true;
			}
			else if (oCamp.className == "subform") 
			{
				if (teAlgunCampPlePanell(oCamp)) return true;
			}
		}

		return false;
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEGeneral.teAlgunCampPlePanell",exc);
	}			
} 

/////////////////////////////////////////////////////////////////////////////
// Nom: getValorVariable
// Descripció: Mètode que obté el valor de la varaible del formulari 'sNom', si no existeix ""
// Paràmetres d'entrada:
//		sNom - No de la variable 
// Paràmetres de sortida:
//		string - Text amb el valor de la variable o "" si no existeix
///////////////////////////////////////////////////////////////////////////// 
function getValorVariable(sNom)
{
	var oVariable = xfa.resolveNode("xfa.form.nodes.item(0).#variables[0]." + sNom);
	return (scoGSITVal.existeixObjecte(oVariable) ? eval(sNom + ".value") : "");
}

/////////////////////////////////////////////////////////////////////////////
// Nom: definirPVs
// Descripció: Mètode que reemplaça els links que conté el text de tipus @LINK_NOM@ per la maquetació en HTML del link, posant com texte el contingut de la variable LINK_NOM_TXT i com a URL el contingut de la variable LINK_NOM
// Paràmetres d'entrada:
//		sText - Text a reemplaçar els @LINK_NOM@ pel tag a de HTML definit
// Paràmetres de sortida:
//		string - Text amb els tag a de HTML definits enlloc dels @LINK_NOM@
///////////////////////////////////////////////////////////////////////////// 
function definirPVs(sText)
{
	if (scoGSITVal.isEmpty(sText)) return ""; 

	var posLink = sText.indexOf("@PV"); 
	if (posLink == -1)
	{		
		return sText;
	}
	else
	{
		var posFiLink = sText.indexOf("@", (posLink+1)); 
		var sLink = sText.substring(posLink, (posFiLink+1));

		var sPV = sLink.replace(/@/g, "");
		var sValor = scoOGEParam.valorPV(sPV, true);		// Agafem el valor del PV definit x l'idioma, sinò el de la varible definida per aquest PV i sinò buit 
		var sValor = (scoGSITVal.isEmpty(sValor) ? getValorVariable(sPV + "_TXT") : sValor);

		sText = sText.replace(sLink, sValor);
		return definirPVs(sText);		
	}
}

/////////////////////////////////////////////////////////////////////////////
// Nom: definirLinks
// Descripció: Mètode que reemplaça els links que conté el text de tipus @LINK_NOM@ per la maquetació en HTML del link, posant com texte el contingut de la variable LINK_NOM_TXT i com a URL el contingut de la variable LINK_NOM
// Paràmetres d'entrada:
//		sText - Text a reemplaçar els @LINK_NOM@ pel tag a de HTML definit
// Paràmetres de sortida:
//		string - Text amb els tag a de HTML definits enlloc dels @LINK_NOM@
///////////////////////////////////////////////////////////////////////////// 
function definirLinks(sText)
{
	if (scoGSITVal.isEmpty(sText)) return ""; 

	var posLink = sText.indexOf("@LINK_"); 
	if (posLink == -1)
	{		
		return sText;
	}
	else
	{
		var posFiLink = sText.indexOf("@", (posLink+1)); 
		var sLink = sText.substring(posLink, (posFiLink+1));

		var sNomVariable = sLink.replace(/@/g, "");
		var sURLLink = eval(sNomVariable + ".value");   // Agafem el valor de les variables definides pel nom i per la URL 
		var sNomLink = eval(sNomVariable + "_TXT.value");
		var sURLMaquetat = scoGSITExData.maquetaLink(sURLLink, sNomLink);
		sText = sText.replace(sLink, sURLMaquetat);
		return definirLinks(sText);		
	}
}

/////////////////////////////////////////////////////////////////////////////
// Nom: defText
// Descripció: Mètode que s'encarrega de definir el text per tipus: label de text, botó, camp de check,...
// Paràmetres d'entrada:
//		oCamp - Camp a definir
//		sText - Valor del text a definir
///////////////////////////////////////////////////////////////////////////// 
function defText(oCamp, sText)
{
	if (!scoGSITVal.existeixObjecte(oCamp)) return;
	if (scoGSITVal.isEmpty(sText)) sText = "";

	oCamp.value.text.value = sText;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: getText
// Descripció: Mètode que retorna el text per tipus: label de text, botó, camp de check,...
// Paràmetres d'entrada:
//		oCamp - Camp a definir
// Paràmetres de sortida:
//		string - Valor del text de 'sText'
///////////////////////////////////////////////////////////////////////////// 
function getText(oCamp)
{
	if (!scoGSITVal.existeixObjecte(oCamp)) return "";

	var sTxt = oCamp.value.text.value;
	return ((scoGSITVal.isEmpty(sTxt)) ? "" : sTxt);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: defCaption
// Descripció: Mètode que s'encarrega de definir el text de Caption per tipus: label de text, botó, camp de check,...
// Paràmetres d'entrada:
//		oCamp - Camp a definir
//		sText - Valor del text a definir
///////////////////////////////////////////////////////////////////////////// 
function defCaption(oCamp, sText)
{
	if (!scoGSITVal.existeixObjecte(oCamp)) return;
	if (scoGSITVal.isEmpty(sText)) sText = "";

	oCamp.caption.value.text.value = sText;
}

/////////////////////////////////////////////////////////////////////////////
// Nom: getCaption
// Descripció: Mètode que retorna el text de Caption per tipus: label de text, botó, camp de check,...
// Paràmetres d'entrada:
//		oCamp - Camp a definir
// Paràmetres de sortida:
//		string - Valor del text de 'sText'
///////////////////////////////////////////////////////////////////////////// 
function getCaption(oCamp)
{
	if (!scoGSITVal.existeixObjecte(oCamp)) return "";

	var sTxt = oCamp.caption.value.text.value;
	return ((scoGSITVal.isEmpty(sTxt)) ? "" : sTxt);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: defTextCampPanell
// Descripció: Mètode que s'encarrega de definir el text de 'sCamp' de tipus: label de text, botó, camp de check,...
// Paràmetres d'entrada:
//		sCamp - Nom del Camp a definir
//		oPanell - Panell que conté a 'sCamp'
//		sText - Valor del text a definir en 'sCamp'
///////////////////////////////////////////////////////////////////////////// 
function defTextCampPanell(sCamp, oPanell, sText)
{
	if (!scoGSITVal.existeixObjecte(oPanell)) return;
	if (scoGSITVal.isEmpty(sCamp)) return;
	if (scoGSITVal.isEmpty(sText)) sText = "";

	defText(scoGSITPanells.obtenirObjecteFill(oPanell, sCamp), sText);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: defCaptionCampPanell
// Descripció: Mètode que s'encarrega de definir el caption de 'sCamp' de tipus: label de text, botó, camp de check,...
// Paràmetres d'entrada:
//		sCamp - Nom del Camp a definir
//		oPanell - Panell que conté a 'sCamp'
//		sText - Valor del text a definir en 'sCamp'
///////////////////////////////////////////////////////////////////////////// 
function defCaptionCampPanell(sCamp, oPanell, sText)
{
	if (!scoGSITVal.existeixObjecte(oPanell)) return;
	if (scoGSITVal.isEmpty(sCamp)) return;
	if (scoGSITVal.isEmpty(sText)) sText = "";

	defCaption(scoGSITPanells.obtenirObjecteFill(oPanell, sCamp), sText);
}

////////////////////////////////////////////////////////////
// Nom: defCampBloquejats
// Descripció: Mètode de definició de les propietats d'un camp
// Paràmetres d'entrada:  
//		oPanell - panell on està definit el camp
//		aNomCamps - array amb els noms dels camps a bloquejar
////////////////////////////////////////////////////////////
function defCampBloquejats(oPanell, aNomCamps)
{
	for (var n=0; n<aNomCamps.length; n++) defCampBloquejat(oPanell, aNomCamps[n]);
} 

////////////////////////////////////////////////////////////
// Nom: defCampsProp
// Descripció: Mètode que defineix propietats de camps
// Paràmetres d'entrada:  
//		aCamps - Llista de camps a definir
//		sAcces - Valor a assignar a la propietat 'access'
//		sValidacio - Valor a assignar a la propietat 'validate.nullTest'
//		sPresencia - Valor a assignar a la propietat 'presence'
//		sValor - Valor al valor del camp
////////////////////////////////////////////////////////////
function defCampsProp(aCamps, sAcces, sValidacio, sPresencia, sValor)
{
	try
	{
		for (var n=0; n<aCamps.length; n++) 
		{
			if (arguments.length < 5) sValor = scoGSITVal.getValor(aCamps[n]);
			scoGSITPanells.defCampPropietats(aCamps[n], sAcces, sValidacio, sPresencia, sValor);
		}
	}
	catch(exc)
	{
		scoGSITGen.retornarExcepcio("defCampsPropietats", exc);
	}				
}

