var aNomCampsNotifMultiple = ["TXT_NOM", "TXT_COGNOM1", "TXT_COGNOM2", "TXT_TIPUS_IDENTIFICADOR", "TXT_NUM_IDENTIFICADOR", "TXT_TELEFON_MOBIL", "TXT_ADRECA_ELECTRONICA", "TXT_PAIS_DOCUMENT", "TXT_PAIS_DOCUMENT_NOM"];						  

