///////////////////////////////////////////////////////////////////////
// Nom : teNotificacions
// Descripció: Mètode que retorna si té notificacions
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si té notificacions
//////////////////////////////////////////////////////////////////////
function teNotificacions()
{
	// PF i PJ segons PV08, ORG mai
	var sTipusSol = scoGSITVal.tipusUsuariPanell(scoGSITPar.oPanellRequeridor);
	return ( (sTipusSol == "particular") || (sTipusSol == "entitat_privada"));
}

///////////////////////////////////////////////////////////////////////
// Nom : teBotoCopiarDades
// Descripció: Mètode que retorna si ha de tenir el botó de copiar dades
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si ha de poder copiar dades
//////////////////////////////////////////////////////////////////////
function teBotoCopiarDades()
{
	// ORG mai
	var sTipusSol = scoGSITVal.tipusUsuariPanell(scoGSITPar.oPanellRequeridor);
	return (sTipusSol == "particular" || sTipusSol == "entitat_privada");
}

///////////////////////////////////////////////////////////////////////
// Nom : esNotificacioInformo
// Descripció: Mètode que retorna si té notificacions informo - Obligació
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si té notificacions informo
//////////////////////////////////////////////////////////////////////
function esNotificacioInformo()
{
	var sTipusSol = scoGSITVal.tipusUsuariPanell(scoGSITPar.oPanellRequeridor);

	// PF segons PV08, PJ sempre, ORG mai
	if (sTipusSol == "particular") return false;//TODO revisar que sea correcto (scoOGEParam.valorParam("PARAM_NOTIF_AUTORIT_INFORMO") == "I");
	else if (sTipusSol == "entitat_privada") return true; 
	else return false;
}

///////////////////////////////////////////////////////////////////////
// Nom : esNotificacioCheck
// Descripció: Mètode que retorna si té notificacions check - Consentiment
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si té notificacions check
//////////////////////////////////////////////////////////////////////
function esNotificacioCheck()
{
	var sTipusSol = scoGSITVal.tipusUsuariPanell(scoGSITPar.oPanellRequeridor);

	// PF segons PV08, PJ mai, ORG mai
	if (sTipusSol == "particular") return true; // TODO revisar que sea correcto (scoOGEParam.valorParam("PARAM_NOTIF_AUTORIT_INFORMO") != "I");
	else return false;
}



///////////////////////////////////////////////////////////////////////
// Nom : esNotificacioMultiple
// Descripció: Mètode que retorna si el tipus de Notificació definida és la múltiple
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si és la múltiple
//////////////////////////////////////////////////////////////////////
function esNotificacioMultiple()
{
	return teNotificacions();
}

///////////////////////////////////////////////////////////////////////
// Nom : numNotifiacions
// Descripció: Funció que retorna el nombre de persones de les notificacions multiples
// Paràmetres d'entrada:
//		oTaula - Bloc de les persones de les notificacions multiples
//////////////////////////////////////////////////////////////////////
function numNotifiacions(oTaula)
{
	return (oTaula._FILA_DADES_IDENTIFICATIVES.count);
}

///////////////////////////////////////////////////////////////////////
// Nom : numMaxPersones
// Descripció: Funció que retorna el nombre de persones màximes de les notificacions multiples
// Paràmetres d'entrada:
//		oTaula - Bloc de les persones de les notificacions multiples
//////////////////////////////////////////////////////////////////////
function numMaxPersones(oTaula)
{
	return (oTaula._FILA_DADES_IDENTIFICATIVES.occur.max);
}

///////////////////////////////////////////////////////////////////////
// Nom : getBlocPersona
// Descripció: Funció que retorna el subformulari de les dades de la persona del que cal copiar la info a les Notificacions
// Paràmetres d'entrada:
//		oTaula - Subformulari de la persona a copiar
//////////////////////////////////////////////////////////////////////
function getBlocPersona(oPersona)
{
	if (scoGSITVal.isFormulariValidat()) return;
	if (!scoGSITVal.existeixObjecte(oPersona));

	var oDades = (scoGSITPanells.esPanellMultiple(oPersona)) ? scoGSITPanells.obtenirPersonaPanellMultiple(oPersona) : scoGSITPanells.obtenirObjecteFill(oPersona, "CONTACTE");
	var sTipusUsuari = scoGSITVal.tipusUsuariPanell(oPersona);		
	if (scoGSITVal.esPanellAmbRepresentant(sTipusUsuari))   oDades = scoGSITPanells.obtenirObjecteFill(oDades, "REPRESENTANT");

	return oDades;
}

///////////////////////////////////////////////////////////////////////
// Nom : panellNotificacions
// Descripció: Mètode que retorna el panell adient de notificacions (simple/múltiple)
//////////////////////////////////////////////////////////////////////
function panellNotificacions()
{
	if (scoGSITVal.isFormulariValidat()) return;

	var nIndex = (scoINSPVisualitzacio.esModeTableta())?scoINSPVisualitzacio.CT_INDEX_TBLT:scoINSPVisualitzacio.CT_INDEX_STD;
	var sPath = "ACTAINSPECCIO[0].contacteAvisos[0].BLOC[0].NOTIF_MULTIPLE[" + nIndex +"].NOTIFICACIO[0]";

	return xfa.resolveNode(sPath);

	/* TODO eliminem??
	if (esNotificacioSimple())        return scoOGEPar.oNotifInd;
	else if (esNotificacioMultiple()) return scoOGEPar.oNotifMult;
	else return null;*/
}

////////////////////////////////////////////////////////////
// Nom: checkMarcat
// Descripció: Mètode que retorna si el check de notificacions està marcat
// Paràmetres d'entrada: 
//		oNotif - Panell de les notificacions
// Paràmetres de sortida: 
//		booleà - Valor (true/false) que indica si el check de notificacions està marcat
/////////////////////////////////////////////////////////////
function checkMarcat(oNotif)
{
	if(arguments.lenght < 1) oNotif = panellNotificacions();	
	var oCamp = scoGSITPanells.obtenirObjecteFill(oNotif, "CHK_NOTIFICACIO");
	return (scoGSITVal.existeixObjecte(oCamp) ? (oCamp.rawValue == "1") : false); 
}

/////////////////////////////////////////////////////////////////////////////
// Nom: defTitolNotificacions
// Descripció: Mètode que s'encarrega de definir el títol de les notificacions segons sigui de consentiment o d'obligació
// Paràmetres d'entrada:
//		oPanellNotif - Panell de notificacions a definir
///////////////////////////////////////////////////////////////////////////// 
function defTitolNotificacions(oPanellNotif)
{
	var sMsg = msgNotifTitolConsentiment.value;		//(esNotificacioInformo()) ? msgNotifTitolObligacio.value : msgNotifTitolConsentiment.value;
	scoOGEGeneral.defTextCampPanell("Titol", oPanellNotif, sMsg);	
}

/////////////////////////////////////////////////////////////////////////////
// Nom: defTextObligacio
// Descripció: Mètode que s'encarrega de definir el text d'Obligació de les notificacions
// Paràmetres d'entrada:
//		oPanellNotif - Panell de notificacions a definir
///////////////////////////////////////////////////////////////////////////// 
function defTextObligacio(oPanellNotif)
{
	scoOGEGeneral.defTextCampPanell("txtObligacio", oPanellNotif.parent, msgNotificacionsObligacio.value);	
}

/////////////////////////////////////////////////////////////////////////////
// Nom: defTextConsentiment
// Descripció: Mètode que s'encarrega de definir el text de Consentiment de les notificacions segons sigui de consentiment o d'obligació
// Paràmetres d'entrada:
//		oPanellNotif - Panell de notificacions a definir
///////////////////////////////////////////////////////////////////////////// 
function defTextConsentiment(oPanellNotif)
{
	scoOGEGeneral.defTextCampPanell("txtConsentiment", oPanellNotif.parent, msgNotificacionsConsentiment.value);	
	scoOGEGeneral.defCaptionCampPanell("CHK_NOTIFICACIO", oPanellNotif.parent, msgNotificacionsConsentimentCheck.value);
}

/////////////////////////////////////////////////////////////////////////////
// Nom: defTextFinalNotificacions
// Descripció: Mètode que s'encarrega de definir el text final dels panells de notificacions
// Paràmetres d'entrada:
//		oPanellNotif - Panell de notificacions a definir
///////////////////////////////////////////////////////////////////////////// 
function defTextFinalNotificacions(oPanellNotif)
{
	var oCampText = scoGSITPanells.obtenirObjecteFill(oPanellNotif.parent, "txtURLCertificats");
	if (!scoGSITVal.existeixObjecte(oCampText)) return;

	var sTxt = scoOGEGeneral.definirLinks(msgNotificacionsInfo1.value); 
	var txtInfo1 = scoGSITExData.maquetaParagraf(sTxt);
	var txtInfo2 = scoGSITExData.maquetaParagraf(msgNotificacionsInfo2.value + ":");
	var txtInfo3 = scoGSITExData.maquetaParagraf(msgNotificacionsInfo3.value); // TODO scoGSITExData.maquetaParagraf(scoOGEGeneral.definirPVs(msgNotificacionsInfo3.value));  // Te 1 PV a definir dins del text
	var txtInfo4 = scoGSITExData.maquetaParagraf(msgNotificacionsInfo4.value);	
	var txtInfo5 = scoGSITExData.maquetaParagraf(msgNotificacionsInfo5.value);
	var txtInfo6 = scoGSITExData.maquetaParagraf(msgNotificacionsInfo6.value);		//(esNotificacioCheck()) ? scoGSITExData.maquetaParagraf(msgNotificacionsInfo6.value) : "";

	var sText = scoGSITExData.maquetaRichTextCamp((txtInfo1 + txtInfo2 + txtInfo3 + txtInfo4 + txtInfo5 + txtInfo6), "", false);	
	scoGSITExData.defValueCampRichText(oCampText, sText);		
}

///////////////////////////////////////////////////////////////////////
// Nom : defPanellNotif
// Descripció: Mètode que defineix el panell de Notificacions
// Paràmetres d'entrada: 
//		oNotif - Panell de les notificacions
//////////////////////////////////////////////////////////////////////
function defPanellNotif(oNotif)
{
	if (scoGSITVal.isFormulariValidat()) return;
	if (!scoGSITVal.existeixObjecte(oNotif)) return;

	var bInformo = esNotificacioInformo();
	var bCheck = esNotificacioCheck();

	scoGSITCamps.defVisibilitat(scoGSITPanells.obtenirObjecteFill(oNotif, "sCheck"),   (bCheck   ? "visible" : "hidden"));
	scoGSITCamps.defVisibilitat(scoGSITPanells.obtenirObjecteFill(oNotif, "sInformo"), (bInformo ? "visible" : "hidden"));

	if (scoGSITVal.isFormulariAcusament())		return;

	if (bInformo)    defTextObligacio(oNotif);
	else if (bCheck) defTextConsentiment(oNotif);

	defTitolNotificacions(oNotif);
	defTextFinalNotificacions(oNotif);

	scoGSITVal.defValor(oNotif, "CHK_NOTIFICACIO", "1");	
	var oBtn = scoGSITPanells.obtenirObjecteFill(oNotif, "BTN_COPIAR_DADES");
	scoGSITBot.activaDesactivaBtn(oBtn, teBotoCopiarDades()); 
}


///////////////////////////////////////////////////////////////////////
// Nom : initPanellNotifMultiple
// Descripció: Mètode que inicialitza el panell de Notificacions múltiple
//////////////////////////////////////////////////////////////////////
function initPanellNotifMultiple(oPanell) 
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (scoGSITVal.esFormulariGuardat() && !scoGSITVal.isFormulariAcusament())	return;
		if (!esNotificacioMultiple()) return;

// TODO serà fix!!!		if (!scoGSITVal.isFormulariAcusament()) scoOGEPVs.defBotoCopiaTxtPregunta(scoOGEPar.oNotifMult.sBotons.BTN_COPIAR_DADES, "PARAM_TEXT_BOTO_COPIA_NOTIF_MULTI", msgPreguntaCopiarDadesANotifMulti, "PARAM_TEXT_PREGUNTA_NOTIF_MULTI");
		defPanellNotif(oPanell);

		var oTaula = scoGSITPanells.obtenirObjecteFill(oPanell, "TAULA_NOTIFICACIONS");		
		var oTxtEspecificar = scoGSITPanells.obtenirObjecteFill(oPanell, "sEspecificar");
		var bInformo = esNotificacioInformo();

		if (scoGSITVal.isFormulariAcusament())
		{
			scoGSITCamps.defCampsVisibilitat([oTxtEspecificar, oTaula], (bInformo || checkMarcat(oPanell) ? "visible" : "hidden"));
		}
		else
		{
			oTaula._FILA_DADES_IDENTIFICATIVES.setInstances(0);
			addBlocPersona(oTaula);
			scoGSITCamps.defCampsVisibilitat([oTxtEspecificar, oTaula], "visible");
			var oBtn = scoGSITPanells.obtenirObjecteFill(oNotif, "BTN_COPIAR_DADES");
			scoGSITBot.activaDesactivaBtn(oBtn, true);	

			if (!scoGSITVal.esFormulariGuardat() || !scoGSITVal.isFormulariAcusament())			copiaDadesANotifMultiple(oPanell, true);
		}
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGENotificacions.initPanellNotifMultiple",exc);
	} 
}

///////////////////////////////////////////////////////////////////////
// Nom : iniNotificacions
// Descripció: Mètode que inicialitza els panells de notificacions
//////////////////////////////////////////////////////////////////////
function iniNotificacions(oPanell)
{
	if (scoGSITVal.isFormulariValidat()) return;

	if (!scoGSITVal.isFormulariAcusament())
	{
		if (!teNotificacions())
		{
			scoGSITCamps.defCampsVisibilitat([oPanell], "hidden");
			return;
		}
	}

	scoGSITCamps.defVisibilitat(oPanell, "visible");
	initPanellNotifMultiple(oPanell.NOTIFICACIO);
}               


///////////////////////////////////////////////////////////////////////
// Nom : acceptaNotificacionsMultiples
// Descripció: Funció que activa/desactiva el panell de notificacions multiples
//////////////////////////////////////////////////////////////////////
function acceptaNotificacionsMultiples(oPanell)
{
	if (scoGSITVal.isFormulariValidat()) return;
	if (!esNotificacioMultiple()) return;

	var oNotif = oPanell;
	var oTaula = scoGSITPanells.obtenirObjecteFill(oNotif, "TAULA_NOTIFICACIONS");		
	var oTxtEspecificar = scoGSITPanells.obtenirObjecteFill(oNotif, "sEspecificar");

	var aCamps = [oTxtEspecificar, oTaula];
	var oBtn = scoGSITPanells.obtenirObjecteFill(oNotif, "BTN_COPIAR_DADES");
	if (checkMarcat(oNotif))
	{
		copiaPersonesANotifMulti(oTaula);
		scoGSITCamps.defCampsVisibilitat(aCamps, "visible");
		scoGSITBot.activaDesactivaBtn(oBtn, true);
	}
	else
	{
		oTaula._FILA_DADES_IDENTIFICATIVES.setInstances(0);
		scoGSITGen.netejarForm(oNotif);
		scoGSITCamps.defCampsVisibilitat(aCamps, "hidden");
		scoGSITBot.activaDesactivaBtn(oBtn, false);		
	}		
}


///////////////////////////////////////////////////////////////////////
// Nom: copiaPersonesANotifMulti  
// Descripció: Mètode que copia la info de 'Requeridor' 'Presentador' y 'Persona de contacte' a les notificació múltiples en cas que estiguin definides com persones diferents
// Paràmetres d'entrada:
//		oTaula - Taula de les notificacions multiples
///////////////////////////////////////////////////////////////////////////// 
function copiaPersonesANotifMulti(oTaula)  
{
	try
	{		
		if (scoGSITVal.isFormulariValidat()) return;
		if (!esNotificacioMultiple()) return;
		if (!scoGSITVal.existeixObjecte(oTaula)) return;


		oTaula._FILA_DADES_IDENTIFICATIVES.setInstances(0);
		addPersonaANotifMultiple(oTaula, scoGSITPar.oPanellRequeridor);
	/* TODO ELIMINAR!! NO TENIM PRESENTADOR 	
		var bEsMostraPresentador = scoOGEFigures.tePresentador() && scoGSITVal.existeixPresentador(); // Per si és opcional i no el mostra
		if (bEsMostraPresentador && !scoOGEFigures.esMateixaPersonaIDPresReq())		
			addPersonaANotifMultiple(oTaula, scoGSITPar.oPanellPresentador);

		if (scoOGEDC.teDadesContacte())
		{	
			// Mirem si té les 3 persones (presentador / sol·licitant / contacte) o nomès 2 (sol·licitant / contacte)
			var bPersoDif = (bEsMostraPresentador ? !scoOGEFigures.esMateixaPersonaIDPresReqCont() : !scoOGEFigures.esMateixaPersonaIDReqCont());
			if (bPersoDif)  addPersonaANotifMultiple(oTaula, scoGSITPar.oPanellAvisos);
		}*/

		if (numNotifiacions(oTaula) == 0) addBlocPersona(oTaula); // Sempre ha de tenir mínim 1 persona 
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGENotificacions.copiaPersonesANotifMulti",exc);
	}  

}

///////////////////////////////////////////////////////////////////////
// Nom : defVisibilitatBtnAfegeix
// Descripció: Funció que defineix la visibilitat del botó per afegir una persona a les notificacions multiples
// Paràmetres d'entrada:
//		oBtn - Botó a definir
//////////////////////////////////////////////////////////////////////
function defVisibilitatBtnAfegeix(oBtn)
{
	try
	{
		var oTaula = oBtn.parent.parent;
		scoOGEGeneral.defBtnBloquejatXIndex(oBtn, numNotifiacions(oTaula), numMaxPersones(oTaula));	
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGENotificacions.defVisibilitatBtnAfegeix",exc);
	}		
}        

///////////////////////////////////////////////////////////////////////
// Nom : addBlocPersona
// Descripció: Funció que afegeix una persona a les notificacions multiples
// Paràmetres d'entrada:
//		oTaula - Taula de les notificacions multiples
//////////////////////////////////////////////////////////////////////
function addBlocPersona(oTaula)
{
	try
	{
		return oNotif = oTaula._FILA_DADES_IDENTIFICATIVES.addInstance(1);
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGENotificacions.addBlocPersona",exc);
	}		
}

///////////////////////////////////////////////////////////////////////
// Nom: addPersonaANotifMultiple
// Descripció: Mètode que afegeix una persona a Notificacions multiple
// Paràmetres d'entrada:
//		oTaula - Taula de les notificacions multiples
//		oPersona - Persona que s'afegirà a les notificacions
///////////////////////////////////////////////////////////////////////////// 
function addPersonaANotifMultiple(oTaula, oPersona)
{
	if (!scoGSITVal.existeixObjecte(oTaula) || !scoGSITVal.existeixObjecte(oPersona)) return;
	var oInfoPersona = getBlocPersona(oPersona);
	var oTipusIdentificador = scoGSITPanells.obtenirObjecteFill(oInfoPersona, "TXT_TIPUS_IDENTIFICADOR");	

	if (numNotifiacions(oTaula) < numMaxPersones(oTaula)) 
	{
		var oPersoNotif = addBlocPersona(oTaula);
		scoGSITPanells.copiaCampsPanells(oInfoPersona, oPersoNotif, aNomCampsNotifMultiple); 
		scoGSITVal.controlPassaport(scoGSITPanells.obtenirObjecteFill(oPersoNotif, "TXT_TIPUS_IDENTIFICADOR")); 
	}
}

///////////////////////////////////////////////////////////////////////
// Nom : deletePersonaNotif
// Descripció: Funció que esborra la persona a notificar
// Paràmetres d'entrada:
//		oBtn - Botó de la persona que s'ha d'esborrar
//////////////////////////////////////////////////////////////////////
function deletePersonaNotif(oBtn)
{
	try
	{
		var oDecla = oBtn.parent.parent;
		oDecla._FILA_DADES_IDENTIFICATIVES.removeInstance(oBtn.parent.index);
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGENotificacions.deletePersonaNotif",exc);
	}		
}


///////////////////////////////////////////////////////////////////////
// Nom : netejaNotificacionsMult
// Descripció: Mètode que neteja el panell de Notificacions múltiples
//////////////////////////////////////////////////////////////////////
function netejaNotificacionsMult(oNotif)
{
	var oTaula = scoGSITPanells.obtenirObjecteFill(oNotif, "TAULA_NOTIFICACIONS");
	oTaula._FILA_DADES_IDENTIFICATIVES.setInstances(0);
	scoGSITGen.netejarForm(oTaula);

	defPanellNotifMultipleCanvi(oNotif);	
}

///////////////////////////////////////////////////////////////////////
// Nom : netejaPanellNotificacions
// Descripció: Mètode que neteja el panell de Notificacions
//////////////////////////////////////////////////////////////////////
function netejaPanellNotificacions(oPanell)
{
	if (scoGSITVal.isFormulariValidat()) return;	
	if (!teNotificacions()) return;

	netejaNotificacionsMult(oPanell);
}

////////////////////////////////////////////////////////////
// Nom: calCopiarNotif
// Descripció: Mètode que mira si s'han de copiar les dades al panell corresponent de notificacions
// Paràmetres d'entrada:
//		bPregunta - Indica si s'ha de preguntar si es vol realitzar la copia. Preguntarà si es volen reemplaçar les dades nomès si hi han camps definits a les notificacions.
//		oNotif - Panell de les notificacions
//		oPanellDades - Panell de les notificions amb les dades
//		sMsg - Missatge que es mostrarà al fer la pregunta
////////////////////////////////////////////////////////////
function calCopiarNotif(bPregunta, oNotif, oPanellDades, sMsg)
{
	if (scoGSITVal.isFormulariValidat()) return;	
	// TODO VISUALITZACIÓ		--> permetem copiar encara que estigui ocult!!!!    if (!scoGSITCamps.esVisible(oNotif)) return;
	if (esNotificacioCheck() && !checkMarcat(oNotif)) return;

	var bPregunta = (scoOGEGeneral.teAlgunCampPlePanell(oPanellDades) && bPregunta) ? true : false;
	bCopia = (bPregunta) ? (scoGSITMissatges.MissatgePregunta(sMsg,"")) : true;

	return bCopia;
} 

////////////////////////////////////////////////////////////
// Nom: copiaDadesRequeridorNotifSimple
// Descripció: Mètode que copia els camps de requeridor a Notif simple
// Paràmetres d'entrada:
//		bPregunta - Indica si s'ha de preguntar si es vol realitzar la copia. Preguntarà si es volen reemplaçar les dades nomès si hi han camps definits a les notificacions.
////////////////////////////////////////////////////////////
function copiaDadesRequeridorNotifSimple(bPregunta)
{
	if (calCopiarNotif(bPregunta, scoOGEPar.oNotifInd, scoOGEPar.oNotifInd.sDadesNotif, msgPreguntaCopiarDadesANotifSimple.value)) copiaRequeridorNotifSimple();		
}    

////////////////////////////////////////////////////////////
// Nom: copiaDadesANotifMultiple
// Descripció: Mètode que copia la info de 'Requeridor' 'Presentador' y 'Persona de contacte' a les notificació múltiples en cas que estiguin definides com persones diferents
// Paràmetres d'entrada:
//		bPregunta - Indica si s'ha de preguntar si es vol realitzar la copia. Preguntarà si es volen reemplaçar les dades nomès si hi han camps definits a les notificacions.
////////////////////////////////////////////////////////////
function copiaDadesANotifMultiple(oPanell, bPregunta)
{
	var oTaula = scoGSITPanells.obtenirObjecteFill(oPanell, "TAULA_NOTIFICACIONS");
	if (calCopiarNotif(bPregunta, oPanell, oTaula, msgPreguntaCopiarDadesANotifMulti.value)) 
	{
		copiaPersonesANotifMulti(oTaula);
		return true;
	}
	return false;
}  


///////////////////////////////////////////////////////////////////////
// Nom : defPanellNotifMultipleCanvi
// Descripció: Mètode que defineix el panell de Notificacions múltiples després d'un canvi de tipus de sol·licitant
//////////////////////////////////////////////////////////////////////
function defPanellNotifMultipleCanvi(oPanell) 
{
	try
	{
		if (scoGSITVal.isFormulariValidat()) return;
		if (!esNotificacioMultiple()) return

		// TODO serà fix!!!   if (!scoGSITVal.isFormulariAcusament()) scoOGEPVs.defBotoCopiaTxtPregunta(scoGSITPar.oNotifMult.sBotons.BTN_COPIAR_DADES, "PARAM_TEXT_BOTO_COPIA_NOTIF_MULTI", msgPreguntaCopiarDadesANotifMulti, "PARAM_TEXT_PREGUNTA_NOTIF_MULTI");
		defPanellNotif(oPanell);

		var oTaula = scoGSITPanells.obtenirObjecteFill(oPanell, "TAULA_NOTIFICACIONS");		
		var oTxtEspecificar = scoGSITPanells.obtenirObjecteFill(oPanell, "sEspecificar");
		oTaula._FILA_DADES_IDENTIFICATIVES.setInstances(0);
		addBlocPersona(oTaula);
