///////////////////////////////////////////////////////////////////////
//Nom : validacioConjunta
//Paràmetres d'entrada : 
//Retorna: 
//Descripció : 
//////////////////////////////////////////////////////////////////////   
function validacioConjunta(aResults)
{
	var bResultCheck={
      validacioCorrecte: true,
      missatgeError : "",
      campsIncorrectes : new Array()
    };

    //Comprovem si tenim un missatge d'error repetit
    for (var nElem=0; nElem<aResults.length; nElem++)
	{	
		for (var nPos=nElem+1; nPos<aResults.length; nPos++)  // Només cal comparar amb els seguents, els anteriors ja els ha fet
			if (aResults[nElem].missatgeError == aResults[nPos].missatgeError) aResults[nPos].missatgeError = "";
	}

	for (var nElem=0; nElem<aResults.length; nElem++)
	{
		if (!aResults[nElem].validacioCorrecte || aResults[nElem].validacioCorrecte == -1)
		{
			bResultCheck.validacioCorrecte = false;
			bResultCheck.missatgeError = bResultCheck.missatgeError + aResults[nElem].missatgeError;
			if(scoGSITVal.existeixObjecte(aResults[nElem].campsIncorrectes))
			{
				for(var nPos=0; nPos<aResults[nElem].campsIncorrectes.length; nPos++)
					bResultCheck.campsIncorrectes = bResultCheck.campsIncorrectes.concat(aResults[nElem].campsIncorrectes[nPos]);
			}
		}
	}
	return(bResultCheck);
}

