///////////////////////////////////////////////////////////////////////
// Nom : tancarFormulari
// Descripció: tanca el formulari un cop s'ha validat.
//			Aquest estat NO permet desbloquejar les dades
//////////////////////////////////////////////////////////////////////
function tancarFormulari()
{
	try
	{
		if (scoGSITMissatges.MissatgePregunta(msgTancarFormulari.value,""))
		{
			// Execuetem codi imatges
			scoINSPImatges.tancaImatgeZoom();

			var bTanquemEnModeStd = scoINSPVisualitzacio.esModeStandard();

			// deixem el formulari en mode STANDARD
			scoINSPVisualitzacio.canviaMode(scoINSPVisualitzacio.CT_INDEX_STD);

			// Si NO estàvem en mode stàndard cal bloquejar de nou els camps!!
			if (!bTanquemEnModeStd)		
			{
				xfa.layout.relayout();
				// Array amb les somExpressions dels camps que no volem bloquejar al tancar
				var arrExceptionSOMs = new Array();	

				scoGSITPar.oDadesCFGTramit.parent.VALIDACIO.TXT_DADES.rawValue = scoGSITVal.getLockableObjects(arrExceptionSOMs);
				scoGSITCamps.protectAllFields(scoGSITPar.oDadesCFGTramit.parent.VALIDACIO.TXT_DADES.rawValue);

				scoINSPPar.oRBModeTableta.rawValue = "1";
			}

			var oBtnDesbloquejar = scoGSITPanells.obtenirObjecteFill(scoGSITPar.oPanellValidacio, "BTN_DESBLOQUEJAR");
			var oBtnTancar = scoGSITPanells.obtenirObjecteFill(scoGSITPar.oPanellValidacio, "BTN_TANCAR");
			scoGSITBot.canviEstatAcceptar(0, null, oBtnDesbloquejar);
			scoGSITBot.canviEstatAcceptar(0, null, oBtnTancar);

			scoGSITPar.oPanellValidacio.resolveNode("S_BTNS[0]").presence = "hidden";
			scoGSITPar.oPanellValidacio.resolveNode("S_BTNS[1]").presence = "hidden";
			scoGSITPar.oPanellDesar.presence = "hidden";

			contacteAvisos.BLOC.resolveNode("BOTONERA_INTERMEDIA[0]").presence = "hidden";
			contacteAvisos.BLOC.resolveNode("BOTONERA_INTERMEDIA[1]").presence = "hidden";

			defFormuariTancat();

			xfa.layout.relayout();	// TODO - PER FORÇAR CANVI COORDENADES	(fem només si canviem de mode?)
			scoINSPCoords.setCoordsFields(contacteAvisos.BLOC.S_SIGNATURE.S_INSPECTOR);	
			scoINSPCoords.setCoordsFields(contacteAvisos.BLOC.S_SIGNATURE.S_COMPAREIXENT);

			// Ocultar identificadors inspectors, per tal que no es mostrin al document pla imprimible.
			ocultarIdentificadorsInspectors();

			// Netejar les dades de les signatures no utilitzades
			scoINSPSignatures.netejarDadesSignaturaExtra();

			// Genera un xml amb les dades dels adjunts annexats per l'usuari
			scoINSPAdjunts.setXmlFileAttachments();

			// Adjunta un xml amb les dades del formulari	
			scoINSPSignatures.attachXMLDades();

			ocultaObjectesACK();
		}
	}
	catch(exc) {
		return scoGSITGen.retornarExcepcio("scoOGEValidacio.tancarFormulari",exc);
	}	
}

/////////////////////////////////////////////////////////////////////////////
// Nom: defFormuariTancat
