	event.target.createDataObject("dades.xml", "");	

	// Force UTF-8 conversion
	var streamXMLUTF8 = util.streamFromString(strXML,"utf-8");
	var strXMLUTF8 = util.stringFromStream(streamXMLUTF8,"utf-8");


	var posIn = strXMLUTF8.indexOf("<Signatures>");
	var posFinal = strXMLUTF8.indexOf("</Signatures>") + "<Signatures>".length;

	// Parse back into an XML document
	var xmlXFAData = XMLData.parse(strXMLUTF8, false);


	strXFAData = xmlXFAData.saveXML();
