}

////////////////////////////////////////////////////////////
// Nom: ocultaBtns
// Descripció:  Mètode que oculta tots els butons del panell
// Paràmetres d'entrada: 
//		oPanell - Panell on ocultar botons
////////////////////////////////////////////////////////////
function ocultaBtns(oNode)
{	
	if (!scoGSITVal.existeixObjecte(oNode))			return;

	var oNodes = oNode.nodes;
	if (oNode.className == "subform")
	{
		for (var i=0; i<oNodes.length; i++)
		{
			if (scoGSITPanells.esObjecteValid(oNodes.item(i))	)		ocultaBtns(oNodes.item(i));
		}
	}
	else
	{
		if (scoGSITGen.existeixPropietat(oNode, "ui"))
		{
			if (scoGSITGen.existeixPropietat(oNode.ui, "button"))	
			{
				oNode.presence = "hidden";
			}
		}
	}
}

