		//var sTextFitxer = SOAP.stringFromStream(oAnexoStream, "ISO-8859-1"); // def
		var sTextFitxer = util.stringFromStream(oAnexoStream, "utf-8"); // prueba
		//var sTextFitxer = SOAP.stringFromStream(oAnexoStream, "utf-8");
		// Assignem la informació al control...
		this.parent.TXT_CAMP.rawValue = sTextFitxer;
		// Cal afinar la codificació
